// ── COLLECTION STOCK RECON ──
async function loadColStockRecon(colId, colName) {
  const el = document.getElementById(`col-stock-${colId}`);
  if (!el) return;
  el.innerHTML = `<div style="color:var(--g400);font-size:12px">Memuat...</div>`;
  try {
    const { data: mappings, error: mErr } = await sb
      .from("product_mappings").select("jubelio_item_id, item_name").ilike("collection", colName);
    if (mErr || !mappings?.length) {
      el.innerHTML = `<div style="color:var(--g400);font-size:12px;padding:4px 0">Belum ada produk yang di-mapping ke koleksi ini.</div>`;
      return;
    }
    // Expand mappings (1 row per item_name) to ALL SKU variants of those names.
    // Chunk both .in(item_name) and downstream .in(item_id) — itemNames can be
    // 2000+ for full reconcile, which blows past PostgREST URL limits.
    const itemNames = [...new Set(mappings.map(m => m.item_name).filter(Boolean))];
    const allVariantRows = await _fetchAllPagesIn('jubelio_items','item_id,item_name,item_code','item_name', itemNames);
    const itemIds = [...new Set(allVariantRows.map(r => r.item_id))];

    const [adjItems, poItems, salesItems, stocks] = await Promise.all([
      _fetchAllPagesIn("jubelio_inventory_adjustment_items","item_id,qty","item_id", itemIds),
      _fetchAllPagesIn("jubelio_purchase_order_items","item_id,qty","item_id", itemIds),
      _fetchAllPagesIn("jubelio_sales_order_items","item_id,qty,salesorder_id","item_id", itemIds),
      _fetchAllPagesIn("jubelio_inventory_stocks","item_id,on_hand","item_id", itemIds),
    ]);
    const jubelioItems = allVariantRows; // already fetched

    // Categorise order IDs by wms_status
    let completedSet = new Set(), inProgressSet = new Set(), returnedSet = new Set();
    if (salesItems.length) {
      const soIds = [...new Set(salesItems.map(s => s.salesorder_id))];
      const chunks = [];
      for (let i = 0; i < soIds.length; i += 200) chunks.push(soIds.slice(i, i + 200));
      const [cRes, ipRes, rRes] = await Promise.all([
        Promise.all(chunks.map(c => sb.from("jubelio_sales_orders").select("salesorder_id").in("salesorder_id",c).eq("wms_status","COMPLETED"))),
        Promise.all(chunks.map(c => sb.from("jubelio_sales_orders").select("salesorder_id").in("salesorder_id",c).in("wms_status",["SHIPPED","FINISH_PACK","FINISH_PICK","PAID","PENDING"]))),
        Promise.all(chunks.map(c => sb.from("jubelio_sales_orders").select("salesorder_id").in("salesorder_id",c).eq("wms_status","RETURNED"))),
      ]);
      for (const r of cRes)  for (const o of (r.data||[])) completedSet.add(o.salesorder_id);
      for (const r of ipRes) for (const o of (r.data||[])) inProgressSet.add(o.salesorder_id);
      for (const r of rRes)  for (const o of (r.data||[])) returnedSet.add(o.salesorder_id);
    }

    // Size map
    const sizeMap = {};
    for (const ji of (jubelioItems||[])) {
      const parts = (ji.item_code||"").split("-");
      sizeMap[ji.item_id] = parts[parts.length-1] || "?";
    }

    // Per-variant aggregates
    const varData = {};
    for (const id of itemIds) varData[id] = {adjIn:0,adjOut:0,po:0,sold:0,inProgress:0,returned:0,stock:0};
    for (const a of adjItems) {
      if (varData[a.item_id]===undefined) continue;
      const qty = parseFloat(a.qty||0);
      if (qty>0) varData[a.item_id].adjIn += qty; else varData[a.item_id].adjOut += Math.abs(qty);
    }
    for (const p of poItems) {
      if (varData[p.item_id]!==undefined) varData[p.item_id].po += parseFloat(p.qty||0);
    }
    for (const si of salesItems) {
      if (varData[si.item_id]===undefined) continue;
      const qty = parseFloat(si.qty||0);
      if (completedSet.has(si.salesorder_id))   varData[si.item_id].sold       += qty;
      else if (inProgressSet.has(si.salesorder_id)) varData[si.item_id].inProgress += qty;
      else if (returnedSet.has(si.salesorder_id))   varData[si.item_id].returned   += qty;
    }
    for (const s of stocks) {
      if (varData[s.item_id]!==undefined) varData[s.item_id].stock += parseFloat(s.on_hand||0);
    }

    // Group by product name — iterate over ALL SKU variants, not just the
    // representative jubelio_item_id stored in product_mappings.
    const productGroups = {};
    for (const v of allVariantRows) {
      if (!v.item_id || !v.item_name) continue;
      if (!productGroups[v.item_name]) productGroups[v.item_name] = {name:v.item_name,variants:[]};
      const vd = varData[v.item_id]||{adjIn:0,adjOut:0,po:0,sold:0,inProgress:0,returned:0,stock:0};
      const stockIn = vd.po + vd.adjIn;
      const sisa    = stockIn - vd.adjOut - vd.sold - vd.inProgress - vd.returned - vd.stock;
      productGroups[v.item_name].variants.push({id:v.item_id, size:sizeMap[v.item_id]||"?",
        ...vd, stockIn, sisa});
    }
    const products = Object.values(productGroups).sort((a,b)=>a.name.localeCompare(b.name,'id')).map(p => {
      const totStockIn    = p.variants.reduce((s,v)=>s+v.stockIn,0);
      const totAdjOut     = p.variants.reduce((s,v)=>s+v.adjOut,0);
      const totSold       = p.variants.reduce((s,v)=>s+v.sold,0);
      const totInProgress = p.variants.reduce((s,v)=>s+v.inProgress,0);
      const totReturned   = p.variants.reduce((s,v)=>s+v.returned,0);
      const totStock      = p.variants.reduce((s,v)=>s+v.stock,0);
      const totSisa       = p.variants.reduce((s,v)=>s+v.sisa,0);
      return {...p, totStockIn, totAdjOut, totSold, totInProgress, totReturned, totStock, totSisa};
    });
    const grand = products.reduce((acc,p)=>{
      acc.stockIn+=p.totStockIn; acc.adjOut+=p.totAdjOut; acc.sold+=p.totSold;
      acc.inProgress+=p.totInProgress; acc.returned+=p.totReturned;
      acc.stock+=p.totStock; acc.sisa+=p.totSisa;
      return acc;
    },{stockIn:0,adjOut:0,sold:0,inProgress:0,returned:0,stock:0,sisa:0});

    const f   = n => (n===0||n==null)?'0':n.toLocaleString('id-ID');
    const TH  = `padding:6px 10px;font-family:var(--mono);font-size:10px;text-transform:uppercase;color:var(--g400);text-align:right;white-space:nowrap;border-bottom:2px solid var(--g100)`;
    const THL = TH.replace('right','left');
    const THc = clr => TH.replace('var(--g400)',clr);

    let html = `<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">
      <thead><tr>
        <th style="${THL}">Produk / Ukuran</th>
        <th style="${TH}">Stock In</th>
        <th style="${TH}">└ PO</th>
        <th style="${TH}">└ Adj+</th>
        <th style="${THc('#c0700a')}">Stock Out</th>
        <th style="${TH}">Terjual</th>
        <th style="${THc('#d97706')}">In Progress</th>
        <th style="${THc('#7c3aed')}">Return</th>
        <th style="${TH}">Stock</th>
        <th style="${TH}">Sisa</th>
      </tr></thead><tbody>`;

    const NA = `<span style="color:var(--g200)">—</span>`;
    products.forEach((p, pi) => {
      const sorted = [...p.variants].sort((a,b)=>{
        const o=SIZE_ORDER; const ai=o.indexOf(a.size),bi=o.indexOf(b.size);
        if(ai===-1&&bi===-1) return a.size.localeCompare(b.size);
        return (ai===-1?999:ai)-(bi===-1?999:bi);
      });
      const hasV = sorted.length>1;
      const key = `${colId}-${pi}`;
      const sisaClr = p.totSisa > 0 ? '#c0392b' : p.totSisa < 0 ? '#3C3489' : 'var(--g400)';
      html += `<tr style="border-top:1px solid var(--g100);background:var(--off)">
        <td style="padding:7px 10px;font-weight:600;${hasV?'cursor:pointer':''}" onclick="${hasV?`toggleSR('${key}')`:''}" >
          ${hasV?`<span id="sr-tog-${key}" style="font-size:10px;margin-right:4px;color:var(--g400)">▶</span>`:''}${p.name}
        </td>
        <td style="padding:7px 10px;text-align:right;font-weight:600">${f(p.totStockIn)}</td>
        <td style="padding:7px 10px;text-align:right;color:var(--g400)">${f(p.variants.reduce((s,v)=>s+v.po,0))}</td>
        <td style="padding:7px 10px;text-align:right;color:var(--g400)">${f(p.variants.reduce((s,v)=>s+v.adjIn,0))}</td>
        <td style="padding:7px 10px;text-align:right;color:#c0700a">${p.totAdjOut?f(p.totAdjOut):NA}</td>
        <td style="padding:7px 10px;text-align:right;font-weight:600">${f(p.totSold)}</td>
        <td style="padding:7px 10px;text-align:right;color:#d97706">${p.totInProgress?f(p.totInProgress):NA}</td>
        <td style="padding:7px 10px;text-align:right;color:#7c3aed">${p.totReturned?f(p.totReturned):NA}</td>
        <td style="padding:7px 10px;text-align:right;font-weight:600">${f(p.totStock)}</td>
        <td style="padding:7px 10px;text-align:right;font-weight:600;color:${sisaClr}">${p.totSisa > 0 ? '+' : ''}${f(p.totSisa)}</td>
      </tr>`;
      if (hasV) {
        for (const v of sorted) {
          const vSisaClr = v.sisa > 0 ? '#c0392b' : v.sisa < 0 ? '#3C3489' : 'var(--g400)';
          html += `<tr data-srg="${key}" style="display:none;background:#fafaf8;border-top:1px solid var(--g100)">
            <td style="padding:4px 10px 4px 28px;color:var(--g400);font-family:var(--mono);font-size:11px">${v.size}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px">${f(v.stockIn)}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;color:var(--g400)">${f(v.po)}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;color:var(--g400)">${f(v.adjIn)}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;color:#c0700a">${v.adjOut?f(v.adjOut):NA}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;font-weight:600">${f(v.sold)}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;color:#d97706">${v.inProgress?f(v.inProgress):NA}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;color:#7c3aed">${v.returned?f(v.returned):NA}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;font-weight:600">${f(v.stock)}</td>
            <td style="padding:4px 10px;text-align:right;font-size:11px;font-weight:600;color:${vSisaClr}">${v.sisa > 0 ? '+' : ''}${f(v.sisa)}</td>
          </tr>`;
        }
      }
    });

    const grandSisaClr = grand.sisa > 0 ? '#c0392b' : grand.sisa < 0 ? '#3C3489' : 'var(--g400)';
    html += `<tr style="border-top:2px solid var(--g100);background:var(--off);font-weight:700">
      <td style="padding:8px 10px;font-family:var(--mono);font-size:11px;text-transform:uppercase">Total</td>
      <td style="padding:8px 10px;text-align:right">${f(grand.stockIn)}</td>
      <td style="padding:8px 10px;text-align:right;color:var(--g400)">—</td>
      <td style="padding:8px 10px;text-align:right;color:var(--g400)">—</td>
      <td style="padding:8px 10px;text-align:right;color:#c0700a">${grand.adjOut?f(grand.adjOut):NA}</td>
      <td style="padding:8px 10px;text-align:right">${f(grand.sold)}</td>
      <td style="padding:8px 10px;text-align:right;color:#d97706">${grand.inProgress?f(grand.inProgress):NA}</td>
      <td style="padding:8px 10px;text-align:right;color:#7c3aed">${grand.returned?f(grand.returned):NA}</td>
      <td style="padding:8px 10px;text-align:right">${f(grand.stock)}</td>
      <td style="padding:8px 10px;text-align:right;color:${grandSisaClr}">${grand.sisa > 0 ? '+' : ''}${f(grand.sisa)}</td>
    </tr></tbody></table></div>
    <div style="margin-top:8px;font-size:10px;color:var(--g400);font-family:var(--mono)">Stock In = PO + Adj+ · Stock Out = Adj− · Terjual = COMPLETED · In Progress = SHIPPED/FINISH_PACK/FINISH_PICK/PAID/PENDING · Return = RETURNED · Sisa = Stock In − Stock Out − Terjual − In Progress − Return − Stock · merah = ada barang tidak tercatat</div>`;

    el.innerHTML = html;
  } catch(e) {
    el.innerHTML = `<div style="color:#c0392b;font-size:12px">Gagal memuat: ${e.message||e}</div>`;
  }
}

function toggleSR(key) {
  const tog = document.getElementById(`sr-tog-${key}`);
  const rows = document.querySelectorAll(`[data-srg="${key}"]`);
  if (!rows.length) return;
  const open = rows[0].style.display === 'table-row';
  rows.forEach(r => r.style.display = open ? 'none' : 'table-row');
  if (tog) tog.textContent = open ? '▶' : '▼';
}

// ── COLLECTION PERF CHART ──
const _colPerfCharts = {};

function getWeekStart(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  const day = d.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  d.setDate(d.getDate() + diff);
  return d.toISOString().slice(0, 10);
}

function setColPerfView(colId, view, el) {
  const container = document.getElementById(`col-chart-btns-${colId}`);
  if (container) container.querySelectorAll('button').forEach(b => {
    b.style.background = 'none';
    b.style.color = 'var(--g600)';
    b.style.borderColor = 'var(--g200)';
  });
  if (el) {
    el.style.background = 'var(--black)';
    el.style.color = 'var(--white)';
    el.style.borderColor = 'var(--black)';
  }
  renderColPerfChart(colId, view);
}

function renderColPerfChart(colId, view) {
  const d = _colPerfCache[colId];
  if (!d || !d.timeSeries) return;
  const canvas = document.getElementById(`col-perf-chart-${colId}`);
  if (!canvas || typeof Chart === 'undefined') return;
  const ID_MONTHS = ['Jan','Feb','Mar','Apr','Mei','Jun','Jul','Agu','Sep','Okt','Nov','Des'];
  const grouped = {};
  for (const [date, vals] of Object.entries(d.timeSeries)) {
    let key;
    if (view === 'day') key = date;
    else if (view === 'week') key = getWeekStart(date);
    else key = date.slice(0, 7);
    if (!grouped[key]) grouped[key] = { qty: 0, revenue: 0 };
    grouped[key].qty += vals.qty;
    grouped[key].revenue += vals.revenue;
  }
  const labels = Object.keys(grouped).sort();
  const fmtLabel = key => {
    if (view === 'month') {
      const [y, m] = key.split('-');
      return `${ID_MONTHS[parseInt(m) - 1]} '${y.slice(2)}`;
    }
    const [, m, dd] = key.split('-');
    return `${parseInt(dd)} ${ID_MONTHS[parseInt(m) - 1]}`;
  };
  if (_colPerfCharts[colId]) { _colPerfCharts[colId].destroy(); delete _colPerfCharts[colId]; }
  if (!labels.length) return;
  const plugins = typeof ChartDataLabels !== 'undefined' ? [ChartDataLabels] : [];
  const fmtVal = v => v >= 1000000 ? (v / 1000000).toFixed(1) + 'jt' : (v / 1000).toFixed(0) + 'k';
  _colPerfCharts[colId] = new Chart(canvas, {
    plugins,
    data: {
      labels: labels.map(fmtLabel),
      datasets: [
        {
          type: 'bar',
          label: 'Total Sales',
          data: labels.map(k => grouped[k].revenue),
          yAxisID: 'yRevenue',
          backgroundColor: 'rgba(45,122,45,0.65)',
          borderRadius: 4,
          order: 2,
          datalabels: {
            display: true,
            anchor: 'end',
            align: 'end',
            offset: 2,
            color: '#2d7a2d',
            font: { size: 8, family: 'DM Mono', weight: '600' },
            formatter: v => v > 0 ? fmtVal(v) : ''
          }
        },
        {
          type: 'line',
          label: 'Qty Terjual',
          data: labels.map(k => grouped[k].qty),
          yAxisID: 'yQty',
          borderColor: '#3b82f6',
          backgroundColor: 'rgba(59,130,246,0.08)',
          tension: 0.35,
          pointRadius: 3,
          pointBackgroundColor: '#3b82f6',
          fill: false,
          order: 1,
          datalabels: { display: false }
        }
      ]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      layout: { padding: { top: 20 } },
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: ctx => ctx.datasetIndex === 0
              ? ` Sales: Rp ${Math.round(ctx.raw).toLocaleString('id-ID')}`
              : ` Qty: ${Math.round(ctx.raw)} pcs`
          }
        },
        datalabels: { display: false } // default off; per-dataset overrides above
      },
      scales: {
        x: {
          grid: { display: false },
          ticks: { font: { size: 10, family: 'DM Mono' } }
        },
        yRevenue: {
          position: 'left',
          grid: { color: 'rgba(0,0,0,0.05)' },
          ticks: {
            font: { size: 9, family: 'DM Mono' },
            callback: v => 'Rp ' + (v >= 1000000 ? (v / 1000000).toFixed(1) + 'jt' : (v / 1000).toFixed(0) + 'k')
          }
        },
        yQty: {
          position: 'right',
          grid: { drawOnChartArea: false },
          ticks: {
            font: { size: 9, family: 'DM Mono' },
            callback: v => v + ' pcs'
          }
        }
      }
    }
  });
}

// ── SALES PERFORMANCE ──

// SP Multi-Select component
const _spMS = {};
let _spMSInitialized = false;

function _initSPMultiSelects() {
  if (_spMSInitialized) return;
  _spMSInitialized = true;
  const defs = [
    { id:'sp-ms-status',     ph:'Semua Status',   staticOpts:['Completed','In Progress','Cancelled','Returned'] },
    { id:'sp-ms-channel',    ph:'Semua Channel',  staticOpts:null },
    { id:'sp-ms-store',      ph:'Semua Store',    staticOpts:null },
    { id:'sp-ms-brand',      ph:'Semua Brand',    staticOpts:null },
    { id:'sp-ms-ip',         ph:'Semua IP',       staticOpts:null },
    { id:'sp-ms-collection', ph:'Semua Koleksi',  staticOpts:null },
  ];
  for (const d of defs) {
    const wrap = document.getElementById(d.id);
    if (!wrap) continue;
    wrap.innerHTML = `<button class="sp-ms-toggle" id="${d.id}-toggle" onclick="_spMSOpen(event,'${d.id}')">${d.ph}</button>`;
    const panel = document.createElement('div');
    panel.id = d.id + '-panel';
    panel.className = 'sp-ms-panel';
    panel.style.display = 'none';
    panel.innerHTML = `
      <div class="sp-ms-search-wrap">
        <input type="text" class="sp-ms-search" placeholder="Type to search" oninput="_spMSSearch('${d.id}',this.value)">
        <div class="sp-ms-actions">
          <button class="sp-ms-action-btn" onclick="event.stopPropagation();_spMSSelectAll('${d.id}')">Pilih Semua</button>
          <button class="sp-ms-action-btn" onclick="event.stopPropagation();_spMSDeselectAll('${d.id}')">Hapus Semua</button>
        </div>
      </div>
      <div class="sp-ms-list" id="${d.id}-list"></div>`;
    wrap.appendChild(panel);
    panel.addEventListener('click', e => e.stopPropagation());
    const ms = {
      id: d.id, ph: d.ph,
      options: [], allValues: [], selected: new Set(),
      getValues() { return (this.selected.size===0||this.selected.size===this.allValues.length) ? [] : [...this.selected]; },
      isAll() { return this.selected.size===0||this.selected.size===this.allValues.length||this.options.length===0; },
      setOptions(opts) { // opts: [{value,label,count}]
        const prevSelected = this.selected.size>0 && !this.isAll() ? new Set(this.selected) : null;
        this.options=opts; this.allValues=opts.map(o=>o.value);
        this.selected = prevSelected ? new Set(this.allValues.filter(v=>prevSelected.has(v))) : new Set(this.allValues);
        if (this.selected.size===0) this.selected=new Set(this.allValues);
        this._render(); this._updateToggle();
      },
      reset() { this.selected=new Set(this.allValues); this._render(); this._updateToggle(); },
      clear() { this.options=[]; this.allValues=[]; this.selected=new Set(); this._render(); this._updateToggle(); },
      toggle(val,checked) { if(checked) this.selected.add(val); else this.selected.delete(val); this._updateToggle(); },
      only(val) { this.selected=new Set([val]); this._render(); this._updateToggle(); },
      _render(search='') {
        const list=document.getElementById(this.id+'-list'); if(!list)return;
        const q=search.toLowerCase();
        const shown=this.options.filter(o=>!q||o.label.toLowerCase().includes(q));
        list.innerHTML=shown.map(o=>`<div class="sp-ms-item"><label class="sp-ms-lbl"><input type="checkbox" ${this.selected.has(o.value)?'checked':''} onchange="_spMSToggle('${this.id}','${o.value}',this.checked)"><span title="${o.label}">${o.label}</span></label>${o.count!=null?`<span class="sp-ms-count">${o.count.toLocaleString('id-ID')}</span>`:''}<button class="sp-ms-only" onclick="event.stopPropagation();_spMSOnly('${this.id}','${o.value}')">ONLY</button></div>`).join('');
      },
      _updateToggle() {
        const btn=document.getElementById(this.id+'-toggle'); if(!btn)return;
        if(this.isAll()){ btn.textContent=this.ph; btn.classList.remove('sp-ms-active'); }
        else { btn.textContent=`${this.ph} (${this.selected.size})`; btn.classList.add('sp-ms-active'); }
      }
    };
    _spMS[d.id] = ms;
    if (d.staticOpts) ms.setOptions(d.staticOpts.map(v=>({value:v,label:v,count:null})));
  }
  document.addEventListener('click', ()=>{ document.querySelectorAll('.sp-ms-panel').forEach(p=>p.style.display='none'); });
}

async function _preloadSPFiltersAndRun() {
  // Load product_mappings (cached) → populate brand/IP/collection dropdowns
  if (!_spAllMappings) {
    _spAllMappings = await _fetchAllPages('product_mappings', 'jubelio_item_id,item_name,brand,ip,collection');
  }
  const brandMS=_spMS['sp-ms-brand'], ipMS=_spMS['sp-ms-ip'], colMS=_spMS['sp-ms-collection'];
  if (_spAllMappings) {
    if (brandMS && brandMS.options.length===0) {
      const brands=[...new Set(_spAllMappings.map(m=>m.brand).filter(Boolean))].sort();
      brandMS.setOptions(brands.map(b=>({value:b,label:b,count:null})));
    }
    if (ipMS && ipMS.options.length===0) {
      const ips=[...new Set(_spAllMappings.map(m=>m.ip).filter(Boolean))].sort();
      ipMS.setOptions(ips.map(i=>({value:i,label:i,count:null})));
    }
    if (colMS && colMS.options.length===0) {
      const cols=[...new Set(_spAllMappings.map(m=>m.collection).filter(Boolean))].sort();
      colMS.setOptions(cols.map(c=>({value:c,label:c,count:null})));
    }
  }
  const emEl=document.getElementById('sp-empty');
  if(emEl) emEl.textContent='Atur filter dan klik "↻ Analisis" untuk memuat data.';
  // Auto-run analysis for current month
  loadSalesPerf();
}

function _spMSOpen(e, id) {
  e.stopPropagation();
  const ms=_spMS[id]; if(!ms)return;
  const panel=document.getElementById(id+'-panel'); if(!panel)return;
  const isOpen=panel.style.display!=='none';
  document.querySelectorAll('.sp-ms-panel').forEach(p=>p.style.display='none');
  if(isOpen)return;
  panel.style.display='flex';
  const search=panel.querySelector('.sp-ms-search');
  if(search){ search.value=''; ms._render(''); setTimeout(()=>search.focus(),30); }
}

function _spMSSearch(id,val) { const ms=_spMS[id]; if(ms) ms._render(val); }
function _spMSToggle(id,val,checked) { const ms=_spMS[id]; if(ms){ ms.toggle(val,checked); } }
function _spMSOnly(id,val) { const ms=_spMS[id]; if(ms) ms.only(val); }
function _spMSSelectAll(id) { const ms=_spMS[id]; if(!ms)return; ms.selected=new Set(ms.allValues); ms._render(); ms._updateToggle(); }
function _spMSDeselectAll(id) { const ms=_spMS[id]; if(!ms)return; ms.selected=new Set(); ms._render(); ms._updateToggle(); }

function clearSPFilters() {
  ['sp-fil-from','sp-fil-to','sp-fil-product'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  ['sp-ms-status','sp-ms-channel','sp-ms-store','sp-ms-brand','sp-ms-ip','sp-ms-collection'].forEach(id => { if(_spMS[id]) _spMS[id].reset(); });
  const orEl = document.getElementById('sp-only-restock'); if (orEl) orEl.checked = false;
}

function populateSPFilterDropdowns(orders, channelData, storeData, productData) {
  // Channel — always refresh with counts from current result
  const chMS = _spMS['sp-ms-channel'];
  if (chMS) {
    const chCount = {}; channelData.forEach(d=>chCount[d.channel]=d.orders);
    const chs = [...new Set(orders.map(o=>o.channel_name).filter(Boolean))].sort();
    chMS.setOptions(chs.map(c=>({value:c,label:SP_CHANNEL_LABELS[c]||c,count:chCount[c]??null})));
  }
  // Store — always refresh with counts from current result
  const stMS = _spMS['sp-ms-store'];
  if (stMS) {
    const stCount = {}; storeData.forEach(d=>stCount[d.store]=d.orders);
    const sts = [...new Set(orders.map(o=>o.store_name).filter(Boolean))].sort();
    stMS.setOptions(sts.map(s=>({value:s,label:s,count:stCount[s]??null})));
  }
  // Brand / IP / Collection — update counts only (options already loaded by _preloadSPFiltersAndRun)
  const brandMS = _spMS['sp-ms-brand'];
  const ipMS    = _spMS['sp-ms-ip'];
  const colMS   = _spMS['sp-ms-collection'];
  if (_spAllMappings) {
    const brandCount={}, ipCount={}, colCount={};
    productData.forEach(p=>{
      if(p.brand) brandCount[p.brand]=(brandCount[p.brand]||0)+Math.round(p.qty);
      if(p.ip)    ipCount[p.ip]=(ipCount[p.ip]||0)+Math.round(p.qty);
      if(p.collection) colCount[p.collection]=(colCount[p.collection]||0)+Math.round(p.qty);
    });
    const _updateCounts = (ms, countMap) => {
      if (!ms || ms.options.length===0) return;
      ms.options = ms.options.map(o=>({...o, count: countMap[o.value]??null}));
      ms._render();
    };
    _updateCounts(brandMS, brandCount);
    _updateCounts(ipMS, ipCount);
    _updateCounts(colMS, colCount);
  }
}

function updateSPStats({ orders, qty, revenue, disc, net, avgDay, stock, str, returnRate, cancelRate }) {
  const fmtRp = n => n >= 1000000 ? 'Rp ' + (n/1000000).toFixed(1) + 'jt' : 'Rp ' + Math.round(n).toLocaleString('id-ID');
  const _s = (id, v) => { const el=document.getElementById(id); if(el) el.textContent=v; };
  _s('sp-s-revenue',     revenue > 0  ? fmtRp(revenue) : '—');
  _s('sp-s-disc',        disc    > 0  ? fmtRp(disc)    : '—');
  _s('sp-s-net',         net     > 0  ? fmtRp(net)     : '—');
  _s('sp-s-avgday',      avgDay);
  _s('sp-s-orders',      typeof orders === 'number' ? orders.toLocaleString('id-ID') : '—');
  _s('sp-s-qty',         Math.round(qty).toLocaleString('id-ID'));
  _s('sp-s-stock',       typeof stock === 'number' ? Math.round(stock).toLocaleString('id-ID') : '—');
  _s('sp-s-str',         str || '—');
  _s('sp-s-return-rate', returnRate);
  _s('sp-s-cancel-rate', cancelRate);
}

async function loadSalesPerf() {
  const btn = document.getElementById('sp-run-btn');
  btn.disabled = true; btn.textContent = 'Memuat...';
  const emptyEl = document.getElementById('sp-empty');
  emptyEl.style.display = 'block';
  emptyEl.textContent = 'Mengambil data...';
  document.getElementById('sp-chart-wrap').style.display = 'none';
  document.getElementById('sp-tables-wrap').style.display = 'none';

  try {
    const from      = document.getElementById('sp-fil-from').value;
    const to        = document.getElementById('sp-fil-to').value;
    const _SP_STATUS_MAP = {'Completed':['COMPLETED','FINISH_PACK','FINISH_PICK','CLOSED'],'In Progress':['PAID','PENDING'],'Cancelled':['CANCELED'],'Returned':['RETURNED']};
    const statusVals = (_spMS['sp-ms-status'] ? _spMS['sp-ms-status'].getValues() : []).flatMap(s => _SP_STATUS_MAP[s] || [s]);
    const channelVals = _spMS['sp-ms-channel'] ? _spMS['sp-ms-channel'].getValues() : [];
    const storeVals   = _spMS['sp-ms-store']   ? _spMS['sp-ms-store'].getValues()   : [];
    const brandVals   = _spMS['sp-ms-brand']   ? _spMS['sp-ms-brand'].getValues()   : [];
    const ipVals      = _spMS['sp-ms-ip']      ? _spMS['sp-ms-ip'].getValues()      : [];
    const colVals     = _spMS['sp-ms-collection'] ? _spMS['sp-ms-collection'].getValues() : [];
    const prodF       = (document.getElementById('sp-fil-product').value || '').trim().toLowerCase();

    // jubelio_sales_orders is only complete from 2026; pre-2026 comes from
    // jubelio_sales_history (CSV import, already enriched with brand/ip/collection).
    const SP_CUTOFF   = '2026-01-01';
    const needHistory = (!from || from < SP_CUTOFF);
    const needOrders  = (!to   || to >= SP_CUTOFF);
    const _ordFrom    = (from && from > SP_CUTOFF) ? from : SP_CUTOFF; // orders clamped to >= cutoff

    // Helper: date/channel/store filters for the 2026+ orders table (clamped to cutoff)
    const _applyDateChanStore = q => {
      q = q.gte('transaction_date', _ordFrom);
      if (to)                 q = q.lte('transaction_date', to + 'T23:59:59');
      if (channelVals.length) q = q.in('channel_name', channelVals);
      if (storeVals.length)   q = q.in('store_name', storeVals);
      return q;
    };

    // 1. Fetch 2026+ orders + return/cancel counts (only if range reaches 2026)
    const [orders, retRes, canRes, totalRes] = needOrders ? await Promise.all([
      _fetchAllPages('jubelio_sales_orders',
        'salesorder_id,transaction_date,wms_status,channel_name,store_name,sub_total,total_disc',
        q => {
          q = _applyDateChanStore(q);
          if (statusVals.length) q = q.in('wms_status', statusVals);
          return q;
        }
      ),
      _applyDateChanStore(sb.from('jubelio_sales_orders').select('salesorder_id',{count:'exact',head:true}).eq('wms_status','RETURNED')),
      _applyDateChanStore(sb.from('jubelio_sales_orders').select('salesorder_id',{count:'exact',head:true}).eq('wms_status','CANCELED')),
      _applyDateChanStore(sb.from('jubelio_sales_orders').select('salesorder_id',{count:'exact',head:true})),
    ]) : [[], {count:0}, {count:0}, {count:0}];

    const orderMap = new Map(orders.map(o => [o.salesorder_id, o]));
    const soIds    = orders.map(o => o.salesorder_id);

    // 2. Fetch 2026+ items (chunked by 500 IDs)
    const allItems = [];
    if (soIds.length) {
      emptyEl.textContent = `Mengambil item untuk ${orders.length.toLocaleString('id-ID')} order...`;
      for (let i = 0; i < soIds.length; i += 500) {
        const chunk = soIds.slice(i, i + 500);
        const rows = await _fetchAllPages('jubelio_sales_order_items',
          'salesorder_id,item_id,item_name,qty,price,disc_amount',
          q => q.in('salesorder_id', chunk)
        );
        allItems.push(...rows);
      }
    }
    // Deduplicate items: sync can produce duplicate rows for same (salesorder_id, item_id).
    const _seen = new Set();
    const allItemsDeduped = allItems.filter(it => {
      const key = `${it.salesorder_id}:${it.item_id}`;
      if (_seen.has(key)) return false;
      _seen.add(key);
      return true;
    });

    // 2b. Pre-2026 from jubelio_sales_history → synthetic orders + items
    let spHistReturned = 0, spHistCanceled = 0, spHistTotal = 0;
    if (needHistory) {
      emptyEl.textContent = 'Menggabungkan data historis (2024–2025)...';
      const _histTo = (to && to < SP_CUTOFF) ? to : '2025-12-31';
      const histRows = await _fetchAllPages('jubelio_sales_history',
        'salesorder_no,transaction_date,channel_name,store_name,status,item_id,item_name,qty,amount,brand,ip,collection',
        q => {
          q = q.lte('transaction_date', _histTo);
          if (from) q = q.gte('transaction_date', from);
          if (channelVals.length) q = q.in('channel_name', channelVals);
          if (storeVals.length)   q = q.in('store_name', storeVals);
          return q;
        }
      );
      // Count distinct orders by status (ignores status filter — matches rate semantics)
      const _seenAll = new Set(), _seenRet = new Set(), _seenCan = new Set();
      for (const r of histRows) {
        const no = r.salesorder_no || '';
        if (!_seenAll.has(no)) { _seenAll.add(no); spHistTotal++; }
        const st = (r.status || '').toUpperCase();
        if (st === 'RETURNED' && !_seenRet.has(no)) { _seenRet.add(no); spHistReturned++; }
        if (st === 'CANCELED' && !_seenCan.has(no)) { _seenCan.add(no); spHistCanceled++; }
      }
      // Apply status filter (same mapping as orders)
      const histFiltered = statusVals.length
        ? histRows.filter(r => statusVals.includes((r.status||'').toUpperCase()))
        : histRows;
      // Build synthetic orders (group by salesorder_no) + items
      const histOrderAgg = {};
      for (const r of histFiltered) {
        const sid = 'H:' + (r.salesorder_no || '');
        const amt = parseFloat(r.amount || 0);
        const qn  = parseFloat(r.qty || 0);
        if (!histOrderAgg[sid]) {
          const o = { salesorder_id: sid, transaction_date: r.transaction_date,
            wms_status: (r.status||'').toUpperCase(), channel_name: r.channel_name,
            store_name: r.store_name, sub_total: 0, total_disc: 0 };
          histOrderAgg[sid] = o; orders.push(o); orderMap.set(sid, o);
        }
        histOrderAgg[sid].sub_total += amt;
        allItemsDeduped.push({
          salesorder_id: sid, item_id: r.item_id || null, item_name: r.item_name || '?',
          qty: qn, price: qn ? amt / qn : 0, disc_amount: 0,
          _hist: true, _brand: r.brand || '', _ip: r.ip || '', _collection: r.collection || '', _parent: r.item_name || '?'
        });
      }
    }

    if (!orders.length) {
      emptyEl.textContent = 'Tidak ada order di periode / filter ini.';
      updateSPStats({ orders: 0, qty: 0, revenue: 0, disc: 0, net: 0, avgDay: '—', returnRate: '—', cancelRate: '—' });
      btn.disabled = false; btn.textContent = '↻ Analisis';
      return;
    }

    // brand/ip/collection resolver: history items carry their own; 2026 items use product_mappings.
    // product_mappings has ONE row per distinct item_name with a single representative
    // jubelio_item_id, so we must fall back to lookup by name when an SKU's item_id
    // doesn't match the stored representative (otherwise only one variant per product
    // ever finds its mapping).
    const _mapOf = it => it._hist
      ? { brand: it._brand, ip: it._ip, collection: it._collection, item_name: it._parent }
      : (mappingById[it.item_id] || mappingByName[it.item_name] || {});

    // 3. Load product_mappings (cached, all pages)
    if (!_spAllMappings) {
      _spAllMappings = await _fetchAllPages('product_mappings', 'jubelio_item_id,item_name,brand,ip,collection');
    }
    // Index by jubelio_item_id (for fast direct match) AND by item_name (fallback
    // so all variants of the same product resolve to the same mapping).
    const mappingById = {};
    const mappingByName = {};
    for (const m of _spAllMappings) {
      if (m.jubelio_item_id) mappingById[m.jubelio_item_id] = m;
      if (m.item_name)       mappingByName[m.item_name] = m;
    }
    // Ensure brand/IP/col dropdowns are populated (in case preload missed them)
    const _bMS=_spMS['sp-ms-brand'], _iMS=_spMS['sp-ms-ip'], _cMS=_spMS['sp-ms-collection'];
    if (_bMS && _bMS.options.length===0) _bMS.setOptions([...new Set(_spAllMappings.map(m=>m.brand).filter(Boolean))].sort().map(b=>({value:b,label:b,count:null})));
    if (_iMS && _iMS.options.length===0) _iMS.setOptions([...new Set(_spAllMappings.map(m=>m.ip).filter(Boolean))].sort().map(i=>({value:i,label:i,count:null})));
    if (_cMS && _cMS.options.length===0) _cMS.setOptions([...new Set(_spAllMappings.map(m=>m.collection).filter(Boolean))].sort().map(c=>({value:c,label:c,count:null})));

    // 4. Client-side filter
    let items = allItemsDeduped;
    if (brandVals.length || ipVals.length || colVals.length || prodF) {
      items = allItemsDeduped.filter(it => {
        const m = _mapOf(it);
        if (brandVals.length && !brandVals.includes(m.brand)) return false;
        if (ipVals.length    && !ipVals.includes(m.ip))       return false;
        if (colVals.length   && !colVals.includes(m.collection)) return false;
        if (prodF && !(it.item_name || '').toLowerCase().includes(prodF)) return false;
        return true;
      });
    }

    const filteredOrderIds  = new Set(items.map(it => it.salesorder_id));
    const filteredOrders    = orders.filter(o => filteredOrderIds.has(o.salesorder_id));

    // When an item-level filter (brand/IP/collection/product) is active, order-level
    // sub_total over-counts (an order may contain other products too). In that case
    // revenue & discount must come from the filtered ITEMS, not the whole order.
    const hasItemFilter = !!(brandVals.length || ipVals.length || colVals.length || prodF);
    // Precompute per-item revenue + allocated discount
    for (const it of items) {
      const o = orderMap.get(it.salesorder_id);
      it._rev = parseFloat(it.qty||0) * parseFloat(it.price||0);
      const oDisc = parseFloat(o?.total_disc||0), oSub = parseFloat(o?.sub_total||0);
      it._disc = parseFloat(it.disc_amount||0) > 0 ? parseFloat(it.disc_amount)
        : (oDisc>0 && oSub>0 ? oDisc * (it._rev/oSub) : 0);
    }

    // 5. Time series (daily) — qty from items; revenue from items (if filtered) or order sub_total.
    // Fallback to grand_total when sub_total is null (some marketplace orders sync with null sub_total
    // — Jubelio's detail endpoint doesn't always populate it). Backfill cron keeps this rare, but the
    // fallback prevents whole-day bars from disappearing if a sync window stores null.
    const timeSeries = {};
    if (!hasItemFilter) {
      for (const o of filteredOrders) {
        const date = (o.transaction_date || '').slice(0, 10);
        if (!date) continue;
        if (!timeSeries[date]) timeSeries[date] = { qty: 0, revenue: 0 };
        const rev = (o.sub_total != null) ? parseFloat(o.sub_total) : parseFloat(o.grand_total || 0);
        timeSeries[date].revenue += rev;
      }
    }
    for (const it of items) {
      const o = orderMap.get(it.salesorder_id);
      if (!o) continue;
      const date = (o.transaction_date || '').slice(0, 10);
      if (!date) continue;
      if (!timeSeries[date]) timeSeries[date] = { qty: 0, revenue: 0 };
      timeSeries[date].qty += parseFloat(it.qty || 0);
      if (hasItemFilter) timeSeries[date].revenue += it._rev;
    }
    // dayCount available early — needed for restock calc in step 8c
    const dayCount = Math.max(1, Object.keys(timeSeries).length);

    // 6. Channel summary — revenue/disc from order-level sub_total/total_disc (matches reference export)
    //    qty still from items (orders don't carry total qty)
    const channelMap = {};
    // First pass: order count (+ order-level revenue/disc when no item filter)
    for (const o of filteredOrders) {
      const ch = o.channel_name || '(Lainnya)';
      if (!channelMap[ch]) channelMap[ch] = { orders: 0, qty: 0, revenue: 0, disc: 0 };
      channelMap[ch].orders  += 1;
      if (!hasItemFilter) {
        channelMap[ch].revenue += parseFloat(o.sub_total  || 0);
        channelMap[ch].disc    += parseFloat(o.total_disc || 0);
      }
    }
    // Second pass: qty from items (+ revenue/disc from items when filtered)
    for (const it of items) {
      const o  = orderMap.get(it.salesorder_id); if (!o) continue;
      const ch = o.channel_name || '(Lainnya)';
      if (channelMap[ch]) {
        channelMap[ch].qty += parseFloat(it.qty || 0);
        if (hasItemFilter) { channelMap[ch].revenue += it._rev; channelMap[ch].disc += it._disc; }
      }
    }
    const channelData = Object.entries(channelMap)
      .map(([ch, d]) => ({ channel: ch, orders: d.orders, qty: d.qty, revenue: d.revenue, disc: d.disc, net: d.revenue - d.disc }))
      .sort((a, b) => b.net - a.net);

    // 7. Store summary — revenue from order-level sub_total
    const storeMap = {};
    for (const o of filteredOrders) {
      const st = o.store_name || '(Lainnya)';
      if (!storeMap[st]) storeMap[st] = { orders: 0, qty: 0, revenue: 0 };
      storeMap[st].orders  += 1;
      if (!hasItemFilter) storeMap[st].revenue += parseFloat(o.sub_total || 0);
    }
    for (const it of items) {
      const o  = orderMap.get(it.salesorder_id); if (!o) continue;
      const st = o.store_name || '(Lainnya)';
      if (storeMap[st]) {
        storeMap[st].qty += parseFloat(it.qty || 0);
        if (hasItemFilter) storeMap[st].revenue += it._rev;
      }
    }
    const storeData = Object.entries(storeMap)
      .map(([st, d]) => ({ store: st, orders: d.orders, qty: d.qty, revenue: d.revenue }))
      .sort((a, b) => b.revenue - a.revenue);

    // 8. Product summary — grouped by parent name (without size variant)
    const productMap = {};
    for (const it of items) {
      const m          = _mapOf(it);
      const parentName = m.item_name || it.item_name || '?'; // parent name from mappings (no variant)
      const variantName = it.item_name || '?';               // full SKU name (with size)
      if (!productMap[parentName]) productMap[parentName] = {
        name: parentName, brand: m.brand || '', ip: m.ip || '', collection: m.collection || '',
        orders: new Set(), qty: 0, revenue: 0, disc: 0,
        variants: {},           // variantName → {orders,qty,revenue,disc}
        itemIds: new Set(),     // collect item_ids for thumbnail lookup
      };
      const pg = productMap[parentName];
      pg.orders.add(it.salesorder_id);
      pg.qty     += parseFloat(it.qty || 0);
      const _rev = it._rev, _itemDisc = it._disc;  // precomputed (rev = qty*price; disc allocated)
      pg.revenue += _rev;
      pg.disc    += _itemDisc;
      if (it.item_id) pg.itemIds.add(it.item_id);
      // Variant-level tracking (store itemId for stock lookup)
      if (!pg.variants[variantName]) pg.variants[variantName] = { name: variantName, itemId: it.item_id, orders: new Set(), qty: 0, revenue: 0, disc: 0 };
      pg.variants[variantName].orders.add(it.salesorder_id);
      pg.variants[variantName].qty     += parseFloat(it.qty || 0);
      pg.variants[variantName].revenue += _rev;
      pg.variants[variantName].disc    += _itemDisc;
    }

    // 8b. Fetch thumbnails + stock in parallel
    const allItemIds = [...new Set(Object.values(productMap).flatMap(p => [...p.itemIds]))];
    const thumbMap = {}, stockMap = {};
    if (allItemIds.length) {
      const [jiRows, stockRows] = await Promise.all([
        _fetchAllPages('jubelio_items', 'item_id,thumbnail',
          q => q.in('item_id', allItemIds).not('thumbnail', 'is', null)),
        _fetchAllPages('jubelio_inventory_stocks', 'item_id,on_hand',
          q => q.in('item_id', allItemIds)),
      ]);
      for (const r of jiRows)    { if (r.thumbnail) thumbMap[r.item_id] = r.thumbnail; }
      for (const r of stockRows) { stockMap[r.item_id] = (stockMap[r.item_id] || 0) + parseFloat(r.on_hand || 0); }
    }
    // 8c. Attach thumbnail, stock, STR, restock flag to each product group
    // Restock logic: days_of_stock = stock / avg_daily_sales; flag if < 30 days
    const RESTOCK_DAYS = 30;
    const _restockFlag = (stock, qty) => {
      if (qty <= 0) return { needsRestock: false, daysOfStock: null };
      const avgDaily = qty / dayCount;
      const days = stock / avgDaily;
      return { needsRestock: days < RESTOCK_DAYS, daysOfStock: Math.floor(days) };
    };
    const _sizeOrder = ['XS','S','M','L','XL','XXL','XXXL','4XL','5XL'];
    const _sizeRank  = s => { const i = _sizeOrder.indexOf((s||'').trim().toUpperCase()); return i >= 0 ? i : 99; };
    const _varSize   = v => { const p = v.name.split(' - '); return p.length > 1 ? p[p.length-1] : v.name; };
    for (const pg of Object.values(productMap)) {
      pg.thumbnail = null;
      for (const iid of pg.itemIds) { if (thumbMap[iid]) { pg.thumbnail = thumbMap[iid]; break; } }
      // Attach stock + per-variant restock, then roll up to product
      pg.stock = 0;
      pg.variants = Object.values(pg.variants).map(v => {
        const vStock = stockMap[v.itemId] || 0;
        pg.stock += vStock;
        const { needsRestock: vRestock, daysOfStock: vDays } = _restockFlag(vStock, v.qty);
        return { ...v, orders: v.orders.size, net: v.revenue - v.disc, stock: vStock,
          str: (v.qty + vStock) > 0 ? ((v.qty / (v.qty + vStock)) * 100).toFixed(1) + '%' : '—',
          needsRestock: vRestock, daysOfStock: vDays };
      }).sort((a, b) => _sizeRank(_varSize(a)) - _sizeRank(_varSize(b)));
    }

    const productData = Object.values(productMap).map(p => {
      const str = (p.qty + p.stock) > 0 ? ((p.qty / (p.qty + p.stock)) * 100).toFixed(1) + '%' : '—';
      const { needsRestock, daysOfStock } = _restockFlag(p.stock, p.qty);
      return { ...p, orders: p.orders.size, net: p.revenue - p.disc, str, needsRestock, daysOfStock };
    }).sort((a, b) => b.net - a.net);

    // 9. Totals
    // Revenue = sum of order sub_total (matches Jubelio export / reference data)
    // Discount = sum of order total_disc
    // Net     = Revenue − Discount
    // Qty     = sum of item qty (orders don't carry a total qty field)
    const totalQty     = items.reduce((s, it) => s + parseFloat(it.qty || 0), 0);
    const totalRevenue = hasItemFilter
      ? items.reduce((s, it) => s + (it._rev || 0), 0)
      : filteredOrders.reduce((s, o) => s + parseFloat(o.sub_total  || 0), 0);
    const totalDisc    = hasItemFilter
      ? items.reduce((s, it) => s + (it._disc || 0), 0)
      : filteredOrders.reduce((s, o) => s + parseFloat(o.total_disc || 0), 0);
    const totalNet     = totalRevenue - totalDisc;
    const totalStock   = productData.reduce((s, p) => s + (p.stock || 0), 0);
    const totalStr     = (totalQty + totalStock) > 0
      ? ((totalQty / (totalQty + totalStock)) * 100).toFixed(1) + '%' : '—';
    const fmtRp        = n => n >= 1000000 ? 'Rp ' + (n/1000000).toFixed(1) + 'jt' : 'Rp ' + Math.round(n).toLocaleString('id-ID');
    const avgDay       = totalNet > 0 ? fmtRp(totalNet / dayCount) : '—';

    // 10. Return / Cancel rate (across all statuses in the period, ignoring status filter)
    const _totalAll = (totalRes.count || 0) + spHistTotal;
    const returnRate = _totalAll > 0 ? (((retRes.count||0)+spHistReturned) / _totalAll * 100).toFixed(1) + '%' : '—';
    const cancelRate = _totalAll > 0 ? (((canRes.count||0)+spHistCanceled) / _totalAll * 100).toFixed(1) + '%' : '—';

    spData = { timeSeries, channelData, storeData, productData, totalQty, totalRevenue, totalDisc, totalNet, totalStock, totalStr, dayCount, avgDay };

    populateSPFilterDropdowns(orders, channelData, storeData, productData);
    updateSPStats({ orders: filteredOrders.length, qty: totalQty, revenue: totalRevenue, disc: totalDisc, net: totalNet, avgDay, stock: totalStock, str: totalStr, returnRate, cancelRate });
    emptyEl.style.display = 'none';
    document.getElementById('sp-chart-wrap').style.display = 'block';
    document.getElementById('sp-tables-wrap').style.display = 'block';
    renderSPChart(spChartView);
    _spProdPage = 0;
    renderSPChannelTable(channelData, totalNet);
    renderSPProductTable(productData, 0);

  } catch (e) {
    emptyEl.textContent = 'Gagal: ' + (e.message || e);
    console.error(e);
  }
  btn.disabled = false; btn.textContent = '↻ Analisis';
}

function switchSPView(view, btn) {
  spChartView = view;
  document.querySelectorAll('#sp-view-btns button').forEach(b => {
    b.style.background = 'none'; b.style.color = 'var(--g600)';
  });
  btn.style.background = 'var(--black)'; btn.style.color = 'var(--white)';
  renderSPChart(view);
}

function renderSPChart(view) {
  if (!spData || !spData.timeSeries) return;
  const canvas = document.getElementById('sp-chart');
  if (!canvas || typeof Chart === 'undefined') return;
  const ID_MONTHS = ['Jan','Feb','Mar','Apr','Mei','Jun','Jul','Agu','Sep','Okt','Nov','Des'];
  const grouped = {};
  for (const [date, vals] of Object.entries(spData.timeSeries)) {
    let key;
    if      (view === 'day')  key = date;
    else if (view === 'week') key = getWeekStart(date);
    else if (view === 'year') key = date.slice(0, 4);
    else                      key = date.slice(0, 7);
    if (!grouped[key]) grouped[key] = { qty: 0, revenue: 0 };
    grouped[key].qty     += vals.qty;
    grouped[key].revenue += vals.revenue;
  }
  const labels = Object.keys(grouped).sort();
  const fmtLabel = key => {
    if (view === 'year') return key;
    if (view === 'month') { const [y,m] = key.split('-'); return `${ID_MONTHS[parseInt(m)-1]} '${y.slice(2)}`; }
    const [,m,dd] = key.split('-');
    return `${parseInt(dd)} ${ID_MONTHS[parseInt(m)-1]}`;
  };
  if (_spChart) { _spChart.destroy(); _spChart = null; }
  if (!labels.length) return;
  const plugins = typeof ChartDataLabels !== 'undefined' ? [ChartDataLabels] : [];
  const fmtVal  = v => v >= 1000000 ? (v/1000000).toFixed(1)+'jt' : (v/1000).toFixed(0)+'k';
  _spChart = new Chart(canvas, {
    plugins,
    data: {
      labels: labels.map(fmtLabel),
      datasets: [
        {
          type: 'bar', label: 'Revenue',
          data: labels.map(k => grouped[k].revenue),
          yAxisID: 'yRevenue', backgroundColor: 'rgba(45,122,45,0.65)', borderRadius: 4, order: 2,
          datalabels: { display: true, anchor: 'end', align: 'end', offset: 2, color: '#2d7a2d', font: { size: 8, family: 'DM Mono', weight: '600' }, formatter: v => v > 0 ? fmtVal(v) : '' }
        },
        {
          type: 'line', label: 'Qty',
          data: labels.map(k => grouped[k].qty),
          yAxisID: 'yQty', borderColor: '#3b82f6', backgroundColor: 'rgba(59,130,246,0.08)',
          tension: 0, cubicInterpolationMode: 'monotone', pointRadius: 3, pointBackgroundColor: '#3b82f6', fill: false, order: 1,
          datalabels: { display: false }
        }
      ]
    },
    options: {
      responsive: true, maintainAspectRatio: false, layout: { padding: { top: 20 } },
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { display: false },
        tooltip: { callbacks: { label: ctx => ctx.datasetIndex === 0 ? ` Revenue: Rp ${Math.round(ctx.raw).toLocaleString('id-ID')}` : ` Qty: ${Math.round(ctx.raw)} pcs` } }
      },
      scales: {
        yRevenue: { type: 'linear', position: 'left', ticks: { font: { size: 9, family: 'DM Mono' }, callback: v => fmtVal(v) }, grid: { color: 'rgba(0,0,0,0.04)' } },
        yQty:     { type: 'linear', position: 'right', beginAtZero: true, ticks: { font: { size: 9, family: 'DM Mono' }, precision: 0 }, grid: { display: false } },
        x:        { ticks: { font: { size: 9, family: 'DM Mono' }, maxRotation: 45 } }
      }
    }
  });
}

function renderSPChannelTable(data, totalNet) {
  const tbody = document.getElementById('sp-channel-tbody');
  if (!tbody) return;
  const fmtRp = n => 'Rp ' + Math.round(n).toLocaleString('id-ID');
  if (!data.length) { tbody.innerHTML = `<tr><td class="empty-td" colspan="7">Tidak ada data channel.</td></tr>`; return; }
  tbody.innerHTML = data.map(d => {
    const pct = totalNet > 0 ? ((d.net / totalNet) * 100).toFixed(1) + '%' : '—';
    return `<tr>
      <td style="padding:7px 10px;font-size:12px;font-weight:500">${SP_CHANNEL_LABELS[d.channel]||d.channel}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${d.orders.toLocaleString('id-ID')}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${Math.round(d.qty).toLocaleString('id-ID')}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g600)">${fmtRp(d.revenue)}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#c0392b">${d.disc > 0 ? fmtRp(d.disc) : '—'}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#2d7a2d;font-weight:600">${fmtRp(d.net)}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${pct}</td>
    </tr>`;
  }).join('');
}

function _spToggleVariants(idx) {
  const varRows = document.querySelectorAll('.sp-var-' + idx);
  if (!varRows.length) return;
  const isHidden = varRows[0].style.display === 'none';
  varRows.forEach(r => r.style.display = isHidden ? '' : 'none');
  const btn = document.getElementById('sp-expand-' + idx);
  if (btn) btn.textContent = isHidden ? '▲' : '▼';
}

function renderSPProductTable(data, page) {
  const tbody = document.getElementById('sp-product-tbody');
  const countEl = document.getElementById('sp-prod-count');
  const pagDiv  = document.getElementById('sp-prod-pagination');
  if (!tbody) return;
  if (document.getElementById('sp-only-restock')?.checked) data = data.filter(d => d.needsRestock);
  _spProdPage = page || 0;
  if (countEl) countEl.textContent = data.length + ' produk';
  const fmtRp = n => 'Rp ' + Math.round(n).toLocaleString('id-ID');
  if (!data.length) { tbody.innerHTML = `<tr><td class="empty-td" colspan="11">Tidak ada produk.</td></tr>`; if(pagDiv) pagDiv.innerHTML=''; return; }
  const totalPages = Math.ceil(data.length / SP_PROD_PAGE_SIZE);
  const start = _spProdPage * SP_PROD_PAGE_SIZE;
  const pageData = data.slice(start, start + SP_PROD_PAGE_SIZE);
  const grandNet = data.reduce((s,d) => s + d.net, 0);
  const TD  = 'style="padding:6px 10px;vertical-align:middle"';
  const TDR = 'style="padding:6px 10px;vertical-align:middle;text-align:right;font-family:var(--mono);font-size:11px"';
  const rows = [];
  pageData.forEach((d, i) => {
    const idx = start + i;
    const pct = grandNet > 0 ? ((d.net / grandNet) * 100).toFixed(1) + '%' : '—';
    const hasVariants = d.variants && d.variants.length > 1;
    const thumb = d.thumbnail
      ? `<div class="sp-thumb-zoom"><img src="${d.thumbnail}" style="width:28px;height:28px;object-fit:cover;border-radius:3px;border:1px solid var(--g100)" onerror="this.parentElement.style.display='none'"><img src="${d.thumbnail}" class="sp-thumb-big"></div>`
      : `<div style="width:28px;height:28px;border-radius:3px;background:var(--g100);flex-shrink:0"></div>`;
    const expandBtn = hasVariants
      ? `<button id="sp-expand-${idx}" onclick="_spToggleVariants(${idx})" style="margin-left:5px;background:none;border:1px solid var(--g200);border-radius:3px;padding:1px 5px;font-size:9px;cursor:pointer;color:var(--g500);flex-shrink:0;line-height:1.2">▼</button>`
      : '';
    const _restockClr = d.daysOfStock !== null && d.daysOfStock < 14 ? '#c0392b' : '#e65100';
    const _restockBg  = d.daysOfStock !== null && d.daysOfStock < 14 ? '#fdf0f0' : '#fff3e0';
    const _restockBdr = d.daysOfStock !== null && d.daysOfStock < 14 ? '#e8b8b8' : '#ffb74d';
    const restockBadge = d.needsRestock
      ? `<span style="font-size:9px;background:${_restockBg};color:${_restockClr};border:1px solid ${_restockBdr};border-radius:3px;padding:1px 5px;font-family:var(--mono);flex-shrink:0;white-space:nowrap">⚠ ${d.daysOfStock}d stock</span>`
      : '';
    const P = 'padding:6px 10px;vertical-align:middle';
    rows.push(`<tr style="border-bottom:1px solid var(--g50)">
      <td style="${P}">
        <div style="display:flex;align-items:center;gap:7px">
          ${thumb}
          <span style="font-size:12px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;min-width:0" title="${d.name}">${idx+1}. ${d.name}</span>
          ${restockBadge}
          ${expandBtn}
        </div>
      </td>
      <td style="${P};font-size:11px;color:var(--g600);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${d.brand || '—'}</td>
      <td style="${P};font-size:11px;color:var(--g600);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${d.ip || '—'}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px">${d.orders.toLocaleString('id-ID')}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px">${Math.round(d.qty).toLocaleString('id-ID')}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px;color:${(d.stock||0)===0?'var(--g300)':'var(--g700)'}">${Math.round(d.stock||0).toLocaleString('id-ID')}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px;font-weight:600;color:${(()=>{const n=parseFloat(d.str)||0;return d.str!=='—'?(n>=70?'#2d7a2d':n>=30?'#e67e00':'#c0392b'):'var(--g400)'})()}">${d.str||'—'}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px;color:var(--g600)">${fmtRp(d.revenue)}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px;color:#c0392b">${d.disc > 0 ? fmtRp(d.disc) : '—'}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px;color:#2d7a2d;font-weight:600">${fmtRp(d.net)}</td>
      <td style="${P};text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${pct}</td>
    </tr>`);
    // Variant sub-rows — injected directly (NOT nested table) so colgroup widths apply
    if (hasVariants) {
      const varRowsHtml = d.variants.map(v => {
        const parts = v.name.split(' - ');
        const sizeLabel = parts.length > 1 ? parts[parts.length - 1] : v.name;
        const varRestockMark = v.needsRestock ? ` <span style="color:#e65100;font-size:10px">⚠</span>` : '';
        return `<tr class="sp-var-row sp-var-${idx}" style="display:none;background:var(--g50)">
          <td style="padding:3px 10px 3px 55px;font-size:11px;color:var(--g500);font-family:var(--mono);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${sizeLabel}${varRestockMark}</td>
          <td></td>
          <td></td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g500)">${v.orders.toLocaleString('id-ID')}</td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g500)">${Math.round(v.qty).toLocaleString('id-ID')}</td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:${(v.stock||0)===0?'var(--g300)':'var(--g500)'}">${Math.round(v.stock||0).toLocaleString('id-ID')}</td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${v.str||'—'}</td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${fmtRp(v.revenue)}</td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#c0392b">${v.disc > 0 ? fmtRp(v.disc) : '—'}</td>
          <td style="padding:3px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#2d7a2d">${fmtRp(v.net)}</td>
          <td></td>
        </tr>`;
      }).join('');
      rows.push(varRowsHtml);
    }
  });
  tbody.innerHTML = rows.join('');
  // Pagination
  if (pagDiv) {
    if (totalPages <= 1) { pagDiv.innerHTML = ''; return; }
    const prevDisabled = _spProdPage===0;
    const nextDisabled = _spProdPage>=totalPages-1;
    const pageNums = [];
    for (let i=0; i<totalPages; i++) {
      if (i===0 || i===totalPages-1 || Math.abs(i-_spProdPage)<=1) pageNums.push(i);
      else if (pageNums[pageNums.length-1]!=='…') pageNums.push('…');
    }
    pagDiv.innerHTML = `
      <span style="color:var(--g400)">${start+1}–${Math.min(start+SP_PROD_PAGE_SIZE,data.length)} dari ${data.length}</span>
      <div style="display:flex;gap:4px;align-items:center">
        <button onclick="_spProdGoPage(${_spProdPage-1})" ${prevDisabled?'disabled':''} style="padding:3px 8px;border:1px solid var(--g200);border-radius:4px;background:${prevDisabled?'var(--g50)':'white'};cursor:${prevDisabled?'default':'pointer'};font-family:var(--mono);font-size:11px;color:${prevDisabled?'var(--g300)':'var(--g700)'}">‹ Prev</button>
        ${pageNums.map(n => n==='…' ? `<span style="color:var(--g400);padding:0 2px">…</span>` :
          `<button onclick="_spProdGoPage(${n})" style="padding:3px 8px;border:1px solid ${n===_spProdPage?'var(--black)':'var(--g200)'};border-radius:4px;background:${n===_spProdPage?'var(--black)':'white'};color:${n===_spProdPage?'white':'var(--g700)'};cursor:pointer;font-family:var(--mono);font-size:11px">${n+1}</button>`
        ).join('')}
        <button onclick="_spProdGoPage(${_spProdPage+1})" ${nextDisabled?'disabled':''} style="padding:3px 8px;border:1px solid var(--g200);border-radius:4px;background:${nextDisabled?'var(--g50)':'white'};cursor:${nextDisabled?'default':'pointer'};font-family:var(--mono);font-size:11px;color:${nextDisabled?'var(--g300)':'var(--g700)'}">Next ›</button>
      </div>`;
  }
}

function _spProdGoPage(page) {
  if (!spData || !spData.productData) return;
  const totalPages = Math.ceil(spData.productData.length / SP_PROD_PAGE_SIZE);
  if (page < 0 || page >= totalPages) return;
  renderSPProductTable(spData.productData, page);
}

// ── INSIGHTS ──
async function loadInsights() {
  _insProdRows = null; _plnGroups = null;   // force production-reco + planner refetch
  const btn = document.getElementById('ins-run-btn');
  btn.disabled = true; btn.textContent = 'Memuat...';
  const emEl = document.getElementById('ins-empty');
  emEl.style.display = 'block'; emEl.textContent = 'Mengambil data order 2026...';
  ['revenue','momentum','stock','geo','bcg','cat','prod'].forEach(t => { const e=document.getElementById('instab-'+t); if(e) e.style.display='none'; });

  try {
    const VALID = ['COMPLETED','FINISH_PACK','FINISH_PICK','CLOSED','PAID','PENDING'];
    const orders = await _fetchAllPages('jubelio_sales_orders',
      'salesorder_id,transaction_date,sub_total,total_disc',
      q => q.gte('transaction_date','2026-01-01').lte('transaction_date','2026-12-31T23:59:59').in('wms_status',VALID)
    );
    if (!orders.length) { emEl.textContent='Tidak ada data order di 2026.'; btn.disabled=false; btn.textContent='↻ Load Insights'; return; }

    emEl.textContent = `Mengambil items untuk ${orders.length.toLocaleString('id-ID')} order...`;
    const soIds = orders.map(o=>o.salesorder_id);
    const _rawItems = [];
    for (let i=0;i<soIds.length;i+=500) {
      const rows = await _fetchAllPages('jubelio_sales_order_items','salesorder_id,item_id,item_name,qty,price,disc_amount',q=>q.in('salesorder_id',soIds.slice(i,i+500)));
      _rawItems.push(...rows);
    }
    const _seen=new Set();
    const items = _rawItems.filter(it=>{ const k=`${it.salesorder_id}:${it.item_id}`; if(_seen.has(k))return false; _seen.add(k); return true; });

    if (!_spAllMappings) _spAllMappings = await _fetchAllPages('product_mappings','jubelio_item_id,item_name,brand,ip,collection');
    // Index by id AND name — product_mappings stores only one representative item_id
    // per distinct item_name, so other SKU variants need a name-based fallback.
    const mById={}, mByName={};
    for (const m of _spAllMappings) {
      if (m.jubelio_item_id) mById[m.jubelio_item_id]=m;
      if (m.item_name)       mByName[m.item_name]=m;
    }
    const _resolveMap = (it) => mById[it.item_id] || mByName[it.item_name] || {};

    const orderMap = new Map(orders.map(o=>[o.salesorder_id,o]));
    const ID_MONTHS = ['Jan','Feb','Mar','Apr','Mei','Jun','Jul','Agu','Sep','Okt','Nov','Des'];

    // Monthly totals + IP breakdown
    const monthlyTotals = Array.from({length:12},()=>({revenue:0,disc:0,net:0,qty:0}));
    const ipMonthly     = {}; // ip → [{revenue,disc,net,qty}×12]
    for (const o of orders) {
      const mi = parseInt((o.transaction_date||'').slice(5,7))-1;
      if (mi<0||mi>11) continue;
      const rev=parseFloat(o.sub_total||0), disc=parseFloat(o.total_disc||0);
      monthlyTotals[mi].revenue+=rev; monthlyTotals[mi].disc+=disc; monthlyTotals[mi].net+=rev-disc;
    }
    const brandMonthly = {};
    for (const it of items) {
      const o=orderMap.get(it.salesorder_id); if(!o) continue;
      const mi=parseInt((o.transaction_date||'').slice(5,7))-1; if(mi<0||mi>11) continue;
      const qty=parseFloat(it.qty||0), rev=qty*parseFloat(it.price||0), disc=parseFloat(it.disc_amount||0);
      monthlyTotals[mi].qty+=qty;
      const ip=_resolveMap(it).ip||'(Lainnya)';
      if (!ipMonthly[ip]) ipMonthly[ip]=Array.from({length:12},()=>({revenue:0,disc:0,net:0,qty:0}));
      ipMonthly[ip][mi].revenue+=rev; ipMonthly[ip][mi].disc+=disc;
      ipMonthly[ip][mi].net+=rev-disc; ipMonthly[ip][mi].qty+=qty;
      const brand=_resolveMap(it).brand||'(Lainnya)';
      if (!brandMonthly[brand]) brandMonthly[brand]=Array.from({length:12},()=>({revenue:0,disc:0,net:0,qty:0}));
      brandMonthly[brand][mi].revenue+=rev; brandMonthly[brand][mi].disc+=disc;
      brandMonthly[brand][mi].net+=rev-disc; brandMonthly[brand][mi].qty+=qty;
    }

    // Timing
    const now=new Date(), cm=now.getMonth();
    const dayOfYear=Math.floor((now-new Date(now.getFullYear(),0,0))/86400000);
    const daysLeft=365-dayOfYear;

    // Projection: avg daily from last 3 complete months
    const projBase=Math.min(3,cm);
    let projDailyNet=0;
    if (projBase>0) {
      let s=0; for(let mi=cm-projBase;mi<cm;mi++) s+=monthlyTotals[mi].net;
      projDailyNet=s/(projBase*30.4);
    } else {
      const ytd=monthlyTotals.slice(0,cm+1).reduce((s,m)=>s+m.net,0);
      projDailyNet=dayOfYear>0?ytd/dayOfYear:0;
    }
    const daysLeftInMonth=new Date(now.getFullYear(),cm+1,0).getDate()-now.getDate();
    const projectedMonthly=Array.from({length:12},(_,mi)=>{
      if (mi<cm) return null;
      const d=mi===cm?daysLeftInMonth:new Date(2026,mi+1,0).getDate();
      return projDailyNet*d;
    });
    const ytdNet=monthlyTotals.slice(0,cm+1).reduce((s,m)=>s+m.net,0);
    const yearEndProj=ytdNet+projDailyNet*daysLeft;

    // Stock data
    emEl.textContent='Mengambil data stok...';
    const allIds=[...new Set(items.map(it=>it.item_id).filter(Boolean))];
    const stockMap={}, thumbMap={};
    if (allIds.length) {
      const [jiR,stR]=await Promise.all([
        _fetchAllPages('jubelio_items','item_id,thumbnail',q=>q.in('item_id',allIds).not('thumbnail','is',null)),
        _fetchAllPages('jubelio_inventory_stocks','item_id,on_hand',q=>q.in('item_id',allIds)),
      ]);
      for (const r of jiR) if(r.thumbnail) thumbMap[r.item_id]=r.thumbnail;
      for (const r of stR) stockMap[r.item_id]=(stockMap[r.item_id]||0)+parseFloat(r.on_hand||0);
    }
    const itemQty2026={};
    for (const it of items) if(it.item_id) itemQty2026[it.item_id]=(itemQty2026[it.item_id]||0)+parseFloat(it.qty||0);

    const stockByIP={};
    for (const [itemId,totalQty] of Object.entries(itemQty2026)) {
      const m=mById[itemId]||{};
      const ip=m.ip||'(Lainnya)', name=m.item_name||itemId;
      const stock=stockMap[itemId]||0, avgDaily=totalQty/Math.max(1,dayOfYear);
      const daysOfStock=avgDaily>0?stock/avgDaily:(stock>0?9999:null);
      const isDead=stock>0&&avgDaily<0.1;
      if (!stockByIP[ip]) stockByIP[ip]={ip,totalStock:0,totalAvgDaily:0,products:[]};
      stockByIP[ip].totalStock+=stock; stockByIP[ip].totalAvgDaily+=avgDaily;
      stockByIP[ip].products.push({name,itemId,stock,avgDaily,daysOfStock,isDead});
    }
    const stockHorizon=Object.values(stockByIP).map(b=>({
      ...b,
      daysOfStock:b.totalAvgDaily>0?b.totalStock/b.totalAvgDaily:(b.totalStock>0?9999:null),
      products:b.products.sort((a,z)=>(a.daysOfStock||9999)-(z.daysOfStock||9999)),
    })).sort((a,b)=>(a.daysOfStock||9999)-(b.daysOfStock||9999));

    // Geo data
    emEl.textContent='Mengambil data geo...';
    const geoRaw = await _fetchAllPages('jubelio_sales_orders',
      'salesorder_id,shipping_city,shipping_province,sub_total,total_disc',
      q => q.gte('transaction_date','2026-01-01').lte('transaction_date','2026-12-31T23:59:59')
            .in('wms_status',VALID).not('shipping_province','is',null).neq('shipping_province','')
    );
    const {geoProvinces,geoCities,geoIntl,geoTotal} = _aggregateGeo(geoRaw);

    // Build salesorder_id lookup per IP and per brand
    const ipToOrderIds={}, brandToOrderIds={};
    for (const it of items) {
      const ip=_resolveMap(it).ip||'(Lainnya)';
      const brand=_resolveMap(it).brand||'(Lainnya)';
      if (!ipToOrderIds[ip]) ipToOrderIds[ip]=new Set();
      ipToOrderIds[ip].add(it.salesorder_id);
      if (!brandToOrderIds[brand]) brandToOrderIds[brand]=new Set();
      brandToOrderIds[brand].add(it.salesorder_id);
    }

    // Build category breakdown
    const _catOrderSets={}, _catRev={}, _catQty={};
    for (const it of items) {
      const m = _resolveMap(it);
      const cat = _extractCategory(m.item_name || '');
      if (!_catOrderSets[cat]) _catOrderSets[cat]=new Set();
      _catOrderSets[cat].add(it.salesorder_id);
      const net = parseFloat(it.price||0)*parseFloat(it.qty||0) - parseFloat(it.disc_amount||0);
      _catRev[cat] = (_catRev[cat]||0) + net;
      _catQty[cat] = (_catQty[cat]||0) + parseFloat(it.qty||0);
    }
    const catData = Object.keys(_catOrderSets)
      .map(cat=>({cat, orders:_catOrderSets[cat].size, revenue:_catRev[cat]||0, qty:_catQty[cat]||0}))
      .sort((a,b)=>b.revenue-a.revenue);

    // Historical revenue per IP/brand (pre-2026, currently 2025) for the BCG matrix.
    // full_rev = full prior year; same_rev = Jan..month cm (matches 2026 YTD window).
    emEl.textContent='Mengambil data historis (2025)...';
    const histIP={}, histBrand={};
    try {
      const {data:histRows} = await sb.rpc('get_history_rev', {p_through_month: cm});
      (histRows||[]).forEach(r=>{
        const o = {full:parseFloat(r.full_rev||0)||0, same:parseFloat(r.same_rev||0)||0};
        if (r.kind==='ip') histIP[r.name]=o; else histBrand[r.name]=o;
      });
    } catch(e){ console.warn('get_history_rev:',e); }

    // Annual revenue 2024 + 2025 (history) for the multi-year trend
    const annualRev = {};
    try {
      const {data:annRows} = await sb.rpc('get_insights_annual_rev');
      (annRows||[]).forEach(r=>{ annualRev[r.yr]=parseFloat(r.net||0)||0; });
    } catch(e){ console.warn('get_insights_annual_rev:',e); }

    // Per-IP yearly revenue (2024/2025) for Momentum + raw category history for Category tab
    const ipYear={};   // ip → {2024,2025}
    let catHist=[];
    try {
      const [{data:eyRows}, {data:chRows}] = await Promise.all([
        sb.rpc('get_entity_year_rev'),
        sb.rpc('get_cat_history'),
      ]);
      (eyRows||[]).forEach(r=>{ if(r.kind!=='ip') return; (ipYear[r.name]=ipYear[r.name]||{})[r.yr]=parseFloat(r.rev||0)||0; });
      catHist = (chRows||[]).map(r=>({rawcat:r.rawcat||'', rev:parseFloat(r.rev||0)||0, qty:parseFloat(r.qty||0)||0, orders:parseInt(r.orders||0)||0}));
    } catch(e){ console.warn('insights history aggregates:',e); }

    _insData={ID_MONTHS,cm,dayOfYear,daysLeft,monthlyTotals,projectedMonthly,ipMonthly,annualRev,
      ytdNet,yearEndProj,projDailyNet,stockHorizon,ips:Object.keys(ipMonthly).sort(),
      geoProvinces,geoCities,geoTotal,geoIntl,geoRaw,ipToOrderIds,brandToOrderIds,brandMonthly,
      catData,histIP,histBrand,ipYear,catHist};

    emEl.style.display='none';
    document.getElementById('instab-'+_insTab).style.display='block';
    _renderInsTab(_insTab);
  } catch(e) { emEl.textContent='Gagal: '+(e.message||e); console.error('loadInsights:',e); }
  btn.disabled=false; btn.textContent='↻ Load Insights';
}

function switchInsTab(tab, btn) {
  _insTab=tab;
  ['revenue','momentum','stock','geo','bcg','cat','prod'].forEach(t=>{
    const tb=document.getElementById('ins-tab-'+t); if(tb) tb.classList.toggle('active',t===tab);
    const pg=document.getElementById('instab-'+t); if(pg) pg.style.display=(t===tab&&_insData)?'block':'none';
  });
  if (_insData) _renderInsTab(tab);
}

function _renderInsTab(tab) {
  if (tab==='revenue')  _renderInsRevenue();
  if (tab==='momentum') _renderInsMomentum();
  if (tab==='stock')    _renderInsStock();
  if (tab==='geo')      _renderInsGeo();
  if (tab==='bcg')      _renderInsBCG();
  if (tab==='cat')      _renderInsCat();
  if (tab==='prod')     _renderInsProd();
}

function _renderInsRevenue() {
  const d=_insData;
  const fmtRp=n=>n>=1e9?'Rp '+(n/1e9).toFixed(1)+'M':n>=1e6?'Rp '+(n/1e6).toFixed(1)+'jt':'Rp '+Math.round(n).toLocaleString('id-ID');
  const _se=(id,v)=>{const e=document.getElementById(id);if(e)e.textContent=v;};

  const completedNets=d.monthlyTotals.slice(0,d.cm).map(m=>m.net).filter(n=>n>0);
  const bestVal=completedNets.length?Math.max(...completedNets):0;
  const bestIdx=d.monthlyTotals.findIndex(m=>m.net===bestVal&&bestVal>0);
  const avgMonthly=completedNets.length?completedNets.reduce((s,n)=>s+n,0)/completedNets.length:0;

  _se('ins-r-ytd',fmtRp(d.ytdNet));
  _se('ins-r-projected',fmtRp(d.yearEndProj));
  _se('ins-r-best',(bestIdx>=0?d.ID_MONTHS[bestIdx]+' · ':'')+fmtRp(bestVal));
  _se('ins-r-avg',fmtRp(avgMonthly));

  // Annual revenue trend 2024 · 2025 · 2026(YTD) · 2026(proyeksi)
  const annEl=document.getElementById('ins-annual');
  if (annEl) {
    const a=d.annualRev||{};
    const rev24=a[2024]||0, rev25=a[2025]||0, rev26=d.ytdNet, rev26p=d.yearEndProj;
    const yoy=(cur,prev)=>prev>0?((cur-prev)/prev*100):null;
    const yoyStr=p=>p===null?'':`<span style="font-size:11px;font-weight:600;color:${p>=0?'#2d7a2d':'#c0392b'}">${p>=0?'▲':'▼'} ${Math.abs(p).toFixed(0)}% YoY</span>`;
    const card=(lbl,val,sub)=>`<div style="border:1px solid var(--g100);border-radius:8px;padding:12px 14px;background:var(--off)">
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;color:var(--g400);letter-spacing:.05em">${lbl}</div>
      <div style="font-size:18px;font-weight:700;font-family:var(--head);margin:4px 0 2px">${fmtRp(val)}</div>
      <div>${sub||'&nbsp;'}</div>
    </div>`;
    annEl.innerHTML =
      card('2024', rev24, '<span style="font-size:11px;color:var(--g400)">full year</span>') +
      card('2025', rev25, yoyStr(yoy(rev25, rev24))) +
      card('2026 YTD', rev26, yoyStr(yoy(rev26, (rev25 * (d.cm/12))))) +
      card('2026 Proyeksi', rev26p, yoyStr(yoy(rev26p, rev25)));
  }

  // Chart
  const canvas=document.getElementById('ins-chart');
  if (canvas&&typeof Chart!=='undefined') {
    if (canvas._chart) { canvas._chart.destroy(); canvas._chart=null; }
    const actualData=d.monthlyTotals.map((m,i)=>i<=d.cm?m.net:null);
    const projData=d.monthlyTotals.map((m,i)=>{
      if (i<d.cm) return null;
      if (i===d.cm) return m.net+(d.projectedMonthly[i]||0);
      return d.projectedMonthly[i]||0;
    });
    canvas._chart=new Chart(canvas,{
      type:'bar',
      data:{labels:d.ID_MONTHS,datasets:[
        {label:'Aktual',data:actualData,backgroundColor:'#3C3489',borderRadius:4,barPercentage:0.65},
        {label:'Proyeksi',data:projData,backgroundColor:'rgba(60,52,137,0.18)',borderColor:'rgba(60,52,137,0.5)',borderWidth:1,borderRadius:4,barPercentage:0.65},
      ]},
      options:{responsive:true,maintainAspectRatio:false,
        plugins:{legend:{display:false},tooltip:{callbacks:{label:ctx=>' '+fmtRp(ctx.raw||0)}}},
        scales:{
          x:{stacked:false,grid:{display:false},ticks:{font:{family:'DM Mono',size:10},color:'#888'}},
          y:{grid:{color:'#f0efe9'},ticks:{font:{family:'DM Mono',size:10},color:'#888',callback:v=>fmtRp(v)}},
        }
      }
    });
  }

  // Table
  const tbody=document.getElementById('ins-r-tbody'); if(!tbody) return;
  const rows=[];
  for (let mi=0;mi<12;mi++) {
    const m=d.monthlyTotals[mi];
    const isProj=mi>d.cm, isPartial=mi===d.cm;
    const prevNet=mi>0?d.monthlyTotals[mi-1].net:0;
    const momPct=(prevNet>0&&m.net>0)?((m.net-prevNet)/prevNet*100):null;
    const momStr=(!isProj&&momPct!==null)?(momPct>=0?'+':'')+momPct.toFixed(1)+'%':'—';
    const momClr=momPct===null?'#aaa':momPct>0?'#2d7a2d':'#c0392b';
    const dispNet=isProj?(d.projectedMonthly[mi]||0):m.net;
    const lbl=d.ID_MONTHS[mi]+(isProj?' 🔮':isPartial?' ·':'');
    rows.push(`<tr style="border-bottom:1px solid var(--g100);${isProj?'background:rgba(60,52,137,0.03);color:var(--g400);font-style:italic':isPartial?'background:#fffdf5':''}">
      <td style="padding:6px 10px;font-size:12px;font-weight:${isProj?400:500}">${lbl}</td>
      <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px">${isProj?'—':fmtRp(m.revenue)}</td>
      <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#c0392b">${isProj?'—':fmtRp(m.disc)}</td>
      <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px;font-weight:${isProj?400:600};color:${isProj?'#aaa':'var(--text)'}">${fmtRp(dispNet)}</td>
      <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px">${isProj?'—':Math.round(m.qty)}</td>
      <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:${momClr}">${momStr}</td>
    </tr>`);
  }
  const ytdRev=d.monthlyTotals.slice(0,d.cm+1).reduce((s,m)=>s+m.revenue,0);
  const ytdDisc=d.monthlyTotals.slice(0,d.cm+1).reduce((s,m)=>s+m.disc,0);
  const ytdQty=Math.round(d.monthlyTotals.slice(0,d.cm+1).reduce((s,m)=>s+m.qty,0));
  rows.push(`<tr style="background:#f7f8fa;font-weight:700;border-top:2px solid var(--g200)">
    <td style="padding:7px 10px;font-size:12px">YTD Aktual</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${fmtRp(ytdRev)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#c0392b">${fmtRp(ytdDisc)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:#2d7a2d">${fmtRp(d.ytdNet)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${ytdQty}</td>
    <td></td>
  </tr>`);
  tbody.innerHTML=rows.join('');
}

function _renderInsMomentum() {
  const d=_insData;
  const fmtRp=n=>n>=1e9?'Rp '+(n/1e9).toFixed(1)+'M':n>=1e6?'Rp '+(n/1e6).toFixed(1)+'jt':'Rp '+Math.round(n).toLocaleString('id-ID');
  const _se=(id,v)=>{const e=document.getElementById(id);if(e)e.textContent=v;};

  const ipStats=d.ips.map(ip=>{
    const mo=d.ipMonthly[ip];
    const ytd=mo.slice(0,d.cm+1).reduce((s,m)=>s+m.net,0);
    const lastNet=d.cm>=1?mo[d.cm-1].net:0;
    const prevNet=d.cm>=2?mo[d.cm-2].net:0;
    const mom=prevNet>0?((lastNet-prevNet)/prevNet*100):null;
    let trend='→';
    if (d.cm>=3){const a=mo[d.cm-3].net,b=mo[d.cm-2].net,c=mo[d.cm-1].net;
      if(c>b&&b>a)trend='↑'; else if(c<b&&b<a)trend='↓'; else if(c>a)trend='↗'; else if(c<a)trend='↘';}
    return {ip,mo,ytd,mom,trend};
  }).sort((a,b)=>b.ytd-a.ytd);

  const top=ipStats[0];
  const fastest=[...ipStats].filter(b=>b.mom!==null).sort((a,b)=>(b.mom||0)-(a.mom||0))[0];
  const declining=ipStats.filter(b=>b.trend==='↓'||b.trend==='↘');
  _se('ins-m-top',top?`${top.ip} · ${fmtRp(top.ytd)}`:'—');
  _se('ins-m-fastest',fastest?`${fastest.ip} +${fastest.mom?.toFixed(1)}%`:'—');
  _se('ins-m-decline',declining.length?declining.map(b=>b.ip).join(', '):'Semua aman ✓');

  const visMo=Array.from({length:d.cm+1},(_,i)=>i);
  const wrap=document.getElementById('ins-m-wrap'); if(!wrap) return;

  let html=`<div class="table-wrap" style="margin:0;overflow-x:auto">
  <table style="width:100%;border-collapse:collapse;font-size:12px">
    <thead><tr style="background:#f7f8fa;border-bottom:2px solid var(--g200)">
      <th style="padding:8px 10px;text-align:left;font-weight:600;white-space:nowrap">IP</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap;color:var(--g400)">2024</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap;color:var(--g400)">2025</th>
      ${visMo.map(mi=>`<th style="padding:8px 10px;text-align:right;font-weight:600;min-width:70px">${d.ID_MONTHS[mi]}</th>`).join('')}
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">MoM</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">2026 YTD</th>
      <th style="padding:8px 10px;text-align:center;font-weight:600">Trend</th>
    </tr></thead><tbody>`;

  for (const bs of ipStats) {
    const maxNet=Math.max(...bs.mo.map(m=>m.net),1);
    const momStr=bs.mom!==null?(bs.mom>=0?'+':'')+bs.mom.toFixed(1)+'%':'—';
    const momClr=bs.mom===null?'#aaa':bs.mom>0?'#2d7a2d':'#c0392b';
    const tClr=bs.trend==='↑'||bs.trend==='↗'?'#2d7a2d':bs.trend==='↓'||bs.trend==='↘'?'#c0392b':'#888';
    const hy=(d.ipYear||{})[bs.ip]||{};
    const cellY=v=>`<td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g500)">${v>0?fmtRp(v):'—'}</td>`;
    html+=`<tr style="border-bottom:1px solid var(--g100)">
      <td style="padding:7px 10px;font-weight:500">${bs.ip}</td>
      ${cellY(hy[2024]||0)}${cellY(hy[2025]||0)}
      ${visMo.map(mi=>{
        const net=bs.mo[mi].net;
        const bg=net>0?`rgba(60,52,137,${((net/maxNet)*0.25).toFixed(2)})`:'transparent';
        return `<td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;background:${bg}">${net>0?fmtRp(net):'—'}</td>`;
      }).join('')}
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px;font-weight:600;color:${momClr}">${momStr}</td>
      <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:12px;font-weight:700;color:#2d7a2d">${fmtRp(bs.ytd)}</td>
      <td style="padding:7px 10px;text-align:center;font-size:15px;color:${tClr}">${bs.trend}</td>
    </tr>`;
  }
  html+='</tbody></table></div>';
  wrap.innerHTML=html;
}

function _renderInsStock() {
  const d=_insData;
  const fmtD=n=>n===null?'—':n>=9999?'∞':Math.round(n)+'d';
  const _se=(id,v)=>{const e=document.getElementById(id);if(e)e.textContent=v;};
  const statusStyle=days=>{
    if (days===null)   return {clr:'#aaa',bg:'#f5f5f5',lbl:'No Data'};
    if (days>=9999)    return {clr:'#2d7a2d',bg:'#e8f5e9',lbl:'∞'};
    if (days<30)       return {clr:'#c0392b',bg:'#fdf0f0',lbl:fmtD(days)};
    if (days<60)       return {clr:'#e65100',bg:'#fff3e0',lbl:fmtD(days)};
    if (days<90)       return {clr:'#b8860b',bg:'#fffde7',lbl:fmtD(days)};
    return {clr:'#2d7a2d',bg:'#e8f5e9',lbl:fmtD(days)};
  };

  const critical=d.stockHorizon.filter(b=>b.daysOfStock!==null&&b.daysOfStock<30);
  const watch=d.stockHorizon.filter(b=>b.daysOfStock!==null&&b.daysOfStock>=30&&b.daysOfStock<60);
  const deadCount=d.stockHorizon.reduce((s,b)=>s+b.products.filter(p=>p.isDead).length,0);
  _se('ins-s-critical',critical.length);
  _se('ins-s-watch',watch.length);
  _se('ins-s-dead',deadCount+' SKU');

  const wrap=document.getElementById('ins-stock-wrap'); if(!wrap) return;
  let html=`<div class="table-wrap" style="margin:0"><table style="width:100%;border-collapse:collapse;font-size:12px">
    <thead><tr style="background:#f7f8fa;border-bottom:2px solid var(--g200)">
      <th style="padding:8px 10px;text-align:left;font-weight:600">IP</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Total Stock</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Avg Daily Sales</th>
      <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Runway</th>
      <th style="padding:8px 10px;text-align:center;font-weight:600">Status</th>
      <th style="padding:8px 10px;width:30px"></th>
    </tr></thead><tbody>`;

  d.stockHorizon.forEach((b,bi)=>{
    const st=statusStyle(b.daysOfStock);
    html+=`<tr style="border-bottom:1px solid var(--g100);cursor:pointer" onclick="_insToggleStock(${bi})">
      <td style="padding:8px 10px;font-weight:600">${b.ip}</td>
      <td style="padding:8px 10px;text-align:right;font-family:var(--mono);font-size:11px">${Math.round(b.totalStock).toLocaleString('id-ID')}</td>
      <td style="padding:8px 10px;text-align:right;font-family:var(--mono);font-size:11px">${b.totalAvgDaily.toFixed(1)}/hari</td>
      <td style="padding:8px 10px;text-align:right;font-family:var(--mono);font-size:13px;font-weight:700;color:${st.clr}">${fmtD(b.daysOfStock)}</td>
      <td style="padding:8px 10px;text-align:center"><span style="font-size:10px;background:${st.bg};color:${st.clr};border-radius:4px;padding:2px 9px;font-family:var(--mono)">${st.lbl}</span></td>
      <td style="padding:8px 10px;text-align:center;font-size:10px;color:var(--g400)" id="ins-she-${bi}">▶</td>
    </tr>
    <tr id="ins-shp-${bi}" style="display:none;background:#fafafa">
      <td colspan="6" style="padding:0 10px 10px 30px">
        <table style="width:100%;border-collapse:collapse;font-size:11px">
          <thead><tr style="color:var(--g400)">
            <th style="padding:4px 8px;text-align:left;font-weight:400">Produk</th>
            <th style="padding:4px 8px;text-align:right;font-weight:400">Stock</th>
            <th style="padding:4px 8px;text-align:right;font-weight:400">Avg Daily</th>
            <th style="padding:4px 8px;text-align:right;font-weight:400">Runway</th>
          </tr></thead><tbody>
          ${b.products.map(p=>{
            const ps=statusStyle(p.daysOfStock);
            const deadTag=p.isDead?` <span style="font-size:9px;background:#fff3e0;color:#e65100;border-radius:3px;padding:1px 4px">dead stock</span>`:'';
            return `<tr style="border-top:1px solid var(--g100)">
              <td style="padding:4px 8px">${p.name}${deadTag}</td>
              <td style="padding:4px 8px;text-align:right;font-family:var(--mono)">${Math.round(p.stock).toLocaleString('id-ID')}</td>
              <td style="padding:4px 8px;text-align:right;font-family:var(--mono)">${p.avgDaily.toFixed(2)}</td>
              <td style="padding:4px 8px;text-align:right;font-family:var(--mono);color:${ps.clr};font-weight:600">${fmtD(p.daysOfStock)}</td>
            </tr>`;
          }).join('')}
          </tbody>
        </table>
      </td>
    </tr>`;
  });
  html+='</tbody></table></div>';
  wrap.innerHTML=html;
}

function _insToggleStock(bi) {
  const row=document.getElementById(`ins-shp-${bi}`);
  const exp=document.getElementById(`ins-she-${bi}`);
  if (!row) return;
  const open=row.style.display!=='none';
  row.style.display=open?'none':'table-row';
  if (exp) exp.textContent=open?'▶':'▼';
}

// ── INSIGHTS BCG ──
function _insBCGMode(val) {
  _insBCGViewMode = val;
  if (_insData) _renderInsBCG();
}

function _renderInsBCG() {
  const d = _insData;
  if (!d) return;

  const fmtRp = n => n>=1e9?'Rp '+(n/1e9).toFixed(1)+'M':n>=1e6?'Rp '+(n/1e6).toFixed(1)+'jt':'Rp '+Math.round(n).toLocaleString('id-ID');
  const mode = _insBCGViewMode;
  const monthly = mode==='ip' ? d.ipMonthly : (d.brandMonthly||{});
  const hist    = mode==='ip' ? (d.histIP||{}) : (d.histBrand||{});

  // YoY: 2026 YTD (Jan..month cm-1, i.e. complete months) vs 2025 same period.
  const cm = d.cm;
  const periodLabel = cm>0 ? `${d.ID_MONTHS[0]}–${d.ID_MONTHS[cm-1]}` : 'YTD';

  // Union of entities seen in 2026 sales and in 2025 history
  const names = new Set([...Object.keys(monthly), ...Object.keys(hist)]);
  const entities = [];
  names.forEach(name => {
    const months = monthly[name];
    const rev2026 = months ? months.slice(0, cm).reduce((s,m)=>s+m.net, 0) : 0;
    const h = hist[name] || {full:0, same:0};
    const total = h.full + rev2026;                 // combined 2025 + 2026 → bubble size & share
    if (total <= 0) return;
    const growth = h.same > 0 ? (rev2026 - h.same)/h.same*100 : (rev2026>0 ? 100 : 0);
    entities.push({name, ytd:total, total, rev2026, hist2025:h.full, hist2025same:h.same, growth, hasGrowth:h.same>0});
  });
  if (!entities.length) return;

  // Market share
  const totalYtd = entities.reduce((s,e)=>s+e.ytd, 0);
  entities.forEach(e => { e.share = totalYtd>0 ? e.ytd/totalYtd*100 : 0; });

  // Thresholds: average share for X, average growth for Y (portfolio-relative)
  const xThresh = entities.reduce((s,e)=>s+e.share,0)  / entities.length;
  const yThresh = entities.reduce((s,e)=>s+e.growth,0) / entities.length;

  // Quadrant assignment
  const QLBL  = {star:'⭐ Star', question:'❓ Question Mark', cow:'🐄 Cash Cow', dog:'🐕 Dog'};
  const QCOL  = {
    star:     {fill:'rgba(39,174,96,0.7)',   border:'#27ae60',  bg:'rgba(39,174,96,0.06)'},
    question: {fill:'rgba(243,156,18,0.7)',  border:'#f39c12',  bg:'rgba(243,156,18,0.06)'},
    cow:      {fill:'rgba(52,152,219,0.7)',  border:'#2980b9',  bg:'rgba(52,152,219,0.06)'},
    dog:      {fill:'rgba(231,76,60,0.7)',   border:'#c0392b',  bg:'rgba(231,76,60,0.06)'},
  };
  entities.forEach(e => {
    const hi=e.share>=xThresh, hg=e.growth>=yThresh;
    e.quadrant = hi&&hg?'star' : !hi&&hg?'question' : hi&&!hg?'cow' : 'dog';
  });

  // Bubble radius (pixels)
  const maxYtd = Math.max(...entities.map(e=>e.ytd), 1);
  entities.forEach(e => { e.r = Math.max(7, Math.round(8 + (e.ytd/maxYtd)*28)); });

  // Custom quadrant background plugin
  const _bcgQuadPlugin = {
    id: 'bcgQuad',
    beforeDraw(chart) {
      const {ctx, chartArea:ca, scales} = chart;
      if (!ca) return;
      const xm = Math.max(ca.left, Math.min(ca.right,  scales.x.getPixelForValue(xThresh)));
      const ym = Math.max(ca.top,  Math.min(ca.bottom, scales.y.getPixelForValue(yThresh)));
      const quads = [
        {x:ca.left, y:ca.top,  w:xm-ca.left, h:ym-ca.top,      bg:QCOL.question.bg, lbl:'❓ Question Mark', lx:ca.left+8, ly:ca.top+14},
        {x:xm,      y:ca.top,  w:ca.right-xm,h:ym-ca.top,      bg:QCOL.star.bg,     lbl:'⭐ Star',          lx:xm+8,      ly:ca.top+14},
        {x:ca.left, y:ym,      w:xm-ca.left, h:ca.bottom-ym,   bg:QCOL.dog.bg,      lbl:'🐕 Dog',           lx:ca.left+8, ly:ca.bottom-6},
        {x:xm,      y:ym,      w:ca.right-xm,h:ca.bottom-ym,   bg:QCOL.cow.bg,      lbl:'🐄 Cash Cow',      lx:xm+8,      ly:ca.bottom-6},
      ];
      quads.forEach(q => {
        ctx.fillStyle = q.bg;
        ctx.fillRect(q.x, q.y, q.w, q.h);
        ctx.fillStyle = 'rgba(0,0,0,0.22)';
        ctx.font = '10px "DM Mono",monospace';
        ctx.fillText(q.lbl, q.lx, q.ly);
      });
      ctx.save();
      ctx.strokeStyle = 'rgba(0,0,0,0.12)';
      ctx.lineWidth = 1;
      ctx.setLineDash([5,5]);
      ctx.beginPath(); ctx.moveTo(xm, ca.top); ctx.lineTo(xm, ca.bottom); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(ca.left, ym); ctx.lineTo(ca.right, ym); ctx.stroke();
      ctx.restore();
    }
  };

  // Destroy old chart
  if (_insBCGChart) { _insBCGChart.destroy(); _insBCGChart = null; }
  const canvas = document.getElementById('ins-bcg-chart');
  if (!canvas) return;

  _insBCGChart = new Chart(canvas, {
    type: 'bubble',
    data: {
      datasets: entities.map(e => ({
        label: e.name,
        data: [{x: e.share, y: e.growth, r: e.r, _e: e}],
        backgroundColor: QCOL[e.quadrant].fill,
        borderColor: QCOL[e.quadrant].border,
        borderWidth: 1.5,
      }))
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {display: false},
        datalabels: {display: false},
        tooltip: {
          callbacks: {
            title: ctx => ctx[0]?.dataset?.label || '',
            label: ctx => {
              const e = ctx.raw._e;
              return [
                `Share: ${e.share.toFixed(1)}%`,
                `YoY Growth: ${e.growth>=0?'+':''}${e.growth.toFixed(1)}%`,
                `Total (24–26): ${fmtRp(e.total)}`,
                `2026 YTD: ${fmtRp(e.rev2026)} · 2024–25: ${fmtRp(e.hist2025)}`,
                `Quadrant: ${QLBL[e.quadrant]}`,
              ];
            }
          }
        }
      },
      scales: {
        x: {
          type: 'logarithmic',
          title: {display:true, text:'Market Share — log scale (%)', font:{size:11}, color:'#888'},
          grid: {display:false},
          min: Math.max(0.05, Math.min(...entities.map(e=>e.share)) * 0.5),
          max: Math.min(100,  Math.max(...entities.map(e=>e.share)) * 1.5),
          ticks: {
            font:{size:10},
            callback: v => {
              // Show clean labels at log-friendly values
              const clean = [0.1,0.2,0.5,1,2,5,10,20,50,100];
              return clean.includes(+v.toFixed(1)) || clean.includes(+v.toFixed(0)) ? v+'%' : '';
            }
          },
        },
        y: {
          title: {display:true, text:`YoY Growth — 2026 vs 2025 (${periodLabel}) (%)`, font:{size:11}, color:'#888'},
          grid: {display:false},
          suggestedMin: Math.min(...entities.map(e=>e.growth)) - 10,
          suggestedMax: Math.max(...entities.map(e=>e.growth)) + 10,
          ticks: {font:{size:10}, callback: v => (v>=0?'+':'')+v+'%'},
        }
      }
    },
    plugins: [_bcgQuadPlugin]
  });

  // Bubble name labels painted after chart renders
  canvas.onclick = null; // reset
  const sortedE = [...entities].sort((a,b)=>b.ytd-a.ytd);

  // Summary table
  const tableEl = document.getElementById('ins-bcg-table');
  if (tableEl) tableEl.innerHTML = `
    <div style="font-family:var(--mono);font-size:11px;text-transform:uppercase;color:var(--g400);margin-bottom:8px;letter-spacing:.05em">
      Detail — ${mode==='ip'?'per IP':'per Brand'} · cutoff share ≥${xThresh.toFixed(2)}% (rata-rata) · growth ≥${yThresh>=0?'+':''}${yThresh.toFixed(1)}% (rata-rata)
    </div>
    <div class="table-wrap" style="margin:0"><table style="width:100%;table-layout:fixed">
      <colgroup><col style="width:auto"><col style="width:120px"><col style="width:60px"><col style="width:75px"><col style="width:115px"><col style="width:100px"><col style="width:100px"></colgroup>
      <thead><tr>
        <th>${mode==='ip'?'IP':'Brand'}</th>
        <th style="text-align:center">Quadrant</th>
        <th style="text-align:right">Share</th>
        <th style="text-align:right">YoY</th>
        <th style="text-align:right">Total (24–26)</th>
        <th style="text-align:right">2026 YTD</th>
        <th style="text-align:right">2024–25</th>
      </tr></thead>
      <tbody>${sortedE.map(e=>`
        <tr>
          <td style="font-weight:500;font-size:12px">${e.name}</td>
          <td style="text-align:center;font-size:11px">${QLBL[e.quadrant]}</td>
          <td style="text-align:right;font-family:var(--mono);font-size:11px">${e.share.toFixed(1)}%</td>
          <td style="text-align:right;font-family:var(--mono);font-size:11px;font-weight:600;color:${e.growth>=0?'#27ae60':'#c0392b'}">${e.growth>=0?'+':''}${e.growth.toFixed(1)}%</td>
          <td style="text-align:right;font-family:var(--mono);font-size:11px">${fmtRp(e.total)}</td>
          <td style="text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${fmtRp(e.rev2026)}</td>
          <td style="text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${fmtRp(e.hist2025)}</td>
        </tr>`).join('')}
      </tbody>
    </table></div>`;
}

// ── INSIGHTS CATEGORY ──
const _CAT_NORM = {
  'T-SHIRT':'T-Shirt','T-SHIRTS':'T-Shirt','TSHIRT':'T-Shirt','T SHIRT':'T-Shirt',
  'BOXY T-SHIRT':'Boxy T-Shirt','BOXY TSHIRT':'Boxy T-Shirt',
  'RINGER T-SHIRT':'Ringer T-Shirt','RAGLAN T-SHIRT':'Raglan T-Shirt',
  'KIDS T-SHIRT':'Kids T-Shirt','KIDS TSHIRT':'Kids T-Shirt',
  'LONG SLEEVE T-SHIRT':'Long Sleeve T-Shirt','LS T-SHIRT':'Long Sleeve T-Shirt',
  'SHORT SLEEVE SHIRT':'Short Sleeve Shirt','LONG SLEEVE SHIRT':'Long Sleeve Shirt',
  'TOTEBAG':'Tote Bag','TOTE BAG':'Tote Bag',
  'BABY TEE':'Baby Tee','HOODIE':'Hoodie','CREWNECK':'Crewneck','SWEATER':'Sweater',
  'SWEATSHIRT':'Sweatshirt','JERSEY':'Jersey','FLEECE':'Fleece',
  'CAP':'Cap','DAD CAP':'Dad Cap','DIRECTOR CAP':'Director Cap','BUCKET HAT':'Bucket Hat','BEANIE':'Beanie',
  'CD':'CD','VINYL':'Vinyl','CASSETTE':'Cassette','BOXSET':'Boxset',
  'POSTER':'Poster','PRINTS':'Prints','PAPER':'Paper','CALENDAR':'Calendar','ZINE':'Zine',
  'KEYCHAIN':'Keychain','LANYARD':'Lanyard','SCARF':'Scarf','SOCKS':'Socks',
  'POUCH':'Pouch','BAG CHARM':'Bag Charm','ENAMEL PIN':'Enamel Pin','PIN PATCHES':'Pin Patches',
  'STICKER PACK':'Sticker Pack','STICKER':'Sticker','PATCH':'Patch',
  'BUNDLE':'Bundle','BUNDLE SET':'Bundle Set',
};
const _CAT_VALID = new Set(Object.values(_CAT_NORM));

function _extractCategory(itemName) {
  if (!itemName) return '(Lainnya)';
  const parts = itemName.replace(/^\./,'').split(' - ');
  if (parts.length < 3) return '(Lainnya)';
  const raw = parts[2].trim().toUpperCase();
  if (_CAT_NORM[raw]) return _CAT_NORM[raw];
  // Title-case fallback for recognised but unlisted types
  const titled = parts[2].trim().replace(/\b\w/g,c=>c.toUpperCase());
  return titled || '(Lainnya)';
}

let _insCatChart = null;

function _renderInsCat() {
  const d = _insData;
  if (!d || !d.catData) return;

  const fmtRp = n => n>=1e9 ? 'Rp '+(n/1e9).toFixed(1)+'M' : n>=1e6 ? 'Rp '+(n/1e6).toFixed(1)+'jt' : 'Rp '+Math.round(n).toLocaleString('id-ID');
  const fmtN  = n => n.toLocaleString('id-ID');

  // Combine 2026 category data with 2024–2025 history (category derived from raw 3rd segment)
  const catMap = {};
  const _add = (cat,rev,qty,ord)=>{ const m=catMap[cat]||(catMap[cat]={cat,revenue:0,qty:0,orders:0}); m.revenue+=rev; m.qty+=qty; m.orders+=ord; };
  (d.catData||[]).forEach(c=>_add(c.cat, c.revenue||0, c.qty||0, c.orders||0));
  (d.catHist||[]).forEach(h=>{
    const cat = !h.rawcat ? '(Lainnya)' : (_CAT_NORM[h.rawcat] || h.rawcat.toLowerCase().replace(/\b\w/g,c=>c.toUpperCase()));
    _add(cat, h.rev||0, h.qty||0, h.orders||0);
  });
  const cats = Object.values(catMap).sort((a,b)=>b.revenue-a.revenue);
  const totalRev = cats.reduce((s,c)=>s+c.revenue,0);
  const validCats = cats.filter(c=>c.cat!=='(Lainnya)');

  // Stat cards
  document.getElementById('ins-cat-total-rev').textContent = fmtRp(totalRev);
  document.getElementById('ins-cat-types').textContent     = validCats.length;
  document.getElementById('ins-cat-top').textContent       = validCats[0] ? validCats[0].cat : '—';

  // Horizontal bar chart — top 15 by revenue (excluding Lainnya)
  const top15 = validCats.slice(0, 15);
  const COLORS = [
    '#3C3489','#5B4FCF','#8E83DD','#27AE60','#1ABC9C',
    '#E67E22','#E74C3C','#3498DB','#9B59B6','#F39C12',
    '#16A085','#2980B9','#8E44AD','#D35400','#C0392B',
  ];

  if (_insCatChart) { _insCatChart.destroy(); _insCatChart = null; }
  const canvas = document.getElementById('ins-cat-chart');
  if (!canvas) return;

  // Dynamically set canvas height based on bar count
  const barH = 32, padH = 80;
  canvas.style.height = (top15.length * barH + padH) + 'px';
  canvas.height = top15.length * barH + padH;

  _insCatChart = new Chart(canvas, {
    type: 'bar',
    data: {
      labels: top15.map(c=>c.cat),
      datasets: [{
        data: top15.map(c=>c.revenue),
        backgroundColor: top15.map((_,i)=>COLORS[i%COLORS.length]+'CC'),
        borderColor:     top15.map((_,i)=>COLORS[i%COLORS.length]),
        borderWidth: 1,
        borderRadius: 4,
      }]
    },
    options: {
      indexAxis: 'y',
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: { display: false },
        tooltip: {
          callbacks: {
            label: ctx => {
              const c = top15[ctx.dataIndex];
              const pct = totalRev > 0 ? (c.revenue/totalRev*100).toFixed(1) : 0;
              return ` ${fmtRp(c.revenue)}  (${pct}%)  •  ${fmtN(c.orders)} order  •  ${fmtN(c.qty)} unit`;
            }
          }
        }
      },
      scales: {
        x: {
          ticks: {
            callback: v => v>=1e9?'Rp '+(v/1e9).toFixed(0)+'M':v>=1e6?'Rp '+(v/1e6).toFixed(0)+'jt':'',
            font: { family: 'monospace', size: 10 },
            color: '#888',
          },
          grid: { color: 'rgba(0,0,0,0.05)' },
        },
        y: {
          ticks: { font: { family: 'monospace', size: 11 }, color: '#333' },
          grid: { display: false },
        }
      }
    }
  });

  // Full table
  const totalOrders = cats.reduce((s,c)=>s+c.orders,0);
  const totalQty    = cats.reduce((s,c)=>s+c.qty,0);
  let rows = cats.map((c,i) => {
    const pct = totalRev>0 ? (c.revenue/totalRev*100).toFixed(1) : '0.0';
    return `<tr>
      <td style="font-family:var(--mono);font-size:11px;color:var(--g400)">${i+1}</td>
      <td style="font-weight:500">${c.cat}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px">${fmtRp(c.revenue)}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;color:var(--g400)">${pct}%</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px">${fmtN(c.orders)}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px">${fmtN(Math.round(c.qty))}</td>
    </tr>`;
  }).join('');
  const tfoot = `<tr style="font-weight:700;border-top:2px solid var(--g200)">
    <td></td><td>Total</td>
    <td style="text-align:right;font-family:var(--mono);font-size:12px">${fmtRp(totalRev)}</td>
    <td style="text-align:right;font-family:var(--mono);font-size:12px">100%</td>
    <td style="text-align:right;font-family:var(--mono);font-size:12px">${fmtN(totalOrders)}</td>
    <td style="text-align:right;font-family:var(--mono);font-size:12px">${fmtN(Math.round(totalQty))}</td>
  </tr>`;
  document.getElementById('ins-cat-table').innerHTML = `
    <div class="table-wrap" style="margin:0">
    <table style="width:100%;table-layout:fixed">
      <colgroup><col style="width:36px"><col><col style="width:130px"><col style="width:70px"><col style="width:90px"><col style="width:90px"></colgroup>
      <thead><tr>
        <th>#</th><th>Kategori Produk</th>
        <th style="text-align:right">Net Revenue</th>
        <th style="text-align:right">%</th>
        <th style="text-align:right">Orders</th>
        <th style="text-align:right">Units</th>
      </tr></thead>
      <tbody>${rows}</tbody>
      <tfoot>${tfoot}</tfoot>
    </table></div>`;
}

// ── INSIGHTS PRODUCTION RECO ──
let _insProdRows = null;   // raw per-SKU rows from get_production_reco
let _plnGroups = null;     // ip → { catLabel → [{name,units,variants}] }

function _plnCatLabel(raw) {
  if (!raw) return '(Lainnya)';
  return _CAT_NORM[raw] || raw.toLowerCase().replace(/\b\w/g, c=>c.toUpperCase());
}
function _plnStripSize(name) {
  const p = (name||'').split(' - ');
  return p.length > 2 ? p.slice(0,-1).join(' - ') : (name||'');
}

async function _loadPlannerData() {
  if (_plnGroups !== null) return;
  const rows = [];
  let from = 0;
  while (true) {
    const {data, error} = await sb.rpc('get_design_units').range(from, from+999);
    if (error) throw error;
    if (!data || !data.length) break;
    rows.push(...data);
    if (data.length < 1000) break;
    from += 1000;
  }
  _plnGroups = {};
  rows.forEach(r => {
    const ip = (r.ip||'').trim();
    if (!ip) return;
    const cat = _plnCatLabel((r.rawcat||'').trim());
    (_plnGroups[ip] = _plnGroups[ip] || {});
    (_plnGroups[ip][cat] = _plnGroups[ip][cat] || []).push({
      name: _plnStripSize(r.design_name), units: parseFloat(r.units||0)||0, variants: parseInt(r.variants||0)||0,
    });
  });
}

function _insPopulatePlanner() {
  const ipSel = document.getElementById('ins-pl-ip');
  if (!ipSel || !_plnGroups) return;
  // IPs sorted by total designs desc
  const ips = Object.keys(_plnGroups).sort((a,b)=>{
    const na = Object.values(_plnGroups[a]).reduce((s,arr)=>s+arr.length,0);
    const nb = Object.values(_plnGroups[b]).reduce((s,arr)=>s+arr.length,0);
    return nb-na;
  });
  const cur = ipSel.value;
  ipSel.innerHTML = ips.map(ip=>`<option value="${ip.replace(/"/g,'&quot;')}"${ip===cur?' selected':''}>${ip.replace(/</g,'&lt;')}</option>`).join('');
  if (!ips.includes(cur) && ips.length) ipSel.value = ips[0];
  _insPlannerIPChange();
}

function _insPlannerIPChange() {
  const ip = document.getElementById('ins-pl-ip')?.value;
  const catSel = document.getElementById('ins-pl-cat');
  if (!ip || !catSel || !_plnGroups || !_plnGroups[ip]) return;
  const cats = Object.keys(_plnGroups[ip]).sort((a,b)=>_plnGroups[ip][b].length - _plnGroups[ip][a].length);
  const cur = catSel.value;
  catSel.innerHTML = cats.map(c=>`<option value="${c.replace(/"/g,'&quot;')}"${c===cur?' selected':''}>${c.replace(/</g,'&lt;')} (${_plnGroups[ip][c].length})</option>`).join('');
  if (!cats.includes(cur) && cats.length) catSel.value = cats[0];
  _renderInsPlanner();
}

function _renderInsPlanner() {
  const box = document.getElementById('ins-pl-result');
  if (!box || !_plnGroups) return;
  const ip = document.getElementById('ins-pl-ip')?.value;
  const cat = document.getElementById('ins-pl-cat')?.value;
  const designs = (_plnGroups[ip]||{})[cat] || [];
  if (!designs.length) { box.innerHTML = `<div style="color:var(--g400);font-size:12px">Belum ada desain pembanding.</div>`; return; }

  const fmtN = n => Math.round(n).toLocaleString('id-ID');
  const units = designs.map(d=>d.units).sort((a,b)=>a-b);
  const pct = p => { const i = Math.min(units.length-1, Math.floor(p*(units.length-1))); return units[i]; };
  const median = units.length%2 ? units[(units.length-1)/2] : (units[units.length/2-1]+units[units.length/2])/2;
  const avg = units.reduce((s,n)=>s+n,0)/units.length;
  const p75 = pct(0.75);
  const avgVar = designs.reduce((s,d)=>s+d.variants,0)/designs.length;

  const card = (lbl,val,big,clr)=>`<div style="border:1px solid var(--g100);border-radius:8px;padding:12px 14px;background:var(--off);flex:1;min-width:120px">
    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;color:var(--g400);letter-spacing:.05em">${lbl}</div>
    <div style="font-size:${big?'24px':'16px'};font-weight:700;font-family:var(--head);margin-top:3px;color:${clr||'var(--black)'}">${val}</div>
  </div>`;

  const top = [...designs].sort((a,b)=>b.units-a.units).slice(0,15);
  box.innerHTML = `
    <div style="background:#eef0fb;border:1px solid #c7cdf0;border-radius:8px;padding:14px 16px;margin-bottom:14px">
      <div style="font-size:13px;color:var(--g600)">Kalau produksi <b>${ip.replace(/</g,'&lt;')} × ${cat.replace(/</g,'&lt;')}</b> baru, acuan produksi:</div>
      <div style="font-size:30px;font-weight:800;font-family:var(--head);color:#3C3489;margin-top:4px">${fmtN(median)} unit <span style="font-size:13px;font-weight:500;color:var(--g500)">(median per desain)</span></div>
      <div style="font-size:12px;color:var(--g500);margin-top:4px">≈ ${fmtN(median/Math.max(1,avgVar))} unit/varian · rata-rata ${avgVar.toFixed(1)} varian per desain</div>
    </div>
    <div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:16px">
      ${card('Median', fmtN(median)+' unit', true, '#3C3489')}
      ${card('Rata-rata', fmtN(avg)+' unit')}
      ${card('P75 (agresif)', fmtN(p75)+' unit')}
      ${card('Desain pembanding', fmtN(designs.length))}
    </div>
    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;color:var(--g400);letter-spacing:.05em;margin-bottom:6px">Desain pembanding (top 15 by units, lifetime)</div>
    <div class="table-wrap" style="margin:0;max-height:280px;overflow:auto"><table style="width:100%;border-collapse:collapse;font-size:12px">
      <thead><tr style="background:#f7f8fa;border-bottom:1px solid var(--g200)">
        <th style="padding:6px 10px;text-align:left;font-weight:600">Desain</th>
        <th style="padding:6px 10px;text-align:right;font-weight:600">Varian</th>
        <th style="padding:6px 10px;text-align:right;font-weight:600">Total Unit</th>
      </tr></thead><tbody>
      ${top.map(d=>`<tr style="border-bottom:1px solid var(--g100)">
        <td style="padding:6px 10px">${_esc(d.name)}</td>
        <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px;color:var(--g500)">${d.variants}</td>
        <td style="padding:6px 10px;text-align:right;font-family:var(--mono);font-size:11px;font-weight:600">${fmtN(d.units)}</td>
      </tr>`).join('')}
      </tbody></table></div>`;
}

async function _renderInsProd() {
  // Planner (new-product benchmark) — load once
  if (_plnGroups === null) {
    const plBox = document.getElementById('ins-pl-result');
    if (plBox) plBox.innerHTML = `<div style="color:var(--g400);font-size:12px">Memuat pola desain…</div>`;
    try { await _loadPlannerData(); _insPopulatePlanner(); }
    catch(e){ console.error('planner:',e); if(plBox) plBox.innerHTML=`<div style="color:#c0392b;font-size:12px">Gagal memuat planner: ${e.message||e}</div>`; }
  }
  const wrap = document.getElementById('ins-prod-wrap');
  if (!wrap) return;
  if (_insProdRows === null) {
    wrap.innerHTML = `<div style="padding:2rem;text-align:center;color:var(--g400);font-family:var(--mono);font-size:12px">Menghitung demand 12 bulan & stok…</div>`;
    try {
      const rows = [];
      let from = 0;
      while (true) {
        const {data, error} = await sb.rpc('get_production_reco').range(from, from+999);
        if (error) throw error;
        if (!data || !data.length) break;
        rows.push(...data);
        if (data.length < 1000) break;
        from += 1000;
      }
      _insProdRows = rows.map(r => ({
        itemId: r.item_id, code: r.item_code||'', name: r.item_name||r.item_code||String(r.item_id),
        ip: r.ip||'', brand: r.brand||'',
        units: parseFloat(r.units_12mo||0)||0, stock: parseFloat(r.stock||0)||0,
      }));
    } catch(e) {
      console.error('get_production_reco:', e);
      wrap.innerHTML = `<div style="padding:1.5rem;color:#c0392b;font-size:12px">Gagal memuat: ${e.message||e}</div>`;
      return;
    }
  }
  _renderInsProdTable();
}

function _renderInsProdTable() {
  const wrap = document.getElementById('ins-prod-wrap');
  if (!wrap || !_insProdRows) return;
  const fmtN = n => Math.round(n).toLocaleString('id-ID');
  const coverage = Math.max(1, parseFloat(document.getElementById('ins-p-coverage')?.value || 3) || 3);
  const search = (document.getElementById('ins-p-search')?.value || '').trim().toLowerCase();
  const onlyNeed = document.getElementById('ins-p-onlyneed')?.checked;

  // Compute recommendation per SKU
  let rows = _insProdRows.map(r => {
    const avgMonth = r.units / 12;
    const avgDaily = r.units / 365;
    const runway = avgDaily > 0 ? r.stock / avgDaily : (r.stock > 0 ? Infinity : 0);
    const target = avgMonth * coverage;
    const reco = Math.max(0, Math.round(target - r.stock));
    return {...r, avgMonth, runway, reco};
  });

  // Stats (pre-filter, full set)
  const needRows = rows.filter(r => r.reco > 0);
  const urgent = rows.filter(r => r.runway < 30).length;
  const totalReco = needRows.reduce((s,r)=>s+r.reco, 0);
  document.getElementById('ins-p-need').textContent   = fmtN(needRows.length);
  document.getElementById('ins-p-units').textContent  = fmtN(totalReco);
  document.getElementById('ins-p-urgent').textContent = fmtN(urgent);
  document.getElementById('ins-p-ok').textContent     = fmtN(rows.length - needRows.length);

  // Filters
  if (onlyNeed) rows = rows.filter(r => r.reco > 0);
  if (search) rows = rows.filter(r => r.name.toLowerCase().includes(search) || r.ip.toLowerCase().includes(search) || r.code.toLowerCase().includes(search));
  rows.sort((a,b) => b.reco - a.reco || a.runway - b.runway);

  const runwayCell = rw => {
    if (rw === Infinity) return `<span style="color:#2d7a2d">∞</span>`;
    const c = rw < 30 ? '#c0392b' : rw < 60 ? '#e65100' : rw < 90 ? '#b8860b' : '#2d7a2d';
    return `<span style="color:${c};font-weight:600">${Math.round(rw)}d</span>`;
  };

  const body = rows.slice(0, 800).map(r => `<tr style="border-bottom:1px solid var(--g100)">
    <td style="padding:7px 10px;font-size:12px">${_esc(r.name)}${r.ip?` <span style="color:var(--g400);font-size:10px">· ${_esc(r.ip)}</span>`:''}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${fmtN(r.units)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${r.avgMonth.toFixed(1)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${fmtN(r.stock)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:11px">${runwayCell(r.runway)}</td>
    <td style="padding:7px 10px;text-align:right;font-family:var(--mono);font-size:13px;font-weight:700;color:${r.reco>0?'#3C3489':'var(--g300)'}">${r.reco>0?'+'+fmtN(r.reco):'—'}</td>
  </tr>`).join('');

  wrap.innerHTML = `<div class="table-wrap" style="margin:0;overflow-x:auto">
    <table style="width:100%;border-collapse:collapse;font-size:12px">
      <thead><tr style="background:#f7f8fa;border-bottom:2px solid var(--g200)">
        <th style="padding:8px 10px;text-align:left;font-weight:600">SKU</th>
        <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Terjual 12bln</th>
        <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Avg/bln</th>
        <th style="padding:8px 10px;text-align:right;font-weight:600">Stok</th>
        <th style="padding:8px 10px;text-align:right;font-weight:600">Runway</th>
        <th style="padding:8px 10px;text-align:right;font-weight:600;white-space:nowrap">Produksi</th>
      </tr></thead>
      <tbody>${body || `<tr><td colspan="6" style="padding:24px;text-align:center;color:var(--g400)">Tidak ada SKU cocok filter.</td></tr>`}</tbody>
    </table></div>
    ${rows.length>800?`<div style="font-size:11px;color:var(--g400);padding:8px 4px">Menampilkan 800 dari ${fmtN(rows.length)} SKU. Pakai search untuk mempersempit.</div>`:''}`;
}

