function _insGeoMetric(val) {
  _insGeoMetricVal = val;
  if (_insData) _renderInsGeo();
}

async function _renderInsGeo() {
  const d = _insData;
  if (!d || !d.geoRaw) return;

  const fmtRp = n => n>=1e9?'Rp '+(n/1e9).toFixed(1)+'M':n>=1e6?'Rp '+(n/1e6).toFixed(1)+'jt':'Rp '+Math.round(n).toLocaleString('id-ID');
  const titl = s => (s||'').toLowerCase().replace(/\b\w/g,c=>c.toUpperCase());
  const _se = (id,v) => { const e=document.getElementById(id); if(e) e.textContent=v; };
  const metric = _insGeoMetricVal;

  // Populate filter dropdown (only once — don't overwrite if already built)
  const filterSel = document.getElementById('ins-geo-filter');
  if (filterSel && filterSel.options.length <= 1) {
    const ips    = Object.keys(d.ipToOrderIds||{}).sort();
    const brands = Object.keys(d.brandToOrderIds||{}).sort();
    if (ips.length) {
      const grp = document.createElement('optgroup'); grp.label = 'Per IP';
      ips.forEach(ip => { const o=document.createElement('option'); o.value='ip:'+ip; o.textContent=ip; grp.appendChild(o); });
      filterSel.appendChild(grp);
    }
    if (brands.length) {
      const grp = document.createElement('optgroup'); grp.label = 'Per Brand';
      brands.forEach(br => { const o=document.createElement('option'); o.value='brand:'+br; o.textContent=br; grp.appendChild(o); });
      filterSel.appendChild(grp);
    }
  }

  // Determine which geoRaw rows to use based on filter
  const filterVal = filterSel?.value || '';
  let filteredRaw = d.geoRaw;
  let filterLabel = 'Semua';
  if (filterVal.startsWith('ip:')) {
    const name = filterVal.slice(3);
    const ids = d.ipToOrderIds[name] || new Set();
    filteredRaw = d.geoRaw.filter(r => ids.has(r.salesorder_id));
    filterLabel = 'IP: ' + name;
  } else if (filterVal.startsWith('brand:')) {
    const name = filterVal.slice(6);
    const ids = d.brandToOrderIds[name] || new Set();
    filteredRaw = d.geoRaw.filter(r => ids.has(r.salesorder_id));
    filterLabel = 'Brand: ' + name;
  }

  // Re-aggregate for current filter
  const {geoProvinces, geoCities, geoIntl, geoTotal} = _aggregateGeo(filteredRaw);

  // Stats
  _se('ins-g-provinces', geoProvinces.length);
  _se('ins-g-top-prov',  geoProvinces[0] ? titl(geoProvinces[0].prov) : '—');
  _se('ins-g-top-city',  geoCities[0]    ? titl(geoCities[0].city)    : '—');
  const idOrders = geoProvinces.reduce((s,p)=>s+p.orders,0);
  const covPct = geoTotal ? Math.round(idOrders/geoTotal*100) : 0;
  const intlTotal = (geoIntl||[]).reduce((s,c)=>s+c.orders,0);
  const intlLabel = intlTotal>0
    ? ` · ${intlTotal} luar negeri (${(geoIntl||[]).map(c=>c.country).join(', ')})`
    : '';
  _se('ins-g-coverage', `${filterLabel} · ${idOrders} orders · ${covPct}% punya data geo${intlLabel}`);

  // Province ranking table
  const provTbody = document.getElementById('ins-g-prov-tbody');
  if (provTbody) provTbody.innerHTML = geoProvinces.slice(0,18).map((p,i)=>`
    <tr>
      <td style="font-size:12px">${i+1}. ${titl(p.prov)}</td>
      <td style="text-align:right;font-weight:600;font-family:var(--mono);font-size:11px">${p.orders.toLocaleString('id-ID')}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${fmtRp(p.revenue)}</td>
    </tr>`).join('') || '<tr><td class="empty-td" colspan="3">Tidak ada data</td></tr>';

  // City ranking table
  const cityTbody = document.getElementById('ins-g-city-tbody');
  if (cityTbody) cityTbody.innerHTML = geoCities.slice(0,18).map((c,i)=>`
    <tr>
      <td style="font-size:12px">${i+1}. ${titl(c.city)}</td>
      <td style="font-size:11px;color:var(--g400)">${titl(c.prov)}</td>
      <td style="text-align:right;font-weight:600;font-family:var(--mono);font-size:11px">${c.orders.toLocaleString('id-ID')}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${fmtRp(c.revenue)}</td>
    </tr>`).join('') || '<tr><td class="empty-td" colspan="4">Tidak ada data</td></tr>';

  // International orders section
  const intlWrap = document.getElementById('ins-g-intl-wrap');
  if (intlWrap && geoIntl && geoIntl.length) {
    intlWrap.innerHTML = `
      <div style="font-family:var(--mono);font-size:11px;text-transform:uppercase;color:var(--g400);margin-bottom:8px;letter-spacing:.05em">🌏 International Orders</div>
      <div class="table-wrap" style="margin:0"><table style="width:100%;table-layout:fixed">
        <colgroup><col style="width:auto"><col style="width:70px"><col style="width:120px"></colgroup>
        <thead><tr><th>Negara</th><th style="text-align:right">Orders</th><th style="text-align:right">Revenue</th></tr></thead>
        <tbody>${geoIntl.map(c=>`
          <tr>
            <td style="font-size:12px">${c.country}</td>
            <td style="text-align:right;font-weight:600;font-family:var(--mono);font-size:11px">${c.orders}</td>
            <td style="text-align:right;font-family:var(--mono);font-size:11px;color:var(--g400)">${fmtRp(c.revenue)}</td>
          </tr>`).join('')}
        </tbody>
      </table></div>`;
    intlWrap.style.display = 'block';
  } else if (intlWrap) { intlWrap.style.display = 'none'; }

  // Map
  const mapEl = document.getElementById('ins-geo-map');
  if (!mapEl || typeof L === 'undefined') return;

  // Destroy existing instance
  if (_insGeoMap) { try { _insGeoMap.remove(); } catch(e){} _insGeoMap = null; }

  _insGeoMap = L.map('ins-geo-map', {
    center: [-2.5, 118], zoom: 5,
    zoomControl: true, attributionControl: false
  });
  L.tileLayer('https://{s}.basemaps.cartocdn.com/light_nolabels/{z}/{x}/{y}{r}.png',
    {subdomains:'abcd',maxZoom:19}).addTo(_insGeoMap);

  // Province choropleth
  const provDataMap = {};
  geoProvinces.forEach(p => { provDataMap[p.prov] = p; });
  const maxVal = metric==='orders'
    ? Math.max(...geoProvinces.map(p=>p.orders),1)
    : Math.max(...geoProvinces.map(p=>p.revenue),1);

  try {
    const resp = await fetch('https://raw.githubusercontent.com/superpikar/indonesia-geojson/master/indonesia-province-simple.json');
    const geojson = await resp.json();
    L.geoJSON(geojson, {
      style: feature => {
        const provName = (feature.properties.Propinsi||feature.properties.name||'').toUpperCase();
        const pd = provDataMap[provName];
        const val = pd ? (metric==='orders'?pd.orders:pd.revenue) : 0;
        const t = maxVal>0 ? val/maxVal : 0;
        return {
          fillColor: `rgba(60,52,137,${(0.1+t*0.8).toFixed(2)})`,
          fillOpacity:1, color:'#3C3489', weight:0.8, opacity:0.5
        };
      },
      onEachFeature: (feature, layer) => {
        const provName = (feature.properties.Propinsi||feature.properties.name||'').toUpperCase();
        const pd = provDataMap[provName];
        const lbl = pd
          ? `<b>${titl(provName)}</b><br>${pd.orders} orders<br>${fmtRp(pd.revenue)}`
          : `<b>${titl(provName)}</b><br><span style="color:#aaa">No data</span>`;
        layer.bindTooltip(lbl, {sticky:true, className:'ins-geo-tip'});
      }
    }).addTo(_insGeoMap);
  } catch(e) { console.warn('GeoJSON failed:', e); }

  // City circles
  const maxCityVal = geoCities.length ? Math.max(...geoCities.map(c=>metric==='orders'?c.orders:c.revenue),1) : 1;
  geoCities.slice(0,60).forEach(c => {
    const coords = _INS_CITY_COORDS[c.city];
    if (!coords) return;
    const val = metric==='orders' ? c.orders : c.revenue;
    const r = 5 + (val/maxCityVal)*22;
    L.circleMarker(coords, {
      radius:r, fillColor:'#e74c3c', fillOpacity:0.75, color:'#c0392b', weight:1
    }).addTo(_insGeoMap)
    .bindTooltip(`<b>${titl(c.city)}</b>, ${titl(c.prov)}<br>${c.orders} orders · ${fmtRp(c.revenue)}`,
      {sticky:true, className:'ins-geo-tip'});
  });
}

// ── MARTE SETTLEMENTS ──
const MST_CATS   = ['Apparel','Accessories','Collectible','Preloved','Wellness','Others'];
const MST_CATKEY = {Apparel:'apparel_rate',Accessories:'accessories_rate',Collectible:'collectible_rate',Preloved:'preloved_rate',Wellness:'wellness_rate',Others:'others_rate'};
const MST_STATUS_CLASS = {Draft:'p-draft',Sent:'p-signings',Invoiced:'p-review',Settled:'p-active'};
const MST_INV_CLASS    = {Draft:'p-draft',Sent:'p-signings',Paid:'p-active'};

let allMarteSettlements = [], _mstItems = [], _mstTid = 0, _mstEditId = null, _mstBrandRow = null;

function _mstRp(n) { return 'Rp'+Math.round(n||0).toLocaleString('id-ID'); }

async function loadMarteSettlements() {
  if (!allBMRows.length) await loadBrandMaster();
  setupAC('mst-brand','ac-mst-brand', ()=>allBMRows.map(r=>r.name).filter(Boolean));
  const {data,error} = await sb.from('marte_settlements').select('*').order('period',{ascending:false}).order('brand_name');
  if (error) { console.error(error); return; }
  allMarteSettlements = data||[];
  _renderMSTStats();
  renderMSTTable();
}

function _renderMSTStats() {
  const now = new Date().toISOString().slice(0,7);
  document.getElementById('mst-s-total').textContent   = allMarteSettlements.length;
  document.getElementById('mst-s-sales').textContent   = _mstRp(allMarteSettlements.filter(r=>r.period===now).reduce((s,r)=>s+parseFloat(r.total_sales||0),0));
  document.getElementById('mst-s-pending').textContent = allMarteSettlements.filter(r=>r.status!=='Settled').length;
  document.getElementById('mst-s-settled').textContent = allMarteSettlements.filter(r=>r.status==='Settled').length;
}

function switchMSTTab(tab, btn) {
  document.querySelectorAll('#page-marte .tab-btn').forEach(b=>b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  document.getElementById('msttab-new').style.display  = tab==='new'  ? '' : 'none';
  document.getElementById('msttab-list').style.display = tab==='list' ? '' : 'none';
}

function renderMSTTable() {
  const st  = (document.getElementById('mst-fil-status')||{}).value||'';
  const srch= ((document.getElementById('mst-fil-search')||{}).value||'').toLowerCase();
  let list  = allMarteSettlements;
  if (st)   list = list.filter(r=>r.status===st);
  if (srch) list = list.filter(r=>(r.brand_name+r.period).toLowerCase().includes(srch));

  document.getElementById('mst-tcount').textContent = list.length+' entri';
  const tb = document.getElementById('mst-tbody');
  if (!list.length) { tb.innerHTML=`<tr><td colspan="9" style="padding:24px;text-align:center;color:var(--g400)">Belum ada data.</td></tr>`; return; }

  tb.innerHTML = list.map(r=>`
<tr>
  <td style="font-family:var(--mono);font-weight:600">${r.period}</td>
  <td>${_escRmd(r.brand_name)}</td>
  <td><span class="pill ${r.brand_type==='PT'?'p-signings':'p-draft'}" style="font-size:10px">${r.brand_type}</span></td>
  <td style="text-align:right;font-family:var(--mono);font-size:12px">${_mstRp(r.total_sales)}</td>
  <td style="text-align:right;font-family:var(--mono);font-size:12px;font-weight:600">${_mstRp(r.net_to_brand)}</td>
  <td><span class="pill ${MST_STATUS_CLASS[r.status]||'p-draft'}">${r.status}</span></td>
  <td>${r.invoice_number?`<span style="font-family:var(--mono);font-size:11px">${_escRmd(r.invoice_number)}</span><br><span class="pill ${MST_INV_CLASS[r.invoice_status]||'p-draft'}" style="font-size:9px">${r.invoice_status}</span>`:'<span style="color:var(--g400);font-size:11px">—</span>'}</td>
  <td>${r.debit_note_number?`<span style="font-family:var(--mono);font-size:11px">${_escRmd(r.debit_note_number)}</span>`:'<span style="color:var(--g400);font-size:11px">—</span>'}</td>
  <td>
    <button class="btn-edit" onclick="openMSTEdit('${r.id}')">Edit</button>
    <button class="btn-del" onclick="deleteMSTEntry('${r.id}')">Hapus</button>
  </td>
</tr>`).join('');
}

// ── MST Form helpers ──
function mstBrandInput() {
  const name = (document.getElementById('mst-brand').value||'').trim();
  _mstBrandRow = allBMRows.find(r=>r.name===name)||null;
  // Re-apply rates to existing items if brand changed
  if (_mstBrandRow) _mstItems.forEach(it=>{ it.consign_fee_rate=_mstGetRate(it.category); _mstCalcItem(it); });
  _mstRenderItems();
}

function _mstGetRate(category) {
  if (!_mstBrandRow) return 0;
  return parseFloat(_mstBrandRow[MST_CATKEY[category]]||0);
}

function mstAddItem() {
  const tid = ++_mstTid;
  const cat = 'Apparel';
  const rate = _mstGetRate(cat);
  _mstItems.push({tid, sku_id:'', item_description:'', category:cat, qty_sold:0, total_sales:0, consign_fee_rate:rate, consign_fee_amount:0, net_receive:0});
  document.getElementById('mst-items-empty').style.display='none';
  _mstRenderItems();
}

function mstRemoveItem(tid) {
  _mstItems = _mstItems.filter(it=>it.tid!==tid);
  _mstRenderItems();
  mstRecalcSummary();
}

function mstItemChange(tid, field, value) {
  const it = _mstItems.find(x=>x.tid===tid);
  if (!it) return;
  it[field] = (field==='qty_sold'||field==='total_sales'||field==='consign_fee_rate') ? parseFloat(value)||0 : value;
  if (field==='category') { it.consign_fee_rate=_mstGetRate(value); document.getElementById(`mst-ir-rate-${tid}`).value=it.consign_fee_rate; }
  _mstCalcItem(it);
  document.getElementById(`mst-ir-fee-${tid}`).textContent  = _mstRp(it.consign_fee_amount);
  document.getElementById(`mst-ir-net-${tid}`).textContent  = _mstRp(it.net_receive);
  mstRecalcSummary();
}

function _mstCalcItem(it) {
  it.consign_fee_amount = it.total_sales * (it.consign_fee_rate/100);
  it.net_receive        = it.total_sales - it.consign_fee_amount;
}

function _mstRenderItems() {
  const tbody = document.getElementById('mst-items-body');
  const foot  = document.getElementById('mst-items-foot');
  const empty = document.getElementById('mst-items-empty');
  if (!_mstItems.length) { empty.style.display=''; foot.style.display='none'; tbody.innerHTML=''; tbody.appendChild(empty); mstRecalcSummary(); return; }
  empty.style.display='none';
  foot.style.display='';
  const catOpts = MST_CATS.map(c=>`<option value="${c}">${c}</option>`).join('');
  const rows = _mstItems.map(it=>`
<tr id="mst-item-${it.tid}" style="border-bottom:1px solid var(--g100)">
  <td style="padding:6px 8px"><input value="${_escRmd(it.sku_id)}" oninput="mstItemChange(${it.tid},'sku_id',this.value)" style="width:100%;min-width:130px;font-size:12px;padding:4px 7px"></td>
  <td style="padding:6px 8px"><input value="${_escRmd(it.item_description)}" oninput="mstItemChange(${it.tid},'item_description',this.value)" style="width:100%;min-width:180px;font-size:12px;padding:4px 7px"></td>
  <td style="padding:6px 8px"><select onchange="mstItemChange(${it.tid},'category',this.value)" style="font-size:12px;padding:4px 7px;width:100%">${MST_CATS.map(c=>`<option value="${c}"${c===it.category?' selected':''}>${c}</option>`).join('')}</select></td>
  <td style="padding:6px 8px"><input type="number" min="0" value="${it.qty_sold}" oninput="mstItemChange(${it.tid},'qty_sold',this.value)" style="width:60px;text-align:right;font-size:12px;padding:4px 7px"></td>
  <td style="padding:6px 8px"><input type="number" min="0" id="mst-ir-sales-${it.tid}" value="${it.total_sales}" oninput="mstItemChange(${it.tid},'total_sales',this.value)" style="width:110px;text-align:right;font-family:var(--mono);font-size:12px;padding:4px 7px"></td>
  <td style="padding:6px 8px"><input type="number" min="0" max="100" id="mst-ir-rate-${it.tid}" value="${it.consign_fee_rate}" oninput="mstItemChange(${it.tid},'consign_fee_rate',this.value)" style="width:55px;text-align:right;font-size:12px;padding:4px 7px"></td>
  <td style="padding:6px 8px;text-align:right;font-family:var(--mono);font-size:12px;color:#c0392b;white-space:nowrap" id="mst-ir-fee-${it.tid}">${_mstRp(it.consign_fee_amount)}</td>
  <td style="padding:6px 8px;text-align:right;font-family:var(--mono);font-size:12px;font-weight:600;white-space:nowrap" id="mst-ir-net-${it.tid}">${_mstRp(it.net_receive)}</td>
  <td style="padding:6px 8px;text-align:center"><button onclick="mstRemoveItem(${it.tid})" style="background:none;border:none;cursor:pointer;color:var(--g400);font-size:14px;padding:2px 4px">✕</button></td>
</tr>`);
  tbody.innerHTML = rows.join('');
  tbody.appendChild(empty);
  mstRecalcSummary();
}

function mstRecalcSummary() {
  const totSales = _mstItems.reduce((s,it)=>s+it.total_sales,0);
  const totFee   = _mstItems.reduce((s,it)=>s+it.consign_fee_amount,0);
  const isPT     = (document.getElementById('mst-brand-type')||{}).value==='PT';
  const pph      = isPT ? totFee*0.02 : 0;
  const net      = totSales - totFee + pph;

  const sum = document.getElementById('mst-summary');
  const foot= document.getElementById('mst-items-foot');
  if (_mstItems.length) {
    sum.style.display=''; foot.style.display='';
  } else {
    sum.style.display='none'; foot.style.display='none';
  }

  const pphCol = document.getElementById('mst-sum-pph-col');
  if (pphCol) pphCol.style.display = isPT ? '' : 'none';

  _mstSetEl('mst-foot-sales', _mstRp(totSales));
  _mstSetEl('mst-foot-fee',   _mstRp(totFee));
  _mstSetEl('mst-foot-net',   _mstRp(net));
  _mstSetEl('mst-sum-sales',  _mstRp(totSales));
  _mstSetEl('mst-sum-fee',    '−'+_mstRp(totFee));
  _mstSetEl('mst-sum-pph',    '+'+_mstRp(pph));
  _mstSetEl('mst-sum-net',    _mstRp(net));
}
function _mstSetEl(id, v) { const el=document.getElementById(id); if(el) el.textContent=v; }

function clearMSTForm() {
  _mstEditId=null; _mstItems=[]; _mstTid=0; _mstBrandRow=null;
  ['mst-brand','mst-period','mst-from','mst-to','mst-report-date','mst-report-link','mst-inv-num','mst-inv-date','mst-dn-num','mst-dn-date','mst-notes'].forEach(id=>{const el=document.getElementById(id);if(el)el.value='';});
  document.getElementById('mst-brand-type').value='PT';
  document.getElementById('mst-inv-status').value='Draft';
  document.getElementById('mst-status').value='Draft';
  _mstRenderItems();
  const fb=document.getElementById('mst-feedback'); if(fb)fb.textContent='';
  const btn=document.getElementById('mst-submit-btn'); if(btn)btn.textContent='Simpan Settlement';
}

async function openMSTEdit(id) {
  const r = allMarteSettlements.find(x=>x.id===id);
  if (!r) return;
  _mstEditId = id;
  _mstBrandRow = allBMRows.find(x=>x.name===r.brand_name)||null;

  document.getElementById('mst-brand').value       = r.brand_name;
  document.getElementById('mst-period').value      = r.period;
  document.getElementById('mst-from').value        = r.date_range_from||'';
  document.getElementById('mst-to').value          = r.date_range_to||'';
  document.getElementById('mst-report-date').value = r.report_date||'';
  document.getElementById('mst-brand-type').value  = r.brand_type||'PT';
  document.getElementById('mst-report-link').value = r.report_link||'';
  document.getElementById('mst-inv-num').value     = r.invoice_number||'';
  document.getElementById('mst-inv-date').value    = r.invoice_date||'';
  document.getElementById('mst-inv-status').value  = r.invoice_status||'Draft';
  document.getElementById('mst-dn-num').value      = r.debit_note_number||'';
  document.getElementById('mst-dn-date').value     = r.debit_note_date||'';
  document.getElementById('mst-status').value      = r.status||'Draft';
  document.getElementById('mst-notes').value       = r.notes||'';

  // Load items
  const {data:items} = await sb.from('marte_settlement_items').select('*').eq('settlement_id',id).order('id');
  _mstItems = (items||[]).map(it=>({tid:++_mstTid, sku_id:it.sku_id, item_description:it.item_description, category:it.category, qty_sold:it.qty_sold, total_sales:parseFloat(it.total_sales), consign_fee_rate:parseFloat(it.consign_fee_rate), consign_fee_amount:parseFloat(it.consign_fee_amount), net_receive:parseFloat(it.net_receive)}));
  _mstRenderItems();

  const btn=document.getElementById('mst-submit-btn'); if(btn)btn.textContent='Simpan Perubahan';
  switchMSTTab('new', document.getElementById('mst-tab-new-btn'));
  document.querySelector('#page-marte').scrollIntoView({behavior:'smooth',block:'start'});
}

async function saveMarteSettlement() {
  const brand  = (document.getElementById('mst-brand').value||'').trim();
  const period = (document.getElementById('mst-period').value||'').trim();
  const fb = document.getElementById('mst-feedback');
  if (!brand||!period) { fb.textContent='⚠ Brand dan Periode wajib diisi.'; fb.style.color='#e74c3c'; return; }
  if (!_mstItems.length) { fb.textContent='⚠ Tambahkan minimal 1 item terjual.'; fb.style.color='#e74c3c'; return; }

  const btn=document.getElementById('mst-submit-btn');
  btn.disabled=true; btn.textContent='Menyimpan...';

  const bmRow   = allBMRows.find(r=>r.name===brand);
  const isPT    = document.getElementById('mst-brand-type').value==='PT';
  const totSales= _mstItems.reduce((s,it)=>s+it.total_sales,0);
  const totFee  = _mstItems.reduce((s,it)=>s+it.consign_fee_amount,0);
  const pph     = isPT ? totFee*0.02 : 0;
  const net     = totSales - totFee + pph;

  const hdr = {
    brand_id: bmRow?bmRow.id:'', brand_name: brand,
    period, brand_type: document.getElementById('mst-brand-type').value,
    date_range_from: document.getElementById('mst-from').value||null,
    date_range_to:   document.getElementById('mst-to').value||null,
    report_date:     document.getElementById('mst-report-date').value||null,
    total_sales:totSales, consign_fee:totFee, pph_23:pph, net_to_brand:net,
    invoice_number:  document.getElementById('mst-inv-num').value.trim(),
    invoice_date:    document.getElementById('mst-inv-date').value||null,
    invoice_status:  document.getElementById('mst-inv-status').value,
    debit_note_number: document.getElementById('mst-dn-num').value.trim(),
    debit_note_date: document.getElementById('mst-dn-date').value||null,
    status:          document.getElementById('mst-status').value,
    report_link:     document.getElementById('mst-report-link').value.trim(),
    notes:           document.getElementById('mst-notes').value.trim(),
    created_by:      currentUser,
    updated_at:      new Date().toISOString(),
  };

  let sid = _mstEditId;
  let error;
  if (sid) {
    ({error} = await sb.from('marte_settlements').update(hdr).eq('id',sid));
  } else {
    sid = genId('MST');
    hdr.id = sid; hdr.created_at = new Date().toISOString();
    ({error} = await sb.from('marte_settlements').insert(hdr));
  }
  if (error) { btn.disabled=false; btn.textContent=_mstEditId?'Simpan Perubahan':'Simpan Settlement'; fb.textContent='⚠ '+error.message; fb.style.color='#e74c3c'; return; }

  // Replace items
  await sb.from('marte_settlement_items').delete().eq('settlement_id',sid);
  const itemPayload = _mstItems.map(it=>({settlement_id:sid, sku_id:it.sku_id, item_description:it.item_description, category:it.category, qty_sold:it.qty_sold, total_sales:it.total_sales, consign_fee_rate:it.consign_fee_rate, consign_fee_amount:it.consign_fee_amount, net_receive:it.net_receive}));
  if (itemPayload.length) await sb.from('marte_settlement_items').insert(itemPayload);

  btn.disabled=false;
  fb.textContent='✓ Settlement berhasil disimpan!'; fb.style.color='#27ae60';
  setTimeout(()=>{ clearMSTForm(); switchMSTTab('list',document.getElementById('mst-tab-list-btn')); },800);
  await loadMarteSettlements();
}

async function deleteMSTEntry(id) {
  if (!confirm('Hapus settlement ini? Data item juga akan ikut terhapus.')) return;
  await sb.from('marte_settlements').delete().eq('id',id);
  allMarteSettlements = allMarteSettlements.filter(r=>r.id!==id);
  _renderMSTStats(); renderMSTTable();
}

// ── ANNOUNCEMENTS ──
async function loadAnnTicker() {
  const ticker = document.getElementById('ann-ticker');
  const track  = document.getElementById('ann-ticker-track');
  if (!ticker || !track) return;
  const {data} = await sb.from('announcements').select('id,title,body,category').eq('pinned',true).order('created_at',{ascending:false}).limit(10);
  if (!data || !data.length) {
    ticker.style.display = 'none';
    document.documentElement.style.setProperty('--ticker-h','0px');
    return;
  }
  const cats = {Info:{e:'📢'},Update:{e:'🔄'},Reminder:{e:'⏰'},Celebration:{e:'🎉'}};
  const items = data.map(a=>{
    const e   = (cats[a.category]||cats.Info).e;
    const ttl = (a.title||'').trim();
    const bod = (a.body||'').replace(/\n/g,' ').trim();
    const txt = ttl && bod ? `<strong style="font-weight:600">${ttl}</strong><span style="opacity:.55"> — </span>${bod}` : `<strong style="font-weight:600">${ttl||bod}</strong>`;
    return `<span style="color:rgba(255,255,255,0.88);font-size:13px;padding:0 40px 0 0;display:inline-flex;align-items:center;gap:7px">${e} <span>${txt}</span></span><span style="color:rgba(255,255,255,0.15);padding:0 40px 0 0;font-size:18px;line-height:1">·</span>`;
  }).join('');
  track.innerHTML = items + items;
  const totalChars = data.reduce((s,a)=>s+(a.title||'').length+(a.body||'').slice(0,80).length,0);
  const dur = Math.max(16, Math.min(70, totalChars * 0.22));
  track.style.animation = `ticker-scroll ${dur}s linear infinite`;
  ticker.style.display = 'flex';
  document.documentElement.style.setProperty('--ticker-h','34px');
}

const ANN_CAT = {
  'Info':        {emoji:'📢', bg:'#e8f0fc', border:'#a8c4f0', label:'Info'},
  'Update':      {emoji:'🔄', bg:'#fef9c3', border:'#fde047', label:'Update'},
  'Reminder':    {emoji:'⏰', bg:'#ffedd5', border:'#fdba74', label:'Reminder'},
  'Celebration': {emoji:'🎉', bg:'#fce7f3', border:'#f9a8d4', label:'Celebration'},
};

let allAnnouncements = [], annReactions = {}; // annReactions: {ann_id: [{user_email,user_name,emoji}]}
let _annTab = 'all', _annEditId = null;
let _annMentions = [], _annACSetup = false;

async function loadAnnouncements() {
  if (!portalUsers.length) await loadPortalUsers();
  if (!_annACSetup) { _annSetupMentionAC(); _annACSetup = true; }

  const [{data: posts}, {data: reacts}] = await Promise.all([
    sb.from('announcements').select('*').order('pinned',{ascending:false}).order('created_at',{ascending:false}),
    sb.from('announcement_reactions').select('announcement_id,user_email,user_name,emoji'),
  ]);
  allAnnouncements = posts || [];
  // Group reactions by announcement_id
  annReactions = {};
  for (const r of (reacts||[])) {
    if (!annReactions[r.announcement_id]) annReactions[r.announcement_id] = [];
    annReactions[r.announcement_id].push(r);
  }
  _renderAnnStats();
  _renderAnnFeed();
}

function _renderAnnStats() {
  document.getElementById('ann-s-total').textContent       = allAnnouncements.length;
  document.getElementById('ann-s-info').textContent        = allAnnouncements.filter(a=>a.category==='Info'||a.category==='Update').length;
  document.getElementById('ann-s-reminder').textContent    = allAnnouncements.filter(a=>a.category==='Reminder').length;
  document.getElementById('ann-s-celebration').textContent = allAnnouncements.filter(a=>a.category==='Celebration').length;
}

function switchAnnTab(tab, btn) {
  _annTab = tab;
  document.querySelectorAll('#page-announcements .tab-btn').forEach(b=>b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  _renderAnnFeed();
}

function _renderAnnFeed() {
  const feed = document.getElementById('ann-feed');
  if (!feed) return;

  let list = allAnnouncements;
  if (_annTab==='pinned') list = allAnnouncements.filter(a=>a.pinned);
  else if (_annTab==='mine') list = allAnnouncements.filter(a=>a.created_by===currentUserEmail);

  if (!list.length) {
    const msgs = {all:'Belum ada announcement. Klik "+ Post" untuk mulai!', pinned:'Belum ada post yang di-pin.', mine:'Kamu belum pernah post.'};
    feed.innerHTML = `<div style="color:var(--g400);font-size:14px;padding:2rem 0">${msgs[_annTab]||''}</div>`;
    return;
  }

  feed.innerHTML = list.map(a => {
    const cat   = ANN_CAT[a.category] || ANN_CAT['Info'];
    const reacts= annReactions[a.id] || [];
    const mentionChips = a.mentions
      ? a.mentions.split(',').map(m=>m.trim()).filter(Boolean)
          .map(m=>`<span style="display:inline-block;background:rgba(0,0,0,0.06);border-radius:10px;padding:1px 8px;font-size:12px;font-family:var(--mono)">@${_escRmd(m)}</span>`).join(' ')
      : '';
    const bodyHtml = (a.body||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>').replace(/(https?:\/\/[^\s<]+)/g,'<a href="$1" target="_blank" rel="noopener" style="color:#1a4a8a;text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">$1</a>');
    const canEdit  = a.created_by===currentUserEmail;
    const pinBadge = a.pinned ? '<span style="font-size:11px;margin-right:4px">📌</span>' : '';

    // Reaction summary: count per emoji
    const emojiCounts = {};
    for (const r of reacts) emojiCounts[r.emoji] = (emojiCounts[r.emoji]||0)+1;
    const myReacts = new Set(reacts.filter(r=>r.user_email===currentUserEmail).map(r=>r.emoji));
    const reactionBtns = ['👍','🔥','❤️','😂'].map(em => {
      const cnt    = emojiCounts[em]||0;
      const active = myReacts.has(em);
      return `<button onclick="toggleAnnReaction('${a.id}','${em}')"
        style="display:inline-flex;align-items:center;gap:4px;padding:3px 9px;border-radius:12px;border:1px solid ${active?'#1a1a1a':'var(--g100)'};background:${active?'var(--off)':'transparent'};cursor:pointer;font-size:13px;transition:all .15s">
        ${em}${cnt?`<span style="font-family:var(--mono);font-size:11px;color:var(--g600)">${cnt}</span>`:''}
      </button>`;
    }).join('');

    return `<div style="background:var(--white);border:1.5px solid var(--g100);border-radius:12px;margin-bottom:1rem;overflow:hidden${a.pinned?';border-color:'+cat.border:''}">
  <div style="background:${cat.bg};border-bottom:1px solid ${cat.border};padding:10px 16px;display:flex;align-items:center;justify-content:space-between">
    <div style="display:flex;align-items:center;gap:8px">
      ${pinBadge}<span style="font-size:13px">${cat.emoji}</span>
      <span style="font-family:var(--mono);font-size:11px;font-weight:600;text-transform:uppercase;letter-spacing:.06em;color:var(--g600)">${a.category}</span>
      ${a.title?`<span style="font-family:var(--syne);font-weight:600;font-size:14px;color:var(--black)">${_escRmd(a.title)}</span>`:''}
    </div>
    <div style="display:flex;gap:4px;align-items:center">
      ${canEdit?`<button onclick="openAnnModal('${a.id}')" title="Edit" style="background:none;border:1px solid ${cat.border};border-radius:5px;cursor:pointer;padding:2px 7px;font-size:12px;color:var(--g600)">✎</button>
      <button onclick="deleteAnn('${a.id}')" title="Hapus" style="background:none;border:1px solid ${cat.border};border-radius:5px;cursor:pointer;padding:2px 7px;font-size:12px;color:var(--g600)">✕</button>`:''}
    </div>
  </div>
  <div style="padding:14px 16px">
    ${a.body?`<div style="font-size:14px;color:var(--black);line-height:1.65;margin-bottom:${mentionChips?'10':'12'}px;white-space:pre-wrap">${bodyHtml}</div>`:''}
    ${mentionChips?`<div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:12px">${mentionChips}</div>`:''}
    <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px">
      <div style="display:flex;gap:6px;flex-wrap:wrap">${reactionBtns}</div>
      <div style="font-family:var(--mono);font-size:11px;color:var(--g400)">${_escRmd(a.created_by_name||a.created_by)} · ${_rmdTimeAgo(a.created_at)}</div>
    </div>
  </div>
</div>`;
  }).join('');
}

function openAnnModal(id) {
  _annEditId = id||null;
  _annMentions = [];
  const fb = document.getElementById('ann-feedback');
  if (fb) fb.textContent = '';

  if (id) {
    const a = allAnnouncements.find(x=>x.id===id);
    if (!a) return;
    document.getElementById('ann-title').value    = a.title||'';
    document.getElementById('ann-body').value     = a.body||'';
    document.getElementById('ann-category').value = a.category||'Info';
    document.getElementById('ann-pinned').checked = a.pinned||false;
    if (a.mentions) {
      a.mentions.split(',').map(m=>m.trim()).filter(Boolean).forEach(name=>{
        const pu = portalUsers.find(u=>u.display_name===name);
        _annMentions.push({email:pu?pu.email:'', name});
      });
    }
    document.getElementById('ann-modal-title').textContent = 'Edit Post';
    document.getElementById('ann-save-btn').textContent    = 'Simpan Perubahan';
  } else {
    document.getElementById('ann-title').value    = '';
    document.getElementById('ann-body').value     = '';
    document.getElementById('ann-category').value = 'Info';
    document.getElementById('ann-pinned').checked = false;
    document.getElementById('ann-modal-title').textContent = 'Post Baru';
    document.getElementById('ann-save-btn').textContent    = 'Post Sekarang';
  }

  _renderAnnMentionChips();
  document.getElementById('ann-modal').style.display = 'flex';
  setTimeout(()=>document.getElementById('ann-title').focus(), 50);
}

function closeAnnModal() {
  document.getElementById('ann-modal').style.display = 'none';
  const dd = document.getElementById('ann-mention-dropdown');
  if (dd) dd.style.display = 'none';
}

function _renderAnnMentionChips() {
  const el = document.getElementById('ann-mention-chips');
  if (!el) return;
  el.innerHTML = _annMentions.map((m,i)=>
    `<span style="display:inline-flex;align-items:center;gap:4px;background:var(--off);border:1px solid var(--g100);border-radius:10px;padding:2px 8px;font-size:11px;font-family:var(--mono)">@${_escRmd(m.name)}<button onclick="_annRemoveMention(${i})" style="background:none;border:none;cursor:pointer;color:var(--g400);font-size:10px;padding:0;line-height:1;margin-left:2px">✕</button></span>`
  ).join('');
}
function _annRemoveMention(i) { _annMentions.splice(i,1); _renderAnnMentionChips(); }

function _annSetupMentionAC() {
  const ta = document.getElementById('ann-body');
  const dd = document.getElementById('ann-mention-dropdown');
  if (!ta||!dd) return;

  ta.addEventListener('input', ()=>{
    const val=ta.value, pos=ta.selectionStart, before=val.slice(0,pos);
    const match=before.match(/@(\w*)$/);
    if (!match) { dd.style.display='none'; return; }
    const hits=portalUsers.filter(u=>u.display_name.toLowerCase().includes(match[1].toLowerCase())&&!_annMentions.some(m=>m.email===u.email)).slice(0,8);
    if (!hits.length) { dd.style.display='none'; return; }
    dd.innerHTML=hits.map(u=>
      `<div onclick="_annSelectMention('${_escRmd(u.email)}','${_escRmd(u.display_name)}')"
        style="padding:8px 12px;cursor:pointer;font-size:13px;display:flex;align-items:center;gap:8px;border-bottom:1px solid var(--g100)"
        onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background=''">
        <span style="display:inline-flex;align-items:center;justify-content:center;width:24px;height:24px;border-radius:50%;background:var(--off);border:1px solid var(--g100);font-size:11px;font-family:var(--mono);font-weight:600;flex-shrink:0">${u.display_name.charAt(0).toUpperCase()}</span>
        ${_escRmd(u.display_name)}
      </div>`
    ).join('');
    dd.style.display='block';
    dd.style.top=(ta.offsetTop+ta.offsetHeight+2)+'px';
    dd.style.left='0'; dd.style.right='0';
  });
  ta.addEventListener('keydown',e=>{ if(e.key==='Escape') dd.style.display='none'; });
  document.addEventListener('click',e=>{ if(!ta.contains(e.target)&&!dd.contains(e.target)) dd.style.display='none'; },true);
}

function _annSelectMention(email,name) {
  const ta=document.getElementById('ann-body'), dd=document.getElementById('ann-mention-dropdown');
  const val=ta.value, pos=ta.selectionStart;
  const newBefore=val.slice(0,pos).replace(/@(\w*)$/,'@'+name+' ');
  ta.value=newBefore+val.slice(pos);
  ta.selectionStart=ta.selectionEnd=newBefore.length;
  ta.focus();
  if(dd) dd.style.display='none';
  if(!_annMentions.some(m=>m.email===email)) { _annMentions.push({email,name}); _renderAnnMentionChips(); }
}

async function saveAnn() {
  const title  = (document.getElementById('ann-title').value||'').trim();
  const body   = (document.getElementById('ann-body').value||'').trim();
  const cat    = document.getElementById('ann-category').value;
  const pinned = document.getElementById('ann-pinned').checked;
  const fb     = document.getElementById('ann-feedback');

  if (!title && !body) { fb.textContent='⚠ Isi judul atau teks post.'; fb.style.color='#e74c3c'; return; }

  const btn=document.getElementById('ann-save-btn');
  btn.disabled=true; btn.textContent='Memposting...';

  const payload={title,body,category:cat,pinned,mentions:_annMentions.map(m=>m.name).join(', '),created_by:currentUserEmail,created_by_name:currentUser,updated_at:new Date().toISOString()};

  let error, newId;
  if (_annEditId) {
    ({error}=await sb.from('announcements').update(payload).eq('id',_annEditId));
  } else {
    newId=genId('ANN');
    payload.id=newId; payload.created_at=new Date().toISOString();
    ({error}=await sb.from('announcements').insert(payload));

    if (!error) {
      // Notify all portal users (except self) + any @mentioned users
      const allEmails=portalUsers.map(u=>u.email).filter(e=>e!==currentUserEmail);
      const notifs=allEmails.map(e=>({
        recipient:e, module:'announcements', record_id:newId,
        message:`${currentUser} post announcement baru: "${title||body.slice(0,50)}"`,
        is_read:false,
      }));
      if(notifs.length) await sb.from('notifications').insert(notifs);
    }
  }

  btn.disabled=false; btn.textContent=_annEditId?'Simpan Perubahan':'Post Sekarang';
  if(error){fb.textContent='⚠ Gagal: '+error.message;fb.style.color='#e74c3c';return;}
  closeAnnModal();
  await loadAnnouncements();
  loadAnnTicker();
}

async function toggleAnnReaction(id, emoji) {
  const reacts = annReactions[id]||[];
  const existing = reacts.find(r=>r.user_email===currentUserEmail&&r.emoji===emoji);
  if (existing) {
    await sb.from('announcement_reactions').delete().eq('announcement_id',id).eq('user_email',currentUserEmail).eq('emoji',emoji);
  } else {
    await sb.from('announcement_reactions').insert({announcement_id:id,user_email:currentUserEmail,user_name:currentUser,emoji});
  }
  // Optimistic refresh of reactions only
  const {data}=await sb.from('announcement_reactions').select('announcement_id,user_email,user_name,emoji').eq('announcement_id',id);
  annReactions[id]=data||[];
  _renderAnnFeed();
}

async function deleteAnn(id) {
  if(!confirm('Hapus announcement ini?')) return;
  const {error}=await sb.from('announcements').delete().eq('id',id);
  if(!error){allAnnouncements=allAnnouncements.filter(x=>x.id!==id);delete annReactions[id];_renderAnnStats();_renderAnnFeed();loadAnnTicker();}
}

// ── REMINDERS ──
const RMD_COLORS = {
  yellow: {bg:'#fef9c3', border:'#fde047'},
  blue:   {bg:'#dbeafe', border:'#93c5fd'},
  green:  {bg:'#dcfce7', border:'#86efac'},
  pink:   {bg:'#fce7f3', border:'#f9a8d4'},
  purple: {bg:'#ede9fe', border:'#c4b5fd'},
};

let allReminders = [], portalUsers = [];
let _rmdTab = 'all', _rmdEditId = null, _rmdColor = 'yellow';
let _rmdMentions = []; // [{email, name}]
let _rmdACSetup = false;

async function upsertPortalUser(user) {
  const name = user.user_metadata?.name || user.email.split('@')[0];
  await sb.from('portal_users').upsert({email: user.email, display_name: name, last_seen: new Date().toISOString()}, {onConflict: 'email'});
}

async function loadPortalUsers() {
  const {data} = await sb.from('portal_users').select('email,display_name').order('display_name');
  portalUsers = data || [];
}

async function loadReminders() {
  await loadPortalUsers();
  if (!_rmdACSetup) { _rmdSetupMentionAC(); _rmdACSetup = true; }
  const {data, error} = await sb.from('reminders').select('*')
    .order('pinned',{ascending:false}).order('created_at',{ascending:false});
  if (error) { console.error(error); return; }
  allReminders = data || [];
  _renderRmdStats();
  _renderRmdGrid();
}

function _renderRmdStats() {
  const active   = allReminders.filter(r => !r.is_done);
  const mine     = active.filter(r => r.created_by === currentUserEmail);
  const mentions = active.filter(r => _rmdMentionedMe(r));
  const done     = allReminders.filter(r => r.is_done);
  document.getElementById('rmd-s-total').textContent   = active.length;
  document.getElementById('rmd-s-mine').textContent    = mine.length;
  document.getElementById('rmd-s-mention').textContent = mentions.length;
  document.getElementById('rmd-s-done').textContent    = done.length;
}

function _rmdMentionedMe(r) {
  if (!r.mentions) return false;
  const names  = r.mentions.split(',').map(s=>s.trim().toLowerCase()).filter(Boolean);
  const myName = (currentUser||'').toLowerCase();
  const myEmail= (currentUserEmail||'').toLowerCase();
  return names.some(n => n===myName || n===myEmail || myEmail.startsWith(n+'@'));
}

function switchRmdTab(tab, btn) {
  _rmdTab = tab;
  document.querySelectorAll('#page-reminders .tab-btn').forEach(b=>b.classList.remove('active'));
  if (btn) btn.classList.add('active');
  _renderRmdGrid();
}

function _renderRmdGrid() {
  const grid = document.getElementById('rmd-grid');
  if (!grid) return;

  let list = allReminders;
  if (_rmdTab==='mine')    list = allReminders.filter(r=>!r.is_done && r.created_by===currentUserEmail);
  else if (_rmdTab==='mention') list = allReminders.filter(r=>!r.is_done && _rmdMentionedMe(r));
  else if (_rmdTab==='done')    list = allReminders.filter(r=>r.is_done);
  else list = allReminders.filter(r=>!r.is_done);

  if (!list.length) {
    const msgs = {all:'Belum ada note aktif. Klik "+ New Note" untuk mulai!',mine:'Kamu belum punya note.',mention:'Belum ada yang mention kamu.',done:'Belum ada note yang ditandai selesai.'};
    grid.innerHTML = `<div style="color:var(--g400);font-size:14px;padding:2rem 0">${msgs[_rmdTab]||''}</div>`;
    return;
  }

  grid.innerHTML = list.map(r => {
    const col = RMD_COLORS[r.color]||RMD_COLORS.yellow;
    const mentionChips = r.mentions
      ? r.mentions.split(',').map(m=>m.trim()).filter(Boolean)
          .map(m=>`<span style="display:inline-block;background:rgba(0,0,0,0.07);border-radius:10px;padding:1px 7px;font-size:11px;font-family:var(--mono)">@${_escRmd(m)}</span>`).join(' ')
      : '';
    const bodyHtml = (r.body||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>').replace(/(https?:\/\/[^\s<]+)/g,'<a href="$1" target="_blank" rel="noopener" style="color:#1a4a8a;text-decoration:underline;word-break:break-all" onclick="event.stopPropagation()">$1</a>');
    const pinIcon  = r.pinned ? '<span style="font-size:11px" title="Pinned">📌 </span>' : '';
    const canEdit  = r.created_by===currentUserEmail;
    const doneStyle= r.is_done ? 'text-decoration:line-through;opacity:0.6' : '';

    return `<div style="break-inside:avoid;margin-bottom:1rem;background:${col.bg};border:1.5px solid ${col.border};border-radius:10px;padding:14px 14px 10px;box-shadow:0 1px 6px rgba(0,0,0,0.05);${r.is_done?'opacity:0.6':''}">
  <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:8px;margin-bottom:${r.body||mentionChips?'8':'4'}px">
    <div style="font-family:var(--syne);font-weight:600;font-size:13px;color:var(--black);flex:1;line-height:1.4;${doneStyle}">${pinIcon}${r.title?_escRmd(r.title):'<span style="color:var(--g400);font-weight:400;font-style:italic">tanpa judul</span>'}</div>
    <div style="display:flex;gap:3px;flex-shrink:0">
      <button onclick="toggleRmdDone('${r.id}')" title="${r.is_done?'Aktifkan kembali':'Tandai selesai'}" style="background:none;border:1px solid ${col.border};border-radius:5px;cursor:pointer;padding:2px 6px;font-size:12px;color:var(--g600);line-height:1">${r.is_done?'↩':'✓'}</button>
      ${canEdit?`<button onclick="openReminderModal('${r.id}')" title="Edit" style="background:none;border:1px solid ${col.border};border-radius:5px;cursor:pointer;padding:2px 6px;font-size:12px;color:var(--g600);line-height:1">✎</button>
      <button onclick="deleteReminder('${r.id}')" title="Hapus" style="background:none;border:1px solid ${col.border};border-radius:5px;cursor:pointer;padding:2px 6px;font-size:12px;color:var(--g600);line-height:1">✕</button>`:''}
    </div>
  </div>
  ${r.body?`<div style="font-size:13px;color:var(--black);line-height:1.6;margin-bottom:8px;white-space:pre-wrap">${bodyHtml}</div>`:''}
  ${mentionChips?`<div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:8px">${mentionChips}</div>`:''}
  <div style="font-family:var(--mono);font-size:10px;color:var(--g400);display:flex;align-items:center;gap:5px;border-top:1px solid ${col.border};padding-top:7px;margin-top:2px">
    <span>${_escRmd(r.created_by_name||r.created_by)}</span><span>·</span><span>${_rmdTimeAgo(r.created_at)}</span>
  </div>
</div>`;
  }).join('');
}

function _escRmd(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

function _rmdTimeAgo(iso) {
  if (!iso) return '';
  const diff = Date.now()-new Date(iso).getTime();
  const m=Math.floor(diff/60000);
  if (m<1)   return 'baru saja';
  if (m<60)  return m+' mnt lalu';
  const h=Math.floor(m/60);
  if (h<24)  return h+' jam lalu';
  const d=Math.floor(h/24);
  if (d<7)   return d+' hari lalu';
  return new Date(iso).toLocaleDateString('id-ID',{day:'numeric',month:'short'});
}

function openReminderModal(id) {
  _rmdEditId = id||null;
  _rmdMentions = [];
  _rmdColor = 'yellow';
  const fb = document.getElementById('rmd-feedback');
  if (fb) fb.textContent = '';

  if (id) {
    const r = allReminders.find(x=>x.id===id);
    if (!r) return;
    document.getElementById('rmd-title').value = r.title||'';
    document.getElementById('rmd-body').value  = r.body||'';
    document.getElementById('rmd-pinned').checked = r.pinned||false;
    _rmdColor = r.color||'yellow';
    if (r.mentions) {
      r.mentions.split(',').map(m=>m.trim()).filter(Boolean).forEach(name => {
        const pu = portalUsers.find(u=>u.display_name===name);
        _rmdMentions.push({email:pu?pu.email:'', name});
      });
    }
    document.getElementById('rmd-modal-title').textContent = 'Edit Note';
    document.getElementById('rmd-save-btn').textContent    = 'Simpan Perubahan';
  } else {
    document.getElementById('rmd-title').value  = '';
    document.getElementById('rmd-body').value   = '';
    document.getElementById('rmd-pinned').checked = false;
    document.getElementById('rmd-modal-title').textContent = 'Note Baru';
    document.getElementById('rmd-save-btn').textContent    = 'Simpan Note';
  }

  // Sync color picker UI
  _rmdSyncColorPicker();
  // Render mention chips
  _renderRmdMentionChips();

  document.getElementById('rmd-modal').style.display = 'flex';
  setTimeout(()=>document.getElementById('rmd-title').focus(), 50);
}

function closeReminderModal() {
  document.getElementById('rmd-modal').style.display = 'none';
  const dd = document.getElementById('rmd-mention-dropdown');
  if (dd) dd.style.display = 'none';
}

function selectRmdColor(color, btn) {
  _rmdColor = color;
  _rmdSyncColorPicker();
}

function _rmdSyncColorPicker() {
  document.querySelectorAll('.rmd-color-btn').forEach(b => {
    b.style.border = b.dataset.color===_rmdColor ? '3px solid #1a1a1a' : '2px solid var(--g200)';
    b.style.outline = b.dataset.color===_rmdColor ? '2px solid rgba(0,0,0,0.15)' : 'none';
    b.style.outlineOffset = '1px';
  });
}

function _renderRmdMentionChips() {
  const el = document.getElementById('rmd-mention-chips');
  if (!el) return;
  el.innerHTML = _rmdMentions.map((m,i) =>
    `<span style="display:inline-flex;align-items:center;gap:4px;background:var(--off);border:1px solid var(--g100);border-radius:10px;padding:2px 8px;font-size:11px;font-family:var(--mono)">@${_escRmd(m.name)}<button onclick="_rmdRemoveMention(${i})" style="background:none;border:none;cursor:pointer;color:var(--g400);font-size:10px;padding:0;line-height:1;margin-left:2px">✕</button></span>`
  ).join('');
}

function _rmdRemoveMention(i) {
  _rmdMentions.splice(i, 1);
  _renderRmdMentionChips();
}

function _rmdSetupMentionAC() {
  const ta = document.getElementById('rmd-body');
  const dd = document.getElementById('rmd-mention-dropdown');
  if (!ta || !dd) return;

  ta.addEventListener('input', () => {
    const val    = ta.value;
    const pos    = ta.selectionStart;
    const before = val.slice(0, pos);
    const match  = before.match(/@(\w*)$/);
    if (!match) { dd.style.display = 'none'; return; }

    const query = match[1].toLowerCase();
    const hits  = portalUsers.filter(u =>
      u.display_name.toLowerCase().includes(query) &&
      !_rmdMentions.some(m=>m.email===u.email)
    ).slice(0, 8);

    if (!hits.length) { dd.style.display = 'none'; return; }

    dd.innerHTML = hits.map(u =>
      `<div onclick="_rmdSelectMention('${_escRmd(u.email)}','${_escRmd(u.display_name)}')"
        style="padding:8px 12px;cursor:pointer;font-size:13px;display:flex;align-items:center;gap:8px;border-bottom:1px solid var(--g100)"
        onmouseover="this.style.background='var(--off)'"
        onmouseout="this.style.background=''">
        <span style="display:inline-flex;align-items:center;justify-content:center;width:24px;height:24px;border-radius:50%;background:var(--off);border:1px solid var(--g100);font-size:11px;font-family:var(--mono);font-weight:600;flex-shrink:0">${u.display_name.charAt(0).toUpperCase()}</span>
        <span>${_escRmd(u.display_name)}</span>
      </div>`
    ).join('');

    dd.style.display = 'block';
    // Position: just below textarea
    dd.style.top  = (ta.offsetTop + ta.offsetHeight + 2) + 'px';
    dd.style.left = '0';
    dd.style.right = '0';
  });

  ta.addEventListener('keydown', e => {
    if (e.key==='Escape') dd.style.display = 'none';
  });

  document.addEventListener('click', e => {
    if (!ta.contains(e.target) && !dd.contains(e.target)) dd.style.display = 'none';
  }, true);
}

function _rmdSelectMention(email, name) {
  const ta     = document.getElementById('rmd-body');
  const dd     = document.getElementById('rmd-mention-dropdown');
  const val    = ta.value;
  const pos    = ta.selectionStart;
  const before = val.slice(0, pos);
  const after  = val.slice(pos);
  const newBefore = before.replace(/@(\w*)$/, '@'+name+' ');
  ta.value = newBefore + after;
  ta.selectionStart = ta.selectionEnd = newBefore.length;
  ta.focus();
  if (dd) dd.style.display = 'none';
  if (!_rmdMentions.some(m=>m.email===email)) {
    _rmdMentions.push({email, name});
    _renderRmdMentionChips();
  }
}

async function saveReminder() {
  const title  = (document.getElementById('rmd-title').value||'').trim();
  const body   = (document.getElementById('rmd-body').value||'').trim();
  const pinned = document.getElementById('rmd-pinned').checked;
  const fb     = document.getElementById('rmd-feedback');

  if (!title && !body) {
    fb.textContent = '⚠ Isi judul atau teks note.'; fb.style.color='#e74c3c'; return;
  }

  const btn = document.getElementById('rmd-save-btn');
  btn.disabled = true; btn.textContent = 'Menyimpan...';

  const mentionsStr = _rmdMentions.map(m=>m.name).join(', ');
  const payload = {
    title, body, color:_rmdColor,
    mentions: mentionsStr,
    created_by: currentUserEmail,
    created_by_name: currentUser,
    updated_at: new Date().toISOString(),
    pinned,
  };

  let error, newId;
  if (_rmdEditId) {
    ({error} = await sb.from('reminders').update(payload).eq('id', _rmdEditId));
  } else {
    newId = genId('RMD');
    payload.id = newId;
    payload.created_at = new Date().toISOString();
    payload.is_done = false;
    ({error} = await sb.from('reminders').insert(payload));
    // Notify mentioned users
    if (!error && _rmdMentions.length) {
      const notifs = _rmdMentions
        .filter(m=>m.email && m.email!==currentUserEmail)
        .map(m=>({
          recipient: m.email,
          module: 'reminders',
          record_id: newId,
          message: `${currentUser} mention kamu di note: "${title||body.slice(0,45)}"`,
          is_read: false,
        }));
      if (notifs.length) await sb.from('notifications').insert(notifs);
    }
  }

  btn.disabled = false; btn.textContent = _rmdEditId ? 'Simpan Perubahan' : 'Simpan Note';
  if (error) { fb.textContent='⚠ Gagal: '+error.message; fb.style.color='#e74c3c'; return; }

  closeReminderModal();
  await loadReminders();
}

async function toggleRmdDone(id) {
  const r = allReminders.find(x=>x.id===id);
  if (!r) return;
  await sb.from('reminders').update({is_done:!r.is_done, updated_at:new Date().toISOString()}).eq('id',id);
  await loadReminders();
}

async function deleteReminder(id) {
  if (!confirm('Hapus note ini? Tindakan ini tidak dapat dibatalkan.')) return;
  const {error} = await sb.from('reminders').delete().eq('id',id);
  if (!error) { allReminders = allReminders.filter(x=>x.id!==id); _renderRmdStats(); _renderRmdGrid(); }
}

// ── MARTE SALES REPORT ──
let _mrSummary  = [];   // per-brand summary from RPC (only brands with sales)
let _mrAllRows  = [];   // merged: all marte brands, zero-filled if no sales
let _mrTracking = {};   // {brand_id: marte_settlements row}
let _mrPeriod   = '';   // YYYY-MM
let _mrModal    = null; // {brandId, brandName, salesRow, trkRow, skuData}

function _mrRp(n)     { const v=parseFloat(n)||0; return v===0?'—':'Rp'+Math.round(v).toLocaleString('id-ID'); }
function _mrRpFull(n) { return 'Rp'+Math.round(parseFloat(n)||0).toLocaleString('id-ID'); }
function _mrFmtDate(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  return `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;
}
function _mrShort(iso) {
  if (!iso) return '';
  const d = new Date(iso);
  return `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}`;
}

// Period navigation
function mrNavPeriod(offset) {
  const inp = document.getElementById('mr-period');
  if (offset === 0) { inp.value = new Date().toISOString().slice(0,7); return; }
  const cur = inp.value ? new Date(inp.value+'-01') : new Date();
  cur.setMonth(cur.getMonth() + offset);
  inp.value = cur.toISOString().slice(0,7);
}

// ── Tab switch + per-brand timeline view ──
let _mrTlBrandsLoaded = false;
function mrSwitchTab(name, el) {
  document.querySelectorAll('#page-martereport .tab-bar .tab-btn').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('mr-tab-period').style.display   = name === 'period'   ? '' : 'none';
  document.getElementById('mr-tab-timeline').style.display = name === 'timeline' ? '' : 'none';
  if (name === 'timeline' && !_mrTlBrandsLoaded) _mrLoadTlBrands();
}

async function _mrLoadTlBrands() {
  const sel = document.getElementById('mr-tl-brand');
  const { data } = await sb.from('brand_master')
    .select('id,name').eq('live_status','Active').ilike('revenue_stream','%Marte%').order('name');
  sel.innerHTML = '<option value="">— Pilih brand —</option>' +
    (data||[]).map(b => `<option value="${_escRmd(b.id)}">${_escRmd(b.name)}</option>`).join('');
  _mrTlBrandsLoaded = true;
}

async function loadMarteTimeline() {
  const brandId = document.getElementById('mr-tl-brand').value;
  const fb = document.getElementById('mr-tl-feedback');
  const wrap = document.getElementById('mr-tl-wrap');
  const summary = document.getElementById('mr-tl-summary');
  if (!brandId) { wrap.style.display='none'; summary.style.display='none'; fb.textContent=''; return; }
  fb.textContent = 'Memuat...'; fb.className = 'feedback';

  const [tlRes, trkRes, invRes] = await Promise.all([
    sb.rpc('get_marte_brand_timeline', { p_brand_id: brandId }),
    sb.from('marte_settlements').select('*').eq('brand_id', brandId),
    sb.rpc('get_marte_inventory_report', { p_start_date: '2026-05-01T00:00:00+07:00', p_end_date: '2026-06-01T00:00:00+07:00' }),
  ]);
  if (tlRes.error) { fb.textContent = 'Error: ' + tlRes.error.message; fb.className='feedback err'; return; }
  const rows = tlRes.data || [];
  const trkByPeriod = {}; (trkRes.data||[]).forEach(t => { trkByPeriod[t.period] = t; });
  const invRow = (invRes.data||[]).find(r => r.brand_master_id === brandId) || {};
  const stockNow = parseFloat(invRow.net_stock)||0;
  const stockVal = parseFloat(invRow.stock_value_retail)||0;

  if (!rows.length) { fb.textContent='Belum ada data untuk brand ini.'; fb.className='feedback err'; wrap.style.display='none'; summary.style.display='none'; return; }
  fb.textContent = '';

  let totSales=0, totFee=0, totNet=0, totIn=0, totOutSales=0, totOutAdj=0;
  document.getElementById('mr-tl-tbody').innerHTML = rows.map(r => {
    const sales=parseFloat(r.total_sales)||0, fee=parseFloat(r.total_fee)||0, net=parseFloat(r.net_payout)||0;
    const oSales=parseFloat(r.outbound_sales)||0, oAdj=parseFloat(r.outbound_adj)||0;
    totSales+=sales; totFee+=fee; totNet+=net;
    totIn+=parseFloat(r.inbound_qty)||0; totOutSales+=oSales; totOutAdj+=oAdj;
    const pills = _mrStatusPill(trkByPeriod[r.period] || null);
    const z = '<span style="color:var(--g300)">—</span>';
    const mlabel = new Date(r.period+'-01T00:00:00').toLocaleDateString('id-ID',{month:'short',year:'numeric'});
    return `<tr>
      <td style="font-weight:600">${mlabel}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;border-left:2px solid var(--g100)">${sales>0?_mrRpFull(sales):z}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;color:#c05">${fee>0?_mrRpFull(fee):z}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;font-weight:600">${net>0?_mrRpFull(net):z}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;color:#16a34a;border-left:2px solid var(--g100)">${parseFloat(r.inbound_qty)>0?Math.round(r.inbound_qty):z}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;color:#ea580c">${oSales>0?Math.round(oSales):z}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:12px;color:#b45309">${oAdj>0?Math.round(oAdj):z}</td>
      <td style="text-align:center;border-left:2px solid var(--g100)">${pills[0]}</td>
      <td style="text-align:center">${pills[1]}</td>
      <td style="text-align:center">${pills[2]}</td>
      <td style="text-align:center">${pills[3]}</td>
    </tr>`;
  }).join('');

  document.getElementById('mr-tl-tfoot').innerHTML = `<tr style="font-weight:700;border-top:2px solid var(--g200);background:var(--off)">
    <td style="padding:8px 10px">TOTAL</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px;border-left:2px solid var(--g100)">${_mrRpFull(totSales)}</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px;color:#c05">${_mrRpFull(totFee)}</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px">${_mrRpFull(totNet)}</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px;color:#16a34a;border-left:2px solid var(--g100)">${Math.round(totIn)}</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px;color:#ea580c">${Math.round(totOutSales)}</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px;color:#b45309">${Math.round(totOutAdj)}</td>
    <td colspan="4"></td>
  </tr>`;

  document.getElementById('mr-tl-s-months').textContent   = rows.filter(r=>parseFloat(r.total_sales)>0).length;
  document.getElementById('mr-tl-s-sales').textContent    = _mrRpFull(totSales);
  document.getElementById('mr-tl-s-fee').textContent      = _mrRpFull(totFee);
  document.getElementById('mr-tl-s-net').textContent      = _mrRpFull(totNet);
  document.getElementById('mr-tl-s-inbound').textContent  = Math.round(totIn).toLocaleString('id-ID')+' pcs';
  document.getElementById('mr-tl-s-outsales').textContent = Math.round(totOutSales).toLocaleString('id-ID')+' pcs';
  document.getElementById('mr-tl-s-outadj').textContent   = Math.round(totOutAdj).toLocaleString('id-ID')+' pcs';
  document.getElementById('mr-tl-s-stock').textContent    = Math.round(stockNow).toLocaleString('id-ID')+' pcs';
  document.getElementById('mr-tl-s-stockval').textContent = stockVal>0 ? _mrRpFull(stockVal) : '—';
  summary.style.display='grid';
  wrap.style.display='';
}

// ── Load period data ──
// Same shape as syncAndReloadSA — pulls fresh adjustments + inventory so the
// Net Stock column (which reads inventory_stocks.available) reflects today's
// Jubelio state, not yesterday's cron snapshot. Net stock was missing same-
// day adjustments before this was wired.
let _mrSyncCooldownUntil = 0;
async function syncAndReloadMR() {
  const btn    = document.getElementById('mr-sync-btn');
  const status = document.getElementById('mr-sync-status');
  const now = Date.now();
  if (now < _mrSyncCooldownUntil) {
    const remaining = Math.ceil((_mrSyncCooldownUntil - now) / 1000);
    if (status) status.textContent = `tunggu ${remaining}s`;
    await loadMarteReport();
    return;
  }
  if (btn) { btn.disabled = true; btn.textContent = '⟳ Syncing...'; }
  if (status) status.textContent = 'syncing adjustment + inventory...';
  const t0 = Date.now();
  try {
    const [adjRes, invRes] = await Promise.allSettled([
      callEdgeFunction('sync-jubelio-inventory-adjustments'),
      callEdgeFunction('sync-jubelio-inventory'),
    ]);
    const elapsed = ((Date.now() - t0) / 1000).toFixed(1);
    const adjOK = adjRes.status === 'fulfilled';
    const invOK = invRes.status === 'fulfilled';
    const newAdj = adjOK ? (adjRes.value?.detailFetched || 0) : '?';
    if (status) status.textContent = (adjOK && invOK)
      ? `synced · ${newAdj} adj baru + stock fresh · ${elapsed}s`
      : `partial · adj ${adjOK?'✓':'✗'} · inv ${invOK?'✓':'✗'} · ${elapsed}s`;
    _mrSyncCooldownUntil = Date.now() + 60_000;
  } catch (e) {
    if (status) status.textContent = `gagal: ${e.message||e}`;
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = '↻ Sync Jubelio'; }
  }
  await loadMarteReport();
}

async function loadMarteReport() {
  const period = document.getElementById('mr-period').value;
  const fb  = document.getElementById('mr-feedback');
  const btn = document.getElementById('mr-load-btn');
  if (!period) { fb.textContent='Pilih periode dulu.'; fb.className='feedback err'; return; }

  _mrPeriod = period;
  fb.textContent=''; btn.textContent='Loading...'; btn.disabled=true;

  const [year, month] = period.split('-').map(Number);
  const startISO = `${period}-01T00:00:00+07:00`;
  // endISO = first day of NEXT month at 00:00 WIB. Old impl used `new Date(year,
  // month, 1).toISOString()` which converted to UTC and crossed the date line
  // backwards (May 31 17:00 UTC), making endISO land on May 31 instead of Jun 1
  // → all May 31 transactions silently dropped.
  const _endY = month === 12 ? year + 1 : year;
  const _endM = month === 12 ? 1 : month + 1;
  const endISO   = `${_endY}-${String(_endM).padStart(2,'0')}-01T00:00:00+07:00`;

  const [salesRes, trkRes, bmRes, invRes] = await Promise.all([
    sb.rpc('get_marte_sales_report', { p_start_date: startISO, p_end_date: endISO }),
    sb.from('marte_settlements').select('*').eq('period', period),
    sb.from('brand_master').select('id,name,brand_type,vat_status').eq('live_status','Active').ilike('revenue_stream','%Marte%').order('name'),
    // p_as_of_date = endISO → stock + all-time totals di-cutoff per akhir
    // periode (mis. report Mei dijalanin di Juni → stock per 31 Mei 23:59).
    // Buat current period, endISO masih di masa depan jadi efeknya = sekarang.
    sb.rpc('get_marte_inventory_report', { p_start_date: startISO, p_end_date: endISO, p_as_of_date: endISO })
  ]);

  btn.textContent='Load Data'; btn.disabled=false;

  if (salesRes.error) { fb.textContent='Error: '+salesRes.error.message; fb.className='feedback err'; return; }

  // SD&Y and Lagaa are scoped to Gudang Marte only (handled in RPCs); all brands included
  _mrSummary  = salesRes.data || [];
  _mrTracking = {};
  (trkRes.data||[]).forEach(r => { _mrTracking[r.brand_id] = r; });

  // Build inventory map keyed by brand_master_id for exact matching
  const invMap = {};
  (invRes.data||[]).forEach(r => { invMap[r.brand_master_id] = r; });

  // Build full brand list: all active marte brands, zero-filled if no sales this period
  const salesMap = {};
  _mrSummary.forEach(r => { salesMap[r.brand_id] = r; });
  const allMarteBrands = (bmRes.data||[]);
  // Add any brands from sales data that aren't in brand_master (legacy/manual)
  _mrSummary.forEach(r => { if (!allMarteBrands.find(b=>b.id===r.brand_id)) allMarteBrands.push({id:r.brand_id, name:r.brand_name}); });
  // Build _bmTypeMap: brand_id → {brand_type, vat_status} from brand_master
  const _bmTypeMap = {};
  allMarteBrands.forEach(b => { _bmTypeMap[b.id] = { brand_type: b.brand_type||null, vat_status: b.vat_status||null }; });

  _mrAllRows = allMarteBrands.map(b => {
    const s   = salesMap[b.id] || { brand_id:b.id, brand_name:b.name, total_sales:0, total_fee:0, net_payout:0, others_sales:0 };
    const inv = invMap[b.id] || {};
    // PPh 23 (2%) withholding — PT brand potong dari consignment fee yang kita
    // charge ke mereka. Net payout ke brand jadi (gross − fee) + pph karena
    // 2% itu tetap di brand untuk disetor ke pajak atas nama kita.
    const fee    = parseFloat(s.total_fee)   || 0;
    const rawNet = parseFloat(s.net_payout)  || 0;
    const isPT   = b.brand_type === 'PT';
    const pph23  = isPT ? Math.round(fee * 0.02) : 0;
    return { ...s, _bm_brand_type:b.brand_type||null, _bm_vat_status:b.vat_status||null,
      _pph23:           pph23,
      _net_payout_adj:  rawNet + pph23,
      // Net stock now reflects 'available' (on_hand minus reserved) — matches
      // what user expected (e.g. Atsiri 121, not 123 on_hand).
      _stock_qty:       parseFloat(inv.net_stock)||0,
      _stock_value:     parseFloat(inv.stock_value_retail)||0,
      _inbound_period:  parseFloat(inv.inbound_period)||0,
      // outbound_period = total_qty from sales report — sales only, no adjustment.
      _outbound_period: parseFloat(s.total_qty)||0,
      _inbound_total:   parseFloat(inv.inbound_total)||0,
      // outbound_total is now SALES-ONLY (RPC was updated to split this).
      _outbound_total:  parseFloat(inv.outbound_total)||0,
      // Adjustment OUT (negative qty: freebies / defect / opname loss) shown
      // as its own metric so finance can separate 'kejual' vs 'dikurangin'.
      _adj_out_period:  parseFloat(inv.adjustment_out_period)||0,
      _adj_out_total:   parseFloat(inv.adjustment_out_total)||0 };
  });

  // Stats — totals reflect PPh adjustment for PT brands so Net Payout matches
  // what we actually transfer (raw + pph kept by brand).
  let totS=0, totF=0, totN=0;
  _mrAllRows.forEach(r => {
    if ((parseFloat(r.total_sales)||0) <= 0) return;
    totS += parseFloat(r.total_sales)||0;
    totF += parseFloat(r.total_fee)||0;
    totN += parseFloat(r._net_payout_adj)||0;
  });
  document.getElementById('mr-s-brands').textContent = _mrSummary.length;
  document.getElementById('mr-s-sales').textContent  = _mrRpFull(totS);
  document.getElementById('mr-s-fee').textContent    = _mrRpFull(totF);
  document.getElementById('mr-s-net').textContent    = _mrRpFull(totN);
  document.getElementById('mr-stats').style.display  = 'grid';
  document.getElementById('mr-tcount').textContent   = _mrAllRows.length+' brand ('+ _mrSummary.length+' ada sales)';
  document.getElementById('mr-result-wrap').style.display = 'block';
  _mrRenderTable();
}

// Render inline action cells. Flow: download sales report + invoice → kirim
// → brand bayar → brand kirim bukti potong (PT only). Bukti Potong upload
// dipindah ke ujung kanan karena posisinya kronologis terakhir.
//   [0] reportPill   — Sales Report Sent toggle
//   [1] payPill      — Pembayaran toggle
//   [2] bpCell       — Bukti Potong file upload (PT only); '—' kalau non-PT
function _mrStatusCells(brandId, trk, isPT) {
  const reportSent = !!trk?.report_sent_at;
  const reportPill = `<span onclick="event.stopPropagation();mrToggleReport('${_escRmd(brandId)}')" style="display:inline-block;cursor:pointer;font-size:10px;padding:3px 9px;border-radius:99px;font-family:var(--mono);font-weight:500;background:${reportSent?'#dcfce7':'var(--off)'};color:${reportSent?'#15803d':'var(--g600)'};border:1px solid ${reportSent?'#86efac':'var(--g200)'}" title="${reportSent?'Klik untuk Not Started':'Klik untuk Sent'}">${reportSent?`✓ Sent · ${_mrShort(trk.report_sent_at)}`:'Not Started'}</span>`;
  const paid = !!trk?.payment_received_at;
  const payPill = `<span onclick="event.stopPropagation();mrTogglePayment('${_escRmd(brandId)}')" style="display:inline-block;cursor:pointer;font-size:10px;padding:3px 9px;border-radius:99px;font-family:var(--mono);font-weight:500;background:${paid?'#dcfce7':'var(--off)'};color:${paid?'#15803d':'var(--g600)'};border:1px solid ${paid?'#86efac':'var(--g200)'}" title="${paid?'Klik untuk Not Paid':'Klik untuk Paid'}">${paid?`✓ Paid · ${_mrShort(trk.payment_received_at)}`:'Not Paid'}</span>`;
  let bpCell;
  if (!isPT) {
    bpCell = `<span style="font-size:10px;color:var(--g300);font-family:var(--mono)">—</span>`;
  } else {
    const hasBP = !!trk?.bukti_potong_file_url;
    bpCell = hasBP
      ? `<div style="display:flex;align-items:center;gap:4px;justify-content:center"><a href="${_escRmd(trk.bukti_potong_file_url)}" target="_blank" onclick="event.stopPropagation()" style="font-size:10px;color:#3C3489;text-decoration:none;font-family:var(--mono)">📎 lihat</a><button onclick="event.stopPropagation();mrRemoveBP('${_escRmd(brandId)}')" style="font-size:10px;padding:1px 5px;background:none;border:1px solid var(--g200);border-radius:3px;cursor:pointer;color:var(--g600)" title="Hapus">×</button></div>`
      : `<label onclick="event.stopPropagation()" style="display:inline-block;cursor:pointer;font-size:10px;padding:3px 9px;border-radius:4px;background:#3C3489;color:white;font-family:var(--mono);font-weight:500" title="Upload bukti potong PPh 23 (PDF/JPG/PNG)">📤 Upload<input type="file" accept="application/pdf,image/*" style="display:none" onchange="mrUploadBP('${_escRmd(brandId)}',this)"></label>`;
  }
  return [reportPill, payPill, bpCell];
}

function _mrRenderTable() {
  const tb = document.getElementById('mr-tbody');
  tb.innerHTML = _mrAllRows.map(r => {
    const trk     = _mrTracking[r.brand_id] || null;
    // brand_type: from Brand Master first, fallback to tracking row
    const tipe    = r._bm_brand_type || trk?.brand_type || '—';
    const cells   = _mrStatusCells(r.brand_id, trk, tipe === 'PT');
    const vatSt   = r._bm_vat_status || '—';
    const tipeClass = tipe==='PT'?'p-signings':tipe==='Individu'?'p-draft':'p-inactive';
    const vatClass  = vatSt==='VAT Included'?'p-active':vatSt==='VAT Excluded'?'p-near':'p-inactive';
    const hasSales  = (parseFloat(r.total_sales)||0) > 0;
    const hasOthers = (parseFloat(r.others_sales)||0) > 0;
    const warn    = hasOthers ? `<span style="color:orange;margin-left:4px;font-size:11px" title="${_mrRp(r.others_sales)} belum terkategori">⚠</span>` : '';
    const bid     = _escRmd(r.brand_id||'');
    const bname   = _escRmd(r.brand_name||'');
    const rowStyle = hasSales ? 'cursor:pointer' : 'cursor:pointer;opacity:.55';
    const zeroCell = `<span style="color:var(--g300);font-family:var(--mono);font-size:12px">—</span>`;
    const fmtQty = n => n>0 ? `<span style="font-family:var(--mono);font-size:12px">${Math.round(n).toLocaleString('id-ID')}</span>` : zeroCell;
    return `<tr style="${rowStyle}" onclick="openMRDetail('${bid}','${bname}')">
      <td style="font-weight:500">${bname}${warn}</td>
      <td><span class="pill ${tipeClass}" style="font-size:10px">${tipe}</span></td>
      <td>${vatSt!=='—'?`<span class="pill ${vatClass}" style="font-size:10px">${vatSt}</span>`:'<span style="color:var(--g300);font-size:11px">—</span>'}</td>
      <td style="text-align:right">${fmtQty(r._stock_qty)}</td>
      <td style="text-align:right">${r._stock_value>0?`<span style="font-family:var(--mono);font-size:12px">${_mrRpFull(r._stock_value)}</span>`:zeroCell}</td>
      <td style="text-align:right">${fmtQty(r._inbound_period)}</td>
      <td style="text-align:right">${fmtQty(r._outbound_period)}</td>
      <td style="text-align:right" title="Adjustment OUT (freebies / defect / opname loss)">${r._adj_out_period>0 ? `<span style="font-family:var(--mono);font-size:12px;color:#a66800">${Math.round(r._adj_out_period).toLocaleString('id-ID')}</span>` : zeroCell}</td>
      <td style="text-align:right">${hasSales ? `<span style="font-family:var(--mono);font-size:12px">${_mrRpFull(r.total_sales)}</span>` : zeroCell}</td>
      <td style="text-align:right">${hasSales ? `<span style="font-family:var(--mono);font-size:12px;color:#c05" title="${(r._pph23||0)>0?'PPh 23 (2%) '+_mrRpFull(r._pph23)+' · net fee '+_mrRpFull((parseFloat(r.total_fee)||0)-(r._pph23||0)):''}">${_mrRpFull(r.total_fee)}${(r._pph23||0)>0?'<sup style="color:#3C3489;font-size:9px;margin-left:2px">PPh</sup>':''}</span>` : zeroCell}</td>
      <td style="text-align:right">${hasSales ? `<span style="font-family:var(--mono);font-size:12px;font-weight:600" title="${(r._pph23||0)>0?'Termasuk PPh 23 2% ('+_mrRpFull(r._pph23)+')':''}">${_mrRpFull(r._net_payout_adj)}</span>` : zeroCell}</td>
      <td style="text-align:center">${cells[0]}</td>
      <td style="text-align:center">${cells[1]}</td>
      <td style="text-align:center"><button onclick="event.stopPropagation();mrDownloadPDF('${bid}','${bname}')" style="font-size:11px;padding:3px 10px;background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-family:var(--mono);color:var(--black)" title="Download Marté Sales Report PDF">📄 Sales Report</button></td>
      <td style="text-align:center"><button onclick="event.stopPropagation();mrDownloadInvoice('${bid}','${bname}')" style="font-size:11px;padding:3px 10px;background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-family:var(--mono);color:var(--black)" title="Download Invoice + PAID stamp">📋 Invoice</button></td>
      <td style="text-align:center"><button onclick="event.stopPropagation();mrSendEmail('${bid}','${bname}')" style="font-size:11px;padding:3px 10px;background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-family:var(--mono);color:var(--black)" title="Send summary email ke brand">✉ Send</button></td>
      <td style="text-align:center">${cells[2]}</td>
      <td><button class="btn-edit" onclick="event.stopPropagation();openMRDetail('${bid}','${bname}')">Detail</button></td>
    </tr>`;
  }).join('');
}

// ── Detail modal ──
async function openMRDetail(brandId, brandName) {
  const salesRow = _mrSummary.find(r => r.brand_id === brandId) || null;
  const trkRow   = _mrTracking[brandId] || null;
  _mrModal = { brandId, brandName, salesRow, trkRow, skuData: null };

  // Populate header
  document.getElementById('mr-modal-brand').textContent  = brandName;
  document.getElementById('mr-modal-period').textContent = _mrPeriod;
  document.getElementById('mr-modal-sales').textContent  = salesRow ? _mrRpFull(salesRow.total_sales) : '—';
  document.getElementById('mr-modal-fee').textContent    = salesRow ? _mrRpFull(salesRow.total_fee)   : '—';
  // Net Payout uses adjusted value (includes PPh 23 kept by brand for PT).
  const _adjRow = _mrAllRows.find(x => x.brand_id === brandId);
  document.getElementById('mr-modal-net').textContent    = salesRow ? _mrRpFull(_adjRow?._net_payout_adj ?? salesRow.net_payout) : '—';
  // Inventory from _mrAllRows
  const invRow = _mrAllRows.find(r=>r.brand_id===brandId);
  const fmtQ = n => n>0 ? Math.round(n).toLocaleString('id-ID')+' pcs' : '—';
  document.getElementById('mr-modal-stock-qty').textContent    = fmtQ(invRow?._stock_qty||0);
  document.getElementById('mr-modal-stock-value').textContent  = (invRow?._stock_value||0)>0 ? _mrRpFull(invRow._stock_value) : '—';
  document.getElementById('mr-modal-inbound-total').textContent  = fmtQ(invRow?._inbound_total||0);
  document.getElementById('mr-modal-outbound-total').textContent = fmtQ(invRow?._outbound_total||0);
  const _adjTotEl = document.getElementById('mr-modal-adj-out-total');
  if (_adjTotEl) _adjTotEl.textContent = fmtQ(invRow?._adj_out_total||0);
  document.getElementById('mr-modal-inbound').textContent      = fmtQ(invRow?._inbound_period||0);
  document.getElementById('mr-modal-outbound').textContent     = fmtQ(invRow?._outbound_period||0);
  const _adjPerEl = document.getElementById('mr-modal-adj-out');
  if (_adjPerEl) _adjPerEl.textContent = fmtQ(invRow?._adj_out_period||0);

  // Status cards
  _mrRenderStatusCards(trkRow);

  // Populate form
  // brand_type comes from Brand Master, not editable here
  const bmType = salesRow?._bm_brand_type || _mrAllRows.find(r=>r.brand_id===brandId)?._bm_brand_type || trkRow?.brand_type || '';
  document.getElementById('mr-f-brand-type').value = bmType;
  const btDisp = document.getElementById('mr-f-brand-type-display');
  if(btDisp) btDisp.textContent = bmType || '—';
  document.getElementById('mr-f-report-sent').value = trkRow?.report_sent_at ? new Date(trkRow.report_sent_at).toISOString().slice(0,10) : '';
  document.getElementById('mr-f-inv-no').value      = trkRow?.invoice_number || '';
  document.getElementById('mr-f-inv-date').value    = trkRow?.invoice_date   || '';
  document.getElementById('mr-f-inv-status').value  = trkRow?.invoice_status || '';
  document.getElementById('mr-f-pay-date').value    = trkRow?.payment_received_at ? new Date(trkRow.payment_received_at).toISOString().slice(0,10) : '';
  document.getElementById('mr-f-pay-ref').value     = trkRow?.payment_ref    || '';
  document.getElementById('mr-f-bp-date').value     = trkRow?.bukti_potong_received_at ? new Date(trkRow.bukti_potong_received_at).toISOString().slice(0,10) : '';
  document.getElementById('mr-f-notes').value       = trkRow?.notes          || '';
  document.getElementById('mr-f-feedback').textContent = '';
  _mrToggleBPField();

  // Show overlay
  const ov = document.getElementById('mr-modal-overlay');
  ov.style.display = 'flex';

  // Load SKU detail async
  document.getElementById('mr-sku-loading').style.display = '';
  document.getElementById('mr-sku-wrap').style.display    = 'none';
  _mrLoadSKUDetail(brandId);
}

// 4 read-only status pills for modal status grid + timeline view.
// Order matches the labels used by callers: ① Sales Report, ② Invoice,
// ③ Pembayaran, ④ Bukti Potong. Bukti Potong → N/A untuk non-PT.
function _mrStatusPill(trk) {
  const mk = (ok, label, neutral) => `<span style="display:inline-block;font-size:11px;padding:3px 9px;border-radius:99px;font-family:var(--mono);font-weight:500;background:${neutral?'var(--off)':(ok?'#dcfce7':'var(--off)')};color:${neutral?'var(--g400)':(ok?'#15803d':'var(--g600)')};border:1px solid ${neutral?'var(--g200)':(ok?'#86efac':'var(--g200)')}">${label}</span>`;
  const reportOK = !!trk?.report_sent_at;
  const invOK    = trk?.invoice_status === 'Sent' || trk?.invoice_status === 'Paid';
  const payOK    = !!trk?.payment_received_at;
  const bpOK     = !!(trk?.bukti_potong_received_at || trk?.bukti_potong_file_url);
  const isPT     = (trk?.brand_type || '') === 'PT';
  return [
    mk(reportOK, reportOK ? `✓ Sent · ${_mrShort(trk.report_sent_at)}` : 'Not Started'),
    mk(invOK,    invOK    ? `✓ ${trk.invoice_status}` : 'Not Sent'),
    mk(payOK,    payOK    ? `✓ Paid · ${_mrShort(trk.payment_received_at)}` : 'Not Paid'),
    isPT ? mk(bpOK, bpOK ? `✓ Received${trk.bukti_potong_received_at?` · ${_mrShort(trk.bukti_potong_received_at)}`:''}` : 'Pending') : mk(false, 'N/A · Non-PT', true),
  ];
}

function _mrRenderStatusCards(trk) {
  const pills = _mrStatusPill(trk);
  const labels = ['① Sales Report','② Invoice','③ Pembayaran','④ Bukti Potong'];
  document.getElementById('mr-modal-status-grid').innerHTML = labels.map((lbl,i) =>
    `<div style="border:1px solid var(--g100);border-radius:8px;padding:10px 12px">
      <div style="font-size:11px;color:var(--g400);margin-bottom:6px">${lbl}</div>
      <div>${pills[i]}</div>
    </div>`
  ).join('');
}

function _mrToggleBPField() {
  const tipe = document.getElementById('mr-f-brand-type').value;
  document.getElementById('mr-f-bp-wrap').style.display = tipe==='PT' ? '' : 'none';
}

async function _mrLoadSKUDetail(brandId) {
  if (!_mrPeriod || !brandId) return;
  const [year, month] = _mrPeriod.split('-').map(Number);
  const startISO = `${_mrPeriod}-01T00:00:00+07:00`;
  // endISO = first day of NEXT month at 00:00 WIB. Old impl used `new Date(year,
  // month, 1).toISOString()` which converted to UTC and crossed the date line
  // backwards (May 31 17:00 UTC), making endISO land on May 31 instead of Jun 1
  // → all May 31 transactions silently dropped.
  const _endY = month === 12 ? year + 1 : year;
  const _endM = month === 12 ? 1 : month + 1;
  const endISO   = `${_endY}-${String(_endM).padStart(2,'0')}-01T00:00:00+07:00`;
  const brandName = _mrAllRows.find(r=>r.brand_id===brandId)?.brand_name || brandId;

  const [salesRes, invRes] = await Promise.all([
    sb.rpc('get_marte_brand_detail', { p_brand_id: brandId, p_start_date: startISO, p_end_date: endISO }),
    sb.rpc('get_marte_brand_inventory_sku', { p_brand_id: brandId, p_start_date: startISO, p_end_date: endISO, p_as_of_date: endISO })
  ]);

  if (_mrModal?.brandId !== brandId) return;
  document.getElementById('mr-sku-loading').style.display = 'none';

  const data    = salesRes.data || [];
  const invData = invRes.data  || [];

  if (!data.length && !invData.length) {
    document.getElementById('mr-sku-loading').textContent = salesRes.error ? 'Gagal memuat data.' : 'Tidak ada data SKU.';
    document.getElementById('mr-sku-loading').style.display = '';
    return;
  }

  _mrModal.skuData    = data;
  _mrModal.invSkuData = invData;
  let totQty=0, totSub=0, totFee=0;
  data.forEach(r=>{ totQty+=parseInt(r.total_qty)||0; totSub+=parseFloat(r.subtotal)||0; totFee+=parseFloat(r.fee_amount)||0; });

  const catColor = {Apparel:'#4a90d9',Accessories:'#7b5ea7',Collectible:'#e8a838',Wellness:'#2e9e5a',Preloved:'#c05040',Others:'#888'};
  document.getElementById('mr-sku-tbody').innerHTML = data.map(r => {
    const cc = catColor[r.fee_category]||'#888';
    return `<tr>
      <td style="font-family:var(--mono);font-size:11px">${_escRmd(r.item_code||'')}</td>
      <td style="max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${_escRmd(r.item_name||'')}">${_escRmd(r.item_name||'')}</td>
      <td><span style="font-size:10px;color:${cc};font-weight:600">${r.fee_category||'Others'}</span></td>
      <td style="text-align:right;font-family:var(--mono)">${parseInt(r.total_qty)||0}</td>
      <td style="text-align:right;font-family:var(--mono)">${_mrRp(r.subtotal)}</td>
      <td style="text-align:right;font-family:var(--mono);color:var(--g400)">${parseFloat(r.fee_rate)||0}%</td>
      <td style="text-align:right;font-family:var(--mono);color:#c05">${_mrRp(r.fee_amount)}</td>
    </tr>`;
  }).join('');

  document.getElementById('mr-sku-tfoot').innerHTML = `<tr style="font-weight:600;border-top:2px solid var(--g200)">
    <td colspan="3" style="padding:8px 10px">TOTAL</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px">${totQty}</td>
    <td style="text-align:right;font-family:var(--mono);padding:8px 10px">${_mrRpFull(totSub)}</td>
    <td></td>
    <td style="text-align:right;font-family:var(--mono);color:#c05;padding:8px 10px">${_mrRpFull(totFee)}</td>
  </tr>`;

  document.getElementById('mr-sku-wrap').style.display = '';

  // ── Inventory Movement table ──
  const invWrap = document.getElementById('mr-inv-wrap');
  if (invWrap && invData.length) {
    const totIn   = invData.reduce((s,r)=>s+(parseFloat(r.inbound_total)||0),0);
    const totInP  = invData.reduce((s,r)=>s+(parseFloat(r.inbound_period)||0),0);
    const totOut  = invData.reduce((s,r)=>s+(parseFloat(r.outbound_total)||0),0);
    const totOutP = invData.reduce((s,r)=>s+(parseFloat(r.outbound_period)||0),0);
    const totAdj  = invData.reduce((s,r)=>s+(parseFloat(r.adjustment_out_period)||0),0);
    const totAdjT = invData.reduce((s,r)=>s+(parseFloat(r.adjustment_out_total)||0),0);
    const totNet  = invData.reduce((s,r)=>s+(parseFloat(r.net_stock)||0),0);

    document.getElementById('mr-inv-tbody').innerHTML = invData.map(r=>`<tr>
      <td style="font-family:var(--mono);font-size:10px;color:var(--g400)">${_escRmd(r.item_code||'')}</td>
      <td style="max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:11px" title="${_escRmd(r.item_name||'')}">${_escRmd(r.item_name||'')}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px">${Math.round(r.inbound_total||0)}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px;color:#16a34a">${Math.round(r.inbound_period||0)||'—'}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px">${Math.round(r.outbound_total||0)}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px;color:#ea580c">${Math.round(r.outbound_period||0)||'—'}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px;color:#a66800">${Math.round(r.adjustment_out_period||0)||'—'}</td>
      <td style="text-align:right;font-family:var(--mono);font-size:11px;font-weight:600">${Math.round(r.net_stock||0)}</td>
    </tr>`).join('');

    document.getElementById('mr-inv-tfoot').innerHTML = `<tr style="font-weight:600;border-top:2px solid var(--g200);background:var(--off)">
      <td colspan="2" style="padding:6px 10px">TOTAL</td>
      <td style="text-align:right;font-family:var(--mono);padding:6px 10px">${Math.round(totIn)}</td>
      <td style="text-align:right;font-family:var(--mono);padding:6px 10px;color:#16a34a">${Math.round(totInP)||'—'}</td>
      <td style="text-align:right;font-family:var(--mono);padding:6px 10px">${Math.round(totOut)}</td>
      <td style="text-align:right;font-family:var(--mono);padding:6px 10px;color:#ea580c">${Math.round(totOutP)||'—'}</td>
      <td style="text-align:right;font-family:var(--mono);padding:6px 10px;color:#a66800">${Math.round(totAdj)||'—'}</td>
      <td style="text-align:right;font-family:var(--mono);padding:6px 10px;font-weight:700">${Math.round(totNet)}</td>
    </tr>`;
    invWrap.style.display = '';
  }
}

function closeMRModal(e) {
  if (e && e.target !== document.getElementById('mr-modal-overlay')) return;
  document.getElementById('mr-modal-overlay').style.display = 'none';
  _mrModal = null;
}

// ── Save tracking ──
// ── Inline action handlers for the Consignment Report table ──
// Helpers for the new inline-toggle UI. Each finds (or creates) the
// settlement row for the current brand+period, mutates one field, and
// re-renders. Shared by ① Sales Report toggle, ② Invoice upload/remove,
// ③ Pembayaran toggle.

async function _mrUpsertSettlement(brandId, patch) {
  const r = _mrAllRows.find(x => x.brand_id === brandId);
  if (!r) return null;
  const trk = _mrTracking[brandId];
  const base = {
    brand_id: brandId,
    brand_name: r.brand_name,
    period: _mrPeriod,
    date_range_from: _mrPeriod + '-01',
    date_range_to: new Date(parseInt(_mrPeriod.split('-')[0]), parseInt(_mrPeriod.split('-')[1]), 0).toISOString().slice(0,10),
    total_sales:  parseFloat(r.total_sales) || 0,
    consign_fee:  parseFloat(r.total_fee)   || 0,
    net_to_brand: parseFloat(r.net_payout)  || 0,
    updated_at: new Date().toISOString(),
    updated_by: currentUser,
  };
  const payload = { ...base, ...patch };
  let row = trk;
  if (trk) {
    const { error } = await sb.from('marte_settlements').update(payload).eq('id', trk.id);
    if (error) { alert('Gagal save: '+error.message); return null; }
    row = { ...trk, ...payload };
  } else {
    payload.id = genId('MST');
    payload.created_by = currentUser;
    payload.created_at = new Date().toISOString();
    const { error } = await sb.from('marte_settlements').insert(payload);
    if (error) { alert('Gagal save: '+error.message); return null; }
    row = payload;
  }
  _mrTracking[brandId] = row;
  _mrRenderTable();
  return row;
}

async function mrToggleReport(brandId) {
  const trk = _mrTracking[brandId];
  const newVal = trk?.report_sent_at ? null : new Date().toISOString();
  await _mrUpsertSettlement(brandId, { report_sent_at: newVal });
}

async function mrTogglePayment(brandId) {
  const trk = _mrTracking[brandId];
  const newVal = trk?.payment_received_at ? null : new Date().toISOString();
  await _mrUpsertSettlement(brandId, { payment_received_at: newVal });
}

async function mrUploadBP(brandId, inputEl) {
  const f = inputEl?.files?.[0];
  if (!f) return;
  inputEl.disabled = true;
  try {
    const safeName = f.name.replace(/[^a-zA-Z0-9._-]+/g,'_');
    const path = `bp/${_mrPeriod}/${brandId}_${Date.now()}_${safeName}`.replace(/[^a-zA-Z0-9./_-]+/g, '_');
    const { error: upErr } = await sb.storage.from('marte-invoices').upload(path, f, { contentType: f.type, upsert: false });
    if (upErr) throw upErr;
    const { data: pub } = sb.storage.from('marte-invoices').getPublicUrl(path);
    await _mrUpsertSettlement(brandId, {
      bukti_potong_file_url: pub.publicUrl,
      // Auto-fill received timestamp when first uploaded so the date field +
      // bukti_potong pill flip green tanpa harus buka modal manually.
      bukti_potong_received_at: _mrTracking[brandId]?.bukti_potong_received_at || new Date().toISOString(),
    });
  } catch (e) { alert('Upload gagal: '+(e.message||e)); }
  finally { inputEl.disabled = false; inputEl.value = ''; }
}

async function mrRemoveBP(brandId) {
  if (!confirm('Hapus file bukti potong yang sudah diupload?')) return;
  await _mrUpsertSettlement(brandId, { bukti_potong_file_url: null });
}

// PDF + Email actions — summary buat finance + brand. Includes both period
// metrics (inbound/terjual selama bulan ini) AND all-time totals + current
// stock so the brand sees the full movement picture, not just bulan ini.
function _mrSummaryText(brandId, brandName) {
  const r = _mrAllRows.find(x => x.brand_id === brandId);
  if (!r) return null;
  const trk = _mrTracking[brandId] || {};
  const fmt = n => 'Rp ' + Math.round(Number(n)||0).toLocaleString('id-ID');
  const pcs = n => Math.round(Number(n)||0).toLocaleString('id-ID') + ' pcs';
  // Period label "2026-06" → "Juni 2026" — more natural in Indonesian email.
  const monthNames = ['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  let periodLabel = _mrPeriod;
  const m = /^(\d{4})-(\d{2})$/.exec(_mrPeriod || '');
  if (m) {
    const mIdx = parseInt(m[2],10) - 1;
    if (mIdx >= 0 && mIdx < 12) periodLabel = `${monthNames[mIdx]} ${m[1]}`;
  }
  // PPh 23 2% withholding for PT brands. Brand keeps the 2% portion (to remit
  // to gov't on our behalf), so net payout grows by the pph amount. Non-PT:
  // no withholding, net payout = total_sales − total_fee.
  const brandType = r._bm_brand_type || trk.brand_type || '';
  const isPT      = brandType === 'PT';
  const grossNum  = parseFloat(r.total_sales) || 0;
  const feeNum    = parseFloat(r.total_fee)   || 0;
  const rawNet    = parseFloat(r.net_payout)  || 0;
  const pphNum    = isPT ? Math.round(feeNum * 0.02) : 0;
  const netNum    = rawNet + pphNum;
  return {
    brandName,
    brandType,
    isPT,
    period:     _mrPeriod,
    periodLabel,
    grossNum,
    feeNum,
    pphNum,
    netNum,
    rawNet,
    gross:      fmt(grossNum),
    fee:        fmt(feeNum),
    pph:        fmt(pphNum),
    net:        fmt(netNum),
    netRaw:     fmt(rawNet),
    inboundPer: pcs(r._inbound_period),
    soldPer:    pcs(r._outbound_period),
    soldAll:    pcs(r._outbound_total),
    stockNow:   pcs(r._stock_qty),
    adjOutPer:  pcs(r._adj_out_period),
    invUrl:     trk.invoice_file_url || '',
    reportSent: trk.report_sent_at,
    paid:       trk.payment_received_at,
  };
}

async function mrDownloadPDF(brandId, brandName) {
  const s = _mrSummaryText(brandId, brandName);
  if (!s) { alert('Brand tidak ditemukan'); return; }
  const r = _mrAllRows.find(x => x.brand_id === brandId);

  // Inventory summary numbers
  const fmt = n => Math.round(Number(n)||0).toLocaleString('id-ID');
  const totalInbound  = fmt(r?._inbound_total || 0);
  const inboundPer    = fmt(r?._inbound_period || 0);
  const soldPer       = fmt(r?._outbound_period || 0);
  const totalSold     = fmt(r?._outbound_total || 0);
  const currentStock  = fmt(r?._stock_qty || 0);

  // Fetch per-SKU breakdown (sales + inventory all-time). Same RPCs as the
  // detail modal. Sales table = SKU yang kejual periode ini. Inventory
  // movement table = semua SKU dengan all-time totals.
  let soldRowsHtml = '', soldFootHtml = '';
  let invRowsHtml = '', invFootHtml = '';
  let soldHeaderCount = '0 SKU TERJUAL · 0 PCS';
  let invHeaderCount  = '0 SKU · 0 PCS CURRENT STOCK';
  try {
    const [year, month] = _mrPeriod.split('-').map(Number);
    const startISO = `${_mrPeriod}-01T00:00:00+07:00`;
    // endISO = first day of NEXT month at 00:00 WIB. Old impl used `new Date(year,
  // month, 1).toISOString()` which converted to UTC and crossed the date line
  // backwards (May 31 17:00 UTC), making endISO land on May 31 instead of Jun 1
  // → all May 31 transactions silently dropped.
  const _endY = month === 12 ? year + 1 : year;
  const _endM = month === 12 ? 1 : month + 1;
  const endISO   = `${_endY}-${String(_endM).padStart(2,'0')}-01T00:00:00+07:00`;
    const [salesRes, invRes] = await Promise.all([
      sb.rpc('get_marte_brand_detail',         { p_brand_id: brandId, p_start_date: startISO, p_end_date: endISO }),
      sb.rpc('get_marte_brand_inventory_sku',  { p_brand_id: brandId, p_start_date: startISO, p_end_date: endISO, p_as_of_date: endISO }),
    ]);
    const sales = (salesRes.data || []).filter(x => (parseInt(x.total_qty)||0) > 0);
    const inv   = invRes.data   || [];
    const fmtRp = n => 'Rp ' + Math.round(Number(n)||0).toLocaleString('id-ID');

    // ── Table 1: Product Sold During Period ──
    // Total row lives INSIDE tbody with a tr.total class so it renders
    // exactly once even when the table breaks across pages. Browser
    // print engines repeat <tfoot> on every page break — that was the
    // earlier 'TOTAL muncul 2x' bug.
    if (sales.length) {
      const sorted = [...sales].sort((a,b) => (a.item_code||'').localeCompare(b.item_code||''));
      const totQty = sorted.reduce((a,x)=>a+(parseInt(x.total_qty)||0), 0);
      const totRev = sorted.reduce((a,x)=>a+(parseFloat(x.subtotal)||0), 0);
      soldHeaderCount = `${sorted.length} SKU TERJUAL · ${totQty} PCS`;
      soldRowsHtml = sorted.map(x => `<tr>
        <td class="sku-code">${_escRmd(x.item_code||'')}</td>
        <td>${_escRmd(x.item_name||'')}</td>
        <td class="sku-num">${parseInt(x.total_qty)||0}</td>
        <td class="sku-num">${fmtRp(x.subtotal)}</td>
      </tr>`).join('')
      + `<tr class="total"><td colspan="2">TOTAL</td><td class="sku-num">${totQty}</td><td class="sku-num">${fmtRp(totRev)}</td></tr>`;
    } else {
      soldRowsHtml = `<tr><td colspan="4" class="sku-empty">Tidak ada penjualan di periode ini.</td></tr>`;
    }

    // ── Table 2: Inventory Movement (all-time) ──
    if (inv.length) {
      const sorted = [...inv].sort((a,b) => (a.item_code||'').localeCompare(b.item_code||''));
      const tIn   = sorted.reduce((a,x)=>a+(parseFloat(x.inbound_total)||0), 0);
      const tOut  = sorted.reduce((a,x)=>a+(parseFloat(x.outbound_total)||0), 0);
      const tAdj  = sorted.reduce((a,x)=>a+(parseFloat(x.adjustment_out_total)||0), 0);
      const tStk  = sorted.reduce((a,x)=>a+(parseFloat(x.net_stock)||0), 0);
      invHeaderCount = `${sorted.length} SKU · ${Math.round(tStk).toLocaleString('id-ID')} PCS CURRENT STOCK`;
      invRowsHtml = sorted.map(x => `<tr>
        <td class="sku-code">${_escRmd(x.item_code||'')}</td>
        <td>${_escRmd(x.item_name||'')}</td>
        <td class="sku-num">${Math.round(x.inbound_total)||'—'}</td>
        <td class="sku-num">${Math.round(x.outbound_total)||'—'}</td>
        <td class="sku-num">${Math.round(x.adjustment_out_total)||'—'}</td>
        <td class="sku-num">${Math.round(x.net_stock||0).toLocaleString('id-ID')}</td>
      </tr>`).join('')
      + `<tr class="total"><td colspan="2">TOTAL</td>
        <td class="sku-num">${Math.round(tIn)}</td>
        <td class="sku-num">${Math.round(tOut)}</td>
        <td class="sku-num">${Math.round(tAdj)||'—'}</td>
        <td class="sku-num">${Math.round(tStk).toLocaleString('id-ID')}</td></tr>`;
    } else {
      invRowsHtml = `<tr><td colspan="6" class="sku-empty">Tidak ada data inventory.</td></tr>`;
    }
  } catch (e) {
    soldRowsHtml = `<tr><td colspan="4" class="sku-empty">Gagal memuat: ${_escRmd(e.message||String(e))}</td></tr>`;
    invRowsHtml = `<tr><td colspan="6" class="sku-empty">Gagal memuat: ${_escRmd(e.message||String(e))}</td></tr>`;
  }

  // Marté brand logo — absolute URL so it loads inside the new window
  // (window.open('', '_blank') has no base URL, relative paths fail).
  const LOGO_URL = 'https://sentragroup.github.io/sentra-portal/assets/logo-marte.png';

  const w = window.open('', '_blank');
  if (!w) { alert('Pop-up diblokir browser'); return; }
  w.document.write(`<!doctype html><html lang="id"><head><meta charset="utf-8">
    <title>Consignment Report · ${s.brandName} · ${s.periodLabel}</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Bagel+Fat+One&family=Fredoka:wght@400;500;600;700&family=Inter:wght@400;500;600;700&family=Space+Mono:wght@400;700&display=swap" rel="stylesheet">
    <style>
      :root {
        --cream:#F1F0D4; --yellow:#FCEE18; --green:#06911A; --green-deep:#0C731A;
        --blue:#0201FD; --red:#ED2024; --ink:#111111; --white:#FFFFFF;
        --font-display:"Bagel Fat One","Fredoka",system-ui,sans-serif;
        --font-mono:"Space Mono","JetBrains Mono",monospace;
        --font-body:"Inter","Space Grotesk",system-ui,sans-serif;
        --radius:20px; --border:4px;
      }
      *{box-sizing:border-box}
      html,body{margin:0;padding:0;background:var(--cream);color:var(--ink);font-family:var(--font-body);font-size:16px;line-height:1.5;-webkit-font-smoothing:antialiased}
      .page{position:relative;max-width:820px;margin:0 auto;padding:36px 56px 80px;overflow:hidden}
      .wedge{position:absolute;top:-120px;right:-120px;width:380px;height:380px;background:var(--yellow);transform:rotate(18deg);z-index:0;pointer-events:none}

      .brand-bar{display:flex;align-items:center;justify-content:space-between;padding-bottom:20px;border-bottom:3px solid var(--blue);margin-bottom:32px;position:relative;z-index:1}
      .brand-bar img{height:32px;width:auto}
      .brand-bar .doc-title{font-family:var(--font-mono);color:var(--blue);text-transform:uppercase;letter-spacing:0.14em;font-size:12px;font-weight:700}

      .kicker{font-family:var(--font-mono);text-transform:uppercase;letter-spacing:0.12em;color:var(--blue);font-size:12px;font-weight:700;position:relative;z-index:1}
      h1{font-family:var(--font-display);font-weight:400;color:var(--green);font-size:88px;line-height:.95;margin:8px 0 6px;letter-spacing:-0.02em;position:relative;z-index:1}
      .h-sub{font-family:var(--font-mono);color:var(--blue);font-size:14px;text-transform:uppercase;letter-spacing:0.08em;font-weight:700;position:relative;z-index:1;margin-bottom:40px}

      .section-title{font-family:var(--font-mono);color:var(--red);text-transform:uppercase;letter-spacing:0.12em;font-weight:700;font-size:14px;line-height:1;margin:0 0 16px;position:relative;z-index:1}
      .section-title::before{content:"★ "}
      .page-break{break-before:page;page-break-before:always}

      /* 5 stat blocks */
      .stat-row{display:grid;grid-template-columns:repeat(5,1fr);gap:14px;margin-bottom:48px;position:relative;z-index:1}
      .stat{background:var(--white);border:var(--border) solid var(--green-deep);border-radius:var(--radius);padding:16px 14px}
      .stat-num{font-family:var(--font-display);color:var(--ink);font-size:40px;line-height:1;letter-spacing:-0.02em}
      .stat-lbl{font-family:var(--font-mono);color:var(--blue);text-transform:uppercase;letter-spacing:0.06em;font-size:10px;font-weight:700;margin-top:10px;line-height:1.3}

      /* Financial yellow panel */
      .panel{background:var(--yellow);border:var(--border) solid var(--green-deep);border-radius:var(--radius);overflow:hidden;margin-bottom:48px;position:relative;z-index:1}
      .panel-header{background:var(--green-deep);color:var(--white);font-family:var(--font-mono);font-weight:700;text-transform:uppercase;letter-spacing:0.1em;font-size:13px;padding:10px 20px}
      .panel-body{padding:20px 24px}
      .row{display:flex;justify-content:space-between;align-items:baseline;padding:10px 0;border-bottom:2px solid var(--green-deep)}
      .row:last-child{border-bottom:0}
      .row .k{font-family:var(--font-body);color:var(--ink);font-size:14px;font-weight:500}
      .row .v{font-family:var(--font-mono);color:var(--ink);font-weight:700;font-size:15px}
      .row.big .k{font-size:16px;font-weight:700}
      .row.big .v{font-family:var(--font-display);font-size:32px;letter-spacing:-0.02em}

      /* Action Required panel */
      .action{background:var(--yellow);border:var(--border) solid var(--ink);border-radius:var(--radius);padding:24px 28px;margin-bottom:48px;position:relative;z-index:1}
      .action-eyebrow{font-family:var(--font-mono);color:var(--red);text-transform:uppercase;letter-spacing:0.12em;font-size:12px;font-weight:700;margin-bottom:12px}
      .action-body{font-family:var(--font-body);font-size:18px;line-height:1.5;color:var(--ink);font-weight:600}
      .action-body .amount{color:var(--green);font-weight:700}

      /* SKU panel + table */
      .sku-panel{background:var(--white);border:var(--border) solid var(--blue);border-radius:var(--radius);overflow:hidden;margin-bottom:48px;position:relative;z-index:1}
      .sku-panel .panel-header{background:var(--blue);color:var(--yellow)}
      .sku-table{width:100%;border-collapse:collapse}
      .sku-table th{font-family:var(--font-mono);font-size:11px;text-transform:uppercase;letter-spacing:0.08em;color:var(--blue);font-weight:700;text-align:left;padding:12px 16px;border-bottom:2px solid var(--ink)}
      .sku-table th:nth-child(n+3){text-align:right}
      .sku-table td{padding:12px 16px;border-bottom:1px solid var(--cream);font-size:13px;vertical-align:top}
      .sku-table .sku-code{font-family:var(--font-mono);font-weight:700;color:var(--blue);font-size:11px;white-space:nowrap}
      .sku-table .sku-num{font-family:var(--font-mono);text-align:right;font-weight:700}
      .sku-table tr.total td{background:var(--yellow);border-top:3px solid var(--ink);border-bottom:0;font-family:var(--font-display);font-weight:400;font-size:18px;padding:14px 16px}
      .sku-empty{text-align:center;color:var(--green-deep);padding:24px 16px;font-style:italic;font-family:var(--font-body)}

      /* Footer with logo */
      .footer{display:flex;justify-content:space-between;align-items:center;padding-top:24px;border-top:3px solid var(--blue);position:relative;z-index:1}
      .footer img{height:28px;width:auto}
      .footer-label{font-family:var(--font-mono);color:var(--blue);text-transform:uppercase;letter-spacing:0.12em;font-size:12px;font-weight:700}

      @page{margin:0;size:A4}
      @media print{.page{padding:32px 40px 56px}}
    </style></head><body>
    <div class="page">
      <div class="wedge"></div>

      <div class="brand-bar">
        <img src="${LOGO_URL}" alt="Marté" crossorigin="anonymous">
        <div class="doc-title">Consignment Report</div>
      </div>

      <div class="kicker">For Brand${s.brandType?` · ${_escRmd(s.brandType)}`:''}</div>
      <h1>${_escRmd(s.brandName)}</h1>
      <div class="h-sub">${_escRmd(s.periodLabel)} · Marté General Store</div>

      <h2 class="section-title">Financial</h2>
      <div class="panel">
        <div class="panel-header">Period ${_escRmd(s.period)}</div>
        <div class="panel-body">
          <div class="row"><span class="k">Gross Sales</span><span class="v">${s.gross}</span></div>
          <div class="row"><span class="k">Konsinyasi Fee</span><span class="v">−${s.fee}</span></div>
          ${s.isPT ? `<div class="row"><span class="k">PPh 23 (2%)</span><span class="v">+${s.pph}</span></div>` : ''}
          <div class="row big"><span class="k">Net Payout</span><span class="v">${s.net}</span></div>
        </div>
      </div>

      ${s.isPT
        ? `<div class="action">
             <div class="action-eyebrow">★ Action Required</div>
             <div class="action-body">Mohon dari ${_escRmd(s.brandName)} untuk mengirimkan <strong>bukti potong PPh 23</strong> sebesar <span class="amount">${s.pph}</span> atas jasa consignment fee (${s.fee}).</div>
           </div>`
        : ''}

      <h2 class="section-title">Inventory</h2>
      <div class="stat-row">
        <div class="stat"><div class="stat-num">${totalInbound}</div><div class="stat-lbl">Total Inbound</div></div>
        <div class="stat"><div class="stat-num">${inboundPer}</div><div class="stat-lbl">Inbound (Periode)</div></div>
        <div class="stat"><div class="stat-num">${soldPer}</div><div class="stat-lbl">Terjual (Periode)</div></div>
        <div class="stat"><div class="stat-num">${totalSold}</div><div class="stat-lbl">Total Terjual</div></div>
        <div class="stat"><div class="stat-num">${currentStock}</div><div class="stat-lbl">Current Stock</div></div>
      </div>

      <h2 class="section-title page-break">Product Sold During Period</h2>
      <div class="sku-panel">
        <div class="panel-header">${soldHeaderCount}</div>
        <table class="sku-table">
          <thead><tr><th>SKU</th><th>Nama Item</th><th>Qty</th><th>Gross Sales</th></tr></thead>
          <tbody>${soldRowsHtml}</tbody>
        </table>
      </div>

      <h2 class="section-title page-break">Inventory Movement (All Time)</h2>
      <div class="sku-panel">
        <div class="panel-header">${invHeaderCount}</div>
        <table class="sku-table">
          <thead><tr><th>SKU</th><th>Nama Item</th><th>Total Inbound</th><th>Total Sold</th><th>Total Adj OUT</th><th>Stock Now</th></tr></thead>
          <tbody>${invRowsHtml}</tbody>
        </table>
      </div>

      <div class="footer">
        <img src="${LOGO_URL}" alt="Marté" crossorigin="anonymous">
        <span class="footer-label">Consignment Report</span>
      </div>
    </div>
    <script>window.onload=()=>setTimeout(()=>window.print(),600)<\/script>
    </body></html>`);
  w.document.close();
}

// Generate an Indonesian-format consignment invoice for the brand. Issuer is
// PT Sandang Dunia Yuwana (Marté's parent). One line item with description
// 'Consignment Fee Marte <Brand> <Period>'. PAID stamp rendered as a rotated
// red bordered block on the signature panel — looks like a stamped invoice
// even though it's print-to-PDF only.
async function mrDownloadInvoice(brandId, brandName) {
  const s = _mrSummaryText(brandId, brandName);
  if (!s) { alert('Brand tidak ditemukan'); return; }

  const today = new Date();
  const dd = String(today.getDate()).padStart(2,'0');
  const mm = String(today.getMonth()+1).padStart(2,'0');
  const yyyy = today.getFullYear();
  const monthNames = ['Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];

  // Invoice number: SDY-INV-{YYMM of period}-{deterministic seq from brand id}
  const periodMatch = /^(\d{4})-(\d{2})$/.exec(s.period || '');
  const periodYY = periodMatch ? periodMatch[1].slice(-2) : String(yyyy).slice(-2);
  const periodMM = periodMatch ? periodMatch[2] : mm;
  const brandSeq = String(brandId).split('').reduce((a,c)=>a + c.charCodeAt(0), 0) % 100;
  const seqStr = String(brandSeq).padStart(2,'0');
  const invoiceNo = `SDY-INV-${periodYY}${periodMM}-${seqStr}-01`;

  // Invoice = tagihan jasa consignment ke brand. Subtotal = Total = full
  // consignment fee (30% × gross). PPh 23 (kalau brand PT) gak ditampilin
  // di invoice — mereka tau sendiri pasti potongannya berapa.
  const subtotalNum = s.feeNum || 0;
  const subtotalStr = 'Rp ' + Math.round(subtotalNum).toLocaleString('id-ID');

  // Terbilang — Indonesian number to words
  const terbilang = (n) => {
    const a = ['','satu','dua','tiga','empat','lima','enam','tujuh','delapan','sembilan','sepuluh','sebelas'];
    n = Math.round(Math.abs(n));
    if (n < 12) return a[n];
    if (n < 20) return a[n - 10] + ' belas';
    if (n < 100) return a[Math.floor(n/10)] + ' puluh' + (n % 10 ? ' ' + a[n % 10] : '');
    if (n < 200) return 'seratus' + (n - 100 ? ' ' + terbilang(n - 100) : '');
    if (n < 1000) return a[Math.floor(n/100)] + ' ratus' + (n % 100 ? ' ' + terbilang(n % 100) : '');
    if (n < 2000) return 'seribu' + (n - 1000 ? ' ' + terbilang(n - 1000) : '');
    if (n < 1000000) return terbilang(Math.floor(n/1000)) + ' ribu' + (n % 1000 ? ' ' + terbilang(n % 1000) : '');
    if (n < 1000000000) return terbilang(Math.floor(n/1000000)) + ' juta' + (n % 1000000 ? ' ' + terbilang(n % 1000000) : '');
    return terbilang(Math.floor(n/1000000000)) + ' milyar' + (n % 1000000000 ? ' ' + terbilang(n % 1000000000) : '');
  };
  const terbilangStr = (terbilang(subtotalNum) + ' rupiah').replace(/\b\w/g, c => c.toUpperCase());

  const description = `Consignment Fee Marte ${s.brandName} ${s.periodLabel}`;

  const LOGO_URL = 'https://sentragroup.github.io/sentra-portal/assets/logo-marte.png';

  const w = window.open('', '_blank');
  if (!w) { alert('Pop-up diblokir browser'); return; }
  w.document.write(`<!doctype html><html lang="id"><head><meta charset="utf-8">
    <title>Invoice ${invoiceNo} · ${s.brandName}</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Space+Mono:wght@400;700&display=swap" rel="stylesheet">
    <style>
      *{box-sizing:border-box}
      html,body{margin:0;padding:0;background:#fff;color:#111;font-family:'Inter',system-ui,sans-serif;font-size:13px;line-height:1.5;-webkit-font-smoothing:antialiased}
      .page{max-width:780px;margin:0 auto;padding:48px 56px;position:relative}

      .top{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #111;padding-bottom:20px;margin-bottom:32px}
      .issuer{max-width:420px}
      .issuer img{height:38px;margin-bottom:10px}
      .issuer h2{margin:0 0 4px;font-size:15px;font-weight:700}
      .issuer p{margin:0;font-size:11px;color:#333;line-height:1.5}
      .doc-meta{text-align:right}
      .doc-meta h1{margin:0;font-family:'Space Mono',monospace;font-size:28px;letter-spacing:0.1em;color:#111;font-weight:700}
      .doc-meta .label{font-family:'Space Mono',monospace;font-size:10px;text-transform:uppercase;letter-spacing:0.1em;color:#666;margin-top:8px}
      .doc-meta .val{font-family:'Space Mono',monospace;font-size:13px;font-weight:700;color:#111;margin-top:2px}

      .recipient{margin-bottom:32px;padding:14px 18px;background:#f7f6f0;border-radius:8px}
      .recipient .lbl{font-family:'Space Mono',monospace;font-size:10px;text-transform:uppercase;letter-spacing:0.1em;color:#666;margin-bottom:4px}
      .recipient .name{font-size:18px;font-weight:700;color:#111}
      .recipient .sub{font-size:12px;color:#555;margin-top:2px}

      table.line{width:100%;border-collapse:collapse;margin-bottom:24px}
      table.line th{font-family:'Space Mono',monospace;font-size:10px;text-transform:uppercase;letter-spacing:0.1em;color:#666;font-weight:700;text-align:left;padding:10px 12px;border-bottom:2px solid #111}
      table.line th.r{text-align:right}
      table.line td{padding:14px 12px;border-bottom:1px solid #e5e5e5;vertical-align:top;font-size:13px}
      table.line td.r{text-align:right;font-family:'Space Mono',monospace;font-weight:700}
      table.line td.no{font-family:'Space Mono',monospace;color:#666;width:36px}
      table.line td.qty{text-align:center;font-family:'Space Mono',monospace;width:60px}

      .totals{display:flex;justify-content:flex-end;margin-bottom:24px}
      .totals table{border-collapse:collapse;min-width:260px}
      .totals td{padding:8px 14px;font-size:13px}
      .totals td.k{color:#555}
      .totals td.v{font-family:'Space Mono',monospace;text-align:right;font-weight:700}
      .totals tr.grand td{border-top:2px solid #111;font-size:16px;padding-top:14px}
      .totals tr.grand td.k{font-weight:700;color:#111}

      .terbilang{padding:14px 18px;background:#f7f6f0;border-radius:8px;font-size:12px;margin-bottom:32px}
      .terbilang strong{font-weight:700}

      .bank{margin-bottom:48px}
      .bank .lbl{font-family:'Space Mono',monospace;font-size:10px;text-transform:uppercase;letter-spacing:0.1em;color:#666;margin-bottom:8px}
      .bank table{border-collapse:collapse;font-size:12px}
      .bank td{padding:4px 12px 4px 0;color:#333}
      .bank td.k{color:#666;width:120px}

      .sign-row{display:grid;grid-template-columns:1fr 1fr;gap:48px;margin-top:48px}
      .sign{position:relative;text-align:center;min-height:140px}
      .sign .role{font-family:'Space Mono',monospace;font-size:10px;text-transform:uppercase;letter-spacing:0.1em;color:#666;margin-bottom:74px}
      .sign .line{border-top:1px solid #111;padding-top:6px;font-size:12px;font-weight:600}

      /* PAID stamp — rotated red bordered block, looks like a rubber stamp */
      .stamp{
        position:absolute;
        top:14px;
        left:50%;
        transform:translateX(-50%) rotate(-12deg);
        border:4px double #c0392b;
        color:#c0392b;
        font-family:'Space Mono',monospace;
        font-weight:700;
        font-size:36px;
        letter-spacing:0.08em;
        padding:8px 24px;
        border-radius:8px;
        opacity:0.92;
        background:rgba(255,255,255,0.4);
        pointer-events:none;
      }
      .stamp .meta{display:block;font-size:9px;letter-spacing:0.18em;font-weight:700;margin-top:2px}

      .footer{margin-top:48px;padding-top:16px;border-top:1px solid #e5e5e5;display:flex;justify-content:space-between;align-items:center;font-size:11px;color:#666}
      .footer .left{font-family:'Space Mono',monospace;letter-spacing:0.06em;text-transform:uppercase}

      @page{margin:0;size:A4}
      @media print{.page{padding:36px 48px}}
    </style></head><body>
    <div class="page">

      <div class="top">
        <div class="issuer">
          <img src="${LOGO_URL}" alt="Marté">
          <h2>PT Sandang Dunia Yuwana</h2>
          <p>M Bloc, Jl. Panglima Polim No.37<br>Jakarta Selatan 12160</p>
        </div>
        <div class="doc-meta">
          <h1>INVOICE</h1>
          <div class="label">No. Invoice</div>
          <div class="val">${invoiceNo}</div>
          <div class="label">Tanggal</div>
          <div class="val">${dd} ${monthNames[parseInt(mm,10)-1]} ${yyyy}</div>
        </div>
      </div>

      <div class="recipient">
        <div class="lbl">Kepada</div>
        <div class="name">${_escRmd(s.brandName)}</div>
        <div class="sub">Mitra Konsinyasi Marté General Store</div>
      </div>

      <table class="line">
        <thead>
          <tr>
            <th>No</th>
            <th>Keterangan</th>
            <th class="r">Qty</th>
            <th class="r">Jumlah</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td class="no">1</td>
            <td>${_escRmd(description)}</td>
            <td class="qty">1</td>
            <td class="r">${subtotalStr}</td>
          </tr>
        </tbody>
      </table>

      <div class="totals">
        <table>
          <tr><td class="k">Subtotal</td><td class="v">${subtotalStr}</td></tr>
          <tr class="grand"><td class="k">Total</td><td class="v">${subtotalStr}</td></tr>
        </table>
      </div>

      <div class="terbilang"><strong>Terbilang:</strong> ${terbilangStr}</div>

      <div class="bank">
        <div class="lbl">Informasi Pajak</div>
        <table>
          <tr><td class="k">NPWP</td><td>63.875.986.0-021.000</td></tr>
          <tr><td class="k">A/N</td><td>PT Sandang Dunia Yuwana</td></tr>
        </table>
      </div>

      <div class="sign-row" style="grid-template-columns:1fr;justify-items:end">
        <div class="sign" style="max-width:320px;width:100%">
          <div class="role">Hormat Kami</div>
          <div class="stamp">PAID<span class="meta">${dd}/${mm}/${yyyy}</span></div>
          <div class="line">PT Sandang Dunia Yuwana</div>
        </div>
      </div>

      <div class="footer">
        <span class="left">Consignment Invoice · Sentra</span>
        <span>Generated ${new Date().toLocaleString('id-ID')}</span>
      </div>

    </div>
    <script>window.onload=()=>setTimeout(()=>window.print(),500)<\/script>
    </body></html>`);
  w.document.close();
}

function mrSendEmail(brandId, brandName) {
  const s = _mrSummaryText(brandId, brandName);
  if (!s) { alert('Brand tidak ditemukan'); return; }
  const bm = (allBMRows||[]).find(b => (b.name||'').toLowerCase().trim() === (brandName||'').toLowerCase().trim());
  const email = bm?.email || '';
  if (!email) {
    if (!confirm(`Email brand belum di-set di Brand Master.\nLanjut buka draft email (tanpa to)?`)) return;
  }
  // periodLabel = "Mei 2026" → ambil nama bulan aja buat subject.
  const monthOnly = (s.periodLabel || '').split(' ')[0] || s.periodLabel;
  const subject = s.isPT
    ? `Laporan Penjualan ${monthOnly} & Invoice Consignment Fee — ${s.brandName} × Marté`
    : `Laporan Penjualan ${monthOnly} & Consignment Fee — ${s.brandName} × Marté`;

  const lines = [];
  lines.push(`Halo Tim ${s.brandName},`, ``);
  lines.push(`Semoga selalu dalam keadaan baik.`, ``);

  if (s.isPT) {
    lines.push(
      `Bersama email ini kami lampirkan laporan penjualan produk ${s.brandName} yang dititipkan secara konsinyasi di Marté untuk periode ${s.periodLabel}, beserta invoice consignment fee dari Marté.`,
      ``,
      `Invoice consignment fee terlampir tidak memerlukan pembayaran — nilainya sudah kami potong langsung dari hasil penjualan, sehingga telah tercermin pada nominal "Total Net Receive" di laporan. Invoice tersebut hanya menjadi dasar bagi ${s.brandName} untuk menerbitkan bukti potong PPh 2% atas jasa konsinyasi.`,
      ``,
      `Mohon bantuannya untuk menerbitkan bukti potong atas invoice tersebut. Dana sebesar "Total Net Receive" akan kami transfer ke rekening ${s.brandName} pada jadwal pembayaran kami, yaitu Kamis terdekat dari tanggal 15.`,
      ``,
    );
  } else {
    lines.push(
      `Bersama email ini kami lampirkan laporan penjualan produk ${s.brandName} yang dititipkan secara konsinyasi di Marté untuk periode ${s.periodLabel}, beserta invoice consignment fee dari Marté sebagai rincian.`,
      ``,
      `Invoice consignment fee terlampir tidak memerlukan pembayaran maupun penerbitan bukti potong — nilainya sudah kami potong langsung dari hasil penjualan, sehingga telah tercermin pada nominal "Total Net Receive" di laporan.`,
      ``,
      `Dana sebesar "Total Net Receive" akan kami transfer ke rekening ${s.brandName} pada jadwal pembayaran kami, yaitu Kamis terdekat dari tanggal 15. Untuk kewajiban perpajakan, masing-masing pihak menanggung kewajibannya sendiri.`,
      ``,
    );
  }

  // Ringkasan finansial — column-aligned plain text, readable di Gmail draft.
  lines.push(
    `Ringkasan ${s.periodLabel}:`,
    `  Gross Sales          : ${s.gross}`,
    `  Consignment Fee      : -${s.fee}`,
  );
  if (s.isPT) lines.push(`  PPh 23 (2%)          : +${s.pph}`);
  lines.push(
    `  Total Net Receive    : ${s.net}`,
    ``,
  );

  lines.push(
    `Apabila ada pertanyaan atau memerlukan informasi tambahan, jangan ragu menghubungi kami — dengan senang hati kami bantu.`,
    ``,
    `Terima kasih atas kerja samanya.`,
    ``,
    `Salam hangat,`,
    `Tim Marté`,
    `Marté General Store · Aulia@suneatercoven.com · +62 857-7519-1850`,
  );

  const body = lines.join('\n');
  // Buka Gmail web compose di tab baru — bypass default mail app handler
  // (Outlook/Apple Mail). Pakai `window.open` supaya gak nge-replace tab
  // portal yang lagi dipake.
  const gmailUrl = `https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(email)}&su=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  window.open(gmailUrl, '_blank');
}

async function saveMRTracking() {
  if (!_mrModal) return;
  const fb = document.getElementById('mr-f-feedback');
  fb.textContent=''; fb.className='feedback';

  const brandType  = document.getElementById('mr-f-brand-type').value;
  const reportSent = document.getElementById('mr-f-report-sent').value;
  const invNo      = document.getElementById('mr-f-inv-no').value.trim();
  const invDate    = document.getElementById('mr-f-inv-date').value;
  const invStatus  = document.getElementById('mr-f-inv-status').value;
  const payDate    = document.getElementById('mr-f-pay-date').value;
  const payRef     = document.getElementById('mr-f-pay-ref').value.trim();
  const bpDate     = document.getElementById('mr-f-bp-date').value;
  const notes      = document.getElementById('mr-f-notes').value.trim();

  const { brandId, brandName, salesRow, trkRow } = _mrModal;

  const payload = {
    brand_id:                 brandId,
    brand_name:               brandName,
    period:                   _mrPeriod,
    date_range_from:          _mrPeriod + '-01',
    date_range_to:            new Date(parseInt(_mrPeriod.split('-')[0]), parseInt(_mrPeriod.split('-')[1]), 0).toISOString().slice(0,10),
    brand_type:               brandType || null,
    total_sales:              parseFloat(salesRow?.total_sales) || 0,
    consign_fee:              parseFloat(salesRow?.total_fee)   || 0,
    net_to_brand:             parseFloat(salesRow?.net_payout)  || 0,
    report_sent_at:           reportSent ? reportSent+'T00:00:00+07:00' : null,
    invoice_number:           invNo      || null,
    invoice_date:             invDate    || null,
    invoice_status:           invStatus  || null,
    payment_received_at:      payDate    ? payDate+'T00:00:00+07:00' : null,
    payment_ref:              payRef     || null,
    bukti_potong_received_at: (brandType==='PT'&&bpDate) ? bpDate+'T00:00:00+07:00' : null,
    notes:                    notes      || null,
    updated_at:               new Date().toISOString(),
    updated_by:               currentUser
  };

  let error;
  if (trkRow) {
    ({ error } = await sb.from('marte_settlements').update(payload).eq('id', trkRow.id));
  } else {
    payload.id         = genId('MST');
    payload.created_by = currentUser;
    payload.created_at = new Date().toISOString();
    ({ error } = await sb.from('marte_settlements').insert(payload));
  }

  if (error) { fb.textContent='Gagal menyimpan: '+error.message; fb.className='feedback err'; return; }

  fb.textContent='Tersimpan ✓'; fb.className='feedback ok';

  // Refresh tracking cache for this brand
  const { data: fresh } = await sb.from('marte_settlements').select('*').eq('brand_id', brandId).eq('period', _mrPeriod).single();
  if (fresh) { _mrTracking[brandId] = fresh; _mrModal.trkRow = fresh; }
  _mrRenderStatusCards(fresh);
  _mrRenderTable();
}

// ── Download Excel (branded) for one brand ──
async function downloadMRBrandXLSX() {
  if (!_mrModal?.skuData?.length && !_mrModal?.invSkuData?.length) { alert('Load data SKU dulu.'); return; }
  const { brandName, salesRow, skuData, invSkuData } = _mrModal;
  const period    = _mrPeriod;
  const [yr, mo]  = period.split('-');
  const monthName = new Date(parseInt(yr), parseInt(mo)-1, 1)
    .toLocaleDateString('id-ID', {month:'long', year:'numeric'});

  const rp = n => 'Rp ' + Math.round(parseFloat(n)||0).toLocaleString('id-ID');
  const totSales  = parseFloat(salesRow?.total_sales)||0;
  const totFeeAmt = parseFloat(salesRow?.total_fee)||0;
  const netPayout = parseFloat(salesRow?.net_payout)||0;
  const totQty    = skuData.reduce((s,r)=>s+(parseInt(r.total_qty)||0),0);
  const totSub    = skuData.reduce((s,r)=>s+(parseFloat(r.subtotal)||0),0);
  const totFee    = skuData.reduce((s,r)=>s+(parseFloat(r.fee_amount)||0),0);

  let logoSrc = '';
  try {
    const resp = await fetch('assets/logo-marte.png');
    const buf  = await resp.arrayBuffer();
    const b64  = btoa(String.fromCharCode(...new Uint8Array(buf)));
    logoSrc = 'data:image/png;base64,' + b64;
  } catch(e) {}

  const CAT_COLOR = { Apparel:'#2563eb',Accessories:'#7c3aed',Collectible:'#d97706',Wellness:'#059669',Preloved:'#db2777',Others:'#6b7280' };
  const CAT_BG    = { Apparel:'#dbeafe',Accessories:'#ede9fe',Collectible:'#fef3c7',Wellness:'#d1fae5',Preloved:'#fce7f3',Others:'#f3f4f6' };

  const skuRows = skuData.map(function(r,i){
    const cat=r.fee_category||'Others', bg=CAT_BG[cat]||CAT_BG.Others, fc=CAT_COLOR[cat]||CAT_COLOR.Others;
    return '<tr>'
      +'<td class="c muted">'+(i+1)+'</td>'
      +'<td class="mono">'+(r.item_code||'')+'</td>'
      +'<td>'+(r.item_name||'')+'</td>'
      +'<td class="c"><span class="pill" style="background:'+bg+';color:'+fc+'">'+cat+'</span></td>'
      +'<td class="c">'+(r.total_qty||0)+'</td>'
      +'<td class="r">'+rp(r.subtotal)+'</td>'
      +'<td class="c muted">'+Math.round(parseFloat(r.fee_rate)||0)+'%</td>'
      +'<td class="r bold accent">'+rp(r.fee_amount)+'</td>'
      +'</tr>';
  }).join('');

  const logoTag = logoSrc
    ? '<img src="'+logoSrc+'" style="max-height:42px;max-width:62px;object-fit:contain;display:block">'
    : '<span style="font-weight:800;font-size:18px;color:#fff;letter-spacing:-1px">marte</span>';
  const today = new Date().toLocaleDateString('id-ID',{day:'2-digit',month:'long',year:'numeric'});

  const CSS = [
    '*{box-sizing:border-box;margin:0;padding:0}',
    'body{font-family:"DM Sans",sans-serif;font-size:11.5px;color:#1a1a1a;background:#fff;-webkit-print-color-adjust:exact;print-color-adjust:exact}',
    '@page{size:A4 portrait;margin:14mm 14mm 12mm 14mm}',
    '.hdr{display:flex;align-items:stretch;background:#3c3489;border-radius:6px;overflow:hidden;margin-bottom:16px}',
    '.hdr-logo{background:#2e2870;width:72px;min-width:72px;display:flex;align-items:center;justify-content:center;padding:10px}',
    '.hdr-body{flex:1;padding:12px 18px;display:flex;flex-direction:column;justify-content:center}',
    '.hdr-title{font-family:"Syne",sans-serif;font-size:17px;font-weight:800;color:#fff;letter-spacing:.4px}',
    '.hdr-sub{font-size:11px;color:#b8b3e8;margin-top:3px}',
    '.kpi-row{display:flex;gap:10px;margin-bottom:16px}',
    '.kpi{flex:1;border:1px solid #e5e3f5;border-radius:6px;padding:10px 14px}',
    '.kpi-label{font-size:9px;text-transform:uppercase;letter-spacing:.9px;color:#9790c9;font-weight:600;margin-bottom:5px}',
    '.kpi-val{font-family:"Syne",sans-serif;font-size:15px;font-weight:700;color:#3c3489}',
    'table{width:100%;border-collapse:collapse;font-size:11px}',
    'thead th{padding:7px 9px;background:#3c3489;color:#fff;font-weight:600;font-size:10px;letter-spacing:.2px;white-space:nowrap}',
    'thead th.r{text-align:right} thead th.c{text-align:center}',
    'tbody tr{border-bottom:1px solid #efefef}',
    'tbody td{padding:7px 9px;vertical-align:middle;background:#fff}',
    '.c{text-align:center} .r{text-align:right}',
    '.muted{color:#bbb} .mono{font-family:"Courier New",monospace;font-size:10px;color:#555}',
    '.bold{font-weight:600} .accent{color:#3c3489}',
    '.pill{display:inline-block;padding:2px 8px;border-radius:99px;font-size:10px;font-weight:700}',
    '.tot td{padding:8px 9px;background:#f4f3fb;border-top:2px solid #3c3489;font-weight:700;font-size:12px}',
    '.tot .tlabel{text-align:right;color:#3c3489;font-family:"Syne",sans-serif}',
    '.tot .tfee{text-align:right;color:#3c3489;font-size:13px;font-weight:700}',
    '.footer{margin-top:18px;padding-top:9px;border-top:1px solid #eee;display:flex;justify-content:space-between;font-size:9px;color:#bbb;font-style:italic}',
    '@media print{.hdr{-webkit-print-color-adjust:exact;print-color-adjust:exact}}'
  ].join('\n');

  const html = [
    '<!DOCTYPE html>',
    '<html lang="id"><head><meta charset="UTF-8">',
    '<title>Consignment Report - '+brandName+' - '+period+'</title>',
    '<link href="https://fonts.googleapis.com/css2?family=Syne:wght@700;800&family=DM+Sans:wght@400;500&display=swap" rel="stylesheet">',
    '<style>'+CSS+'</style></head>',
    '<body>',
    '<div class="hdr"><div class="hdr-logo">'+logoTag+'</div>',
    '<div class="hdr-body"><div class="hdr-title">CONSIGNMENT REPORT</div>',
    '<div class="hdr-sub">'+brandName+'&nbsp;&nbsp;&middot;&nbsp;&nbsp;'+monthName+'</div></div></div>',
    '<div class="kpi-row">',
    '<div class="kpi"><div class="kpi-label">Gross Sales</div><div class="kpi-val">'+rp(totSales)+'</div></div>',
    '<div class="kpi"><div class="kpi-label">Fee Konsinyasi</div><div class="kpi-val">'+rp(totFeeAmt)+'</div></div>',
    '<div class="kpi"><div class="kpi-label">Net Payout ke Brand</div><div class="kpi-val">'+rp(netPayout)+'</div></div>',
    '</div>',
    '<table>',
    '<thead><tr>',
    '<th class="c" style="width:26px">#</th>',
    '<th style="width:108px">SKU / Item Code</th>',
    '<th>Nama Item</th>',
    '<th class="c" style="width:86px">Kategori</th>',
    '<th class="c" style="width:36px">Qty</th>',
    '<th class="r" style="width:108px">Gross Subtotal</th>',
    '<th class="c" style="width:56px">Fee Rate</th>',
    '<th class="r" style="width:108px">Fee Amount</th>',
    '</tr></thead>',
    '<tbody>'+skuRows+'</tbody>',
    '<tfoot><tr class="tot">',
    '<td colspan="4" class="tlabel">TOTAL</td>',
    '<td class="c">'+totQty+'</td>',
    '<td class="r">'+rp(totSub)+'</td>',
    '<td></td>',
    '<td class="tfee">'+rp(totFee)+'</td>',
    '</tr></tfoot>',
    '</table>',
    // ── Inventory Movement section ──
    ...(invSkuData?.length ? [
      '<div style="margin-top:20px;margin-bottom:8px;border-top:2px solid #3c3489;padding-top:14px">',
      '<div style="font-family:\'Syne\',sans-serif;font-size:13px;font-weight:700;color:#3c3489;margin-bottom:10px">INVENTORY MOVEMENT REPORT</div>',
      '<table>',
      '<thead><tr>',
      '<th style="width:108px">SKU / Item Code</th>',
      '<th>Nama Item</th>',
      '<th class="r" style="width:56px">Total In</th>',
      '<th class="r" style="width:72px;background:#1e4d2b">In (Period)</th>',
      '<th class="r" style="width:60px">Total Out</th>',
      '<th class="r" style="width:72px;background:#6b2d1a">Out (Period)</th>',
      '<th class="r" style="width:62px">Net Stock</th>',
      '</tr></thead>',
      '<tbody>' + (invSkuData.map(function(r,i){
        return '<tr>'
          +'<td class="mono">'+(r.item_code||'')+'</td>'
          +'<td>'+(r.item_name||'')+'</td>'
          +'<td class="r">'+(Math.round(r.inbound_total||0))+'</td>'
          +'<td class="r bold" style="color:#15803d">'+(Math.round(r.inbound_period||0)||'—')+'</td>'
          +'<td class="r">'+(Math.round(r.outbound_total||0))+'</td>'
          +'<td class="r bold" style="color:#c2410c">'+(Math.round(r.outbound_period||0)||'—')+'</td>'
          +'<td class="r bold">'+(Math.round(r.net_stock||0))+'</td>'
          +'</tr>';
      }).join('')),
      '<tr class="tot">',
      '<td colspan="2" class="tlabel">TOTAL</td>',
      '<td class="r">'+(Math.round(invSkuData.reduce(function(s,r){return s+(parseFloat(r.inbound_total)||0);},0)))+'</td>',
      '<td class="r bold" style="color:#15803d">'+(Math.round(invSkuData.reduce(function(s,r){return s+(parseFloat(r.inbound_period)||0);},0))||'—')+'</td>',
      '<td class="r">'+(Math.round(invSkuData.reduce(function(s,r){return s+(parseFloat(r.outbound_total)||0);},0)))+'</td>',
      '<td class="r bold" style="color:#c2410c">'+(Math.round(invSkuData.reduce(function(s,r){return s+(parseFloat(r.outbound_period)||0);},0))||'—')+'</td>',
      '<td class="r bold">'+(Math.round(invSkuData.reduce(function(s,r){return s+(parseFloat(r.net_stock)||0);},0)))+'</td>',
      '</tr></tbody></table></div>'
    ] : []),
    '<div class="footer">',
    '<span>Dokumen ini dibuat otomatis oleh Sentra Internal Portal &middot; '+today+'</span>',
    '<span>Sentra &middot; Internal Use Only</span>',
    '</div>',
    '<script>window.onload=function(){setTimeout(function(){window.print();},350);};<\/script>',
    '</body></html>'
  ].join('\n');

  const win = window.open('', '_blank', 'width=860,height=680');
  if (!win) { alert('Pop-up diblokir browser. Izinkan pop-up untuk portal ini.'); return; }
  win.document.write(html);
  win.document.close();
}

// ── CHAT ──
let _chatRealtime     = null;
let _chatLoaded       = false;
let _chatAllMsgs      = [];      // all messages: root + replies
let _chatView         = 'main';  // 'main' | 'thread'
let _chatThreadRootId = null;
let _chatAtQuery      = '';
let _chatAtStart      = -1;

// ── Panel ──────────────────────────────────────────────────────────────
function toggleChatPanel() {
  const popup = document.getElementById('chat-popup');
  if (!popup) return;
  if (popup.style.display === 'none' || !popup.style.display) openChatPanel();
  else closeChatPanel();
}

function openChatPanel() {
  const popup = document.getElementById('chat-popup');
  if (!popup) return;
  popup.style.display = 'flex';
  const badge = document.getElementById('chat-unread-badge');
  if (badge) badge.style.display = 'none';
  const inp = document.getElementById('chat-input');
  if (inp) { inp.oninput = _chatOnInput; inp.onkeydown = _chatOnKeydown; }
  if (!_chatLoaded) { _chatLoaded = true; loadChat(); }
  else _chatScrollBottom(true);
}

function closeChatPanel() {
  const popup = document.getElementById('chat-popup');
  if (popup) popup.style.display = 'none';
  closeChatAC();
}

// ── Load ───────────────────────────────────────────────────────────────
async function loadChat() {
  const wrap = document.getElementById('chat-msgs');
  if (wrap) wrap.innerHTML = '<div style="padding:32px;text-align:center;color:var(--g400);font-size:12px">Memuat pesan…</div>';

  const { data, error } = await sb.from('chat_messages')
    .select('*').eq('is_deleted', false)
    .order('created_at', { ascending: true }).limit(300);

  if (error) { console.error(error); return; }
  _chatAllMsgs = data || [];
  _chatRender();
  _chatScrollBottom(true);

  if (!_chatRealtime) {
    _chatRealtime = sb.channel('chat-general')
      .on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'chat_messages' }, function(payload) {
        if (!payload.new.is_deleted) {
          if (_chatAllMsgs.find(function(m){ return m.id === payload.new.id; })) return;
          _chatAllMsgs.push(payload.new);
          _chatRender();
          const m = document.getElementById('chat-msgs');
          if (m && m.scrollHeight - m.scrollTop - m.clientHeight < 100) _chatScrollBottom(false);
          const popup = document.getElementById('chat-popup');
          if (!popup || popup.style.display === 'none') {
            const badge = document.getElementById('chat-unread-badge');
            if (badge) { badge.style.display = 'inline-flex'; badge.textContent = (parseInt(badge.textContent)||0) + 1; }
          }
        }
      })
      .on('postgres_changes', { event: 'UPDATE', schema: 'public', table: 'chat_messages' }, function(payload) {
        const idx = _chatAllMsgs.findIndex(function(m){ return m.id === payload.new.id; });
        if (idx !== -1) {
          if (payload.new.is_deleted) _chatAllMsgs.splice(idx, 1);
          else _chatAllMsgs[idx] = payload.new;
          _chatRender();
        }
      })
      .subscribe();
  }
}

// ── Thread view ────────────────────────────────────────────────────────
function openChatThread(rootId) {
  _chatView = 'thread';
  _chatThreadRootId = rootId;
  _chatUpdateHeader();
  _chatUpdateCompose();
  _chatRender();
  _chatScrollBottom(true);
  setTimeout(function() { const inp = document.getElementById('chat-input'); if (inp) inp.focus(); }, 80);
}

function closeChatThread() {
  _chatView = 'main';
  _chatThreadRootId = null;
  _chatUpdateHeader();
  _chatUpdateCompose();
  _chatRender();
  _chatScrollBottom(true);
}

function _chatUpdateHeader() {
  const h = document.getElementById('chat-popup-header');
  if (!h) return;
  if (_chatView === 'main') {
    h.innerHTML = '<div style="display:flex;align-items:center;gap:8px"><span style="font-family:var(--head);font-weight:700;font-size:14px">Chat</span><span style="font-size:11px;color:var(--g400);font-family:var(--mono)">General Channel</span></div><button onclick="closeChatPanel()" style="background:none;border:none;cursor:pointer;color:var(--g400);font-size:18px;line-height:1;padding:2px 6px;border-radius:4px">✕</button>';
  } else {
    const root  = _chatAllMsgs.find(function(m){ return m.id === _chatThreadRootId; });
    const sndr  = root ? (root.sender||'').split('@')[0] : '';
    const prev  = root ? (root.body||'').slice(0,40) + ((root.body||'').length > 40 ? '…' : '') : '';
    h.innerHTML = '<div style="display:flex;align-items:center;gap:6px;min-width:0;flex:1;overflow:hidden">'
      + '<button onclick="closeChatThread()" style="background:none;border:none;cursor:pointer;color:var(--black);font-size:18px;padding:0 6px 0 0;flex-shrink:0;line-height:1">←</button>'
      + '<div style="min-width:0"><div style="font-family:var(--head);font-weight:700;font-size:13px">Thread</div>'
      + '<div style="font-size:10px;color:var(--g400);font-family:var(--mono);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + _esc(sndr) + ': ' + _esc(prev) + '</div></div></div>'
      + '<button onclick="closeChatPanel()" style="background:none;border:none;cursor:pointer;color:var(--g400);font-size:18px;line-height:1;padding:2px 6px;border-radius:4px;flex-shrink:0">✕</button>';
  }
}

function _chatUpdateCompose() {
  const label = document.getElementById('chat-thread-label');
  const inp   = document.getElementById('chat-input');
  if (label) label.style.display = _chatView === 'thread' ? 'block' : 'none';
  if (inp)   inp.placeholder = _chatView === 'thread' ? 'Balas di thread… (Enter kirim)' : 'Tulis pesan… Ketik @ untuk mention';
}

// ── Render ─────────────────────────────────────────────────────────────
function _chatRender() {
  if (_chatView === 'thread') _chatRenderThread();
  else _chatRenderMain();
}

function _chatRenderMain() {
  const wrap = document.getElementById('chat-msgs');
  if (!wrap) return;
  const roots = _chatAllMsgs.filter(function(m){ return !m.reply_to; });
  if (!roots.length) {
    wrap.innerHTML = '<div style="padding:40px 16px;text-align:center;color:var(--g400);font-size:12px">Belum ada pesan. Mulai ngobrol! 💬</div>';
    return;
  }
  const html = [];
  let prev = null;
  for (let i = 0; i < roots.length; i++) { html.push(_chatMsgHTML(roots[i], prev, false)); prev = roots[i]; }
  wrap.innerHTML = html.join('');
}

function _chatRenderThread() {
  const wrap    = document.getElementById('chat-msgs');
  if (!wrap) return;
  const root    = _chatAllMsgs.find(function(m){ return m.id === _chatThreadRootId; });
  const replies = _chatAllMsgs.filter(function(m){ return m.reply_to === _chatThreadRootId; });
  const html    = [];
  if (root) html.push(_chatMsgHTML(root, null, true));
  if (replies.length) {
    html.push('<div style="margin:8px 10px 4px;display:flex;align-items:center;gap:8px"><span style="font-size:10px;font-family:var(--mono);color:var(--g400)">' + replies.length + ' balasan</span><span style="flex:1;height:1px;background:var(--g100)"></span></div>');
    let prev = null;
    for (let i = 0; i < replies.length; i++) { html.push(_chatMsgHTML(replies[i], prev, true)); prev = replies[i]; }
  } else {
    html.push('<div style="padding:16px;text-align:center;color:var(--g400);font-size:12px">Belum ada balasan. Jadi yang pertama! 😊</div>');
  }
  wrap.innerHTML = html.join('');
}

function _chatMsgHTML(msg, prev, inThread) {
  const senderShort = (msg.sender||'').split('@')[0];
  const initials    = senderShort.slice(0,2).toUpperCase();
  const ts          = new Date(msg.created_at);
  const timeStr     = ts.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'});
  const sameDay     = prev && _chatSameDay(new Date(prev.created_at), ts);
  const grouped     = prev && prev.sender===msg.sender && (ts - new Date(prev.created_at)) < 5*60*1000 && sameDay;

  let divider = '';
  if (!prev || !sameDay) {
    divider = '<div style="text-align:center;margin:10px 0 6px"><span style="background:var(--off);border:1px solid var(--g100);border-radius:99px;padding:2px 10px;font-size:10px;font-family:var(--mono);color:var(--g600)">' + _esc(_chatDateLabel(ts)) + '</span></div>';
  }

  const bodyHtml = _chatHighlight(_chatRenderBody(msg.body||''));
  const isOwn    = msg.sender === currentUser;
  const deleteBtn = isOwn
    ? '<button class="chat-del-btn" onclick="deleteChatMsg(\''+_esc(msg.id)+'\')" title="Hapus">🗑</button>'
    : '';

  // Thread bar — only on root messages in main view
  let threadBar = '';
  if (!inThread) {
    const COLORS = ['#7c3aed','#2563eb','#059669','#d97706','#dc2626','#0891b2','#9333ea','#65a30d'];
    const replies = _chatAllMsgs.filter(function(m){ return m.reply_to === msg.id; });
    if (replies.length > 0) {
      const seen = {}, uniqSenders = [];
      replies.forEach(function(r){ const s=(r.sender||'').split('@')[0]; if(!seen[s]){seen[s]=1;uniqSenders.push(s);} });
      const avatars = uniqSenders.slice(0,3).map(function(s){
        const c = COLORS[s.charCodeAt(0) % COLORS.length];
        return '<span style="width:18px;height:18px;border-radius:50%;background:' + c + '22;color:' + c + ';font-size:8px;font-weight:700;display:inline-flex;align-items:center;justify-content:center;flex-shrink:0">' + s.slice(0,2).toUpperCase() + '</span>';
      }).join('');
      threadBar = '<div class="chat-thread-bar" onclick="openChatThread(\'' + _esc(msg.id) + '\')">'
        + '<div style="display:flex;gap:2px">' + avatars + '</div>'
        + '<span class="chat-thread-count">' + replies.length + ' balasan</span>'
        + '<span style="color:var(--g200);margin-left:auto;font-size:11px">›</span>'
        + '</div>';
    } else {
      threadBar = '<div class="chat-thread-empty" onclick="openChatThread(\'' + _esc(msg.id) + '\')">Balas di thread</div>';
    }
  }

  const COLORS = ['#7c3aed','#2563eb','#059669','#d97706','#dc2626','#0891b2','#9333ea','#65a30d'];
  const ci        = senderShort.charCodeAt(0) % COLORS.length;
  const avatarBg  = COLORS[ci] + '22';
  const avatarFg  = COLORS[ci];

  if (grouped) {
    return divider
      + '<div class="chat-msg chat-grouped" id="cmsg-' + msg.id + '" title="' + _esc(timeStr) + '">'
      + '<div class="chat-avatar-space"></div>'
      + '<div class="chat-bubble"><div class="chat-body">' + bodyHtml + '</div>' + threadBar + '</div>'
      + deleteBtn
      + '</div>';
  }

  return divider
    + '<div class="chat-msg" id="cmsg-' + msg.id + '">'
    + '<div class="chat-avatar" style="background:' + avatarBg + ';color:' + avatarFg + '">' + initials + '</div>'
    + '<div class="chat-bubble">'
    + '<div class="chat-meta"><span class="chat-sender">' + _esc(senderShort) + '</span><span class="chat-time">' + _esc(timeStr) + '</span></div>'
    + '<div class="chat-body">' + bodyHtml + '</div>'
    + threadBar
    + '</div>'
    + deleteBtn
    + '</div>';
}

// ── Send ───────────────────────────────────────────────────────────────
async function sendChatMessage() {
  const inp = document.getElementById('chat-input');
  if (!inp) return;
  const body = inp.value.trim();
  if (!body) return;

  const btn = document.getElementById('chat-send-btn');
  if (btn) { btn.disabled = true; btn.textContent = '…'; }

  const msgId   = genId('CHT');
  const replyTo = _chatView === 'thread' ? _chatThreadRootId : null;

  inp.value = '';
  inp.style.height = 'auto';
  closeChatAC();

  // Optimistic render
  const optimistic = { id: msgId, body: body, sender: currentUser, reply_to: replyTo, created_at: new Date().toISOString(), is_deleted: false };
  _chatAllMsgs.push(optimistic);
  _chatRender();
  _chatScrollBottom(false);

  const { error } = await sb.from('chat_messages').insert({ id: msgId, body: body, sender: currentUser, reply_to: replyTo });

  if (btn) { btn.disabled = false; btn.textContent = 'Kirim'; }
  if (error) {
    console.error(error);
    _chatAllMsgs = _chatAllMsgs.filter(function(m){ return m.id !== msgId; });
    _chatRender();
    inp.value = body;
    return;
  }

  // Notify: reply to thread
  if (replyTo) {
    const root = _chatAllMsgs.find(function(m){ return m.id === replyTo; });
    if (root && root.sender !== currentUser) {
      insertNotif(root.sender, 'chat', msgId, currentUser.split('@')[0] + ' membalas thread kamu di Chat');
    }
    // Other thread participants
    const seen = {};
    _chatAllMsgs.filter(function(m){ return m.reply_to === replyTo && m.sender !== currentUser && m.sender !== (root && root.sender); })
      .forEach(function(m){
        if (!seen[m.sender]) { seen[m.sender] = 1; insertNotif(m.sender, 'chat', msgId, currentUser.split('@')[0] + ' juga membalas thread di Chat'); }
      });
  }

  // Notify: @mentions
  const mentions = [...body.matchAll(/@([\w.\-]+)/g)].map(function(m){ return m[1]; });
  for (const name of mentions) {
    const match = (acPics||[]).find(function(p){ return p.toLowerCase().includes(name.toLowerCase()); });
    if (match) insertNotif(match, 'chat', msgId, currentUser.split('@')[0] + ' menyebut kamu di Chat');
  }
  logActivity('Chat', 'send', 'CHT', body.slice(0,60));
}

// ── Helpers ────────────────────────────────────────────────────────────
function _chatHighlight(escapedText) {
  const meShort = currentUser ? currentUser.split('@')[0] : '';
  return escapedText.replace(/@([\w.\-]+)/g, function(m, name) {
    const isMe = meShort && name.toLowerCase() === meShort.toLowerCase();
    return '<span class="chat-mention' + (isMe ? ' chat-mention-me' : '') + '">' + m + '</span>';
  });
}

function _chatDateLabel(d) {
  const today = new Date(); today.setHours(0,0,0,0);
  const dd = new Date(d); dd.setHours(0,0,0,0);
  const diff = (today - dd) / 86400000;
  if (diff === 0) return 'Hari ini';
  if (diff === 1) return 'Kemarin';
  return d.toLocaleDateString('id-ID', { day:'numeric', month:'long', year:'numeric' });
}

function _chatSameDay(a, b) {
  return a.getFullYear()===b.getFullYear() && a.getMonth()===b.getMonth() && a.getDate()===b.getDate();
}

function _esc(s) {
  return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
}

function _chatScrollBottom(instant) {
  const wrap = document.getElementById('chat-msgs');
  if (!wrap) return;
  setTimeout(function(){ wrap.scrollTop = wrap.scrollHeight; }, instant ? 0 : 60);
}

// ── @mention autocomplete ──────────────────────────────────────────────
function _chatOnInput(e) {
  const inp = e.target;
  inp.style.height = 'auto';
  inp.style.height = Math.min(inp.scrollHeight, 100) + 'px';
  const val = inp.value, pos = inp.selectionStart, before = val.slice(0, pos);
  const atIdx = before.lastIndexOf('@');
  if (atIdx !== -1) {
    const afterAt = before.slice(atIdx + 1);
    if (!afterAt.includes(' ')) { _chatAtStart = atIdx; _chatAtQuery = afterAt.toLowerCase(); _chatShowAC(_chatAtQuery); return; }
  }
  closeChatAC();
}

function _chatOnKeydown(e) {
  const ac = document.getElementById('chat-ac');
  if (ac && ac.style.display !== 'none') {
    const items = ac.querySelectorAll('.chat-ac-item');
    const active = ac.querySelector('.chat-ac-item.active');
    if (e.key === 'ArrowDown') { e.preventDefault(); const nxt = active?(active.nextElementSibling||items[0]):items[0]; if(active)active.classList.remove('active'); if(nxt)nxt.classList.add('active'); return; }
    if (e.key === 'ArrowUp')   { e.preventDefault(); const prv = active?(active.previousElementSibling||items[items.length-1]):items[items.length-1]; if(active)active.classList.remove('active'); if(prv)prv.classList.add('active'); return; }
    if (e.key === 'Enter' || e.key === 'Tab') { const sel = ac.querySelector('.chat-ac-item.active')||items[0]; if(sel){e.preventDefault();_chatPickMention(sel.dataset.name);return;} }
    if (e.key === 'Escape') { closeChatAC(); return; }
  }
  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendChatMessage(); }
}

function _chatShowAC(query) {
  const ac = document.getElementById('chat-ac');
  if (!ac) return;
  const senders = [...new Set(_chatAllMsgs.map(function(m){ return (m.sender||'').split('@')[0]; }).filter(Boolean))];
  const allNames = [...new Set([...(acPics||[]).map(function(p){ return p.split('@')[0]; }), ...senders])].filter(Boolean);
  const matches = query ? allNames.filter(function(n){ return n.toLowerCase().includes(query); }) : allNames.slice(0,8);
  if (!matches.length) { closeChatAC(); return; }
  ac.innerHTML = matches.slice(0,8).map(function(p){ return '<div class="chat-ac-item" data-name="'+_esc(p)+'" onclick="_chatPickMention(\''+_esc(p)+'\')">'+_esc(p)+'</div>'; }).join('');
  ac.style.display = 'block';
}

function _chatPickMention(name) {
  const inp = document.getElementById('chat-input');
  if (!inp) return;
  const before = inp.value.slice(0, _chatAtStart), after = inp.value.slice(inp.selectionStart);
  inp.value = before + '@' + name + ' ' + after;
  const newPos = before.length + name.length + 2;
  inp.setSelectionRange(newPos, newPos);
  closeChatAC();
  inp.focus();
}

function closeChatAC() {
  const ac = document.getElementById('chat-ac');
  if (ac) ac.style.display = 'none';
  _chatAtQuery = ''; _chatAtStart = -1;
}

// ── Body renderer: links + images ──────────────────────────────────────
function _chatRenderBody(rawText) {
  // Split text by URLs, render image URLs as <img>, other URLs as <a>
  const URL_RE = /https?:\/\/[^\s<>"]+/g;
  const IMG_EXT = /\.(jpg|jpeg|png|gif|webp)(\?[^\s]*)?$/i;
  let last = 0, result = '';
  let m;
  URL_RE.lastIndex = 0;
  while ((m = URL_RE.exec(rawText)) !== null) {
    result += _esc(rawText.slice(last, m.index));
    const url = m[0];
    if (IMG_EXT.test(url)) {
      result += '<img class="chat-img" src="' + _esc(url) + '" alt="image" onclick="window.open(\'' + _esc(url) + '\',\'_blank\')">';
    } else {
      result += '<a class="chat-link" href="' + _esc(url) + '" target="_blank" rel="noopener noreferrer">' + _esc(url) + '</a>';
    }
    last = m.index + url.length;
  }
  result += _esc(rawText.slice(last));
  return result;
}

// ── Delete message ─────────────────────────────────────────────────────
async function deleteChatMsg(id) {
  if (!confirm('Hapus pesan ini?')) return;
  const idx = _chatAllMsgs.findIndex(function(m){ return m.id === id; });
  if (idx !== -1) _chatAllMsgs.splice(idx, 1);
  _chatRender();
  const { error } = await sb.from('chat_messages').update({ is_deleted: true }).eq('id', id);
  if (error) {
    console.error(error);
    // rollback not needed — realtime UPDATE will sync state
  }
}

// ── Image upload ───────────────────────────────────────────────────────
function _chatPickImage() {
  const inp = document.getElementById('chat-img-input');
  if (inp) inp.click();
}

async function _chatUploadImage(file) {
  if (!file) return;
  if (file.size > 5 * 1024 * 1024) { alert('Ukuran file maksimal 5MB.'); return; }
  const btn = document.getElementById('chat-img-btn');
  if (btn) { btn.disabled = true; btn.textContent = '⏳'; }

  const ext  = file.name.split('.').pop().toLowerCase();
  const path = 'chat/' + genId('IMG') + '.' + ext;
  const { error: upErr } = await sb.storage.from('chat-attachments').upload(path, file, { contentType: file.type, upsert: false });

  if (upErr) {
    console.error(upErr);
    alert('Gagal upload gambar: ' + upErr.message);
    if (btn) { btn.disabled = false; btn.textContent = '🖼'; }
    return;
  }

  const { data: { publicUrl } } = sb.storage.from('chat-attachments').getPublicUrl(path);

  // Send as a chat message containing only the image URL (render will show inline)
  const msgId   = genId('CHT');
  const replyTo = _chatView === 'thread' ? _chatThreadRootId : null;
  const optimistic = { id: msgId, body: publicUrl, sender: currentUser, reply_to: replyTo, created_at: new Date().toISOString(), is_deleted: false };
  _chatAllMsgs.push(optimistic);
  _chatRender();
  _chatScrollBottom(false);

  const { error } = await sb.from('chat_messages').insert({ id: msgId, body: publicUrl, sender: currentUser, reply_to: replyTo });
  if (error) {
    console.error(error);
    _chatAllMsgs = _chatAllMsgs.filter(function(m){ return m.id !== msgId; });
    _chatRender();
  }

  if (btn) { btn.disabled = false; btn.textContent = '🖼'; }
  // Reset file input so same file can be re-uploaded
  const imgInp = document.getElementById('chat-img-input');
  if (imgInp) imgInp.value = '';
}

