// KOL Database name cache for MP's kol activity quick-add — lazy loaded when
// the kol activity first renders. Refreshed on auto-insert.
let _mpKolNames = [];
let _mpKolNamesLoaded = false;
async function _mpLoadKolDbNames(force) {
  if (_mpKolNamesLoaded && !force) return;
  try {
    const {data} = await sb.from('kol_database').select('name').order('name');
    _mpKolNames = (data||[]).map(r => r.name).filter(Boolean);
    _mpKolNamesLoaded = true;
  } catch (e) { console.warn('Load KOL Database names failed:', e); }
}

// Master-list auto-seed — when MP quick-add or inline edit saves a name that
// isn't yet in the corresponding master table, insert a stub there too so the
// roster grows organically. Currently only wired for kol → kol_database.
async function _mpEnsureMasterEntry(actKey, name) {
  const n = (name||'').trim();
  if (!n) return;
  if (actKey === 'kol') {
    await _mpLoadKolDbNames();
    const exists = _mpKolNames.some(x => x.toLowerCase().trim() === n.toLowerCase());
    if (exists) return;
    try {
      const id = genId('KD');
      await sb.from('kol_database').insert({
        id, name: n,
        added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
        last_updated: new Date().toISOString(), last_updated_by: currentUser,
      });
      _mpKolNames.push(n);
      _mpKolNames.sort((a,b)=>a.localeCompare(b));
    } catch (e) { console.warn('Auto-seed KOL Database failed:', e); }
  }
}

function _mpStatusTone(act, status) {
  const def = _MP_ACTIVITY_DEFS[act];
  return def?.statusToneFor ? def.statusToneFor(status) : 'p-draft';
}

async function _mpLoadActivitySummary(activity, cid, expanded) {
  const countEl = document.getElementById(`mp-act-count-${activity.key}`);
  const bodyEl  = document.getElementById(`mp-act-body-${activity.key}`);
  const def = _MP_ACTIVITY_DEFS[activity.key];
  if (!def) return;
  // Lazy load KOL Database names so the name AC has options when first rendered.
  if (activity.key === 'kol' && !_mpKolNamesLoaded) await _mpLoadKolDbNames();
  let rows = [];
  try {
    let q = sb.from(def.table).select(def.selectCols).eq('collection_id', cid);
    if (def.extraFilter && def.extraFilter.includes('ilike')) q = q.ilike('content_type','%video%');
    q = q.order(def.orderBy, {ascending:true, nullsFirst:false});
    const {data} = await q;
    rows = data || [];
    if (def.extraFilterClient) rows = rows.filter(def.extraFilterClient);
  } catch (e) { console.warn('MP activity load failed for '+activity.key, e); }
  if (countEl) countEl.textContent = rows.length ? `${rows.length} entri` : 'belum ada';
  if (bodyEl && expanded) {
    const quickAddForm = `<div id="mp-qa-${activity.key}" style="display:none;background:var(--off);border:1px solid var(--g100);border-radius:6px;padding:10px 12px;margin-bottom:10px">
      <div style="font-size:11px;color:var(--g600);font-family:var(--mono);text-transform:uppercase;letter-spacing:0.3px;font-weight:600;margin-bottom:8px">+ Tambah ${activity.label}</div>
      ${_mpQuickAddFormHTML(activity)}
      <div style="display:flex;gap:6px;margin-top:8px">
        <button onclick="_mpQuickAddSubmit('${activity.key}','${cid}')" style="padding:6px 14px;background:#3C3489;color:white;border:none;border-radius:4px;cursor:pointer;font-size:11px;font-weight:600">💾 Simpan</button>
        <button onclick="document.getElementById('mp-qa-${activity.key}').style.display='none'" style="padding:6px 14px;background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:11px">Batal</button>
        <div id="mp-qa-fb-${activity.key}" style="margin-left:auto;font-size:11px;align-self:center"></div>
      </div>
    </div>`;
    const toolbar = `<div style="display:flex;align-items:center;gap:8px;padding-bottom:8px;margin-bottom:8px;border-bottom:1px solid var(--g100)">
      <div style="font-size:11px;color:var(--g400)">Klik baris untuk buka di modul lengkap. ✎ inline edit · 🗑 hapus.</div>
      <button onclick="document.getElementById('mp-qa-${activity.key}').style.display='block'" style="margin-left:auto;padding:5px 12px;background:var(--white);border:1px solid #3C3489;color:#3C3489;border-radius:4px;cursor:pointer;font-size:11px;font-weight:600">+ Tambah cepat</button>
    </div>`;
    bodyEl.innerHTML = quickAddForm + toolbar + (rows.length
      ? rows.map(r => _mpRenderActRow(activity.key, r, cid)).join('')
      : `<div style="text-align:center;padding:14px;color:var(--g400);font-size:12px">Belum ada entri ${activity.label.toLowerCase()}. Klik <strong>+ Tambah cepat</strong> di atas atau <a href="#${activity.moduleHref}" onclick="showPage('${activity.moduleHref}',null);return false" style="color:#3C3489;text-decoration:underline">buka modul lengkap</a>.</div>`);
    _mpWireDatalistAC(activity.key, 'mpqa');
  }
}

// Render one row of the mirror — name (clickable to module deeplink),
// inline date input, status pill, ✎ edit, 🗑 delete buttons.
// All right-side controls get flex-shrink:0 so name never gets squeezed
// into a vertical word-tower.
function _mpRenderActRow(key, r, cid) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return '';
  const esc = s => (s==null?'':String(s)).replace(/</g,'&lt;').replace(/"/g,'&quot;');
  const id = r.id;
  const name = r[def.nameField] || '—';
  const date = r[def.dateField] || '';
  const status = r[def.statusField] || def.defaultStatus;
  const statusTone = _mpStatusTone(key, status);
  // Build meta — exclude date (date has its own inline input now) — only
  // show the extras (location, channel, owner, etc.) under the name.
  const metaParts = [];
  for (const ex of def.extras) {
    const v = r[ex.f];
    if (!v) continue;
    if (ex.f === 'fee') metaParts.push(`Rp ${Math.round(v).toLocaleString('id-ID')}`);
    else metaParts.push(esc(v));
  }
  const meta = metaParts.join(' · ');
  const extLink = def.linkField && r[def.linkField] ? r[def.linkField] : null;
  return `<div id="mp-row-${key}-${id}" style="padding:8px 4px;border-bottom:1px solid var(--g100);font-size:12px;display:flex;gap:8px;align-items:center;width:100%;box-sizing:border-box">
    <div style="flex:1 1 200px;min-width:160px;overflow:hidden">
      <div style="font-weight:600;color:#3C3489;cursor:pointer;text-decoration:underline;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" onclick="_mpJumpToModule('${key}','${id}')" title="↗ Buka di modul ${def.moduleHref}">${esc(name)}</div>
      ${meta?`<div style="color:var(--g600);font-size:11px;margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${meta}</div>`:''}
    </div>
    <input type="date" value="${date}" onchange="_mpSaveActField('${key}','${id}','${def.dateField}',this.value)" title="${def.dateLabel}" style="font-size:11px;padding:3px 6px;border:1px solid var(--g200);border-radius:4px;width:140px;flex-shrink:0;background:var(--white)">
    ${extLink?`<a href="${esc(extLink)}" target="_blank" title="Buka asset/link" style="font-size:13px;color:var(--g600);text-decoration:none;padding:4px 6px;flex-shrink:0">↗</a>`:''}
    <select onchange="_mpSaveActField('${key}','${id}','${def.statusField}',this.value)" class="pill ${statusTone}" style="font-size:10px;padding:3px 8px;border-radius:99px;cursor:pointer;border:1px solid transparent;flex-shrink:0;width:130px;max-width:130px">
      ${def.statusOpts.map(s => `<option value="${s}"${s===status?' selected':''}>${s}</option>`).join('')}
    </select>
    <button onclick="_mpEditRow('${key}','${id}')" title="Edit inline (semua field)" style="background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:13px;padding:3px 8px;flex-shrink:0;line-height:1">✎</button>
    <button onclick="_mpDeleteRow('${key}','${id}','${cid}')" title="Hapus" style="background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:13px;padding:3px 8px;color:#c0392b;flex-shrink:0;line-height:1">🗑</button>
  </div>`;
}

// Navigate to source module page — user can then find the specific row there.
function _mpJumpToModule(key, id) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return;
  showPage(def.moduleHref, null);
}

// Status pill is editable inline — fire small update without re-render.
async function _mpSaveActField(key, id, field, value) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return;
  try {
    const payload = { [field]: value || null,
      last_updated: new Date().toISOString(), last_updated_by: currentUser||'' };
    const {error} = await sb.from(def.table).update(payload).eq('id', id);
    if (error) throw error;
    // Update pill tone live
    const row = document.getElementById(`mp-row-${key}-${id}`);
    if (row && field === 'status') {
      const sel = row.querySelector('select');
      if (sel) sel.className = 'pill ' + _mpStatusTone(key, value);
    }
  } catch (e) { console.warn('Save activity field failed:', e); }
}

// Inline edit: replace row with mini form (same fields as quick-add, pre-filled).
async function _mpEditRow(key, id) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return;
  // Fetch the row fresh — selectCols already covers what we need
  const {data, error} = await sb.from(def.table).select(def.selectCols).eq('id', id).single();
  if (error || !data) { alert('Gagal load row: ' + (error?.message||'not found')); return; }
  const r = data;
  const rowEl = document.getElementById(`mp-row-${key}-${id}`);
  if (!rowEl) return;
  rowEl.outerHTML = `<div id="mp-row-${key}-${id}" style="padding:10px 12px;border-bottom:1px solid var(--g100);background:var(--off);border-radius:4px;margin-bottom:4px">
    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g400);font-weight:600;margin-bottom:6px">✎ Edit ${def.nameLabel}</div>
    ${_mpRenderEditFormFields(key, r)}
    <div style="display:flex;gap:6px;margin-top:8px">
      <button onclick="_mpSaveRowEdit('${key}','${id}')" style="padding:6px 14px;background:#3C3489;color:white;border:none;border-radius:4px;cursor:pointer;font-size:11px;font-weight:600">💾 Simpan</button>
      <button onclick="_mpCancelRowEdit('${key}','${id}')" style="padding:6px 14px;background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:11px">Batal</button>
      <div id="mp-rowedit-fb-${key}-${id}" style="margin-left:auto;font-size:11px;align-self:center"></div>
    </div>
  </div>`;
  _mpWireDatalistAC(key, 'mpedit');
}

function _mpRenderEditFormFields(key, r) {
  const def = _MP_ACTIVITY_DEFS[key];
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const fields = [];
  if (def.nameAC) {
    fields.push(`<div style="position:relative">
      <input type="text" id="mpedit-${key}-name" value="${esc(r[def.nameField])}" placeholder="${def.nameLabel} *" autocomplete="off" style="font-size:12px;padding:5px 8px;width:100%;box-sizing:border-box">
      <div class="ac-list" id="ac-mpedit-${key}-name"></div>
    </div>`);
  } else {
    fields.push(`<input type="text" id="mpedit-${key}-name" value="${esc(r[def.nameField])}" placeholder="${def.nameLabel} *" style="font-size:12px;padding:5px 8px">`);
  }
  fields.push(`<div style="display:flex;flex-direction:column;gap:2px">
    <span style="font-size:9px;color:var(--g600);font-family:var(--mono);text-transform:uppercase;letter-spacing:0.3px">${def.dateLabel}</span>
    <input type="date" id="mpedit-${key}-date" value="${r[def.dateField]||''}" style="font-size:12px;padding:5px 8px;width:100%;box-sizing:border-box">
  </div>`);
  for (const ex of def.extras) {
    fields.push(_mpFieldInputHTML(key, ex, r[ex.f]||'', 'mpedit'));
  }
  fields.push(`<select id="mpedit-${key}-status" style="font-size:12px;padding:5px 8px">${def.statusOpts.map(s => `<option value="${s}"${s===r[def.statusField]?' selected':''}>${s}</option>`).join('')}</select>`);
  return `<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:6px;align-items:end">${fields.join('')}</div>`;
}

async function _mpSaveRowEdit(key, id) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return;
  const fb = document.getElementById(`mp-rowedit-fb-${key}-${id}`);
  const setFB = (msg, ok) => { if (fb) { fb.style.color = ok?'#0a7d3a':'#c0392b'; fb.textContent = msg; } };
  const name = document.getElementById(`mpedit-${key}-name`)?.value.trim();
  if (!name) { setFB('Nama wajib', false); return; }
  const payload = {
    [def.nameField]: name,
    [def.dateField]: document.getElementById(`mpedit-${key}-date`)?.value || null,
    [def.statusField]: document.getElementById(`mpedit-${key}-status`)?.value || def.defaultStatus,
    last_updated: new Date().toISOString(), last_updated_by: currentUser||'',
  };
  for (const ex of def.extras) {
    const v = document.getElementById(`mpedit-${key}-${ex.f}`)?.value;
    payload[ex.f] = ex.type === 'number' ? (v===''?null:Number(v)) : (v||null);
    if (ex.type === 'datalist' && v) _mpPushVocab(key, ex.f, v);
  }
  try {
    const {error} = await sb.from(def.table).update(payload).eq('id', id);
    if (error) throw error;
    if (def.nameAutoInsert) await _mpEnsureMasterEntry(key, name);
    setFB('✓ Tersimpan', true);
    // Refresh the activity card so the edited row re-renders correctly
    const cid = _mpCurrentColId;
    const activities = [
      { key:'photoshoot',  source:'Photoshoot Planning', moduleHref:'photoshoot',    label:'Photoshoot' },
      { key:'video',       source:'Video Production',    moduleHref:'videoprod',     label:'Video Production' },
      { key:'content',     source:'Content Planning',    moduleHref:'contentplan',   label:'Content Planning' },
      { key:'activation',  source:'Marketing Activation',moduleHref:'mktactivation', label:'Marketing Activation' },
      { key:'ads',         source:'Ads Management',      moduleHref:'adsmgmt',       label:'Ads' },
      { key:'kol',         source:'KOL Management',      moduleHref:'kolmgmt',       label:'KOL Placement' },
    ];
    const act = activities.find(a => a.key === key);
    if (act) setTimeout(() => _mpLoadActivitySummary(act, cid, true), 300);
  } catch (e) { setFB('Gagal: ' + (e.message||e), false); }
}

async function _mpCancelRowEdit(key, id) {
  const activities = [
    { key:'photoshoot',  source:'Photoshoot Planning', moduleHref:'photoshoot',    label:'Photoshoot' },
    { key:'video',       source:'Video Production',    moduleHref:'videoprod',     label:'Video Production' },
    { key:'content',     source:'Content Planning',    moduleHref:'contentplan',   label:'Content Planning' },
    { key:'activation',  source:'Marketing Activation',moduleHref:'mktactivation', label:'Marketing Activation' },
    { key:'ads',         source:'Ads Management',      moduleHref:'adsmgmt',       label:'Ads' },
    { key:'kol',         source:'KOL Management',      moduleHref:'kolmgmt',       label:'KOL Placement' },
  ];
  const act = activities.find(a => a.key === key);
  if (act) await _mpLoadActivitySummary(act, _mpCurrentColId, true);
}

async function _mpDeleteRow(key, id, cid) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return;
  if (!confirm('Hapus entri ini?')) return;
  try {
    const {error} = await sb.from(def.table).delete().eq('id', id);
    if (error) throw error;
    // Update grid cache
    if (_mpExecCounts[cid]) {
      if (key === 'photoshoot') _mpExecCounts[cid].ps = Math.max(0, _mpExecCounts[cid].ps - 1);
      else if (key === 'video') _mpExecCounts[cid].video = Math.max(0, _mpExecCounts[cid].video - 1);
      else if (key === 'content') _mpExecCounts[cid].content = Math.max(0, _mpExecCounts[cid].content - 1);
      else if (key === 'activation') _mpExecCounts[cid].me = Math.max(0, _mpExecCounts[cid].me - 1);
      else if (key === 'kol') _mpExecCounts[cid].kol = Math.max(0, _mpExecCounts[cid].kol - 1);
      else if (key === 'ads') _mpExecCounts[cid].ads = Math.max(0, _mpExecCounts[cid].ads - 1);
    }
    const activities = [
      { key:'photoshoot',  source:'Photoshoot Planning', moduleHref:'photoshoot',    label:'Photoshoot' },
      { key:'video',       source:'Video Production',    moduleHref:'videoprod',     label:'Video Production' },
      { key:'content',     source:'Content Planning',    moduleHref:'contentplan',   label:'Content Planning' },
      { key:'activation',  source:'Marketing Activation',moduleHref:'mktactivation', label:'Marketing Activation' },
      { key:'ads',         source:'Ads Management',      moduleHref:'adsmgmt',       label:'Ads' },
      { key:'kol',         source:'KOL Management',      moduleHref:'kolmgmt',       label:'KOL Placement' },
    ];
    const act = activities.find(a => a.key === key);
    if (act) await _mpLoadActivitySummary(act, cid, true);
  } catch (e) { alert('Gagal hapus: ' + (e.message||e)); }
}

// Per-activity quick-add mini form HTML — driven by _MP_ACTIVITY_DEFS so
// every activity gets the same field set: name * | date | extras | status.
// 'datalist' extra type renders <input list> + <datalist> for picker-with-
// free-text — user can choose from suggestions OR type new value (saved as
// free text so the list grows organically).
function _mpQuickAddFormHTML(activity) {
  const def = _MP_ACTIVITY_DEFS[activity.key];
  if (!def) return '';
  const fields = [];
  // Name — AC pattern when def.nameAC, plain input otherwise.
  if (def.nameAC) {
    fields.push(`<div style="position:relative">
      <input type="text" id="mpqa-${activity.key}-name" placeholder="${def.nameLabel} *" autocomplete="off" style="font-size:12px;padding:5px 8px;width:100%;box-sizing:border-box">
      <div class="ac-list" id="ac-mpqa-${activity.key}-name"></div>
    </div>`);
  } else {
    fields.push(`<input type="text" id="mpqa-${activity.key}-name" placeholder="${def.nameLabel} *" style="font-size:12px;padding:5px 8px">`);
  }
  // Date — wrap with mono caption so user knows what it represents.
  fields.push(`<div style="display:flex;flex-direction:column;gap:2px">
    <span style="font-size:9px;color:var(--g600);font-family:var(--mono);text-transform:uppercase;letter-spacing:0.3px">${def.dateLabel}</span>
    <input type="date" id="mpqa-${activity.key}-date" style="font-size:12px;padding:5px 8px;width:100%;box-sizing:border-box">
  </div>`);
  for (const ex of def.extras) {
    fields.push(_mpFieldInputHTML(activity.key, ex, '', 'mpqa'));
  }
  fields.push(`<select id="mpqa-${activity.key}-status" style="font-size:12px;padding:5px 8px">${def.statusOpts.map(s => `<option value="${s}"${s===def.defaultStatus?' selected':''}>${s}</option>`).join('')}</select>`);
  const cols = Math.min(fields.length, 4);
  return `<div style="display:grid;grid-template-columns:repeat(${cols},1fr);gap:6px;align-items:end">${fields.join('')}</div>`;
}

// Render a single extra field input given its type. Used by both quick-add
// and inline-edit so they stay in sync. For 'datalist' we render the custom
// setupAC pattern (input + .ac-list div) — caller MUST invoke
// _mpWireDatalistAC after the HTML is inserted into the DOM.
function _mpFieldInputHTML(actKey, ex, value, prefix) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  if (ex.type === 'datalist') {
    const inpId = `${prefix}-${actKey}-${ex.f}`;
    const lstId = `ac-${prefix}-${actKey}-${ex.f}`;
    return `<div style="position:relative">
      <input type="text" id="${inpId}" value="${esc(value)}" placeholder="${ex.placeholder}" autocomplete="off" style="font-size:12px;padding:5px 8px;width:100%;box-sizing:border-box">
      <div class="ac-list" id="${lstId}"></div>
    </div>`;
  }
  return `<input type="${ex.type}" id="${prefix}-${actKey}-${ex.f}" value="${esc(value)}" placeholder="${ex.placeholder}" style="font-size:12px;padding:5px 8px">`;
}

async function _mpQuickAddSubmit(key, cid) {
  const def = _MP_ACTIVITY_DEFS[key];
  if (!def) return;
  const fb = document.getElementById(`mp-qa-fb-${key}`);
  const setFB = (msg, ok) => { if (fb) { fb.style.color = ok?'#0a7d3a':'#c0392b'; fb.textContent = msg; } };
  const name = document.getElementById(`mpqa-${key}-name`)?.value.trim();
  if (!name) { setFB('Nama wajib', false); return; }
  try {
    const payload = {
      id: genId(def.idPrefix), collection_id: cid,
      [def.nameField]: name,
      [def.dateField]: document.getElementById(`mpqa-${key}-date`)?.value || null,
      [def.statusField]: document.getElementById(`mpqa-${key}-status`)?.value || def.defaultStatus,
      added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    };
    for (const ex of def.extras) {
      const v = document.getElementById(`mpqa-${key}-${ex.f}`)?.value;
      payload[ex.f] = ex.type === 'number' ? (v===''?null:Number(v)) : (v||null);
      if (ex.type === 'datalist' && v) _mpPushVocab(key, ex.f, v);
    }
    if (def.fixed) Object.assign(payload, def.fixed);
    const {error} = await sb.from(def.table).insert(payload);
    if (error) throw error;
    // Auto-seed master list (e.g. kol → kol_database) when a brand-new name was typed.
    if (def.nameAutoInsert) await _mpEnsureMasterEntry(key, name);
    setFB('✓ Tersimpan', true);
    const activities = [
      { key:'photoshoot',  source:'Photoshoot Planning', moduleHref:'photoshoot',    label:'Photoshoot' },
      { key:'video',       source:'Video Production',    moduleHref:'videoprod',     label:'Video Production' },
      { key:'content',     source:'Content Planning',    moduleHref:'contentplan',   label:'Content Planning' },
      { key:'activation',  source:'Marketing Activation',moduleHref:'mktactivation', label:'Marketing Activation' },
      { key:'ads',         source:'Ads Management',      moduleHref:'adsmgmt',       label:'Ads' },
      { key:'kol',         source:'KOL Management',      moduleHref:'kolmgmt',       label:'KOL Placement' },
    ];
    const act = activities.find(a => a.key === key);
    if (act) await _mpLoadActivitySummary(act, cid, true);
    const form = document.getElementById(`mp-qa-${key}`);
    if (form) setTimeout(() => { form.style.display='none'; if (fb) fb.textContent=''; }, 1500);
    if (_mpExecCounts[cid]) {
      if (key === 'photoshoot') _mpExecCounts[cid].ps++;
      else if (key === 'video') _mpExecCounts[cid].video++;
      else if (key === 'content') _mpExecCounts[cid].content++;
      else if (key === 'activation') _mpExecCounts[cid].me++;
      else if (key === 'kol') _mpExecCounts[cid].kol++;
      else if (key === 'ads') _mpExecCounts[cid].ads++;
    }
  } catch (e) { setFB('Gagal: ' + (e.message||e), false); }
}

function toggleMPExpand(key) {
  if (_mpExpanded.has(key)) _mpExpanded.delete(key);
  else _mpExpanded.add(key);
  const col = _mpCols.find(c => c.id === _mpCurrentColId);
  if (col && _mpCurrentPlan) renderMPDetailBody(col, _mpCurrentPlan);
}

async function toggleMPActivity(key, dbFlag, on) {
  if (!_mpCurrentPlan) return;
  try {
    const {error} = await sb.from('marketing_plans').update({
      [dbFlag]: on,
      last_updated: new Date().toISOString(), last_updated_by: currentUser||'',
    }).eq('id', _mpCurrentPlan.id);
    if (error) throw error;
    const flagKey = {activity_photoshoot:'actPhotoshoot',activity_video:'actVideo',activity_content:'actContent',activity_activation:'actActivation',activity_kol:'actKol',activity_ads:'actAds'}[dbFlag];
    if (flagKey) _mpCurrentPlan[flagKey] = on;
    if (on) _mpExpanded.add(key); else _mpExpanded.delete(key);
    const col = _mpCols.find(c => c.id === _mpCurrentColId);
    if (col) renderMPDetailBody(col, _mpCurrentPlan);
  } catch (e) { alert('Gagal: ' + (e.message||e)); }
}

// Reference links — in-memory edits to plan.links, persisted whole-array
// on blur. Pattern mirrors sampling_links on collections.
function addMPLink() {
  if (!_mpCurrentPlan) return;
  _mpCurrentPlan.links = (_mpCurrentPlan.links||[]).concat([{label:'',url:''}]);
  _mpRerenderLinks();
  saveMPLinks();
}

function removeMPLink(idx) {
  if (!_mpCurrentPlan) return;
  const list = _mpCurrentPlan.links||[];
  list.splice(idx, 1);
  _mpCurrentPlan.links = list;
  _mpRerenderLinks();
  saveMPLinks();
}

function updateMPLink(idx, field, value) {
  if (!_mpCurrentPlan) return;
  const list = _mpCurrentPlan.links||[];
  if (!list[idx]) return;
  list[idx][field] = value;
}

async function saveMPLinks() {
  if (!_mpCurrentPlan) return;
  try {
    const {error} = await sb.from('marketing_plans').update({
      links: _mpCurrentPlan.links||[],
      last_updated: new Date().toISOString(), last_updated_by: currentUser||'',
    }).eq('id', _mpCurrentPlan.id);
    if (error) throw error;
  } catch (e) { console.warn('Save MP links failed:', e); }
}

// Re-render only the links list (not the whole detail body) on add/remove.
function _mpRerenderLinks() {
  const host = document.getElementById('mp-links-list');
  if (!host || !_mpCurrentPlan) return;
  const esc = s => (s||'').replace(/"/g,'&quot;');
  const list = _mpCurrentPlan.links||[];
  host.innerHTML = list.length ? list.map((l,i) => `<div style="display:grid;grid-template-columns:1fr 2fr auto;gap:6px;margin-bottom:6px;align-items:center">
    <input type="text" value="${esc(l.label||'')}" placeholder="Label (e.g. Moodboard)" oninput="updateMPLink(${i},'label',this.value)" onblur="saveMPLinks()" style="font-size:12px;padding:5px 8px">
    <input type="url" value="${esc(l.url||'')}" placeholder="https://..." oninput="updateMPLink(${i},'url',this.value)" onblur="saveMPLinks()" style="font-size:12px;padding:5px 8px;font-family:var(--mono)">
    <button onclick="removeMPLink(${i})" title="Hapus link" style="background:none;border:1px solid var(--g200);border-radius:4px;color:#c0392b;cursor:pointer;font-size:11px;padding:4px 10px">✕</button>
  </div>`).join('') : `<div style="text-align:center;padding:14px;color:var(--g400);font-size:12px">Belum ada link. Klik <strong>+ Tambah Link</strong> untuk simpan moodboard, brief, drive, deck, dll.</div>`;
}

async function saveMPField(field, value) {
  if (!_mpCurrentPlan) return;
  const payload = {
    last_updated: new Date().toISOString(), last_updated_by: currentUser||'',
  };
  const numericFields = ['budget','target_reach','target_engagement_rate','target_roi'];
  const dateFields = ['campaign_start','campaign_end'];
  if (numericFields.includes(field)) payload[field] = value === '' ? null : Number(value);
  else if (dateFields.includes(field)) payload[field] = value || null;
  else payload[field] = (value||'').trim() || null;
  try {
    const {error} = await sb.from('marketing_plans').update(payload).eq('id', _mpCurrentPlan.id);
    if (error) throw error;
    const localKey = {concept:'concept',objective:'objective',budget:'budget',kpi_targets:'kpiTargets',campaign_start:'campaignStart',campaign_end:'campaignEnd',status:'status',pic:'pic',notes:'notes',target_reach:'targetReach',target_engagement_rate:'targetEngagementRate',target_roi:'targetRoi'}[field];
    if (localKey) _mpCurrentPlan[localKey] = payload[field];
  } catch (e) { console.warn('Save MP field failed:', e); }
}

async function loadPhotoshoot() {
  if (!allColRows.length) await loadCollections().catch(()=>{});
  // Outbound cache (for sample shipment badge) + product_mappings (for sample picker)
  if (!allOutboundRows.length) {
    try {
      const {data} = await sb.from('outbound_requests').select('*');
      allOutboundRows = (data||[]).map(mapOutbound);
    } catch(e) { /* non-fatal */ }
  }
  // Lazy-load product_mappings via the KOL ref-data loader (idempotent)
  _kolMgmtEnsureRefData().catch(()=>{});
  const tbody = document.getElementById('psTableBody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="10">Memuat...</td></tr>`;
  try {
    const fStat = document.getElementById('ps-fil-status')?.value || '';
    const fCol  = document.getElementById('ps-fil-collection')?.value || '';
    const search = (document.getElementById('ps-search')?.value || '').trim().toLowerCase();
    let q = sb.from('photoshoots').select('*').order('shoot_date',{ascending:false,nullsFirst:false}).limit(5000);
    if (fStat) q = q.eq('status', fStat);
    if (fCol)  q = q.eq('collection_id', fCol);
    const {data, error} = await q;
    if (error) throw error;
    _psRows = (data||[]).map(mapPs);
    _psLocations = [...new Set(_psRows.map(r => r.location).filter(Boolean))].sort();
    // Populate collection filter dropdown from allColRows once
    const colSel = document.getElementById('ps-fil-collection');
    if (colSel && allColRows.length && colSel.options.length <= 1) {
      const cur = colSel.value;
      colSel.innerHTML = `<option value="">Semua Collection</option>` +
        allColRows.map(c => `<option value="${(c.id||'').replace(/"/g,'&quot;')}"${c.id===cur?' selected':''}>${(_colDisplayLabel(c)||'').replace(/</g,'&lt;')}</option>`).join('');
    }
    let rows = _psRows;
    if (search) rows = rows.filter(r => `${r.name} ${r.location} ${r.pic}`.toLowerCase().includes(search));
    const today = new Date().toISOString().slice(0,10);
    document.getElementById('ps-s-total').textContent     = _psRows.length;
    document.getElementById('ps-s-upcoming').textContent  = _psRows.filter(r=>r.shootDate && r.shootDate >= today && !['Delivered','Cancelled'].includes(r.status)).length;
    document.getElementById('ps-s-delivered').textContent = _psRows.filter(r=>r.status==='Delivered').length;
    document.getElementById('ps-s-budget').textContent    = _moRp(_psRows.reduce((s,r)=>s+Number(r.budget||0),0));
    document.getElementById('ps-tcount').textContent = `${rows.length} entri`;
    const colName = id => allColRows.find(c=>c.id===id)?.collectionName || '—';
    if (!rows.length) { tbody.innerHTML = `<tr><td class="empty-td" colspan="10">Tidak ada data.</td></tr>`; return; }
    tbody.innerHTML = rows.map(r => {
      const dueOver = r.deliveryDue && r.deliveryDue < today && r.status !== 'Delivered' && r.status !== 'Cancelled';
      const bb = r.budgetBreakdown||[];
      const sampleCogs = _kolItemsCOGS(r.sampleItems);
      const linkCount = (r.links||[]).length + (r.deliverablesUrl?1:0);
      const linkCell = linkCount
        ? `<span style="font-size:11px;color:#3C3489" title="${linkCount} link">↗ ${linkCount}</span>`
        : '<span style="color:var(--g400);font-size:10px">—</span>';
      return `<tr>
      <td><a href="#" onclick="event.preventDefault();openPsDrawerEdit('${r.id}')" style="font-weight:600;color:#3C3489;text-decoration:none" title="Klik buat buka detail">${_moEsc(r.name)}</a></td>
      <td style="font-size:11px;color:var(--g600)">${_moEsc(colName(r.collectionId))}</td>
      <td style="white-space:nowrap;font-size:11px">${_moDate(r.shootDate)}</td>
      <td style="white-space:nowrap;font-size:11px${dueOver?';color:#c33;font-weight:600':''}">${dueOver?'⚠ ':''}${_moDate(r.deliveryDue)}</td>
      <td style="font-size:11px">${_moEsc(r.location)||'—'}</td>
      <td style="font-size:11px">${_moEsc(r.pic)||'—'}</td>
      <td class="mono" style="text-align:right;white-space:nowrap">${_moRp(r.budget)}${sampleCogs>0?`<div style="font-size:9px;color:var(--g400);font-family:var(--mono);margin-top:1px">incl. sample ${_moRp(sampleCogs)}</div>`:bb.length?`<div style="font-size:9px;color:var(--g400);font-family:var(--mono);margin-top:1px">${bb.length} item</div>`:''}</td>
      <td><select onchange="updatePsStatus('${r.id}',this.value)" class="pill ${_PS_STATUS_TONE[r.status]||'p-draft'}" style="font-size:10px;padding:2px 6px;border:1px solid;border-radius:99px">${_PS_STATUS_OPTS.map(s=>`<option${r.status===s?' selected':''}>${s}</option>`).join('')}</select></td>
      <td>${linkCell}</td>
      <td style="white-space:nowrap"><button class="btn-icon" style="font-size:13px;color:#c0392b" onclick="deletePs('${r.id}')" title="Hapus">🗑</button></td>
    </tr>`;}).join('');
  } catch(e) { if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="10">Gagal: ${e.message||e}</td></tr>`; }
}

function clearPsFilters() {
  ['ps-fil-status','ps-fil-collection','ps-search'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  loadPhotoshoot();
}
function clearPsForm() {
  ['ps-name','ps-collection','ps-shoot-date','ps-delivery','ps-location','ps-pic','ps-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  const stat = document.getElementById('ps-status'); if (stat) stat.value = 'Planning';
  const fb=document.getElementById('ps-feedback'); if(fb) fb.textContent='';
}
async function submitPs() {
  const fb = document.getElementById('ps-feedback');
  const setFB = (msg, ok) => { fb.style.color = ok?'#0a7d3a':'#c0392b'; fb.textContent = msg; };
  const name = document.getElementById('ps-name').value.trim();
  if (!name) { setFB('⚠️ Shoot name wajib.', false); return; }
  try {
    const id = genId('PS');
    const {error} = await sb.from('photoshoots').insert({
      id, shoot_name: name,
      collection_id: _psPickedCollectionId(),
      shoot_date: document.getElementById('ps-shoot-date').value || null,
      delivery_due: document.getElementById('ps-delivery').value || null,
      location: document.getElementById('ps-location').value.trim() || null,
      pic: document.getElementById('ps-pic').value.trim() || null,
      notes: document.getElementById('ps-notes').value.trim() || null,
      status: document.getElementById('ps-status').value || 'Planning',
      added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    });
    if (error) throw error;
    logActivity('Photoshoot','create',id,`Shoot: ${name}`);
    setFB('✅ Tersimpan. Klik nama shoot di tab Semua buat tambah budget, links, sample request.', true);
    clearPsForm();
    setTimeout(()=>{fb.textContent='';}, 3500);
  } catch(e) { setFB('❌ Gagal: '+(e.message||e), false); }
}
async function updatePsStatus(id, status) {
  try {
    await sb.from('photoshoots').update({status, last_updated:new Date().toISOString(), last_updated_by:currentUser}).eq('id',id);
    const r = _psRows.find(x => x.id === id); if (r) r.status = status;
  } catch(e) { alert('Gagal: '+(e.message||e)); loadPhotoshoot(); }
}
async function deletePs(id) {
  const r = _psRows.find(x => x.id === id);
  if (!confirm(`Hapus shoot ${r?.name||id}?`)) return;
  try {
    if (r?.sampleOutboundId) await sb.from('outbound_requests').delete().eq('id', r.sampleOutboundId);
    await sb.from('photoshoots').delete().eq('id', id);
    logActivity('Photoshoot','delete',id,`Hapus: ${r?.name||id}`);
    loadPhotoshoot();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// ── PS drawer ─────────────────────────────────────────────────────────
async function openPsDrawerEdit(id) {
  const r = _psRows.find(x => x.id === id);
  if (!r) return;
  if (!allColRows.length) await loadCollections().catch(()=>{});
  await _kolMgmtEnsureRefData().catch(()=>{});
  document.getElementById('psDrawerTitle').textContent = `✎ ${r.name || id}`;
  document.getElementById('psDrawerBody').innerHTML = _psDrawerFormHTML(r);
  openPsDrawer();
  _psAttachDrawerAC(id);
}
function openPsDrawer() {
  document.getElementById('psDrawerBackdrop').style.display = 'block';
  document.getElementById('psDrawer').style.display = 'flex';
  document.body.style.overflow = 'hidden';
}
function closePsDrawer() {
  document.getElementById('psDrawerBackdrop').style.display = 'none';
  document.getElementById('psDrawer').style.display = 'none';
  document.body.style.overflow = '';
}

function _psBudgetRowHTML(b, idx, id) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const category = b?.category || '';
  const amount = b?.amount==null?'':b.amount;
  const note = b?.note || '';
  return `<div class="ps-bb-row" data-idx="${idx}" style="display:flex;gap:6px;align-items:center;margin-bottom:4px">
    <input type="text" class="psb-cat-${id}" value="${esc(category)}" placeholder="Kategori (Studio, Talent, Wardrobe, ...)" style="font-size:12px;padding:5px 8px;flex:1.2">
    <input type="number" min="0" class="psb-amt-${id}" value="${amount}" placeholder="Rp" style="font-size:12px;padding:5px 8px;width:110px;text-align:right">
    <input type="text" class="psb-note-${id}" value="${esc(note)}" placeholder="Note" style="font-size:12px;padding:5px 8px;flex:1">
    <button type="button" onclick="this.parentElement.remove();_psBudgetSumUpdate('${id}')" style="background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:13px;padding:3px 8px;color:#c0392b;line-height:1">🗑</button>
  </div>`;
}

function _psLinkRowHTML(l, idx, id) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const label = l?.label || '';
  const url = l?.url || '';
  return `<div class="ps-lnk-row" data-idx="${idx}" style="display:flex;gap:6px;align-items:center;margin-bottom:4px">
    <input type="text" class="psl-label-${id}" value="${esc(label)}" placeholder="Label (Moodboard, Brief, Drive, dll.)" style="font-size:12px;padding:5px 8px;flex:1">
    <input type="url" class="psl-url-${id}" value="${esc(url)}" placeholder="https://..." style="font-size:12px;padding:5px 8px;flex:1.5;font-family:var(--mono)">
    <button type="button" onclick="this.parentElement.remove()" style="background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:13px;padding:3px 8px;color:#c0392b;line-height:1">🗑</button>
  </div>`;
}

function _psDrawerFormHTML(r) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const colName = _colDisplayLabel(allColRows.find(c => c.id === r.collectionId)) || '';
  const id = r.id;
  const budgetRows = (r.budgetBreakdown||[]).map((b,i) => _psBudgetRowHTML(b, i, id)).join('');
  const linkRows = (r.links||[]).map((l,i) => _psLinkRowHTML(l, i, id)).join('');
  // Legacy deliverables_url surfaces as a pre-filled link row if links is empty
  const legacyLinkRow = (!r.links?.length && r.deliverablesUrl) ? _psLinkRowHTML({label:'Drive', url:r.deliverablesUrl}, 0, id) : '';
  const sampleRows = (r.sampleItems||[]).map(it => _kolFreebieRowHTML(it, `ps-sam-${id}`)).join('');
  const tabBtn = (key, label, badge) => `<button type="button" class="tab-btn ${key==='general'?'active':''}" data-tab="${key}" onclick="switchPsDrawerTab('${id}','${key}',this)" style="padding:6px 12px;font-size:11px;border:1px solid var(--g100);background:var(--white);border-radius:99px;cursor:pointer;font-family:var(--mono);font-weight:600;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600)">${label}${badge?` <span style="background:var(--g100);padding:1px 6px;border-radius:99px;font-size:9px;margin-left:3px">${badge}</span>`:''}</button>`;
  return `<div>
    <div id="psd-tabs-${id}" style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px;padding-bottom:10px;border-bottom:1px solid var(--g100)">
      ${tabBtn('general','General')}
      ${tabBtn('budget','💰 Budget', (r.budgetBreakdown||[]).length)}
      ${tabBtn('links','🔗 Links', (r.links||[]).length + (r.deliverablesUrl?1:0))}
      ${tabBtn('sample','🎁 Sample', (r.sampleItems||[]).length)}
    </div>

    <!-- General tab -->
    <div id="psdtab-general-${id}" class="psdtab-${id}">
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px">
        <div class="fg" style="margin:0"><label style="font-size:11px">Shoot Name *</label><input type="text" id="psed-name-${id}" value="${esc(r.name)}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg" style="margin:0;position:relative"><label style="font-size:11px">Collection</label>
          <input type="text" id="psed-collection-${id}" value="${esc(colName)}" autocomplete="off" placeholder="—" style="font-size:12px;padding:5px 8px">
          <div class="ac-list" id="ac-psed-collection-${id}"></div>
        </div>
        <div class="fg" style="margin:0"><label style="font-size:11px">Shoot Date</label><input type="date" id="psed-shoot-date-${id}" value="${r.shootDate||''}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg" style="margin:0"><label style="font-size:11px">Delivery Due</label><input type="date" id="psed-delivery-${id}" value="${r.deliveryDue||''}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg" style="margin:0;position:relative"><label style="font-size:11px">Location</label>
          <input type="text" id="psed-location-${id}" value="${esc(r.location)}" autocomplete="off" style="font-size:12px;padding:5px 8px">
          <div class="ac-list" id="ac-psed-location-${id}"></div>
        </div>
        <div class="fg" style="margin:0;position:relative"><label style="font-size:11px">PIC</label>
          <input type="text" id="psed-pic-${id}" value="${esc(r.pic)}" autocomplete="off" style="font-size:12px;padding:5px 8px">
          <div class="ac-list" id="ac-psed-pic-${id}"></div>
        </div>
        <div class="fg" style="margin:0"><label style="font-size:11px">Status</label>
          <select id="psed-status-${id}" style="font-size:12px;padding:5px 8px">${_PS_STATUS_OPTS.map(s=>`<option${r.status===s?' selected':''}>${s}</option>`).join('')}</select>
        </div>
      </div>
      <div class="fg" style="margin:0 0 12px"><label style="font-size:11px">Notes</label><textarea id="psed-notes-${id}" rows="3" style="font-size:12px;padding:5px 8px;resize:vertical">${esc(r.notes)}</textarea></div>
    </div>

    <!-- Budget tab -->
    <div id="psdtab-budget-${id}" class="psdtab-${id}" style="display:none">
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px;display:flex;align-items:center;gap:8px">
        💰 Budget Breakdown
        <span style="text-transform:none;letter-spacing:0;font-weight:400;color:var(--g400)">— budget total = Σ kategori + sample COGS</span>
        <span style="margin-left:auto;font-family:var(--mono);font-size:12px;color:#0a7d3a;font-weight:600">Total <span id="psb-sum-${id}">${_moRp(0)}</span></span>
      </div>
      <div id="psed-bb-${id}">${budgetRows}</div>
      <button class="btn-ghost" type="button" onclick="addPsBudgetRow('${id}')" style="padding:4px 10px;font-size:11px;margin-top:4px">+ Tambah Budget Item</button>
    </div>

    <!-- Links tab -->
    <div id="psdtab-links-${id}" class="psdtab-${id}" style="display:none">
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px">🔗 Links <span style="text-transform:none;letter-spacing:0;font-weight:400;color:var(--g400)">— moodboard, brief, drive deliverables, references</span></div>
      <div id="psed-links-${id}">${linkRows || legacyLinkRow}</div>
      <button class="btn-ghost" type="button" onclick="addPsLinkRow('${id}')" style="padding:4px 10px;font-size:11px;margin-top:4px">+ Tambah Link</button>
    </div>

    <!-- Sample tab -->
    <div id="psdtab-sample-${id}" class="psdtab-${id}" style="display:none">
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px">🎁 Sample Request</div>
      <div class="fg" style="margin:0 0 8px"><label style="font-size:11px">Alamat pengiriman</label><textarea id="psed-address-${id}" rows="2" style="font-size:12px;padding:5px 8px;resize:vertical" placeholder="Jl, kota, kode pos...">${esc(r.recipientAddress)}</textarea></div>
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px">Items</div>
      <div id="psed-sample-${id}" style="display:flex;flex-direction:column;gap:6px;margin-bottom:6px">${sampleRows}</div>
      <div style="display:flex;gap:6px;align-items:center;margin-bottom:12px">
        <button class="btn-ghost" type="button" onclick="addPsSampleRow('${id}')" style="padding:4px 10px;font-size:11px">+ Tambah Item</button>
        <div id="psed-sample-ship-${id}" style="font-size:11px;color:var(--g600);margin-left:auto"></div>
        <button class="btn-icon" type="button" onclick="requestPsSampleShipment('${id}')" id="psed-sample-btn-${id}" style="padding:4px 12px;font-size:11px;background:white;border:1px solid #c9bdf0;color:#3C3489;border-radius:4px">📦 Request Pengiriman</button>
      </div>
    </div>

    <div style="display:flex;gap:6px;padding-top:8px;margin-top:8px;border-top:1px solid var(--g100)">
      <button class="btn-primary" onclick="savePsEdit('${id}')" style="padding:7px 16px;font-size:13px">💾 Simpan</button>
      <button class="btn-ghost" onclick="closePsDrawer()" style="padding:7px 16px;font-size:13px">Batal</button>
      <div id="psed-fb-${id}" style="margin-left:auto;font-size:11px;align-self:center"></div>
    </div>
  </div>`;
}

function switchPsDrawerTab(id, key, btn) {
  document.querySelectorAll(`#psd-tabs-${id} .tab-btn`).forEach(b => {
    b.classList.remove('active');
    b.style.background = 'var(--white)';
    b.style.color = 'var(--g600)';
  });
  if (btn) {
    btn.classList.add('active');
    btn.style.background = '#3C3489';
    btn.style.color = 'var(--white)';
  }
  document.querySelectorAll(`.psdtab-${id}`).forEach(el => el.style.display = 'none');
  const target = document.getElementById(`psdtab-${key}-${id}`);
  if (target) target.style.display = '';
}

function _psAttachDrawerAC(id) {
  setupAC(`psed-collection-${id}`, `ac-psed-collection-${id}`, () => allColRows.map(c => _colDisplayLabel(c)).filter(Boolean));
  setupAC(`psed-location-${id}`, `ac-psed-location-${id}`, () => _psLocations);
  setupAC(`psed-pic-${id}`, `ac-psed-pic-${id}`, () => acPics);
  _psWireBudgetRowsAC(id);
  _psWireSampleRowsAC(id);
  _psRenderSampleShipBadge(id);
  _psBudgetSumUpdate(id);
  // Style General tab button as active
  const generalBtn = document.querySelector(`#psd-tabs-${id} [data-tab="general"]`);
  if (generalBtn) { generalBtn.style.background = '#3C3489'; generalBtn.style.color = 'var(--white)'; }
}

function _psWireBudgetRowsAC(id) {
  const host = document.getElementById(`psed-bb-${id}`);
  if (!host) return;
  host.querySelectorAll('.ps-bb-row').forEach(row => {
    row.querySelector(`.psb-amt-${id}`)?.addEventListener('input', () => _psBudgetSumUpdate(id));
  });
}

function _psWireSampleRowsAC(id) {
  const host = document.getElementById(`psed-sample-${id}`);
  if (!host) return;
  host.querySelectorAll('.kol-frb-row').forEach(row => {
    const display = row.querySelector(`.ps-sam-${id}-display`);
    const ac = row.querySelector(`.ps-sam-${id}-ac`);
    if (!display || !ac) return;
    display.addEventListener('input', () => _kolFrbRenderAC(display, ac));
    display.addEventListener('focus', () => _kolFrbRenderAC(display, ac));
    document.addEventListener('click', e => {
      if (!display.contains(e.target) && !ac.contains(e.target)) ac.style.display = 'none';
    });
    const refresh = () => _psBudgetSumUpdate(id);
    row.querySelector(`.ps-sam-${id}-qty`)?.addEventListener('input', refresh);
  });
}

function addPsBudgetRow(id) {
  const host = document.getElementById(`psed-bb-${id}`);
  const idx = host.children.length;
  host.insertAdjacentHTML('beforeend', _psBudgetRowHTML(null, idx, id));
  _psWireBudgetRowsAC(id);
}

function addPsLinkRow(id) {
  const host = document.getElementById(`psed-links-${id}`);
  const idx = host.children.length;
  host.insertAdjacentHTML('beforeend', _psLinkRowHTML(null, idx, id));
}

function addPsSampleRow(id) {
  const host = document.getElementById(`psed-sample-${id}`);
  host.insertAdjacentHTML('beforeend', _kolFreebieRowHTML(null, `ps-sam-${id}`));
  const row = host.lastElementChild;
  const display = row.querySelector(`.ps-sam-${id}-display`);
  const ac = row.querySelector(`.ps-sam-${id}-ac`);
  if (display && ac) {
    display.addEventListener('input', () => _kolFrbRenderAC(display, ac));
    display.addEventListener('focus', () => _kolFrbRenderAC(display, ac));
    document.addEventListener('click', e => {
      if (!display.contains(e.target) && !ac.contains(e.target)) ac.style.display = 'none';
    });
  }
  _psBudgetSumUpdate(id);
}

function _psBudgetSumUpdate(id) {
  const host = document.getElementById(`psed-bb-${id}`);
  if (!host) return;
  let breakdownSum = 0;
  host.querySelectorAll(`.psb-amt-${id}`).forEach(inp => {
    const v = parseFloat(inp.value); if (!isNaN(v)) breakdownSum += v;
  });
  const sampleItems = _kolReadFreebieFrom(`psed-sample-${id}`, `ps-sam-${id}`);
  const sampleCogs = _kolItemsCOGS(sampleItems);
  const total = breakdownSum + sampleCogs;
  const el = document.getElementById(`psb-sum-${id}`);
  if (el) {
    if (sampleCogs > 0) {
      el.innerHTML = `${_moRp(total)} <span style="font-size:9px;color:var(--g400);font-weight:400">(${_moRp(breakdownSum)} budget + ${_moRp(sampleCogs)} sample)</span>`;
    } else {
      el.textContent = _moRp(total);
    }
  }
}

function _psReadBudget(id) {
  const host = document.getElementById(`psed-bb-${id}`);
  if (!host) return [];
  const out = [];
  host.querySelectorAll('.ps-bb-row').forEach(row => {
    const category = (row.querySelector(`.psb-cat-${id}`)?.value || '').trim();
    const amountRaw = row.querySelector(`.psb-amt-${id}`)?.value;
    const note = (row.querySelector(`.psb-note-${id}`)?.value || '').trim();
    const amount = amountRaw === '' ? null : Number(amountRaw);
    if (category || amount || note) out.push({category, amount, note});
  });
  return out;
}

function _psReadLinks(id) {
  const host = document.getElementById(`psed-links-${id}`);
  if (!host) return [];
  const out = [];
  host.querySelectorAll('.ps-lnk-row').forEach(row => {
    const label = (row.querySelector(`.psl-label-${id}`)?.value || '').trim();
    const url = (row.querySelector(`.psl-url-${id}`)?.value || '').trim();
    if (url) out.push({label, url});
  });
  return out;
}

function _psRenderSampleShipBadge(id) {
  const r = _psRows.find(x => x.id === id);
  if (!r) return;
  const badge = document.getElementById(`psed-sample-ship-${id}`);
  const btn = document.getElementById(`psed-sample-btn-${id}`);
  if (!badge || !btn) return;
  if (r.sampleOutboundId) {
    const ob = allOutboundRows.find(x => x.id === r.sampleOutboundId);
    const status = ob?.status ? ` · ${ob.status}` : '';
    const ship = (typeof ob?.shippingCost === 'number') ? ` · 🚚 ${_moRp(ob.shippingCost)}` : '';
    badge.innerHTML = `<a href="#" onclick="event.preventDefault();showPage('outbound',null)" style="color:#3C3489;text-decoration:underline">✓ ${(r.sampleOutboundId||'').replace(/</g,'&lt;')}</a><span style="color:var(--g600)">${status}${ship}</span>`;
    btn.style.display = 'none';
  } else {
    badge.textContent = '';
    btn.style.display = '';
  }
}

async function savePsEdit(id) {
  const fb = document.getElementById(`psed-fb-${id}`);
  const setFB = (msg, ok) => { if (fb) { fb.style.color = ok?'#0a7d3a':'#c0392b'; fb.textContent = msg; } };
  const name = (document.getElementById(`psed-name-${id}`).value || '').trim();
  if (!name) { setFB('Shoot name wajib', false); return; }
  const colName = (document.getElementById(`psed-collection-${id}`).value || '').trim().toLowerCase();
  const colMatch = _colFindByLabel(colName);
  const breakdown = _psReadBudget(id);
  const breakdownSum = breakdown.reduce((s, b) => s + Number(b.amount||0), 0);
  const sampleItems = _kolReadFreebieFrom(`psed-sample-${id}`, `ps-sam-${id}`);
  const budgetTotal = breakdownSum + _kolItemsCOGS(sampleItems);
  const links = _psReadLinks(id);
  const payload = {
    shoot_name: name,
    collection_id: colMatch ? colMatch.id : null,
    shoot_date: document.getElementById(`psed-shoot-date-${id}`).value || null,
    delivery_due: document.getElementById(`psed-delivery-${id}`).value || null,
    location: (document.getElementById(`psed-location-${id}`).value || '').trim() || null,
    pic: (document.getElementById(`psed-pic-${id}`).value || '').trim() || null,
    notes: (document.getElementById(`psed-notes-${id}`).value || '').trim() || null,
    status: document.getElementById(`psed-status-${id}`).value || 'Planning',
    recipient_address: (document.getElementById(`psed-address-${id}`).value || '').trim() || null,
    budget: budgetTotal > 0 ? budgetTotal : null,
    budget_breakdown: breakdown,
    sample_items: sampleItems,
    links,
    last_updated: new Date().toISOString(), last_updated_by: currentUser || '',
  };
  try {
    const {error} = await sb.from('photoshoots').update(payload).eq('id', id);
    if (error) throw error;
    logActivity('Photoshoot','edit',id,`Edit: ${name}`);
    setFB('✓ Tersimpan', true);
    setTimeout(() => closePsDrawer(), 600);
    loadPhotoshoot();
  } catch(e) { setFB('Gagal: ' + (e.message||e), false); }
}

async function requestPsSampleShipment(id) {
  const r = _psRows.find(x => x.id === id);
  if (!r) return;
  if (r.sampleOutboundId) { alert('Sudah ada outbound request: ' + r.sampleOutboundId); return; }
  const items = _kolReadFreebieFrom(`psed-sample-${id}`, `ps-sam-${id}`);
  if (!items.length) { alert('Belum ada item sample. Tambahkan dulu trus klik lagi.'); return; }
  const address = (document.getElementById(`psed-address-${id}`)?.value || '').trim();
  const pic = (document.getElementById(`psed-pic-${id}`)?.value || '').trim();
  const sd = document.getElementById(`psed-shoot-date-${id}`)?.value || '';
  if (!confirm(`Buat outbound ticket buat ${items.length} sample item ke "${address || r.location || '(no address)'}"?`)) return;
  try {
    await sb.from('photoshoots').update({
      sample_items: items, recipient_address: address || null,
      last_updated: new Date().toISOString(), last_updated_by: currentUser||'',
    }).eq('id', id);
    const obId = genId('OB');
    const payload = {
      id: obId,
      source_module: 'PhotoshootPlanning',
      source_id: id,
      recipient_name: pic || r.name,
      recipient_address: address || r.location || null,
      recipient_phone: null,
      requested_ship_date: sd || null,
      items, status: 'Pending',
      notes: `Auto-created from photoshoot ${id} (${r.name})`,
      added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    };
    const {error: e1} = await sb.from('outbound_requests').insert(payload);
    if (e1) throw e1;
    const {error: e2} = await sb.from('photoshoots').update({
      sample_outbound_id: obId, last_updated: new Date().toISOString(), last_updated_by: currentUser||'',
    }).eq('id', id);
    if (e2) throw e2;
    r.sampleItems = items;
    r.sampleOutboundId = obId;
    r.recipientAddress = address;
    if (allOutboundRows.length) allOutboundRows.push(mapOutbound({...payload}));
    _psRenderSampleShipBadge(id);
    logActivity('Photoshoot','request_sample',id,`→ ${obId}`);
    alert(`✓ Ticket ${obId} dibuat. Buka modul Outbond Request buat track delivery.`);
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// ── 6. KOL MANAGEMENT ──
let _kolRows = [];
// ── KOL MANAGEMENT (revamped essentials) ──
// Form fields: collection, KOL name (AC from kol_database with auto-tier display),
// deliverables multi-row picker, payment category (Barter / Pay / Pay+Barter),
// conditional fee + freebie section (recipient/address/items). Save creates
// kol_placement; "Request Pengiriman" creates outbound_request linked back.

const _KOL_STATUS_OPTS = ['Planning','Outreach','Publish'];
const _KOL_STATUS_TONE = { Planning:'p-draft', Outreach:'p-review', Publish:'p-active' };
const _KOL_PAY_CATS = ['Barter','Pay','Pay+Barter'];
let _kolDbCachePromise = null;
let _kolProdMapCache = []; // [{id, item_name, brand}] for freebie picker
let _kolProdMapCachePromise = null;

function switchKolTab(tab, el) {
  document.querySelectorAll('#page-kolmgmt .tab-btn').forEach(b=>b.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('koltab-new').style.display  = tab==='new'  ? '' : 'none';
  document.getElementById('koltab-list').style.display = tab==='list' ? '' : 'none';
  if (tab==='list') loadKolMgmt();
  if (tab==='new') { _kolMgmtEnsureRefData(); _kolMgmtSeedForm(); }
}

function mapKol(r) {
  return {
    id: r.id, collectionId: r.collection_id || '',
    name: r.kol_name || '',
    kolDbId: r.kol_db_id || '',
    paymentCategory: r.payment_category || '',
    deliverablesList: Array.isArray(r.deliverables_list) ? r.deliverables_list : [],
    freebieItems: Array.isArray(r.freebie_items) ? r.freebie_items : [],
    outboundRequestId: r.outbound_request_id || '',
    recipientAddress: r.recipient_address || '',
    recipientPhone: r.recipient_phone || '',
    requestedShipDate: r.requested_ship_date,
    // legacy / kept fields
    fee: r.fee, postDate: r.post_date || '', pic: r.pic || '',
    status: r.status || 'Planning', notes: r.notes || '',
    handle: r.handle || '', platform: r.platform || '',
    tier: r.tier || '', followers: r.followers,
    paymentStatus: r.payment_status || '',
    deliverablesText: r.deliverables || '',
    briefUrl: r.brief_url || '', postUrl: r.post_url || '',
  };
}

// Lazy-load reference caches (collections, kol_database, product_mappings,
// outbound_requests) once per session
let _kolColCachePromise = null;
let _kolOutboundCachePromise = null;
async function _kolMgmtEnsureRefData() {
  // outbound_requests — for shipping_cost / status callback on linked placements.
  // Use a data-only fetch (loadOutbound paints DOM that only exists on page-outbound).
  if (!allOutboundRows.length) {
    if (!_kolOutboundCachePromise) {
      _kolOutboundCachePromise = (async () => {
        try {
          const {data} = await sb.from('outbound_requests').select('*');
          allOutboundRows = (data||[]).map(mapOutbound);
        } catch (e) { console.warn('outbound_requests cache failed:', e); }
      })();
    }
    await _kolOutboundCachePromise;
  }
  // collections — for AC + filter + colName lookup in table
  if (!allColRows.length) {
    if (!_kolColCachePromise) _kolColCachePromise = loadCollections().catch(() => {});
    await _kolColCachePromise;
  }
  // kol_database — populates allKolDbRows used by name AC + insights display
  if (!allKolDbRows.length) {
    if (!_kolDbCachePromise) _kolDbCachePromise = loadKolDb().catch(() => {});
    await _kolDbCachePromise;
  }
  // product_mappings — picker source for freebie items. Joins thumbnail from
  // jubelio_items so the AC dropdown + saved rows can show product photos.
  if (!_kolProdMapCache.length) {
    if (!_kolProdMapCachePromise) {
      _kolProdMapCachePromise = (async () => {
        try {
          // Supabase server caps responses at 1000 rows regardless of .limit().
          // Paginate via .range() so all 3000+ rows make it into the cache,
          // otherwise items past the alphabetical 1000 mark disappear from the
          // freebie picker (was hiding "Marbles ..." items, etc).
          const rows = [];
          const CHUNK = 1000;
          let from = 0;
          while (true) {
            const {data: page} = await sb.from('product_mappings')
              .select('id,item_name,brand,jubelio_item_id')
              .order('item_name')
              .range(from, from + CHUNK - 1);
            if (!page || !page.length) break;
            rows.push(...page);
            if (page.length < CHUNK) break;
            from += CHUNK;
            if (from > 50000) break;  // safety net
          }
          // Resolve thumbnails + average_cost (HPP) via jubelio_items.item_id —
          // chunk to dodge .in() URL cap. HPP feeds freebie/sample COGS so it
          // gets counted as budget in Marketing Activation MER calcs.
          const itemIds = [...new Set(rows.map(r => r.jubelio_item_id).filter(Boolean))];
          const thumbMap = new Map();
          const costMap = new Map();
          const THUMB_CHUNK = 500;
          for (let i = 0; i < itemIds.length; i += THUMB_CHUNK) {
            const chunk = itemIds.slice(i, i + THUMB_CHUNK);
            const {data: items} = await sb.from('jubelio_items').select('item_id,thumbnail,average_cost').in('item_id', chunk);
            (items || []).forEach(it => {
              if (it.thumbnail) thumbMap.set(String(it.item_id), it.thumbnail);
              if (it.average_cost != null) costMap.set(String(it.item_id), Number(it.average_cost));
            });
          }
          // Dedupe by item_name (parent-level), same treatment as the Product
          // Mapping module — show one row per product instead of per size variant.
          // Size is entered manually in the freebie/sample row's Size field.
          // Representative row = first variant; thumbnail + HPP inherit from it
          // (HPP can be overridden per ticket in Outbond Request anyway).
          const byName = new Map();
          for (const x of rows) {
            const name = (x.item_name || x.id || '').trim();
            if (!name) continue;
            if (byName.has(name)) {
              byName.get(name).variantCount += 1;
              continue;
            }
            byName.set(name, {
              id: x.id,
              item_name: name,
              brand: x.brand || '',
              thumbnail: x.jubelio_item_id ? (thumbMap.get(String(x.jubelio_item_id)) || '') : '',
              hpp: x.jubelio_item_id ? (costMap.get(String(x.jubelio_item_id)) || 0) : 0,
              variantCount: 1,
            });
          }
          _kolProdMapCache = [...byName.values()];
        } catch (e) { console.warn('product_mappings cache failed:', e); }
      })();
    }
    await _kolProdMapCachePromise;
  }
}

// Initial form setup: ensure status default + AC wires + one empty row each section
let _kolFormWired = false;
async function _kolMgmtSeedForm() {
  await _kolMgmtEnsureRefData();
  if (!_kolFormWired) {
    setupAC('kol-collection', 'ac-kol-collection', () => allColRows.map(c => _colDisplayLabel(c)).filter(Boolean));
    setupAC('kol-name', 'ac-kol-name', () => allKolDbRows.map(k => k.name).filter(Boolean));
    setupAC('kol-pic', 'ac-kol-pic', () => acPics);
    // Track KOL name picks → update insights display
    const nameInp = document.getElementById('kol-name');
    if (nameInp) nameInp.addEventListener('change', _kolRefreshInsights);
    if (nameInp) nameInp.addEventListener('blur', _kolRefreshInsights);
    _kolFormWired = true;
  }
  // Start with at least 1 deliverable row + barter section visible per current category
  if (document.getElementById('kol-deliverables-rows').children.length === 0) addKolDeliverableRow();
  toggleKolPaymentSections();
}

function _kolRefreshInsights() {
  const name = (document.getElementById('kol-name')?.value || '').trim();
  const host = document.getElementById('kol-insights-display');
  if (!host) return;
  if (!name) { host.textContent = 'Pilih KOL untuk lihat tier & follower count dari KOL Database.'; return; }
  const k = allKolDbRows.find(x => (x.name||'').toLowerCase() === name.toLowerCase());
  if (!k) {
    host.innerHTML = `<span style="color:var(--g600)">"${name.replace(/</g,'&lt;')}" belum ada di KOL Database — bakal auto-buat entry baru saat simpan.</span>`;
    return;
  }
  const fbp = k.followersByPlatform || {};
  let primary = 0, total = 0;
  for (const v of Object.values(fbp)) { if (typeof v === 'number') { total += v; if (v > primary) primary = v; } }
  const tierHtml = _kolDbTierBadge(k.tier);
  const reach = primary
    ? `<span style="font-family:var(--mono);font-size:11px;color:var(--g600);margin-left:8px">Primary ${_kolDbFmtFollowers(primary)} · Total reach ${_kolDbFmtFollowers(total)}</span>`
    : `<span style="font-size:11px;color:var(--g400);margin-left:8px">Insights belum di-refresh</span>`;
  host.innerHTML = `${tierHtml}${reach}`;
}

// Map kol-name display value back to kol_database id (for FK)
function _kolPickedDbId() {
  const name = (document.getElementById('kol-name')?.value || '').trim().toLowerCase();
  if (!name) return null;
  const k = allKolDbRows.find(x => (x.name||'').toLowerCase() === name);
  return k ? k.id : null;
}

// Map collection display value back to collection id
function _kolPickedCollectionId() {
  const name = (document.getElementById('kol-collection')?.value || '').trim().toLowerCase();
  if (!name) return null;
  const c = _colFindByLabel(name);
  return c ? c.id : null;
}

// Multi-row picker: deliverables (platform + URL — reuses KOL DB pattern)
function _kolDeliverableRowHTML(platform, url, prefix) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const opts = _KOLDB_PLATFORMS.map(p => `<option value="${p}"${p===platform?' selected':''}>${p}</option>`).join('');
  return `<div class="kol-deliv-row" style="display:flex;gap:6px;align-items:center">
    <select class="${prefix}-platform" style="font-size:12px;padding:5px 8px;width:130px;flex-shrink:0">${opts}</select>
    <input type="url" class="${prefix}-url" value="${esc(url)}" placeholder="https://..." style="font-size:12px;padding:5px 8px;flex:1;font-family:var(--mono)">
    <button type="button" onclick="this.parentElement.remove()" style="background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:13px;padding:3px 8px;color:#c0392b;line-height:1">🗑</button>
  </div>`;
}

function addKolDeliverableRow(platform, url) {
  const host = document.getElementById('kol-deliverables-rows');
  host.insertAdjacentHTML('beforeend', _kolDeliverableRowHTML(platform || 'Instagram', url || '', 'kol-deliv'));
}

function _kolReadDelivFrom(containerId, prefix) {
  const rows = document.querySelectorAll(`#${containerId} .kol-deliv-row`);
  const out = [];
  rows.forEach(r => {
    const platform = r.querySelector(`.${prefix}-platform`)?.value || '';
    const url = (r.querySelector(`.${prefix}-url`)?.value || '').trim();
    if (platform && url) out.push({platform, url});
  });
  return out;
}
function _kolReadDeliverables() { return _kolReadDelivFrom('kol-deliverables-rows', 'kol-deliv'); }

// Multi-row picker: freebie items (SKU from product_mappings + qty)
function _kolFreebieRowHTML(item, prefix) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const sku = item?.sku || '';
  const itemName = item?.item_name || '';
  const thumb = item?.thumbnail || '';
  const size = item?.size || '';
  const qty = item?.qty || 1;
  const hpp = Number(item?.hpp || 0);
  const display = sku ? `${sku} — ${itemName}` : '';
  const previewInner = thumb
    ? `<img src="${esc(thumb)}" alt="" style="width:32px;height:32px;border-radius:4px;object-fit:cover">`
    : `<div style="width:32px;height:32px;border-radius:4px;background:var(--g100);display:flex;align-items:center;justify-content:center;color:var(--g400);font-size:14px">📦</div>`;
  const subVal = hpp > 0 ? _moRp(hpp * qty) : '—';
  return `<div class="kol-frb-row" style="display:flex;gap:6px;align-items:center">
    <div class="kol-frb-preview" style="flex-shrink:0">${previewInner}</div>
    <div style="flex:1;position:relative">
      <input type="text" class="${prefix}-display" value="${esc(display)}" placeholder="Ketik nama / SKU buat search dari product master" autocomplete="off" style="font-size:12px;padding:5px 8px;width:100%;box-sizing:border-box">
      <div class="ac-list ${prefix}-ac"></div>
      <input type="hidden" class="${prefix}-sku" value="${esc(sku)}">
      <input type="hidden" class="${prefix}-name" value="${esc(itemName)}">
      <input type="hidden" class="${prefix}-thumb" value="${esc(thumb)}">
      <input type="hidden" class="${prefix}-hpp" value="${hpp}">
    </div>
    <input type="text" class="${prefix}-size" value="${esc(size)}" placeholder="Size" style="font-size:12px;padding:5px 8px;width:60px;text-align:center" title="Size">
    <input type="number" min="1" class="${prefix}-qty" value="${qty}" onchange="_kolFrbRecalcSub(this)" oninput="_kolFrbRecalcSub(this)" style="font-size:12px;padding:5px 8px;width:60px;text-align:right" title="Qty">
    <span class="kol-frb-sub" style="font-size:10px;font-family:var(--mono);color:var(--g600);min-width:90px;text-align:right" title="HPP × qty — override di Outbond Request kalau kosong">${subVal}</span>
    <button type="button" onclick="this.parentElement.remove()" style="background:none;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:13px;padding:3px 8px;color:#c0392b;line-height:1">🗑</button>
  </div>`;
}

// Live-update the HPP×qty subtotal label when qty OR hpp changes
function _kolFrbRecalcSub(inp) {
  const row = inp.closest('.kol-frb-row');
  if (!row) return;
  const hpp = parseFloat(row.querySelector('[class$="-hpp"]')?.value) || 0;
  const qty = parseInt(row.querySelector('[class$="-qty"]')?.value, 10) || 1;
  const sub = row.querySelector('.kol-frb-sub');
  if (sub) sub.textContent = hpp > 0 ? _moRp(hpp * qty) : '—';
}

function addKolFreebieRow(item) {
  const host = document.getElementById('kol-freebie-rows');
  host.insertAdjacentHTML('beforeend', _kolFreebieRowHTML(item || null, 'kol-frb'));
  // Wire the new row's AC against the last appended display input
  const row = host.lastElementChild;
  const display = row.querySelector('.kol-frb-display');
  const ac = row.querySelector('.kol-frb-ac');
  display.addEventListener('input', () => _kolFrbRenderAC(display, ac));
  display.addEventListener('focus', () => _kolFrbRenderAC(display, ac));
  document.addEventListener('click', e => {
    if (!display.contains(e.target) && !ac.contains(e.target)) ac.style.display = 'none';
  });
}

function _kolFrbRenderAC(display, ac) {
  const q = display.value.toLowerCase().trim();
  if (!q) { ac.style.display = 'none'; return; }
  const matches = _kolProdMapCache.filter(p =>
    p.id.toLowerCase().includes(q) || (p.item_name||'').toLowerCase().includes(q)
  ).slice(0, 20);
  if (!matches.length) { ac.style.display = 'none'; return; }
  const r = display.getBoundingClientRect();
  ac.style.position = 'fixed';
  ac.style.top = (r.bottom + 4) + 'px';
  ac.style.left = r.left + 'px';
  ac.style.width = Math.max(r.width, 360) + 'px';
  ac.style.right = 'auto';
  ac.innerHTML = matches.map(m => {
    const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;').replace(/</g,'&lt;');
    const thumb = m.thumbnail
      ? `<img src="${esc(m.thumbnail)}" alt="" loading="lazy" style="width:36px;height:36px;border-radius:4px;object-fit:cover;background:var(--g100);flex-shrink:0">`
      : `<div style="width:36px;height:36px;border-radius:4px;background:var(--g100);flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:14px;color:var(--g400)">📦</div>`;
    const meta = [];
    if (m.brand) meta.push(esc(m.brand));
    if (m.variantCount > 1) meta.push(`${m.variantCount} sizes`);
    if (m.hpp > 0) meta.push(`HPP ${_moRp(m.hpp)}`);
    const metaLine = meta.length ? `<div style="font-size:10px;color:var(--g600);font-family:var(--mono);margin-top:1px">${meta.join(' · ')}</div>` : '';
    return `<div class="ac-item" data-sku="${esc(m.id)}" data-name="${esc(m.item_name)}" data-thumb="${esc(m.thumbnail)}" data-hpp="${m.hpp||0}" style="display:flex;align-items:center;gap:8px;padding:6px 10px">
      ${thumb}
      <div style="min-width:0;flex:1">
        <div style="font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${esc(m.item_name)}</div>
        ${metaLine}
      </div>
    </div>`;
  }).join('');
  ac.style.display = 'block';
  ac.querySelectorAll('.ac-item').forEach(it => {
    it.addEventListener('click', () => {
      const sku = it.dataset.sku, name = it.dataset.name, thumb = it.dataset.thumb;
      const hpp = parseFloat(it.dataset.hpp) || 0;
      display.value = `${sku} — ${name}`;
      const row = display.closest('.kol-frb-row');
      row.querySelector('[class$="-sku"]').value = sku;
      row.querySelector('[class$="-name"]').value = name;
      const thumbInp = row.querySelector('[class$="-thumb"]');
      if (thumbInp) thumbInp.value = thumb || '';
      const hppInp = row.querySelector('[class$="-hpp"]');
      if (hppInp) hppInp.value = hpp;
      // Update per-row HPP × qty subtotal display
      const subEl = row.querySelector('.kol-frb-sub');
      if (subEl) {
        const qty = parseInt(row.querySelector('[class$="-qty"]')?.value,10) || 1;
        subEl.textContent = hpp > 0 ? _moRp(hpp * qty) : '—';
      }
      // update thumb preview in the row
      const preview = row.querySelector('.kol-frb-preview');
      if (preview) {
        preview.innerHTML = thumb
          ? `<img src="${thumb}" alt="" style="width:32px;height:32px;border-radius:4px;object-fit:cover">`
          : `<div style="width:32px;height:32px;border-radius:4px;background:var(--g100);display:flex;align-items:center;justify-content:center;color:var(--g400);font-size:14px">📦</div>`;
      }
      ac.style.display = 'none';
    });
  });
}

function _kolReadFreebieFrom(containerId, prefix) {
  const rows = document.querySelectorAll(`#${containerId} .kol-frb-row`);
  const out = [];
  rows.forEach(r => {
    const sku = r.querySelector(`.${prefix}-sku`)?.value || '';
    const item_name = r.querySelector(`.${prefix}-name`)?.value || '';
    const thumbnail = r.querySelector(`.${prefix}-thumb`)?.value || '';
    const size = (r.querySelector(`.${prefix}-size`)?.value || '').trim();
    const qty = parseInt(r.querySelector(`.${prefix}-qty`)?.value, 10) || 1;
    const hpp = parseFloat(r.querySelector(`.${prefix}-hpp`)?.value) || 0;
    if (sku) out.push({sku, item_name, thumbnail, size, qty, hpp});
  });
  return out;
}

// Sum HPP × qty across a saved items array
function _kolItemsCOGS(items) {
  return (items||[]).reduce((s, it) => s + (Number(it.hpp||0) * Number(it.qty||1)), 0);
}

// Recalc the KOL drawer's freebie-section Total HPP label on qty/item changes.
function _kolEditRecalcCOGS(id) {
  const items = _kolReadFreebieFrom(`kole-frb-${id}`, `kole-frb-${id}`);
  const el = document.getElementById(`kole-cogs-${id}`);
  if (el) el.textContent = _moRp(_kolItemsCOGS(items));
}
function _kolReadFreebieItems() { return _kolReadFreebieFrom('kol-freebie-rows', 'kol-frb'); }

// Toggle visibility of Fee field + Barter section based on payment_category
function toggleKolPaymentSections() {
  const cat = document.getElementById('kol-payment-category')?.value || 'Barter';
  const feeFg = document.getElementById('kol-fee-fg');
  const barterSec = document.getElementById('kol-barter-section');
  if (feeFg) feeFg.style.display = (cat === 'Pay' || cat === 'Pay+Barter') ? '' : 'none';
  if (barterSec) barterSec.style.display = (cat === 'Barter' || cat === 'Pay+Barter') ? '' : 'none';
  // Seed at least one freebie row when barter shown
  if ((cat === 'Barter' || cat === 'Pay+Barter') && document.getElementById('kol-freebie-rows').children.length === 0) {
    addKolFreebieRow();
  }
}

function clearKolForm() {
  ['kol-collection','kol-name','kol-fee','kol-rec-name','kol-rec-phone','kol-rec-address','kol-ship-date','kol-post-date','kol-pic','kol-notes'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  const cat = document.getElementById('kol-payment-category'); if (cat) cat.value = 'Barter';
  const stat = document.getElementById('kol-status'); if (stat) stat.value = 'Planning';
  document.getElementById('kol-deliverables-rows').innerHTML = '';
  document.getElementById('kol-freebie-rows').innerHTML = '';
  const fb = document.getElementById('kol-feedback'); if (fb) fb.textContent = '';
  _kolRefreshInsights();
  toggleKolPaymentSections();
  addKolDeliverableRow();
}

async function submitKol() {
  const fb = document.getElementById('kol-feedback');
  const setFB = (msg, ok) => { fb.style.color = ok?'#0a7d3a':'#c0392b'; fb.textContent = msg; };
  const name = (document.getElementById('kol-name').value || '').trim();
  if (!name) { setFB('⚠️ Nama KOL wajib.', false); return; }
  const cat = document.getElementById('kol-payment-category').value || 'Barter';
  const fee = (cat === 'Pay' || cat === 'Pay+Barter')
    ? (parseFloat(document.getElementById('kol-fee').value) || null) : null;
  const deliverables = _kolReadDeliverables();
  const freebieItems = (cat === 'Barter' || cat === 'Pay+Barter') ? _kolReadFreebieItems() : [];
  try {
    const id = genId('KOL');
    const colId = _kolPickedCollectionId();
    const kolDbId = _kolPickedDbId();
    const recName = (document.getElementById('kol-rec-name').value || '').trim() || name;
    const payload = {
      id, kol_name: name,
      kol_db_id: kolDbId,
      collection_id: colId,
      payment_category: cat,
      fee,
      deliverables_list: deliverables,
      freebie_items: freebieItems,
      recipient_address: (document.getElementById('kol-rec-address').value || '').trim() || null,
      recipient_phone: (document.getElementById('kol-rec-phone').value || '').trim() || null,
      requested_ship_date: document.getElementById('kol-ship-date').value || null,
      post_date: document.getElementById('kol-post-date').value || null,
      pic: (document.getElementById('kol-pic').value || '').trim() || null,
      status: document.getElementById('kol-status').value || 'Planning',
      notes: (document.getElementById('kol-notes').value || '').trim() || null,
      added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    };
    const {error} = await sb.from('kol_placements').insert(payload);
    if (error) throw error;
    // Auto-seed kol_database if user typed a new name
    if (!kolDbId) {
      try {
        const kdId = genId('KD');
        await sb.from('kol_database').insert({
          id: kdId, name,
          added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
          last_updated: new Date().toISOString(), last_updated_by: currentUser,
        });
      } catch (e) { console.warn('Auto-seed kol_database failed:', e); }
    }
    logActivity('KolManagement','create',id,`KOL: ${name} · ${cat}`);
    setFB('✅ Placement tersimpan.', true);
    clearKolForm();
    setTimeout(() => { fb.textContent = ''; }, 2500);
  } catch(e) { setFB('❌ Gagal: ' + (e.message||e), false); }
}

function _kolFmtRp(n) {
  if (typeof n !== 'number' || !isFinite(n)) return '—';
  return 'Rp ' + Math.round(n).toLocaleString('id-ID');
}

async function loadKolMgmt() {
  await _kolMgmtEnsureRefData();
  // Populate collection filter dropdown from allColRows
  const colFil = document.getElementById('kol-fil-collection');
  if (colFil && allColRows.length && colFil.options.length <= 1) {
    const cur = colFil.value;
    colFil.innerHTML = `<option value="">Semua Collection</option>` +
      allColRows.map(c => `<option value="${(c.id||'').replace(/"/g,'&quot;')}"${c.id===cur?' selected':''}>${(_colDisplayLabel(c)||'').replace(/</g,'&lt;')}</option>`).join('');
  }
  const tbody = document.getElementById('kolTableBody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Memuat...</td></tr>`;
  try {
    const fStat = document.getElementById('kol-fil-status')?.value || '';
    const fPay  = document.getElementById('kol-fil-payment')?.value || '';
    const fCol  = document.getElementById('kol-fil-collection')?.value || '';
    const search = (document.getElementById('kol-search')?.value || '').trim().toLowerCase();
    let q = sb.from('kol_placements').select('*').order('date_added',{ascending:false,nullsFirst:false}).limit(5000);
    if (fStat) q = q.eq('status', fStat);
    if (fPay)  q = q.eq('payment_category', fPay);
    if (fCol)  q = q.eq('collection_id', fCol);
    const {data, error} = await q;
    if (error) throw error;
    _kolRows = (data||[]).map(mapKol);
    let rows = _kolRows;
    if (search) rows = rows.filter(r => `${r.name} ${r.pic} ${r.notes}`.toLowerCase().includes(search));
    // Stats from unfiltered set
    document.getElementById('kol-s-total').textContent = _kolRows.length;
    document.getElementById('kol-s-confirmed').textContent = _kolRows.filter(r=>r.status==='Outreach').length;
    document.getElementById('kol-s-posted').textContent = _kolRows.filter(r=>r.status==='Publish').length;
    document.getElementById('kol-s-fee').textContent = _kolFmtRp(_kolRows.reduce((s,r)=>s+Number(r.fee||0),0));
    document.getElementById('kol-s-paid').textContent = _kolRows.filter(r=>r.outboundRequestId).length;
    document.getElementById('kol-tcount').textContent = `${rows.length} entri`;
    const colName = id => allColRows.find(c=>c.id===id)?.collectionName || '—';
    const kolDb = id => allKolDbRows.find(k=>k.id===id);
    if (!rows.length) { tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Tidak ada data.</td></tr>`; return; }
    tbody.innerHTML = rows.map(r => {
      const esc = s => (s==null?'':String(s)).replace(/</g,'&lt;').replace(/"/g,'&quot;');
      const k = kolDb(r.kolDbId);
      let tierBadge = '<span style="color:var(--g400);font-size:10px">—</span>', followerTxt = '';
      if (k) {
        tierBadge = _kolDbTierBadge(k.tier);
        const fbp = k.followersByPlatform || {};
        let max = 0; for (const v of Object.values(fbp)) if (typeof v === 'number' && v > max) max = v;
        if (max) followerTxt = `<div style="font-size:10px;color:var(--g600);font-family:var(--mono);margin-top:2px">${_kolDbFmtFollowers(max)}</div>`;
      }
      const delivCount = (r.deliverablesList||[]).length;
      const delivLinks = (r.deliverablesList||[]).slice(0,3).map(d =>
        `<a href="${esc(d.url)}" target="_blank" style="display:inline-block;padding:1px 6px;background:#eef0f8;border:1px solid #c9bdf0;color:#3C3489;border-radius:99px;font-size:9px;text-decoration:none;margin:1px 2px" title="${esc(d.url)}">${esc(d.platform)} ↗</a>`
      ).join('') + (delivCount > 3 ? `<span style="font-size:9px;color:var(--g600);margin-left:4px">+${delivCount-3} more</span>` : '');
      const payCat = r.paymentCategory || '—';
      const payCatPill = payCat === 'Barter' ? '<span class="pill p-near">Barter</span>'
        : payCat === 'Pay' ? '<span class="pill p-active">Pay</span>'
        : payCat === 'Pay+Barter' ? '<span class="pill p-signings">Pay + Barter</span>'
        : `<span style="color:var(--g400);font-size:10px">${esc(payCat)}</span>`;
      const feeRow = (payCat === 'Pay' || payCat === 'Pay+Barter') ? `<div style="font-size:10px;font-family:var(--mono);color:var(--g600);margin-top:2px">${_kolFmtRp(r.fee)}</div>` : '';
      const isBarter = (payCat === 'Barter' || payCat === 'Pay+Barter');
      const itemCount = (r.freebieItems||[]).length;
      let shipCell;
      if (!isBarter) {
        shipCell = '<span style="color:var(--g400);font-size:10px">—</span>';
      } else if (r.outboundRequestId) {
        const ob = allOutboundRows.find(x => x.id === r.outboundRequestId);
        const shipLine = (ob && typeof ob.shippingCost === 'number')
          ? `<div style="font-size:10px;font-family:var(--mono);color:var(--g600);margin-top:1px">🚚 ${_kolFmtRp(ob.shippingCost)}${ob.status?` · ${esc(ob.status)}`:''}</div>`
          : (ob && ob.status ? `<div style="font-size:10px;color:var(--g600);margin-top:1px">${esc(ob.status)}</div>` : '');
        shipCell = `<a href="#" onclick="event.preventDefault();showPage('outbound',null)" style="font-size:10px;color:#3C3489;text-decoration:underline" title="Outbound ticket: ${esc(r.outboundRequestId)}">✓ ${esc(r.outboundRequestId)}</a>${shipLine}`;
      } else if (itemCount) {
        shipCell = `<button class="btn-icon" style="font-size:10px;color:#3C3489;border:1px solid #c9bdf0;border-radius:4px;padding:3px 8px;background:white" onclick="requestKolShipment('${r.id}')" title="Create outbound ticket">📦 Request Pengiriman</button>`;
      } else {
        shipCell = '<span style="font-size:10px;color:var(--g400)">Items kosong</span>';
      }
      const itemsBrief = (r.freebieItems||[]).map(it => {
        const name = esc(it.item_name||it.sku);
        const sz = it.size?` (${esc(it.size)})`:'';
        const q = it.qty?`×${it.qty}`:'';
        return `${name}${sz}${q}`;
      }).join(', ');
      const itemThumbs = (r.freebieItems||[]).slice(0,4).map(it => it.thumbnail
        ? `<img src="${esc(it.thumbnail)}" alt="" loading="lazy" style="width:24px;height:24px;border-radius:3px;object-fit:cover;border:1px solid var(--g100)" title="${esc(it.item_name||it.sku)}">`
        : `<div style="width:24px;height:24px;border-radius:3px;background:var(--g100);display:inline-flex;align-items:center;justify-content:center;color:var(--g400);font-size:11px;border:1px solid var(--g100)" title="${esc(it.item_name||it.sku)}">📦</div>`
      ).join('');
      const itemMoreCount = (r.freebieItems||[]).length - 4;
      return `<tr>
        <td>
          <div style="display:flex;align-items:center;gap:6px">
            <a href="#" onclick="event.preventDefault();openKolDrawerEdit('${r.id}')" style="font-weight:600;color:#3C3489;text-decoration:none;cursor:pointer" title="Klik buat edit">${esc(r.name)}</a>
            ${tierBadge}
          </div>
          ${followerTxt}
        </td>
        <td style="font-size:11px;color:var(--g600)">${esc(colName(r.collectionId))}</td>
        <td>${delivLinks || '<span style="color:var(--g400);font-size:10px">—</span>'}</td>
        <td>${payCatPill}${feeRow}</td>
        <td style="font-size:11px;color:var(--g600);max-width:240px">
          ${itemThumbs ? `<div style="display:flex;gap:3px;align-items:center;flex-wrap:wrap" title="${esc(itemsBrief)}">${itemThumbs}${itemMoreCount>0?`<span style="font-size:9px;color:var(--g400);margin-left:2px">+${itemMoreCount}</span>`:''}</div>` : ''}
          ${itemsBrief ? `<div style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-top:3px" title="${esc(itemsBrief)}">${itemsBrief}</div>` : ''}
          <div style="margin-top:3px">${shipCell}</div>
        </td>
        <td style="font-size:11px;white-space:nowrap">${r.postDate||'—'}</td>
        <td style="font-size:11px">${esc(r.pic)||'—'}</td>
        <td>
          <select onchange="updateKolStatus('${r.id}',this.value)" class="pill ${_KOL_STATUS_TONE[r.status]||'p-draft'}" style="font-size:10px;padding:3px 8px;border-radius:99px;cursor:pointer;border:1px solid transparent;width:100px">
            ${_KOL_STATUS_OPTS.map(s => `<option value="${s}"${s===r.status?' selected':''}>${s}</option>`).join('')}
          </select>
        </td>
        <td style="white-space:nowrap">
          <button class="btn-icon" onclick="deleteKol('${r.id}')" title="Hapus" style="color:#c0392b">🗑</button>
        </td>
      </tr>`;
    }).join('');
  } catch(e) { if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Gagal: ${e.message||e}</td></tr>`; }
}

function clearKolFilters() {
  ['kol-fil-status','kol-fil-payment','kol-fil-collection','kol-search'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  loadKolMgmt();
}

async function updateKolStatus(id, status) {
  try {
    await sb.from('kol_placements').update({status, last_updated:new Date().toISOString(), last_updated_by:currentUser}).eq('id',id);
    const r = _kolRows.find(x => x.id === id); if (r) r.status = status;
  } catch(e) { alert('Gagal: '+(e.message||e)); loadKolMgmt(); }
}

async function deleteKol(id) {
  const r = _kolRows.find(x => x.id === id);
  if (!confirm(`Hapus placement ${r?.name||id}?`)) return;
  try {
    // Also delete linked outbound_request if any
    if (r?.outboundRequestId) {
      await sb.from('outbound_requests').delete().eq('id', r.outboundRequestId);
    }
    await sb.from('kol_placements').delete().eq('id', id);
    logActivity('KolManagement','delete',id,`Hapus: ${r?.name||id}`);
    loadKolMgmt();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// Create an outbound_request from a kol_placement's freebie data
async function requestKolShipment(placementId) {
  const r = _kolRows.find(x => x.id === placementId);
  if (!r) return;
  if (r.outboundRequestId) { alert('Sudah ada outbound request: ' + r.outboundRequestId); return; }
  if (!(r.freebieItems||[]).length) { alert('Belum ada item freebie di placement ini. Edit dulu.'); return; }
  if (!confirm(`Buat outbound ticket buat "${r.name}"? Bisa di-track di modul Outbond Request.`)) return;
  try {
    const obId = genId('OB');
    const payload = {
      id: obId,
      source_module: 'KolManagement',
      source_id: placementId,
      recipient_name: r.name,
      recipient_address: r.recipientAddress || null,
      recipient_phone: r.recipientPhone || null,
      requested_ship_date: r.requestedShipDate || null,
      items: r.freebieItems || [],
      status: 'Pending',
      notes: `Auto-created from KOL placement ${placementId} (${r.name})`,
      added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    };
    const {error: e1} = await sb.from('outbound_requests').insert(payload);
    if (e1) throw e1;
    const {error: e2} = await sb.from('kol_placements').update({
      outbound_request_id: obId,
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', placementId);
    if (e2) throw e2;
    logActivity('KolManagement','request_shipment',placementId,`→ ${obId}`);
    alert(`✓ Ticket ${obId} dibuat. Buka modul Outbond Request buat track delivery & set biaya kirim.`);
    loadKolMgmt();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// Right-side drawer for editing — click KOL name in list to open
async function openKolDrawerEdit(id) {
  const r = _kolRows.find(x => x.id === id);
  if (!r) return;
  await _kolMgmtEnsureRefData();
  document.getElementById('kolDrawerTitle').textContent = `✎ Edit · ${r.name || id}`;
  document.getElementById('kolDrawerBody').innerHTML = _kolEditFormHTML(r);
  openKolDrawer();
  _kolEditAttachAC(id);
  _kolEditToggleSections(id);
}

function openKolDrawer() {
  document.getElementById('kolDrawerBackdrop').style.display = 'block';
  document.getElementById('kolDrawer').style.display = 'flex';
  document.body.style.overflow = 'hidden';
}

function closeKolDrawer() {
  document.getElementById('kolDrawerBackdrop').style.display = 'none';
  document.getElementById('kolDrawer').style.display = 'none';
  document.body.style.overflow = '';
}

// closeKolEdit kept as alias so the form's Batal button still works
function closeKolEdit(id) { closeKolDrawer(); }

function _kolEditFormHTML(r) {
  const esc = s => (s==null?'':String(s)).replace(/"/g,'&quot;');
  const colName = _colDisplayLabel(allColRows.find(c => c.id === r.collectionId)) || '';
  const cat = r.paymentCategory || 'Barter';
  const id = r.id;
  const delivRowsHTML = (r.deliverablesList && r.deliverablesList.length)
    ? r.deliverablesList.map(d => _kolDeliverableRowHTML(d.platform || 'Instagram', d.url || '', `kole-deliv-${id}`)).join('')
    : _kolDeliverableRowHTML('Instagram', '', `kole-deliv-${id}`);
  const freebieRowsHTML = (r.freebieItems && r.freebieItems.length)
    ? r.freebieItems.map(it => _kolFreebieRowHTML(it, `kole-frb-${id}`)).join('')
    : '';
  return `<div style="padding:12px;border:1px solid var(--g100);border-radius:6px;background:var(--white)">
    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:8px">✎ Edit Placement · <span style="font-family:var(--mono);font-size:10px">${esc(id)}</span></div>

    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px">Identitas</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px">
      <div class="fg" style="position:relative;margin:0">
        <label style="font-size:11px">Collection</label>
        <input type="text" id="kole-collection-${id}" value="${esc(colName)}" placeholder="—" autocomplete="off" style="font-size:12px;padding:5px 8px">
        <div class="ac-list" id="ac-kole-collection-${id}"></div>
      </div>
      <div class="fg" style="position:relative;margin:0">
        <label style="font-size:11px">Nama KOL *</label>
        <input type="text" id="kole-name-${id}" value="${esc(r.name)}" autocomplete="off" style="font-size:12px;padding:5px 8px">
        <div class="ac-list" id="ac-kole-name-${id}"></div>
      </div>
    </div>

    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px">Deliverables</div>
    <div id="kole-deliv-${id}" style="display:flex;flex-direction:column;gap:6px;margin-bottom:6px">${delivRowsHTML}</div>
    <button class="btn-ghost" type="button" onclick="_kolEditAddDelivRow('${id}')" style="padding:4px 10px;font-size:11px;margin-bottom:10px">+ Tambah Deliverable</button>

    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px;margin-top:4px">Payment</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px">
      <div class="fg" style="margin:0">
        <label style="font-size:11px">Kategori</label>
        <select id="kole-cat-${id}" onchange="_kolEditToggleSections('${id}')" style="font-size:12px;padding:5px 8px">
          ${_KOL_PAY_CATS.map(c => `<option value="${c}"${c===cat?' selected':''}>${c}</option>`).join('')}
        </select>
      </div>
      <div class="fg" id="kole-fee-fg-${id}" style="margin:0;display:none">
        <label style="font-size:11px">Fee KOL (Rp)</label>
        <input type="number" id="kole-fee-${id}" min="0" value="${r.fee==null?'':r.fee}" style="font-size:12px;padding:5px 8px">
      </div>
    </div>

    <div id="kole-barter-${id}" style="display:none;border:1px dashed var(--g200);padding:10px;border-radius:6px;margin-bottom:10px">
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:6px">Pengiriman Freebie</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:8px">
        <div class="fg" style="margin:0"><label style="font-size:11px">Phone</label><input type="text" id="kole-rec-phone-${id}" value="${esc(r.recipientPhone)}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg" style="margin:0"><label style="font-size:11px">Tgl Kirim</label><input type="date" id="kole-ship-date-${id}" value="${r.requestedShipDate||''}" style="font-size:12px;padding:5px 8px"></div>
        <div class="fg" style="margin:0"><label style="font-size:11px">Outbound</label>${(() => {
          if (!r.outboundRequestId) return `<div style="font-size:11px;padding:5px 0;color:var(--g400)">Belum di-request</div>`;
          const ob = allOutboundRows.find(x => x.id === r.outboundRequestId);
          const link = `<a href="#" onclick="event.preventDefault();showPage('outbound',null)" style="color:#3C3489;text-decoration:underline;font-size:11px">✓ ${esc(r.outboundRequestId)}</a>`;
          const status = ob?.status ? `<div style="font-size:10px;color:var(--g600);margin-top:2px">${esc(ob.status)}${ob.trackingNumber?` · <span style="font-family:var(--mono)">${esc(ob.trackingNumber)}</span>`:''}</div>` : '';
          const ship = (typeof ob?.shippingCost === 'number')
            ? `<div style="font-size:10px;font-family:var(--mono);color:var(--g600);margin-top:1px">🚚 ${_kolFmtRp(ob.shippingCost)}</div>`
            : (ob ? `<div style="font-size:10px;color:var(--g400);margin-top:1px">Biaya kirim belum di-set</div>` : '');
          return `<div style="padding:5px 0">${link}${status}${ship}</div>`;
        })()}</div>
      </div>
      <div class="fg" style="margin:0 0 8px"><label style="font-size:11px">Alamat lengkap</label><textarea id="kole-rec-address-${id}" rows="2" style="font-size:12px;padding:5px 8px;resize:vertical">${esc(r.recipientAddress)}</textarea></div>
      <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px;display:flex;align-items:center;gap:8px">
        Items
        <span style="margin-left:auto;font-family:var(--mono);font-size:11px;color:var(--g600);font-weight:400">💰 Total HPP <span id="kole-cogs-${id}">${_moRp(_kolItemsCOGS(r.freebieItems))}</span></span>
      </div>
      <div id="kole-frb-${id}" style="display:flex;flex-direction:column;gap:6px;margin-bottom:6px" oninput="_kolEditRecalcCOGS('${id}')">${freebieRowsHTML}</div>
      <button class="btn-ghost" type="button" onclick="_kolEditAddFreebieRow('${id}')" style="padding:4px 10px;font-size:11px">+ Tambah Item</button>
    </div>

    <div style="font-family:var(--mono);font-size:10px;text-transform:uppercase;letter-spacing:0.3px;color:var(--g600);margin-bottom:4px">Status &amp; Meta</div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:8px;margin-bottom:8px">
      <div class="fg" style="margin:0">
        <label style="font-size:11px">Status</label>
        <select id="kole-status-${id}" style="font-size:12px;padding:5px 8px">
          ${_KOL_STATUS_OPTS.map(s => `<option value="${s}"${s===r.status?' selected':''}>${s}</option>`).join('')}
        </select>
      </div>
      <div class="fg" style="margin:0"><label style="font-size:11px">Post Date</label><input type="date" id="kole-post-date-${id}" value="${r.postDate||''}" style="font-size:12px;padding:5px 8px"></div>
      <div class="fg" style="margin:0;position:relative"><label style="font-size:11px">PIC</label>
        <input type="text" id="kole-pic-${id}" value="${esc(r.pic)}" autocomplete="off" style="font-size:12px;padding:5px 8px">
        <div class="ac-list" id="ac-kole-pic-${id}"></div>
      </div>
    </div>
    <div class="fg" style="margin:0 0 10px"><label style="font-size:11px">Notes</label><textarea id="kole-notes-${id}" rows="2" style="font-size:12px;padding:5px 8px;resize:vertical">${esc(r.notes)}</textarea></div>

    <div style="display:flex;gap:6px">
      <button class="btn-save" onclick="saveKolEdit('${id}')">💾 Simpan</button>
      <button class="btn-cancel" onclick="closeKolEdit('${id}')">Batal</button>
      <div id="kole-fb-${id}" style="margin-left:auto;font-size:11px;align-self:center"></div>
    </div>
  </div>`;
}

// Wire setupAC for the per-row collection + KOL name inputs
function _kolEditAttachAC(id) {
  setupAC(`kole-collection-${id}`, `ac-kole-collection-${id}`, () => allColRows.map(c => _colDisplayLabel(c)).filter(Boolean));
  setupAC(`kole-name-${id}`, `ac-kole-name-${id}`, () => allKolDbRows.map(k => k.name).filter(Boolean));
  setupAC(`kole-pic-${id}`, `ac-kole-pic-${id}`, () => acPics);
  // Wire AC for existing freebie rows (when reopening with prefilled items)
  const host = document.getElementById(`kole-frb-${id}`);
  if (host) {
    host.querySelectorAll(`.kol-frb-row`).forEach(row => {
      const display = row.querySelector(`.kole-frb-${id}-display`);
      const ac = row.querySelector(`.kole-frb-${id}-ac`);
      if (!display || !ac) return;
      display.addEventListener('input', () => _kolFrbRenderAC(display, ac));
      display.addEventListener('focus', () => _kolFrbRenderAC(display, ac));
      document.addEventListener('click', e => {
        if (!display.contains(e.target) && !ac.contains(e.target)) ac.style.display = 'none';
      });
    });
  }
}

function _kolEditAddDelivRow(id) {
  const host = document.getElementById(`kole-deliv-${id}`);
  host.insertAdjacentHTML('beforeend', _kolDeliverableRowHTML('Instagram', '', `kole-deliv-${id}`));
}

function _kolEditAddFreebieRow(id) {
  const host = document.getElementById(`kole-frb-${id}`);
  host.insertAdjacentHTML('beforeend', _kolFreebieRowHTML(null, `kole-frb-${id}`));
  const row = host.lastElementChild;
  const display = row.querySelector(`.kole-frb-${id}-display`);
  const ac = row.querySelector(`.kole-frb-${id}-ac`);
  display.addEventListener('input', () => _kolFrbRenderAC(display, ac));
  display.addEventListener('focus', () => _kolFrbRenderAC(display, ac));
  document.addEventListener('click', e => {
    if (!display.contains(e.target) && !ac.contains(e.target)) ac.style.display = 'none';
  });
}

function _kolEditToggleSections(id) {
  const cat = document.getElementById(`kole-cat-${id}`)?.value || 'Barter';
  const feeFg = document.getElementById(`kole-fee-fg-${id}`);
  const barter = document.getElementById(`kole-barter-${id}`);
  if (feeFg) feeFg.style.display = (cat === 'Pay' || cat === 'Pay+Barter') ? '' : 'none';
  if (barter) barter.style.display = (cat === 'Barter' || cat === 'Pay+Barter') ? '' : 'none';
}

async function saveKolEdit(id) {
  const fb = document.getElementById(`kole-fb-${id}`);
  const setFB = (msg, ok) => { if (fb) { fb.style.color = ok?'#0a7d3a':'#c0392b'; fb.textContent = msg; } };
  const r = _kolRows.find(x => x.id === id);
  if (!r) return;
  const name = (document.getElementById(`kole-name-${id}`).value || '').trim();
  if (!name) { setFB('Nama KOL wajib', false); return; }
  const cat = document.getElementById(`kole-cat-${id}`).value || 'Barter';
  const fee = (cat === 'Pay' || cat === 'Pay+Barter')
    ? (parseFloat(document.getElementById(`kole-fee-${id}`).value) || null) : null;
  // Resolve collection name → id
  const colName = (document.getElementById(`kole-collection-${id}`).value || '').trim().toLowerCase();
  const colMatch = _colFindByLabel(colName);
  const collection_id = colMatch ? colMatch.id : null;
  // Resolve KOL name → kol_db_id
  const kolMatch = allKolDbRows.find(k => (k.name||'').toLowerCase() === name.toLowerCase());
  const kol_db_id = kolMatch ? kolMatch.id : null;
  const deliverables = _kolReadDelivFrom(`kole-deliv-${id}`, `kole-deliv-${id}`);
  const freebieItems = (cat === 'Barter' || cat === 'Pay+Barter') ? _kolReadFreebieFrom(`kole-frb-${id}`, `kole-frb-${id}`) : [];
  const payload = {
    kol_name: name,
    kol_db_id,
    collection_id,
    payment_category: cat,
    fee,
    deliverables_list: deliverables,
    freebie_items: freebieItems,
    recipient_address: (document.getElementById(`kole-rec-address-${id}`)?.value || '').trim() || null,
    recipient_phone: (document.getElementById(`kole-rec-phone-${id}`)?.value || '').trim() || null,
    requested_ship_date: document.getElementById(`kole-ship-date-${id}`)?.value || null,
    status: document.getElementById(`kole-status-${id}`).value || 'Planning',
    post_date: document.getElementById(`kole-post-date-${id}`).value || null,
    pic: (document.getElementById(`kole-pic-${id}`).value || '').trim() || null,
    notes: (document.getElementById(`kole-notes-${id}`).value || '').trim() || null,
    last_updated: new Date().toISOString(), last_updated_by: currentUser || '',
  };
  try {
    const {error} = await sb.from('kol_placements').update(payload).eq('id', id);
    if (error) throw error;
    // Auto-seed kol_database if new name
    if (!kol_db_id) {
      try {
        const kdId = genId('KD');
        await sb.from('kol_database').insert({
          id: kdId, name,
          added_by: currentUser, date_added: new Date().toISOString().slice(0,10),
          last_updated: new Date().toISOString(), last_updated_by: currentUser,
        });
      } catch (e) { console.warn('Auto-seed kol_database failed:', e); }
    }
    logActivity('KolManagement','edit',id,`Edit: ${name} · ${cat}`);
    setFB('✓ Tersimpan', true);
    setTimeout(() => closeKolDrawer(), 600);
    loadKolMgmt();
  } catch(e) { setFB('Gagal: ' + (e.message||e), false); }
}

// ── 7. TRANSACTION MAPPING ──
// Maps jubelio_sales_orders rows (excluding Gudang Bintaro & Gudang Marte)
// to categories + project refs via a separate transaction_mappings table.
// Supports bulk-edit: select multiple rows, set category + project ref once.

const TX_EXCLUDE_LOCATIONS = ['Gudang Bintaro', 'Gudang Marte'];
const TX_CATEGORIES = ['Wholesale', 'Consignment', 'Pop Up Booth', 'Internal Purchase'];
let _txRows = [];               // current page rows with mapping merged in
let _txTotalCount = 0;
let _txPage = 0;
let _txSelected = new Set();    // selected salesorder_ids
let _txDistPartners = [];       // [{id, name}] — for Wholesale/Consignment ref
let _txPopupBooths = [];        // [{id, name, date}] — for Pop Up Booth ref

async function _txLoadLookups() {
  if (_txDistPartners.length && _txPopupBooths.length) return;
  try {
    const [dpRes, pbRes] = await Promise.all([
      sb.from('dist_partners').select('id,partner_name').order('partner_name'),
      sb.from('popup_booths').select('id,event_name,event_date').order('event_date',{ascending:false})
    ]);
    _txDistPartners = (dpRes.data||[]).filter(r=>r.partner_name).map(r => ({id:r.id, name:r.partner_name}));
    _txPopupBooths  = (pbRes.data||[]).filter(r=>r.event_name).map(r => ({id:r.id, name:r.event_name, date:r.event_date}));
  } catch(e) { console.error('_txLoadLookups:', e); }
}

// Build {value,label} options for the Project Ref dropdown based on category.
function _txRefOptions(category) {
  if (category === 'Wholesale' || category === 'Consignment') {
    return _txDistPartners.map(p => ({value:p.name, label:p.name}));
  }
  if (category === 'Pop Up Booth') {
    return _txPopupBooths.map(p => {
      const dateLbl = p.date ? ` (${new Date(p.date).toLocaleDateString('id-ID',{day:'2-digit',month:'short',year:'2-digit'})})` : '';
      return {value:p.name, label:p.name + dateLbl};
    });
  }
  return [];
}

function _txRefSelectHTML(rowId, category, currentValue) {
  if (!category) {
    return `<select disabled style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--off);color:var(--g400)"><option>— pilih category dulu —</option></select>`;
  }
  // Internal Purchase doesn't have a lookup table — free-text input (buyer name)
  if (category === 'Internal Purchase') {
    return `<input type="text" value="${_txEsc(currentValue||'')}" placeholder="Nama pembeli / staff" style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--white)" onblur="updateTxField(${rowId},'project_ref',this.value)">`;
  }
  const opts = _txRefOptions(category);
  if (!opts.length) {
    return `<select disabled style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--off);color:var(--g400)"><option>${category==='Pop Up Booth'?'Tidak ada event di Pop Up Booth':'Tidak ada partner di Distribution Master'}</option></select>`;
  }
  // Include current value as an extra option if it doesn't match any lookup (e.g., legacy free-text)
  const hasCurrent = !currentValue || opts.some(o => o.value === currentValue);
  const extra = hasCurrent ? '' : `<option value="${_txEsc(currentValue)}" selected>${_txEsc(currentValue)} (legacy)</option>`;
  return `<select onchange="updateTxField(${rowId},'project_ref',this.value)" style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--white)">
    <option value="">— pilih ref —</option>
    ${extra}
    ${opts.map(o => `<option value="${_txEsc(o.value)}"${o.value===currentValue?' selected':''}>${_txEsc(o.label)}</option>`).join('')}
  </select>`;
}

// Triggered when bulk category dropdown changes — repopulate the bulk Ref select.
function _txUpdateBulkRefOptions() {
  const cat = document.getElementById('tx-bulk-category').value;
  const sel = document.getElementById('tx-bulk-project-ref');
  if (!sel) return;
  if (!cat) {
    sel.innerHTML = `<option value="">— pilih category dulu —</option>`;
    sel.disabled = true;
    return;
  }
  // Internal Purchase ref is free-text per row, not a lookup. Disable bulk ref.
  if (cat === 'Internal Purchase') {
    sel.innerHTML = `<option value="">— Internal Purchase: isi ref per row —</option>`;
    sel.disabled = true;
    return;
  }
  const opts = _txRefOptions(cat);
  sel.disabled = false;
  if (!opts.length) {
    sel.innerHTML = `<option value="">${cat==='Pop Up Booth'?'Tidak ada event di Pop Up Booth':'Tidak ada partner di Distribution Master'}</option>`;
    return;
  }
  sel.innerHTML = `<option value="">— pilih ref (opsional) —</option>` + opts.map(o => `<option value="${_txEsc(o.value)}">${_txEsc(o.label)}</option>`).join('');
}

function _txEsc(s) { return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function _txRp(n) {
  if (n==null || isNaN(Number(n))) return '—';
  return 'Rp ' + new Intl.NumberFormat('id-ID').format(Math.round(Number(n)));
}
function _txDate(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('id-ID', {day:'2-digit',month:'short',year:'2-digit'});
}

async function loadTxMap() {
  const tbody = document.getElementById('txTableBody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="14">Memuat...</td></tr>`;
  // Lookups must be ready before render (category-dependent ref dropdown).
  await _txLoadLookups();
  // Reset selection on reload
  _txSelected.clear();
  _txUpdateBulkBar();
  // Read filters
  const from = document.getElementById('tx-from').value;
  const to   = document.getElementById('tx-to').value;
  const loc  = document.getElementById('tx-fil-location').value || '';
  const chan = document.getElementById('tx-fil-channel').value || '';
  const mapStatus = document.getElementById('tx-fil-mapstatus').value || '';
  const cat  = document.getElementById('tx-fil-category').value || '';
  const search = (document.getElementById('tx-search').value || '').trim();
  const pageSize = parseInt(document.getElementById('tx-page-size').value, 10) || 100;

  try {
    // Base sales orders query (excluding Bintaro & Marte)
    const baseFilter = q => {
      let qq = q
        .not('location_name', 'in', `("${TX_EXCLUDE_LOCATIONS.join('","')}")`);
      if (from) qq = qq.gte('transaction_date', from);
      if (to)   qq = qq.lte('transaction_date', to + 'T23:59:59');
      if (loc)  qq = qq.eq('location_name', loc);
      if (chan) qq = qq.eq('channel_name', chan);
      if (search) {
        // OR across SO no, customer name, ref
        qq = qq.or(`salesorder_no.ilike.%${search}%,customer_name.ilike.%${search}%,shipping_full_name.ilike.%${search}%`);
      }
      return qq;
    };

    // Total count + dropdown filter population happen in parallel
    const orderCols = 'salesorder_id,salesorder_no,transaction_date,location_name,channel_name,store_name,customer_name,shipping_full_name,wms_status,sub_total,total_disc,grand_total,is_canceled,note';
    const from_n = _txPage * pageSize;
    const to_n   = from_n + pageSize - 1;

    const [
      {data: orderRows, error: ordErr, count},
      {data: locRows},
      {data: chanRows}
    ] = await Promise.all([
      baseFilter(sb.from('jubelio_sales_orders').select(orderCols, {count:'exact'}))
        .order('transaction_date', {ascending:false})
        .range(from_n, to_n),
      sb.from('jubelio_sales_orders').select('location_name')
        .not('location_name','in',`("${TX_EXCLUDE_LOCATIONS.join('","')}")`)
        .not('location_name','is',null).limit(5000),
      sb.from('jubelio_sales_orders').select('channel_name')
        .not('channel_name','is',null).limit(5000)
    ]);
    if (ordErr) throw ordErr;
    _txTotalCount = count || 0;

    // Populate location + channel filter dropdowns once
    const lSel = document.getElementById('tx-fil-location');
    if (lSel && lSel.options.length <= 1) {
      const locs = [...new Set((locRows||[]).map(r=>r.location_name).filter(Boolean))].sort();
      lSel.innerHTML = `<option value="">Semua location</option>` +
        locs.map(l => `<option value="${_txEsc(l)}">${_txEsc(l)}</option>`).join('');
      lSel.onchange = loadTxMap;
    }
    const cSel = document.getElementById('tx-fil-channel');
    if (cSel && cSel.options.length <= 1) {
      const chans = [...new Set((chanRows||[]).map(r=>r.channel_name).filter(Boolean))].sort();
      cSel.innerHTML = `<option value="">Semua channel</option>` +
        chans.map(c => `<option value="${_txEsc(c)}">${_txEsc(c)}</option>`).join('');
      cSel.onchange = loadTxMap;
    }

    // Fetch mappings for these orders (chunked if many)
    const orderIds = (orderRows||[]).map(o => o.salesorder_id);
    const mapByOrderId = new Map();
    if (orderIds.length) {
      for (let i = 0; i < orderIds.length; i += 500) {
        const chunk = orderIds.slice(i, i + 500);
        const {data: maps} = await sb.from('transaction_mappings').select('*').in('salesorder_id', chunk);
        (maps||[]).forEach(m => mapByOrderId.set(m.salesorder_id, m));
      }
    }

    // Apply mapping-status + category filter (post-fetch since these are on the joined table)
    let merged = (orderRows||[]).map(o => ({
      ...o,
      _mapping: mapByOrderId.get(o.salesorder_id) || null
    }));
    if (mapStatus === 'mapped') {
      merged = merged.filter(r => r._mapping && (r._mapping.category || r._mapping.project_ref));
    } else if (mapStatus === 'unmapped') {
      merged = merged.filter(r => !r._mapping || !(r._mapping.category || r._mapping.project_ref));
    }
    if (cat) {
      merged = merged.filter(r => r._mapping?.category === cat);
    }
    _txRows = merged;

    _renderTxTable();
    _renderTxStats();
    _renderTxPagination(pageSize);
  } catch (e) {
    console.error('loadTxMap:', e);
    if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="14">Gagal: ${e.message||e}</td></tr>`;
  }
}

function _renderTxStats() {
  // Stats computed from the current visible page (since post-filter happens client-side)
  const total = _txRows.length;
  const mapped = _txRows.filter(r => r._mapping && (r._mapping.category || r._mapping.project_ref)).length;
  const grossSum = _txRows.reduce((s,r) => s + Number(r.sub_total || 0), 0);
  const tEl = document.getElementById('tx-s-total');     if (tEl) tEl.textContent = _txTotalCount.toLocaleString('id-ID') + ' tx';
  const uEl = document.getElementById('tx-s-unmapped');  if (uEl) uEl.textContent = (total - mapped).toLocaleString('id-ID') + ' (page)';
  const mEl = document.getElementById('tx-s-mapped');    if (mEl) mEl.textContent = mapped.toLocaleString('id-ID') + ' (page)';
  const aEl = document.getElementById('tx-s-amount');    if (aEl) aEl.textContent = _txRp(grossSum) + ' (page)';
  const pEl = document.getElementById('tx-s-mapped-pct');if (pEl) pEl.textContent = total ? Math.round(mapped/total*100) + '%' : '—';
}

function _renderTxTable() {
  const tbody = document.getElementById('txTableBody');
  if (!tbody) return;
  if (!_txRows.length) {
    tbody.innerHTML = `<tr><td class="empty-td" colspan="14">Tidak ada data sesuai filter.</td></tr>`;
    document.getElementById('tx-tcount').textContent = '0 entri';
    return;
  }
  document.getElementById('tx-tcount').textContent = `${_txRows.length} di page ini · ${_txTotalCount.toLocaleString('id-ID')} total`;

  const catOpts = ['', ...TX_CATEGORIES];

  tbody.innerHTML = _txRows.map(r => {
    const cat = r._mapping?.category || '';
    const proj = r._mapping?.project_ref || '';
    // Notes now come from Jubelio (read-only) — usually carries event /
    // location context like "Sarasvatifest - Bali March 1, 2026". Strip
    // tabs and trim so the cell renders cleanly.
    const jubNote = (r.note || '').replace(/\s+/g, ' ').trim();
    const isMapped = !!cat || !!proj;
    const rowBg = isMapped ? 'background:#fafdf6' : '';
    const isCanceled = r.is_canceled || (r.wms_status === 'CANCELED');
    const checked = _txSelected.has(r.salesorder_id) ? ' checked' : '';
    return `<tr style="${rowBg}">
      <td style="text-align:center"><input type="checkbox" data-tx-id="${r.salesorder_id}" onclick="toggleTxSelect(${r.salesorder_id},this.checked)"${checked}></td>
      <td class="mono" style="font-size:11px;font-weight:600">${_txEsc(r.salesorder_no || ('#'+r.salesorder_id))}</td>
      <td class="mono" style="font-size:11px;white-space:nowrap">${_txDate(r.transaction_date)}</td>
      <td style="font-size:11px">${_txEsc(r.location_name || '—')}</td>
      <td style="font-size:11px">${_txEsc([r.channel_name, r.store_name].filter(Boolean).join(' / ')) || '—'}</td>
      <td style="font-size:11px">${_txEsc(r.customer_name || r.shipping_full_name || '—')}</td>
      <td class="mono" style="text-align:right;font-size:11px;white-space:nowrap">${_txRp(r.sub_total)}</td>
      <td class="mono" style="text-align:right;font-size:11px;white-space:nowrap;color:${Number(r.total_disc||0)>0?'#c0392b':'var(--g400)'}">${Number(r.total_disc||0)>0?'-'+_txRp(r.total_disc):'—'}</td>
      <td class="mono" style="text-align:right;font-size:11px;white-space:nowrap;font-weight:600">${_txRp(r.grand_total)}</td>
      <td><span class="pill ${isCanceled ? 'p-expired' : 'p-info'}" style="font-size:10px">${_txEsc(r.wms_status || '—')}</span></td>
      <td><select onchange="updateTxField(${r.salesorder_id},'category',this.value)" class="pill ${isMapped ? 'p-active' : 'p-draft'}" style="font-size:10px;padding:2px 6px;border:1px solid;width:100%">${catOpts.map(o => `<option value="${o}"${o===cat?' selected':''}>${o || '— Unmapped —'}</option>`).join('')}</select></td>
      <td>${_txRefSelectHTML(r.salesorder_id, cat, proj)}</td>
      <td style="font-size:11px;color:var(--g600);max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${_txEsc(jubNote)}">${jubNote ? _txEsc(jubNote) : '<span style="color:var(--g400)">—</span>'}</td>
      <td style="text-align:center">${isMapped ? `<button class="btn-icon" style="font-size:10px;color:#c33" onclick="unmapTx(${r.salesorder_id})">✕</button>` : '—'}</td>
    </tr>`;
  }).join('');
}

function _renderTxPagination(pageSize) {
  const el = document.getElementById('tx-pagination');
  if (!el) return;
  const totalPages = Math.ceil(_txTotalCount / pageSize);
  if (totalPages <= 1) { el.innerHTML = ''; return; }
  const cur = _txPage;
  el.innerHTML = `
    <button class="btn-ghost" style="padding:4px 12px;font-size:12px" onclick="txGoToPage(${cur-1})" ${cur===0?'disabled':''}>← Prev</button>
    <span style="font-size:12px;color:var(--g400);font-family:var(--mono)">${cur+1} / ${totalPages}</span>
    <button class="btn-ghost" style="padding:4px 12px;font-size:12px" onclick="txGoToPage(${cur+1})" ${cur>=totalPages-1?'disabled':''}>Next →</button>
  `;
}

function txGoToPage(p) {
  _txPage = Math.max(0, p);
  loadTxMap();
}

function clearTxFilters() {
  ['tx-fil-location','tx-fil-channel','tx-search'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  document.getElementById('tx-fil-mapstatus').value = 'unmapped';
  document.getElementById('tx-fil-category').value = '';
  _txPage = 0;
  loadTxMap();
}

// ── Single-row inline edits (upsert mapping) ──
async function updateTxField(salesorderId, field, value) {
  const valueClean = (value || '').trim() || null;
  // Existing mapping in current rows?
  const row = _txRows.find(r => r.salesorder_id === salesorderId);
  const existing = row?._mapping || {salesorder_id: salesorderId};
  const next = {...existing, [field]: valueClean, last_updated: new Date().toISOString(), last_updated_by: currentUser};
  if (!existing.mapped_by) { next.mapped_by = currentUser; next.mapped_at = new Date().toISOString(); }
  try {
    const {error} = await sb.from('transaction_mappings').upsert(next, {onConflict: 'salesorder_id'});
    if (error) throw error;
    if (row) row._mapping = next;
    _renderTxTable();
    _renderTxStats();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

async function unmapTx(salesorderId) {
  if (!confirm('Hapus mapping untuk transaksi ini?')) return;
  try {
    await sb.from('transaction_mappings').delete().eq('salesorder_id', salesorderId);
    const row = _txRows.find(r => r.salesorder_id === salesorderId);
    if (row) row._mapping = null;
    _renderTxTable();
    _renderTxStats();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// ── Selection + Bulk edit ──
function toggleTxSelect(salesorderId, checked) {
  if (checked) _txSelected.add(salesorderId); else _txSelected.delete(salesorderId);
  _txUpdateBulkBar();
}

function toggleTxSelectAll(masterCheckbox) {
  const want = masterCheckbox.checked;
  _txRows.forEach(r => want ? _txSelected.add(r.salesorder_id) : _txSelected.delete(r.salesorder_id));
  // Reflect in row checkboxes
  document.querySelectorAll('#txTableBody input[type="checkbox"][data-tx-id]').forEach(cb => { cb.checked = want; });
  _txUpdateBulkBar();
}

function clearTxSelection() {
  _txSelected.clear();
  document.querySelectorAll('#txTableBody input[type="checkbox"][data-tx-id]').forEach(cb => { cb.checked = false; });
  document.getElementById('tx-select-all').checked = false;
  _txUpdateBulkBar();
}

function _txUpdateBulkBar() {
  const bar = document.getElementById('tx-bulk-bar');
  const cnt = document.getElementById('tx-bulk-count');
  if (cnt) cnt.textContent = _txSelected.size;
  if (bar) bar.style.display = _txSelected.size > 0 ? 'flex' : 'none';
}

async function applyTxBulk() {
  const cat = document.getElementById('tx-bulk-category').value;
  const projRef = document.getElementById('tx-bulk-project-ref').value.trim();
  if (!cat && !projRef) { alert('Pilih category atau isi project ref dulu.'); return; }
  if (!_txSelected.size) { alert('Tidak ada baris dipilih.'); return; }
  if (!confirm(`Apply mapping ke ${_txSelected.size} transaksi?`)) return;
  const ids = [..._txSelected];
  const now = new Date().toISOString();
  // Upsert one row per selected ID
  // Preserve existing fields if not being changed
  const existingMap = new Map();
  try {
    // Chunk fetch
    for (let i = 0; i < ids.length; i += 500) {
      const chunk = ids.slice(i, i+500);
      const {data} = await sb.from('transaction_mappings').select('*').in('salesorder_id', chunk);
      (data||[]).forEach(m => existingMap.set(m.salesorder_id, m));
    }
    const rows = ids.map(id => {
      const ex = existingMap.get(id) || {};
      return {
        salesorder_id: id,
        category: cat || ex.category || null,
        project_ref: projRef || ex.project_ref || null,
        notes: ex.notes || null,
        mapped_by: ex.mapped_by || currentUser,
        mapped_at: ex.mapped_at || now,
        last_updated: now,
        last_updated_by: currentUser
      };
    });
    // Upsert in chunks
    for (let i = 0; i < rows.length; i += 500) {
      const chunk = rows.slice(i, i+500);
      const {error} = await sb.from('transaction_mappings').upsert(chunk, {onConflict: 'salesorder_id'});
      if (error) throw error;
    }
    logActivity('TransactionMapping','bulk',`${ids.length}`, `Bulk mapped ${ids.length} tx → ${cat||''} / ${projRef||''}`);
    // Reload to reflect
    clearTxSelection();
    document.getElementById('tx-bulk-category').value = '';
    document.getElementById('tx-bulk-project-ref').value = '';
    loadTxMap();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

async function clearTxBulkClear() {
  if (!_txSelected.size) { alert('Tidak ada baris dipilih.'); return; }
  if (!confirm(`Hapus mapping dari ${_txSelected.size} transaksi?`)) return;
  const ids = [..._txSelected];
  try {
    // Delete in chunks
    for (let i = 0; i < ids.length; i += 500) {
      const chunk = ids.slice(i, i+500);
      await sb.from('transaction_mappings').delete().in('salesorder_id', chunk);
    }
    logActivity('TransactionMapping','bulk_unmap',`${ids.length}`, `Bulk unmapped ${ids.length} tx`);
    clearTxSelection();
    loadTxMap();
  } catch(e) { alert('Gagal: '+(e.message||e)); }
}

// ── INTERNAL PURCHASE ────────────────────────────────────────────────────────
// Shows only transactions mapped to category 'Internal Purchase' from the
// Transaction Mapping module. Each row exposes a bukti-transfer URL input
// stored on transaction_mappings.transfer_proof_url so finance can verify
// the staff payment matches the Jubelio order amount.

let _ipRows = []; // {salesorder_id, salesorder_no, ..., _mapping}

async function loadInternalPurchase() {
  const tbody = document.getElementById('ipTableBody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Memuat...</td></tr>`;
  const from = document.getElementById('ip-from')?.value || '';
  const to   = document.getElementById('ip-to')?.value || '';
  const proofFil = document.getElementById('ip-fil-proof')?.value || '';
  const search = (document.getElementById('ip-search')?.value || '').trim().toLowerCase();
  try {
    // 1. Mappings tagged Internal Purchase
    let mq = sb.from('transaction_mappings').select('*').eq('category', 'Internal Purchase');
    const {data: maps, error: mErr} = await mq;
    if (mErr) throw mErr;
    if (!maps || !maps.length) {
      tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Belum ada transaksi yang di-map ke Internal Purchase. Map di modul Transaction Mapping dulu.</td></tr>`;
      _ipRows = [];
      _renderIPStats();
      const tc=document.getElementById('ip-tcount'); if(tc) tc.textContent = '0 entri';
      return;
    }
    const orderIds = maps.map(m => m.salesorder_id);
    // 2. Fetch the matching sales orders (chunked)
    const ordRows = [];
    for (let i = 0; i < orderIds.length; i += 500) {
      const chunk = orderIds.slice(i, i+500);
      let q = sb.from('jubelio_sales_orders').select(
        'salesorder_id,salesorder_no,transaction_date,customer_name,shipping_full_name,wms_status,sub_total,is_canceled,note,location_name'
      ).in('salesorder_id', chunk);
      if (from) q = q.gte('transaction_date', from);
      if (to)   q = q.lte('transaction_date', to + 'T23:59:59');
      const {data} = await q;
      ordRows.push(...(data||[]));
    }
    const ordById = new Map(ordRows.map(o => [o.salesorder_id, o]));
    // 3. Merge: only keep rows whose order survived the date filter
    let merged = maps
      .filter(m => ordById.has(m.salesorder_id))
      .map(m => ({ ...ordById.get(m.salesorder_id), _mapping: m }))
      .sort((a, b) => (b.transaction_date||'').localeCompare(a.transaction_date||''));
    // 4. Apply proof filter + search
    if (proofFil === 'missing') merged = merged.filter(r => !r._mapping?.transfer_proof_url);
    else if (proofFil === 'filled') merged = merged.filter(r => !!r._mapping?.transfer_proof_url);
    if (search) {
      merged = merged.filter(r =>
        (r.salesorder_no||'').toLowerCase().includes(search) ||
        (r._mapping?.project_ref||'').toLowerCase().includes(search) ||
        (r.customer_name||'').toLowerCase().includes(search) ||
        (r.shipping_full_name||'').toLowerCase().includes(search)
      );
    }
    _ipRows = merged;
    _renderIPTable();
    _renderIPStats();
  } catch (e) {
    console.error('loadInternalPurchase:', e);
    if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Gagal: ${e.message||e}</td></tr>`;
  }
}

function _renderIPStats() {
  const total = _ipRows.length;
  const pending = _ipRows.filter(r => !r._mapping?.transfer_proof_url).length;
  const done = total - pending;
  const sum = _ipRows.reduce((s, r) => s + Number(r.sub_total || 0), 0);
  const tEl = document.getElementById('ip-s-total');   if (tEl) tEl.textContent = total;
  const pEl = document.getElementById('ip-s-pending'); if (pEl) pEl.textContent = pending;
  const dEl = document.getElementById('ip-s-done');    if (dEl) dEl.textContent = done;
  const aEl = document.getElementById('ip-s-amount');  if (aEl) aEl.textContent = _txRp(sum);
}

function _renderIPTable() {
  const tbody = document.getElementById('ipTableBody');
  if (!tbody) return;
  const tc = document.getElementById('ip-tcount');
  if (!_ipRows.length) {
    tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Tidak ada data sesuai filter.</td></tr>`;
    if (tc) tc.textContent = '0 entri';
    return;
  }
  if (tc) tc.textContent = `${_ipRows.length} entri`;
  tbody.innerHTML = _ipRows.map(r => {
    const m = r._mapping || {};
    const proof = m.transfer_proof_url || '';
    const isCanceled = r.is_canceled || (r.wms_status === 'CANCELED');
    const jubNote = (r.note || '').replace(/\s+/g, ' ').trim();
    const mappedAt = m.mapped_at ? new Date(m.mapped_at).toLocaleDateString('id-ID',{day:'2-digit',month:'short',year:'2-digit'}) : '—';
    const proofLink = proof
      ? `<a href="${_txEsc(proof)}" target="_blank" style="font-size:10px;color:#3C3489;text-decoration:underline">↗ Lihat</a>`
      : `<span style="font-size:10px;color:#c0392b">⚠ Belum ada</span>`;
    return `<tr>
      <td class="mono" style="font-size:11px;font-weight:600">${_txEsc(r.salesorder_no || ('#'+r.salesorder_id))}</td>
      <td class="mono" style="font-size:11px;white-space:nowrap">${_txDate(r.transaction_date)}</td>
      <td style="font-size:12px;font-weight:600">${_txEsc(m.project_ref || '—')}</td>
      <td style="font-size:11px;color:var(--g600)">${_txEsc(r.customer_name || r.shipping_full_name || '—')}</td>
      <td class="mono" style="text-align:right;font-size:11px;white-space:nowrap">${_txRp(r.sub_total)}</td>
      <td><span class="pill ${isCanceled ? 'p-expired' : 'p-info'}" style="font-size:10px">${_txEsc(r.wms_status || '—')}</span></td>
      <td>
        <div style="display:flex;gap:6px;align-items:center">
          <input type="url" value="${_txEsc(proof)}" placeholder="https:// (paste Drive / WhatsApp / photo link)" style="flex:1;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--white)" onblur="saveIPProof(${r.salesorder_id}, this.value)">
          ${proofLink}
        </div>
      </td>
      <td style="font-size:11px;color:var(--g600);max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${_txEsc(jubNote)}">${jubNote || '<span style="color:var(--g400)">—</span>'}</td>
      <td style="font-size:10px;color:var(--g400);white-space:nowrap">${mappedAt}</td>
    </tr>`;
  }).join('');
}

async function saveIPProof(salesorderId, url) {
  const val = (url || '').trim() || null;
  try {
    const {error} = await sb.from('transaction_mappings').update({
      transfer_proof_url: val,
      last_updated: new Date().toISOString(),
      last_updated_by: currentUser,
    }).eq('salesorder_id', salesorderId);
    if (error) throw error;
    const row = _ipRows.find(r => r.salesorder_id === salesorderId);
    if (row) row._mapping = { ...(row._mapping||{}), transfer_proof_url: val };
    _renderIPTable();
    _renderIPStats();
  } catch (e) { alert('Gagal save bukti: ' + (e.message||e)); }
}

function clearInternalPurchaseFilters() {
  ['ip-from','ip-to','ip-search'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  const pf = document.getElementById('ip-fil-proof'); if (pf) pf.value = '';
  loadInternalPurchase();
}

// ── 8. INVENTORY TRANSFER ──
// Lists jubelio_transfer_outs (TRFO) with item count + total qty derived from
// jubelio_transfer_out_items. Mapping table = inventory_transfer_mappings.
// Categories: Wholesale | Consignment → dist_partners, Event → popup_booths,
// Partner → ip_master.

const IT_CATEGORIES = ['Wholesale', 'Consignment', 'Event', 'Partner'];
// Jubelio convention: transfer_type "0" = OUT, "1" = IN (verified by item_transfer_no prefix).
const IT_TYPE_OUT = '0';
const IT_TYPE_IN  = '1';
let _itMode = 'out';            // 'out' | 'in' — drives filter + title
let _itRows = [];
let _itTotalCount = 0;
let _itPage = 0;
let _itSelected = new Set();
const _itExpanded = new Set();  // xferIds whose item rows are expanded
const _itItemsCache = new Map();// xferId → items[]
let _itDistWholesale = [];   // [{id, name}]
let _itDistConsign   = [];
let _itPopupBooths   = [];   // [{id, name, date}]
let _itIPMaster      = [];   // [{id, name}]

async function _itLoadLookups() {
  if (_itDistWholesale.length || _itDistConsign.length || _itPopupBooths.length || _itIPMaster.length) return;
  try {
    const [dpRes, pbRes, ipRes] = await Promise.all([
      sb.from('dist_partners').select('id,partner_name,type').order('partner_name'),
      sb.from('popup_booths').select('id,event_name,event_date').order('event_date',{ascending:false}),
      sb.from('ip_master').select('id,name').order('name')
    ]);
    // dist_partners.type is comma-separated multi-value: "Wholesale, Bulk Purchase" etc.
    const allDP = (dpRes.data||[]).filter(r=>r.partner_name);
    _itDistWholesale = allDP.filter(r => (r.type||'').toLowerCase().includes('wholesale')).map(r => ({id:r.id, name:r.partner_name}));
    _itDistConsign   = allDP.filter(r => (r.type||'').toLowerCase().includes('consignment')).map(r => ({id:r.id, name:r.partner_name}));
    // Fallback: if filter yields nothing (e.g., no type set), show all partners
    if (!_itDistWholesale.length) _itDistWholesale = allDP.map(r => ({id:r.id, name:r.partner_name}));
    if (!_itDistConsign.length)   _itDistConsign   = allDP.map(r => ({id:r.id, name:r.partner_name}));
    _itPopupBooths = (pbRes.data||[]).filter(r=>r.event_name).map(r => ({id:r.id, name:r.event_name, date:r.event_date}));
    _itIPMaster    = (ipRes.data||[]).filter(r=>r.name).map(r => ({id:r.id, name:r.name}));
  } catch(e) { console.error('_itLoadLookups:', e); }
}

function _itRefOptions(category) {
  if (category === 'Wholesale')   return _itDistWholesale.map(p => ({value:p.name, label:p.name}));
  if (category === 'Consignment') return _itDistConsign.map(p => ({value:p.name, label:p.name}));
  if (category === 'Event') {
    return _itPopupBooths.map(p => {
      const dateLbl = p.date ? ` (${new Date(p.date).toLocaleDateString('id-ID',{day:'2-digit',month:'short',year:'2-digit'})})` : '';
      return {value:p.name, label:p.name + dateLbl};
    });
  }
  if (category === 'Partner')     return _itIPMaster.map(p => ({value:p.name, label:p.name}));
  return [];
}

function _itRefSelectHTML(rowId, category, currentValue) {
  if (!category) {
    return `<select disabled style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--off);color:var(--g400)"><option>— pilih category dulu —</option></select>`;
  }
  const opts = _itRefOptions(category);
  if (!opts.length) {
    const msg = category === 'Event' ? 'Tidak ada event di Pop Up Booth'
              : category === 'Partner' ? 'Tidak ada IP di IP Master'
              : 'Tidak ada partner di Distribution Master';
    return `<select disabled style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--off);color:var(--g400)"><option>${msg}</option></select>`;
  }
  const hasCurrent = !currentValue || opts.some(o => o.value === currentValue);
  const extra = hasCurrent ? '' : `<option value="${_itEsc(currentValue)}" selected>${_itEsc(currentValue)} (legacy)</option>`;
  return `<select onchange="updateInvTransferField(${rowId},'ref_label',this.value)" style="width:100%;padding:4px 6px;font-size:11px;border:1px solid var(--g100);border-radius:3px;background:var(--white)">
    <option value="">— pilih ref —</option>
    ${extra}
    ${opts.map(o => `<option value="${_itEsc(o.value)}"${o.value===currentValue?' selected':''}>${_itEsc(o.label)}</option>`).join('')}
  </select>`;
}

function _itUpdateBulkRefOptions() {
  const cat = document.getElementById('it-bulk-category').value;
  const sel = document.getElementById('it-bulk-ref');
  if (!sel) return;
  if (!cat) {
    sel.innerHTML = `<option value="">— pilih category dulu —</option>`;
    sel.disabled = true;
    return;
  }
  const opts = _itRefOptions(cat);
  sel.disabled = false;
  if (!opts.length) {
    const msg = cat === 'Event' ? 'Tidak ada event' : cat === 'Partner' ? 'Tidak ada IP' : 'Tidak ada partner';
    sel.innerHTML = `<option value="">${msg}</option>`;
    return;
  }
  sel.innerHTML = `<option value="">— pilih ref (opsional) —</option>` + opts.map(o => `<option value="${_itEsc(o.value)}">${_itEsc(o.label)}</option>`).join('');
}

function _itEsc(s) { return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function _itDate(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('id-ID', {day:'2-digit',month:'short',year:'2-digit'});
}

// Switch between Transfer Out / Transfer In modes. Resets pagination + filter
// dropdowns so they get repopulated with the new mode's distinct locations.
function switchInvTransferMode(mode, btn) {
  _itMode = mode === 'in' ? 'in' : 'out';
  _itPage = 0;
  _itSelected.clear();
  _itExpanded.clear();
  // Disable select-all checkbox in TRFI (bulk apply doesn't apply — mapping is synced)
  const sa = document.getElementById('it-select-all');
  if (sa) { sa.checked = false; sa.disabled = _itMode === 'in'; }

  // Title + subtitle swap
  const tEl = document.getElementById('it-page-title');
  const sEl = document.getElementById('it-page-sub');
  if (tEl) tEl.textContent = _itMode === 'in' ? 'Transfer In (TRFI)' : 'Transfer Out (TRFO)';
  if (sEl) sEl.textContent = _itMode === 'in'
    ? 'Barang masuk antar gudang — TRFI dari Jubelio, status delivery & putaway, plus mapping ke Wholesale / Consignment / Event / Partner.'
    : 'Barang keluar antar gudang — TRFO dari Jubelio, status delivery & putaway, plus mapping ke Wholesale / Consignment / Event / Partner.';

  // Topbar title also swaps
  const tb = document.getElementById('topbarPage');
  if (tb) tb.textContent = _itMode === 'in' ? 'Transfer In (TRFI)' : 'Transfer Out (TRFO)';

  // Tab active state
  document.getElementById('it-tab-out')?.classList.toggle('active', _itMode === 'out');
  document.getElementById('it-tab-in') ?.classList.toggle('active', _itMode === 'in');

  // URL hash so refresh restores the right mode (without polluting back stack)
  const wantedHash = '#invtransfer' + (_itMode === 'in' ? 'in' : 'out');
  if (location.hash !== wantedHash) history.replaceState(null, '', wantedHash);
  sessionStorage.setItem('snt_page', _itMode === 'in' ? 'invtransferin' : 'invtransferout');

  // Reset source/destination dropdowns — distinct values differ between TRFI/TRFO.
  const sSel = document.getElementById('it-fil-source');
  const dSel = document.getElementById('it-fil-destination');
  if (sSel) { sSel.innerHTML = '<option value="">Semua source</option>'; sSel.value = ''; }
  if (dSel) { dSel.innerHTML = '<option value="">Semua destination</option>'; dSel.value = ''; }

  loadInvTransfer();
}

async function loadInvTransfer() {
  const tbody = document.getElementById('invTransferTableBody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="13">Memuat...</td></tr>`;
  await _itLoadLookups();
  _itSelected.clear();
  _itUpdateBulkBar();

  const from = document.getElementById('it-from').value;
  const to   = document.getElementById('it-to').value;
  const src  = document.getElementById('it-fil-source').value || '';
  const dst  = document.getElementById('it-fil-destination').value || '';
  const mapStatus = document.getElementById('it-fil-mapstatus').value || '';
  const cat  = document.getElementById('it-fil-category').value || '';
  const putawayFil = document.getElementById('it-fil-putaway').value || '';
  const search = (document.getElementById('it-search').value || '').trim();
  const pageSize = parseInt(document.getElementById('it-page-size').value, 10) || 100;

  try {
    const typeWanted = _itMode === 'in' ? IT_TYPE_IN : IT_TYPE_OUT;
    const baseFilter = q => {
      let qq = q.eq('transfer_type', typeWanted);
      if (from) qq = qq.gte('transaction_date', from);
      if (to)   qq = qq.lte('transaction_date', to + 'T23:59:59');
      if (src)  qq = qq.eq('source', src);
      if (dst)  qq = qq.eq('destination', dst);
      if (putawayFil === 'done')    qq = qq.eq('is_putaway', true);
      if (putawayFil === 'pending') qq = qq.or('is_putaway.is.null,is_putaway.eq.false');
      if (search) qq = qq.or(`item_transfer_no.ilike.%${search}%,note.ilike.%${search}%`);
      return qq;
    };

    const cols = 'item_transfer_id,item_transfer_no,transaction_date,received_date,source,destination,source_location_id,destination_location_id,is_putaway,note,transfer_type,source_transfer_id,source_transfer_no';
    const from_n = _itPage * pageSize;
    const to_n   = from_n + pageSize - 1;

    const [
      {data: trfRows, error: trfErr, count},
      {data: srcRows},
      {data: dstRows}
    ] = await Promise.all([
      baseFilter(sb.from('jubelio_transfer_outs').select(cols, {count:'exact'}))
        .order('transaction_date', {ascending:false})
        .range(from_n, to_n),
      sb.from('jubelio_transfer_outs').select('source').eq('transfer_type', typeWanted).not('source','is',null).limit(5000),
      sb.from('jubelio_transfer_outs').select('destination').eq('transfer_type', typeWanted).not('destination','is',null).limit(5000)
    ]);
    if (trfErr) throw trfErr;
    _itTotalCount = count || 0;

    // Populate source/destination filter dropdowns once
    const sSel = document.getElementById('it-fil-source');
    if (sSel && sSel.options.length <= 1) {
      const srcs = [...new Set((srcRows||[]).map(r=>r.source).filter(Boolean))].sort();
      sSel.innerHTML = `<option value="">Semua source</option>` + srcs.map(s => `<option value="${_itEsc(s)}">${_itEsc(s)}</option>`).join('');
      sSel.onchange = loadInvTransfer;
    }
    const dSel = document.getElementById('it-fil-destination');
    if (dSel && dSel.options.length <= 1) {
      const dsts = [...new Set((dstRows||[]).map(r=>r.destination).filter(Boolean))].sort();
      dSel.innerHTML = `<option value="">Semua destination</option>` + dsts.map(s => `<option value="${_itEsc(s)}">${_itEsc(s)}</option>`).join('');
      dSel.onchange = loadInvTransfer;
    }

    // Item count + total qty per transfer (single round-trip)
    const xferIds = (trfRows||[]).map(r => r.item_transfer_id);
    const summary = new Map();
    if (xferIds.length) {
      for (let i = 0; i < xferIds.length; i += 500) {
        const chunk = xferIds.slice(i, i + 500);
        const {data: items} = await sb.from('jubelio_transfer_out_items')
          .select('item_transfer_id,qty_in_base').in('item_transfer_id', chunk);
        (items||[]).forEach(it => {
          const cur = summary.get(it.item_transfer_id) || {count:0, qty:0};
          cur.count += 1;
          cur.qty   += Number(it.qty_in_base || 0);
          summary.set(it.item_transfer_id, cur);
        });
      }
    }

    // Mappings — TRFO maps by own item_transfer_id; TRFI mirrors its source TRFO's mapping.
    const mapByXferId = new Map();
    // Build the set of IDs we need to look up: own IDs for TRFO, source_transfer_id for TRFI.
    const mappingIds = _itMode === 'in'
      ? (trfRows||[]).map(r => r.source_transfer_id).filter(Boolean)
      : xferIds;
    if (mappingIds.length) {
      for (let i = 0; i < mappingIds.length; i += 500) {
        const chunk = mappingIds.slice(i, i + 500);
        const {data: maps} = await sb.from('inventory_transfer_mappings').select('*').in('item_transfer_id', chunk);
        (maps||[]).forEach(m => mapByXferId.set(m.item_transfer_id, m));
      }
    }

    let merged = (trfRows||[]).map(r => {
      // TRFI: mapping is INHERITED from the source TRFO (read-only mirror).
      const mappingKey = _itMode === 'in' ? r.source_transfer_id : r.item_transfer_id;
      return {
        ...r,
        _summary: summary.get(r.item_transfer_id) || {count:0, qty:0},
        _mapping: (mappingKey != null) ? (mapByXferId.get(mappingKey) || null) : null,
        _mappingFromSource: _itMode === 'in' && mappingKey != null
      };
    });
    if (mapStatus === 'mapped')   merged = merged.filter(r => r._mapping && (r._mapping.category || r._mapping.ref_label));
    if (mapStatus === 'unmapped') merged = merged.filter(r => !r._mapping || !(r._mapping.category || r._mapping.ref_label));
    if (cat) merged = merged.filter(r => r._mapping?.category === cat);
    _itRows = merged;

    _renderInvTransferTable();
    _renderInvTransferStats();
    _renderInvTransferPagination(pageSize);
  } catch (e) {
    console.error('loadInvTransfer:', e);
    if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="13">Gagal: ${e.message||e}</td></tr>`;
  }
}

function _renderInvTransferStats() {
  const total = _itRows.length;
  const mapped = _itRows.filter(r => r._mapping && (r._mapping.category || r._mapping.ref_label)).length;
  const putawayDone = _itRows.filter(r => r.is_putaway).length;
  const tEl = document.getElementById('it-s-total');     if (tEl) tEl.textContent = _itTotalCount.toLocaleString('id-ID') + ' TRFO';
  const uEl = document.getElementById('it-s-unmapped');  if (uEl) uEl.textContent = (total - mapped).toLocaleString('id-ID') + ' (page)';
  const mEl = document.getElementById('it-s-mapped');    if (mEl) mEl.textContent = mapped.toLocaleString('id-ID') + ' (page)';
  const pEl = document.getElementById('it-s-putaway');   if (pEl) pEl.textContent = putawayDone.toLocaleString('id-ID') + ' / ' + total;
  const pcEl= document.getElementById('it-s-mapped-pct');if (pcEl) pcEl.textContent = total ? Math.round(mapped/total*100) + '%' : '—';
}

function _renderInvTransferTable() {
  const tbody = document.getElementById('invTransferTableBody');
  if (!tbody) return;
  // Header label swap (TRFO mode shows "TRFO No", TRFI shows "TRFI No (← Source TRFO)")
  const thNo = document.getElementById('it-th-trfono');
  if (thNo) thNo.textContent = _itMode === 'in' ? 'TRFI No (Source)' : 'TRFO No';

  if (!_itRows.length) {
    tbody.innerHTML = `<tr><td class="empty-td" colspan="13">Tidak ada data sesuai filter.</td></tr>`;
    document.getElementById('it-tcount').textContent = '0 entri';
    return;
  }
  document.getElementById('it-tcount').textContent = `${_itRows.length} di page ini · ${_itTotalCount.toLocaleString('id-ID')} total`;

  const catOpts = ['', ...IT_CATEGORIES];
  const isTRFI = _itMode === 'in';

  tbody.innerHTML = _itRows.map(r => {
    const cat = r._mapping?.category || '';
    const ref = r._mapping?.ref_label || '';
    const isMapped = !!cat || !!ref;
    const rowBg = isMapped ? 'background:#fafdf6' : '';
    const checked = _itSelected.has(r.item_transfer_id) ? ' checked' : '';
    const route = `${_itEsc(r.source || '—')} → ${_itEsc(r.destination || '—')}`;
    const putawayPill = r.is_putaway
      ? `<span class="pill p-active" style="font-size:10px">Done</span>`
      : `<span class="pill p-draft" style="font-size:10px">Pending</span>`;

    // Doc no cell: TRFO mode shows just its own no; TRFI mode shows TRFI no + source TRFO chip
    const docNoCell = isTRFI
      ? `<div class="mono" style="font-size:11px;font-weight:600">${_itEsc(r.item_transfer_no || ('#'+r.item_transfer_id))}</div>
         ${r.source_transfer_no
            ? `<div class="mono" style="font-size:10px;color:var(--g600);margin-top:2px">↳ ${_itEsc(r.source_transfer_no)}</div>`
            : `<div class="mono" style="font-size:10px;color:#c33;margin-top:2px">↳ no source</div>`}`
      : `<div class="mono" style="font-size:11px;font-weight:600">${_itEsc(r.item_transfer_no || ('#'+r.item_transfer_id))}</div>`;

    // Mapping cells: editable in TRFO mode, read-only mirror in TRFI mode
    let catCell, refCell, aksiCell;
    if (isTRFI) {
      // TRFI mirrors source TRFO's mapping (or shows "no source" / "source unmapped")
      const sourceMissing = !r.source_transfer_id;
      const sourceUnmapped = r.source_transfer_id && !isMapped;
      if (sourceMissing) {
        catCell = `<span class="pill p-draft" style="font-size:10px" title="TRFI tidak punya source_transfer_id">No source</span>`;
        refCell = `<span style="font-size:11px;color:var(--g400)">—</span>`;
      } else if (sourceUnmapped) {
        catCell = `<span class="pill p-draft" style="font-size:10px" title="Source TRFO belum di-mapping">— Unmapped —</span>`;
        refCell = `<span style="font-size:11px;color:var(--g400)" title="Map source TRFO dulu untuk auto-isi ini">map source dulu</span>`;
      } else {
        catCell = `<span class="pill p-active" style="font-size:10px" title="Synced dari ${_itEsc(r.source_transfer_no||'')}">${_itEsc(cat)}</span>`;
        refCell = `<span style="font-size:11px;font-weight:500" title="Synced dari ${_itEsc(r.source_transfer_no||'')}">${_itEsc(ref || '—')}</span>`;
      }
      aksiCell = `<span style="font-size:10px;color:var(--g400)" title="Mapping hanya bisa diedit di tab Transfer Out">🔗 sync</span>`;
    } else {
      catCell = `<select onchange="updateInvTransferField(${r.item_transfer_id},'category',this.value)" class="pill ${isMapped ? 'p-active' : 'p-draft'}" style="font-size:10px;padding:2px 6px;border:1px solid;width:100%">${catOpts.map(o => `<option value="${o}"${o===cat?' selected':''}>${o || '— Unmapped —'}</option>`).join('')}</select>`;
      refCell = _itRefSelectHTML(r.item_transfer_id, cat, ref);
      aksiCell = isMapped ? `<button class="btn-icon" style="font-size:10px;color:#c33" onclick="unmapInvTransfer(${r.item_transfer_id})">✕</button>` : '—';
    }

    // Checkbox disabled in TRFI mode (bulk edit irrelevant)
    const checkboxCell = isTRFI
      ? `<span style="color:var(--g100);font-size:14px" title="Mapping di-sync dari source TRFO">—</span>`
      : `<input type="checkbox" data-it-id="${r.item_transfer_id}" onclick="toggleInvTransferSelect(${r.item_transfer_id},this.checked)"${checked}>`;

    const isExpanded = _itExpanded.has(r.item_transfer_id);
    const chevron = isExpanded ? '▾' : '▸';
    const jubNote = r.note || '';

    const mainRow = `<tr style="${rowBg};cursor:pointer" onclick="toggleInvTransferItems(${r.item_transfer_id})">
      <td style="text-align:center;font-size:13px;color:var(--g600);font-family:var(--mono)">${chevron}</td>
      <td style="text-align:center" onclick="event.stopPropagation()">${checkboxCell}</td>
      <td>${docNoCell}</td>
      <td class="mono" style="font-size:11px;white-space:nowrap">${_itDate(r.transaction_date)}</td>
      <td style="font-size:11px">${route}</td>
      <td class="mono" style="text-align:right;font-size:11px">${r._summary.count}</td>
      <td class="mono" style="text-align:right;font-size:11px">${r._summary.qty.toLocaleString('id-ID')}</td>
      <td class="mono" style="font-size:11px;white-space:nowrap">${_itDate(r.received_date)}</td>
      <td>${putawayPill}</td>
      <td onclick="event.stopPropagation()">${catCell}</td>
      <td onclick="event.stopPropagation()">${refCell}</td>
      <td style="font-size:11px;color:var(--g600);max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${_itEsc(jubNote)}">${_itEsc(jubNote) || '<span style="color:var(--g400)">—</span>'}</td>
      <td style="text-align:center" onclick="event.stopPropagation()">${aksiCell}</td>
    </tr>`;

    // Expand row: lazy-rendered, shows item lines for this transfer
    const expandRow = isExpanded
      ? `<tr id="it-items-${r.item_transfer_id}"><td colspan="13" style="padding:0;background:var(--off)">${_itRenderItemsBlock(r.item_transfer_id)}</td></tr>`
      : '';

    return mainRow + expandRow;
  }).join('');
}

// ── Item lines expand block ──
function _itRenderItemsBlock(xferId) {
  const items = _itItemsCache.get(xferId);
  if (items === undefined) {
    // Fetch on demand
    _itFetchItems(xferId);
    return `<div style="padding:14px 16px;font-size:11px;color:var(--g400)">Memuat items…</div>`;
  }
  if (!items.length) {
    return `<div style="padding:14px 16px;font-size:11px;color:var(--g400)">Tidak ada items.</div>`;
  }
  return `<div style="padding:8px 12px 12px 50px">
    <table style="width:auto;min-width:760px;background:var(--white);border:1px solid var(--g100);border-radius:4px">
      <thead>
        <tr style="background:var(--off)">
          <th style="font-size:10px;text-align:left;padding:6px 10px">SKU</th>
          <th style="font-size:10px;text-align:left;padding:6px 10px">Item</th>
          <th style="font-size:10px;text-align:left;padding:6px 10px">Variant</th>
          <th style="font-size:10px;text-align:right;padding:6px 10px">Qty</th>
          <th style="font-size:10px;text-align:left;padding:6px 10px">Bin</th>
        </tr>
      </thead>
      <tbody>
        ${items.map(it => `<tr>
          <td class="mono" style="font-size:10px;padding:5px 10px;color:var(--g600)">${_itEsc(it.item_code || '—')}</td>
          <td style="font-size:11px;padding:5px 10px">${_itEsc(it.item_name || '—')}</td>
          <td style="font-size:11px;padding:5px 10px">${_itEsc(it.variant || '—')}</td>
          <td class="mono" style="font-size:11px;padding:5px 10px;text-align:right">${Number(it.qty_in_base||0).toLocaleString('id-ID')}</td>
          <td class="mono" style="font-size:10px;padding:5px 10px;color:var(--g600)">${_itEsc(it.bin_final_code || '—')}</td>
        </tr>`).join('')}
      </tbody>
    </table>
  </div>`;
}

async function _itFetchItems(xferId) {
  try {
    const {data, error} = await sb.from('jubelio_transfer_out_items')
      .select('item_code,item_name,variant,qty_in_base,bin_final_code')
      .eq('item_transfer_id', xferId)
      .order('item_transfer_detail_id');
    if (error) throw error;
    _itItemsCache.set(xferId, data || []);
    // Re-render only the items block for this row (without rebuilding the whole table)
    const cell = document.querySelector(`#it-items-${xferId} td`);
    if (cell) cell.innerHTML = _itRenderItemsBlock(xferId);
  } catch (e) {
    console.error('_itFetchItems:', e);
    _itItemsCache.set(xferId, []);
  }
}

function toggleInvTransferItems(xferId) {
  if (_itExpanded.has(xferId)) _itExpanded.delete(xferId);
  else _itExpanded.add(xferId);
  _renderInvTransferTable();
}

function _renderInvTransferPagination(pageSize) {
  const el = document.getElementById('it-pagination');
  if (!el) return;
  const totalPages = Math.ceil(_itTotalCount / pageSize);
  if (totalPages <= 1) { el.innerHTML = ''; return; }
  const cur = _itPage;
  el.innerHTML = `
    <button class="btn-ghost" style="padding:4px 12px;font-size:12px" onclick="invTransferGoToPage(${cur-1})" ${cur===0?'disabled':''}>← Prev</button>
    <span style="font-size:12px;color:var(--g400);font-family:var(--mono)">${cur+1} / ${totalPages}</span>
    <button class="btn-ghost" style="padding:4px 12px;font-size:12px" onclick="invTransferGoToPage(${cur+1})" ${cur>=totalPages-1?'disabled':''}>Next →</button>
  `;
}

function invTransferGoToPage(p) { _itPage = Math.max(0, p); loadInvTransfer(); }

function clearInvTransferFilters() {
  ['it-fil-source','it-fil-destination','it-search'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  document.getElementById('it-fil-mapstatus').value = 'unmapped';
  document.getElementById('it-fil-category').value = '';
  document.getElementById('it-fil-putaway').value = '';
  _itPage = 0;
  loadInvTransfer();
}

// ── Inline mapping upsert ──
async function updateInvTransferField(xferId, field, value) {
  const valueClean = (value || '').trim() || null;
  const row = _itRows.find(r => r.item_transfer_id === xferId);
  const existing = row?._mapping || {item_transfer_id: xferId};
  const next = {...existing, [field]: valueClean, last_updated: new Date().toISOString(), last_updated_by: currentUser};
  // Setting category to null should also clear ref_label.
  if (field === 'category' && !valueClean) next.ref_label = null;
  if (!existing.mapped_by) { next.mapped_by = currentUser; next.mapped_at = new Date().toISOString(); }
  try {
    const {error} = await sb.from('inventory_transfer_mappings').upsert(next, {onConflict: 'item_transfer_id'});
    if (error) throw error;
    if (row) row._mapping = next;
    // Re-render only if category changed (ref dropdown needs new options)
    if (field === 'category') _renderInvTransferTable();
    _renderInvTransferStats();
  } catch (e) {
    console.error('updateInvTransferField:', e);
    alert('Gagal simpan: ' + (e.message || e));
  }
}

async function unmapInvTransfer(xferId) {
  if (!confirm('Hapus mapping untuk transfer ini?')) return;
  try {
    const {error} = await sb.from('inventory_transfer_mappings').delete().eq('item_transfer_id', xferId);
    if (error) throw error;
    const row = _itRows.find(r => r.item_transfer_id === xferId);
    if (row) row._mapping = null;
    _renderInvTransferTable();
    _renderInvTransferStats();
  } catch (e) {
    console.error('unmapInvTransfer:', e);
    alert('Gagal: ' + (e.message || e));
  }
}

// ── Bulk selection + bulk apply ──
function toggleInvTransferSelect(xferId, checked) {
  if (checked) _itSelected.add(xferId); else _itSelected.delete(xferId);
  _itUpdateBulkBar();
}
function toggleInvTransferSelectAll(cb) {
  document.querySelectorAll('#invTransferTableBody input[data-it-id]').forEach(el => {
    el.checked = cb.checked;
    const id = parseInt(el.dataset.itId, 10);
    if (cb.checked) _itSelected.add(id); else _itSelected.delete(id);
  });
  _itUpdateBulkBar();
}
function clearInvTransferSelection() {
  _itSelected.clear();
  document.querySelectorAll('#invTransferTableBody input[data-it-id]').forEach(el => el.checked = false);
  const sel = document.getElementById('it-select-all'); if (sel) sel.checked = false;
  _itUpdateBulkBar();
}
function _itUpdateBulkBar() {
  const bar = document.getElementById('it-bulk-bar');
  if (!bar) return;
  // TRFI mode: mapping is derived from source TRFO — no bulk apply.
  if (_itMode === 'in') { bar.style.display = 'none'; return; }
  const n = _itSelected.size;
  document.getElementById('it-bulk-count').textContent = n;
  bar.style.display = n > 0 ? 'flex' : 'none';
}

async function applyInvTransferBulk() {
  const cat = document.getElementById('it-bulk-category').value;
  const ref = document.getElementById('it-bulk-ref').value;
  if (!cat) { alert('Pilih category dulu.'); return; }
  if (!_itSelected.size) { alert('Tidak ada baris dipilih.'); return; }
  if (!confirm(`Apply category="${cat}"${ref?` + ref="${ref}"`:''} ke ${_itSelected.size} transfer?`)) return;
  const now = new Date().toISOString();
  const rows = [..._itSelected].map(id => ({
    item_transfer_id: id,
    category: cat,
    ref_label: ref || null,
    mapped_by: currentUser, mapped_at: now,
    last_updated: now, last_updated_by: currentUser
  }));
  try {
    const {error} = await sb.from('inventory_transfer_mappings').upsert(rows, {onConflict: 'item_transfer_id'});
    if (error) throw error;
    _itSelected.clear();
    await loadInvTransfer();
  } catch (e) {
    console.error('applyInvTransferBulk:', e);
    alert('Gagal: ' + (e.message || e));
  }
}

async function clearInvTransferBulkClear() {
  if (!_itSelected.size) { alert('Tidak ada baris dipilih.'); return; }
  if (!confirm(`Unmap ${_itSelected.size} transfer?`)) return;
  try {
    const ids = [..._itSelected];
    for (let i = 0; i < ids.length; i += 100) {
      const chunk = ids.slice(i, i + 100);
      const {error} = await sb.from('inventory_transfer_mappings').delete().in('item_transfer_id', chunk);
      if (error) throw error;
    }
    _itSelected.clear();
    await loadInvTransfer();
  } catch (e) {
    console.error('clearInvTransferBulkClear:', e);
    alert('Gagal: ' + (e.message || e));
  }
}

// ── Manual Jubelio sync trigger ──
async function syncInvTransfer() {
  if (!confirm('Trigger sync TRFO terbaru dari Jubelio? (incremental, ~5-15 detik)')) return;
  const btn = event?.target;
  const oldTxt = btn ? btn.textContent : '';
  if (btn) { btn.disabled = true; btn.textContent = 'Syncing...'; }
  try {
    const {data, error} = await sb.functions.invoke('sync-jubelio-transfer-outs', { body: {} });
    if (error) throw error;
    alert(`Sync selesai. fetched=${data.fetched}, missing=${data.missing}, headers=${data.headersUpserted}, items=${data.itemsInserted}`);
    await loadInvTransfer();
  } catch (e) {
    console.error('syncInvTransfer:', e);
    alert('Gagal: ' + (e.message || e));
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = oldTxt; }
  }
}

// ── VENDOR MASTER ──
let allVMRows = [];
let allJubSuppliers = [];   // jubelio_contacts where contact_type=1
let vmDetailCurrentId = null;

function mapVM(r) {
  return {
    id: r.id, rowIndex: r.id,
    vendorName: r.vendor_name || '',
    jubelioContactId: r.jubelio_contact_id || null,
    contactPerson: r.contact_person || '',
    email: r.email || '',
    phone: r.phone || '',
    address: r.address || '',
    npwp: r.npwp || '',
    defaultLocation: r.default_location || 'Pusat',
    defaultTax: r.default_tax || 'PPN',
    defaultTaxIncluded: r.default_tax_included === true,
    notes: r.notes || '',
    dateAdded: r.date_added, addedBy: r.added_by,
    lastUpdated: r.last_updated, lastUpdatedBy: r.last_updated_by,
    // synced fields filled in loadVendorMaster() from jubelio_contacts join
    syncedName: null, syncedContact: null, syncedEmail: null, syncedPhone: null,
    syncedNpwp: null, syncedCity: null, syncedPaymentTerm: null,
  };
}

function vmSyncedField(r, field) {
  // Manual values are source of truth; Jubelio mirror only fills in if manual is empty
  const manual = {
    name: r.vendorName, contact: r.contactPerson, email: r.email,
    phone: r.phone, npwp: r.npwp, address: r.address,
  }[field] || '';
  if (manual) return manual;
  if (r.jubelioContactId) {
    return ({
      name: r.syncedName, contact: r.syncedContact, email: r.syncedEmail,
      phone: r.syncedPhone, npwp: r.syncedNpwp, address: r.syncedCity,
    }[field]) || '';
  }
  return '';
}

function switchVMTab(name, el) {
  document.querySelectorAll('#page-vendormaster .tab-btn').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('vmtab-new').style.display = name === 'new' ? 'block' : 'none';
  document.getElementById('vmtab-list').style.display = name === 'list' ? 'block' : 'none';
  const capTab = document.getElementById('vmtab-capabilities');
  if (capTab) capTab.style.display = name === 'capabilities' ? 'block' : 'none';
  if (name === 'list') loadVendorMaster();
  if (name === 'capabilities') loadVMCapabilitiesMatrix();
  if (name === 'new') loadJubSuppliers(); // preload picker (used by 'Pre-fill dari Jubelio')
}

async function loadJubSuppliers(forceRefresh = false) {
  if (allJubSuppliers.length && !forceRefresh) return allJubSuppliers;
  try {
    const {data, error} = await sb.from('jubelio_contacts')
      .select('contact_id,contact_name,primary_contact,email,phone,mobile,npwp,billing_city,billing_address,payment_term')
      .eq('contact_type', 1)
      .order('contact_name');
    if (error) throw error;
    allJubSuppliers = data || [];
    return allJubSuppliers;
  } catch (e) {
    console.error('loadJubSuppliers:', e);
    allJubSuppliers = [];
    return [];
  }
}

// Trigger sync-jubelio-contacts edge function in fast 'suppliers_only' mode.
// Used to be ~45s because it walked the full 56k-contact list; the
// suppliers_only path only hits /contacts/suppliers/ (~30 records) so it
// returns in ~2s. Daily cron still runs the full sweep to keep customer +
// staff data fresh.
async function vmSyncFromJubelio() {
  const btn = document.getElementById('vm-jub-sync-btn');
  const status = document.getElementById('vm-jub-sync-status');
  if (btn) { btn.disabled = true; btn.textContent = '⟳ Syncing...'; }
  if (status) status.textContent = 'syncing supplier dari Jubelio...';
  try {
    const r = await fetch(`${SUPABASE_URL}/functions/v1/sync-jubelio-contacts?suppliers_only=true`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${SUPABASE_ANON}`, 'Content-Type': 'application/json' },
    });
    const j = await r.json();
    if (!j.ok) throw new Error(j.error || 'Sync failed');
    // Refresh local cache from DB
    allJubSuppliers = []; // bust cache
    await loadJubSuppliers(true);
    const count = (allJubSuppliers || []).length;
    const countEl = document.getElementById('vm-jub-picker-count');
    if (countEl) countEl.textContent = count;
    if (status) {
      const parts = [
        `${j.suppliers_endpoint?.kept ?? '?'} supplier dari Jubelio`,
        j.deleted_orphan_suppliers > 0 ? `${j.deleted_orphan_suppliers} orphan dihapus` : null,
        new Date().toLocaleTimeString('id-ID', {hour:'2-digit',minute:'2-digit'}),
      ].filter(Boolean);
      status.textContent = `synced ${parts.join(' · ')}`;
    }
    renderVMJubPickerList();
  } catch (e) {
    if (status) status.textContent = `gagal: ${e.message||e}`;
    alert('Sync gagal: ' + (e.message || e));
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = '↻ Sync'; }
  }
}

async function loadVendorMaster() {
  const tbody = document.getElementById('vmTableBody');
  if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="7">Memuat...</td></tr>`;
  try {
    // Load vendors + supplier mirror + variant counts (for "SKU diorder" column) in parallel
    const [vmRes, jubRes, pdRes] = await Promise.all([
      sb.from('vendor_master').select('*').order('vendor_name'),
      loadJubSuppliers(),
      sb.from('product_dev').select('vendor').not('vendor','is',null).limit(20000),
    ]);
    if (vmRes.error) throw vmRes.error;
    const jubById = new Map((jubRes||[]).map(s => [s.contact_id, s]));
    allVMRows = (vmRes.data||[]).map(mapVM).map(r => {
      if (r.jubelioContactId) {
        const j = jubById.get(r.jubelioContactId);
        if (j) {
          r.syncedName = j.contact_name; r.syncedContact = j.primary_contact;
          r.syncedEmail = j.email; r.syncedPhone = j.phone || j.mobile;
          r.syncedNpwp = j.npwp; r.syncedCity = j.billing_city;
          r.syncedPaymentTerm = j.payment_term;
        }
      }
      return r;
    });
    // SKU counts per vendor name (use synced name first, fall back to vendor_name)
    const pdCounts = new Map();
    (pdRes.data||[]).forEach(p => {
      const k = (p.vendor||'').trim().toLowerCase();
      if (k) pdCounts.set(k, (pdCounts.get(k)||0) + 1);
    });
    allVMRows.forEach(r => {
      const name = vmSyncedField(r, 'name');
      r.skuCount = pdCounts.get((name||'').toLowerCase()) || 0;
    });
    renderVMStats();
    applyVMFilters();
  } catch (e) {
    if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="7">Gagal: ${e.message||e}</td></tr>`;
  }
}

function renderVMStats() {
  const total = allVMRows.length;
  const linked = allVMRows.filter(r => r.jubelioContactId).length;
  const withSku = allVMRows.filter(r => (r.skuCount||0) > 0).length;
  document.getElementById('vm-s-total').textContent = total;
  const el2 = document.getElementById('vm-s-with-contact');
  if (el2) { el2.textContent = linked; el2.parentElement.querySelector('.stat-lbl').textContent = 'Linked ke Jubelio'; }
  const el3 = document.getElementById('vm-s-incomplete');
  if (el3) { el3.textContent = withSku; el3.parentElement.querySelector('.stat-lbl').textContent = 'Punya SKU di Product Dev'; }
}

function applyVMFilters() {
  const q = (document.getElementById('vmSearch')?.value || '').toLowerCase();
  let rows = allVMRows;
  if (q) rows = rows.filter(r =>
    (vmSyncedField(r,'name')||'').toLowerCase().includes(q) ||
    (vmSyncedField(r,'contact')||'').toLowerCase().includes(q) ||
    (vmSyncedField(r,'email')||'').toLowerCase().includes(q) ||
    (vmSyncedField(r,'phone')||'').toLowerCase().includes(q)
  );
  renderVMTable(rows);
}

function renderVMTable(rows) {
  const tbody = document.getElementById('vmTableBody');
  const tc = document.getElementById('vm-tcount');
  if (tc) tc.textContent = `${rows.length} entri`;
  if (!rows.length) {
    tbody.innerHTML = `<tr><td class="empty-td" colspan="6">Tidak ada vendor. Klik tab "Tambah" untuk input baru.</td></tr>`;
    return;
  }
  tbody.innerHTML = rows.map(r => {
    const name = vmSyncedField(r, 'name');
    const contact = vmSyncedField(r, 'contact');
    const phone = vmSyncedField(r, 'phone');
    const taxPill = `<span class="pill ${r.defaultTax==='PPN'?'p-signings':'p-draft'}" style="font-size:11px">${r.defaultTax}${r.defaultTaxIncluded?' (incl)':''}</span>`;
    const linkChip = r.jubelioContactId
      ? `<span class="pill p-active" style="font-size:9px;margin-left:6px" title="Linked to Jubelio contact_id: ${r.jubelioContactId}">🔗 Jubelio</span>`
      : '';
    const skuCell = r.skuCount > 0
      ? `<strong style="color:var(--black)">${r.skuCount}</strong> <span style="font-size:10px;color:var(--g400)">SKU</span>`
      : `<span style="color:var(--g400);font-size:11px">—</span>`;
    return `<tr>
      <td><a href="#" onclick="openVMDetail('${r.id}');return false" style="color:var(--black);text-decoration:none;font-weight:600">${(name||'(belum diset)').replace(/</g,'&lt;')}</a>${linkChip}</td>
      <td style="font-size:12px">
        <div>${(contact||'—').replace(/</g,'&lt;')}</div>
        <div class="mono" style="font-size:11px;color:var(--g600)">${(phone||'—').replace(/</g,'&lt;')}</div>
      </td>
      <td style="font-size:11px">${(r.defaultLocation||'—').replace(/</g,'&lt;')}</td>
      <td>${taxPill}</td>
      <td style="font-size:12px">${skuCell}</td>
      <td>
        <button class="btn-icon" onclick="openVMDetail('${r.id}')">Detail</button>
        <button class="btn-icon" style="color:#c0392b" onclick="deleteVM('${r.id}')">Del</button>
      </td>
    </tr>`;
  }).join('');
}

// ── VENDOR MASTER — Jubelio picker (optional pre-fill / link) ──
async function openVMJubPicker(scope) {
  const modal = document.getElementById('vmJubPickerModal');
  modal.dataset.scope = scope || '';
  modal.style.display = 'flex';
  await loadJubSuppliers();
  document.getElementById('vm-jub-picker-count').textContent = allJubSuppliers.length;
  document.getElementById('vm-jub-picker-search').value = '';
  renderVMJubPickerList();
}

function closeVMJubPicker() {
  document.getElementById('vmJubPickerModal').style.display = 'none';
}

function renderVMJubPickerList() {
  const q = (document.getElementById('vm-jub-picker-search').value || '').toLowerCase().trim();
  const list = document.getElementById('vm-jub-picker-list');
  // Build lookup of already-linked contact_ids so user can't double-link
  const linkedIds = new Set(allVMRows.map(r => r.jubelioContactId).filter(Boolean));
  let rows = allJubSuppliers;
  if (q) rows = rows.filter(s => (s.contact_name||'').toLowerCase().includes(q) || (s.primary_contact||'').toLowerCase().includes(q));
  if (!rows.length) {
    list.innerHTML = `<div style="padding:20px;text-align:center;color:var(--g400);font-size:12px">Tidak ada match.</div>`;
    return;
  }
  list.innerHTML = rows.map(s => {
    const linked = linkedIds.has(s.contact_id);
    const name = (s.contact_name||'').replace(/</g,'&lt;');
    const pc = (s.primary_contact||'—').replace(/</g,'&lt;');
    const ph = (s.phone || s.mobile || '—').replace(/</g,'&lt;');
    const city = (s.billing_city||'').replace(/</g,'&lt;');
    return `<div style="border-bottom:1px solid var(--g100);padding:10px 0;display:flex;justify-content:space-between;align-items:center;gap:12px">
      <div style="flex:1;min-width:0">
        <div style="font-weight:600;font-size:13px">${name}${linked?' <span class="pill p-active" style="font-size:9px;margin-left:6px">linked</span>':''}</div>
        <div style="font-size:11px;color:var(--g600);margin-top:2px">PIC: ${pc} · Telp: ${ph}${city?` · ${city}`:''}</div>
      </div>
      <button class="btn-icon" onclick="vmSelectJubSupplier(${s.contact_id})" ${linked?'disabled style="opacity:0.4"':''}>Pilih</button>
    </div>`;
  }).join('');
}

function vmSelectJubSupplier(contactId) {
  const s = allJubSuppliers.find(x => x.contact_id === contactId);
  if (!s) return;
  const modal = document.getElementById('vmJubPickerModal');
  const scope = modal.dataset.scope || '';
  closeVMJubPicker();
  if (scope === '') {
    // Picking for the new-vendor form: pre-fill manual fields (still editable)
    document.getElementById('vm-jub-contact-id').value = contactId;
    // Only pre-fill empty inputs — don't clobber what user already typed
    const setIfEmpty = (id, value) => {
      const el = document.getElementById(id);
      if (el && !el.value && value) el.value = value;
    };
    setIfEmpty('vm-name', s.contact_name);
    setIfEmpty('vm-contact-person', s.primary_contact);
    setIfEmpty('vm-email', s.email);
    setIfEmpty('vm-phone', s.phone || s.mobile);
    setIfEmpty('vm-npwp', s.npwp);
    setIfEmpty('vm-address', s.billing_address || s.billing_city);
    _vmUpdateJubLinkBar(s);
  } else {
    // Re-link an existing vendor (from detail modal)
    vmRelinkExisting(scope, contactId);
  }
}

function _vmUpdateJubLinkBar(s) {
  const status = document.getElementById('vm-jub-link-status');
  const unlinkBtn = document.getElementById('vm-jub-unlink-btn');
  if (s) {
    status.innerHTML = `<span class="pill p-active" style="font-size:10px;margin-right:6px">✓ Linked</span>Jubelio: <strong>${(s.contact_name||'').replace(/</g,'&lt;')}</strong> <span class="mono" style="color:var(--g400);font-size:11px">(id ${s.contact_id})</span>`;
    unlinkBtn.style.display = 'inline-block';
  } else {
    status.innerHTML = '<span style="color:var(--g600)">Belum terhubung ke pemasok Jubelio.</span>';
    unlinkBtn.style.display = 'none';
  }
}

function vmClearJubSelection() {
  document.getElementById('vm-jub-contact-id').value = '';
  _vmUpdateJubLinkBar(null);
}

function clearVMForm() {
  vmClearJubSelection();
  ['vm-name','vm-contact-person','vm-email','vm-phone','vm-address','vm-npwp','vm-notes'].forEach(id => {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  document.getElementById('vm-default-location').value = 'Pusat';
  document.getElementById('vm-default-tax').value = 'PPN';
  document.getElementById('vm-default-tax-included').value = 'false';
  document.getElementById('vm-feedback').textContent = '';
}

async function submitVM() {
  const fb = document.getElementById('vm-feedback');
  const btn = document.getElementById('vmSubmitBtn');
  const vendorName = document.getElementById('vm-name').value.trim();
  const phone = document.getElementById('vm-phone').value.trim();
  if (!vendorName) { fb.textContent = '⚠️ Nama vendor wajib.'; return; }
  if (!phone) { fb.textContent = '⚠️ No. Telp wajib (untuk PO ke Jubelio).'; return; }
  const jubContactId = parseInt(document.getElementById('vm-jub-contact-id').value, 10) || null;
  if (jubContactId && allVMRows.some(r => r.jubelioContactId === jubContactId)) {
    fb.textContent = '⚠️ Pemasok Jubelio ini sudah ter-link ke vendor lain.'; return;
  }
  btn.disabled = true; fb.textContent = 'Menyimpan...';
  try {
    const id = genId('VM');
    const row = {
      id,
      vendor_name: vendorName,
      jubelio_contact_id: jubContactId,
      contact_person: document.getElementById('vm-contact-person').value.trim() || null,
      email: document.getElementById('vm-email').value.trim() || null,
      phone,
      address: document.getElementById('vm-address').value.trim() || null,
      npwp: document.getElementById('vm-npwp').value.trim() || null,
      default_location: document.getElementById('vm-default-location').value,
      default_tax: document.getElementById('vm-default-tax').value,
      default_tax_included: document.getElementById('vm-default-tax-included').value === 'true',
      notes: document.getElementById('vm-notes').value.trim() || null,
      added_by: currentUser, date_added: new Date().toISOString(),
    };
    const {error} = await sb.from('vendor_master').insert(row);
    if (error) throw error;
    fb.innerHTML = `<span class="fb-ok">✓ Vendor "${vendorName}" tersimpan${jubContactId?' (linked ke Jubelio)':''}</span>`;
    clearVMForm();
    await loadVendorMaster();
  } catch (e) {
    fb.innerHTML = `<span class="fb-err">Gagal: ${e.message || e}</span>`;
  } finally {
    btn.disabled = false;
  }
}

async function deleteVM(id) {
  const row = allVMRows.find(r => r.id === id);
  if (!confirm(`Hapus vendor "${vmSyncedField(row,'name') || id}"?\n\nIni juga akan menghapus semua capabilities yang dilampirkan ke vendor ini.`)) return;
  try {
    const {error} = await sb.from('vendor_master').delete().eq('id', id);
    if (error) throw error;
    await loadVendorMaster();
  } catch (e) {
    alert('Gagal: ' + (e.message || e));
  }
}

// ── VENDOR MASTER — detail modal (Identity / Catalog / PO / Capabilities) ──
async function openVMDetail(id) {
  const row = allVMRows.find(r => r.id === id);
  if (!row) return;
  vmDetailCurrentId = id;
  document.getElementById('vmDetailModal').style.display = 'flex';
  document.getElementById('vm-detail-name').textContent = vmSyncedField(row, 'name') || '(belum diset)';
  const meta = [];
  if (row.jubelioContactId) meta.push(`Jubelio contact_id: ${row.jubelioContactId}`);
  else meta.push('Manual');
  if (row.dateAdded) meta.push(`Ditambah ${row.dateAdded.slice(0,10)}`);
  document.getElementById('vm-detail-meta').textContent = meta.join(' · ');
  // Reset tabs
  document.querySelectorAll('#vmDetailModal .tab-btn').forEach((b,i) => b.classList.toggle('active', i===0));
  ['identity','catalog','po','capabilities'].forEach((t,i) => {
    document.getElementById(`vm-detail-tab-${t}`).style.display = i===0 ? 'block':'none';
  });
  _vmRenderIdentityTab(row);
}

function closeVMDetail() {
  document.getElementById('vmDetailModal').style.display = 'none';
  vmDetailCurrentId = null;
}

function vmSwitchDetailTab(name, el) {
  document.querySelectorAll('#vmDetailModal .tab-btn').forEach(b => b.classList.remove('active'));
  if (el) el.classList.add('active');
  ['identity','catalog','po','capabilities'].forEach(t => {
    document.getElementById(`vm-detail-tab-${t}`).style.display = t===name ? 'block':'none';
  });
  const row = allVMRows.find(r => r.id === vmDetailCurrentId);
  if (!row) return;
  if (name === 'catalog') _vmRenderCatalogTab(row);
  else if (name === 'po') _vmRenderPoTab(row);
  else if (name === 'capabilities') _vmRenderCapabilitiesTab(row);
}

function _vmRenderIdentityTab(r) {
  const linked = !!r.jubelioContactId;
  const cont = document.getElementById('vm-detail-tab-identity');
  // Jubelio link mirror (shown as small reference under each field if linked)
  const ref = (jubVal) => linked && jubVal ? `<div style="font-size:10px;color:var(--g400);margin-top:2px">📎 Jubelio: ${jubVal.toString().replace(/</g,'&lt;')}</div>` : '';
  cont.innerHTML = `
    <div style="background:var(--off);border-radius:6px;padding:14px;margin-bottom:16px">
      <div style="display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:12px;flex-wrap:wrap">
        <div style="font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px">
          Identity (manual)
          ${linked?`<span class="pill p-active" style="font-size:10px;margin-left:8px">🔗 Linked to Jubelio (id ${r.jubelioContactId})</span>`:`<span class="pill p-draft" style="font-size:10px;margin-left:8px">Tidak ter-link</span>`}
        </div>
        <div style="display:flex;gap:6px">
          <button class="btn-icon" onclick="openVMJubPicker('${r.id}')">${linked?'Ubah link Jubelio':'+ Link ke Jubelio'}</button>
          ${linked?`<button class="btn-icon" style="color:#c0392b" onclick="vmUnlinkExisting('${r.id}')">Lepas link</button>`:''}
        </div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">
        <div class="fg"><label>Nama Vendor *</label><input id="vmd-name" type="text" value="${(r.vendorName||'').replace(/"/g,'&quot;')}">${ref(r.syncedName)}</div>
        <div class="fg"><label>Contact Person</label><input id="vmd-contact" type="text" value="${(r.contactPerson||'').replace(/"/g,'&quot;')}">${ref(r.syncedContact)}</div>
        <div class="fg"><label>Email</label><input id="vmd-email" type="email" value="${(r.email||'').replace(/"/g,'&quot;')}">${ref(r.syncedEmail)}</div>
        <div class="fg"><label>No. Telp *</label><input id="vmd-phone" type="text" value="${(r.phone||'').replace(/"/g,'&quot;')}">${ref(r.syncedPhone)}</div>
        <div class="fg full"><label>Alamat</label><input id="vmd-address" type="text" value="${(r.address||'').replace(/"/g,'&quot;')}">${ref(r.syncedCity)}</div>
        <div class="fg"><label>NPWP</label><input id="vmd-npwp" type="text" value="${(r.npwp||'').replace(/"/g,'&quot;')}">${ref(r.syncedNpwp)}</div>
      </div>
      ${linked?`<div style="margin-top:10px;text-align:right"><button class="btn-icon" onclick="vmPullFromJubelio('${r.id}')" title="Replace manual fields with Jubelio data">↻ Tarik ulang dari Jubelio</button></div>`:''}
    </div>

    <div style="background:var(--off);border-radius:6px;padding:14px">
      <div style="font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px">Default PO ke Jubelio</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px">
        <div class="fg"><label>Default Lokasi</label>
          <select id="vmd-loc">
            ${['Pusat','Gudang Bintaro','Gudang Penerimaan Barang','Gudang Offline','Gudang Marte'].map(l =>
              `<option value="${l}"${r.defaultLocation===l?' selected':''}>${l==='Pusat'?'Gudang Pusat':l}</option>`).join('')}
          </select>
        </div>
        <div class="fg"><label>Default Pajak</label>
          <select id="vmd-tax">
            <option value="PPN"${r.defaultTax==='PPN'?' selected':''}>PPN (11%)</option>
            <option value="No Tax"${r.defaultTax==='No Tax'?' selected':''}>No Tax</option>
          </select>
        </div>
        <div class="fg"><label>Harga Termasuk Pajak?</label>
          <select id="vmd-tax-incl">
            <option value="false"${!r.defaultTaxIncluded?' selected':''}>FALSE</option>
            <option value="true"${r.defaultTaxIncluded?' selected':''}>TRUE</option>
          </select>
        </div>
        <div class="fg"><label>Notes Internal</label><input id="vmd-notes" type="text" value="${(r.notes||'').replace(/"/g,'&quot;')}"></div>
      </div>
      <div style="margin-top:14px;text-align:right">
        <button class="btn-save" onclick="saveVMDetailIdentity('${r.id}')">Simpan Semua</button>
      </div>
    </div>`;
}

async function saveVMDetailIdentity(id) {
  const name = document.getElementById('vmd-name').value.trim();
  const phone = document.getElementById('vmd-phone').value.trim();
  if (!name) { alert('Nama vendor wajib.'); return; }
  if (!phone) { alert('No. Telp wajib.'); return; }
  try {
    const {error} = await sb.from('vendor_master').update({
      vendor_name: name,
      contact_person: document.getElementById('vmd-contact').value.trim() || null,
      email: document.getElementById('vmd-email').value.trim() || null,
      phone,
      address: document.getElementById('vmd-address').value.trim() || null,
      npwp: document.getElementById('vmd-npwp').value.trim() || null,
      default_location: document.getElementById('vmd-loc').value,
      default_tax: document.getElementById('vmd-tax').value,
      default_tax_included: document.getElementById('vmd-tax-incl').value === 'true',
      notes: document.getElementById('vmd-notes').value.trim() || null,
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', id);
    if (error) throw error;
    await loadVendorMaster();
    const row = allVMRows.find(r => r.id === id);
    if (row) _vmRenderIdentityTab(row);
    alert('✓ Tersimpan');
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function vmUnlinkExisting(id) {
  if (!confirm('Lepas link ke Jubelio? Manual fields tetap utuh, hanya jubelio_contact_id yang di-null-kan.')) return;
  try {
    const {error} = await sb.from('vendor_master').update({
      jubelio_contact_id: null,
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', id);
    if (error) throw error;
    await loadVendorMaster();
    const row = allVMRows.find(r => r.id === id);
    if (row) _vmRenderIdentityTab(row);
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function vmPullFromJubelio(id) {
  if (!confirm('Replace nama/contact/email/telp/NPWP/alamat dengan data Jubelio terkini? Field yang sudah kamu edit manual akan tertimpa.')) return;
  const row = allVMRows.find(r => r.id === id);
  if (!row || !row.jubelioContactId) return;
  const s = allJubSuppliers.find(x => x.contact_id === row.jubelioContactId);
  if (!s) { alert('Data Jubelio tidak ditemukan. Coba refresh halaman.'); return; }
  try {
    const {error} = await sb.from('vendor_master').update({
      vendor_name: s.contact_name || row.vendorName,
      contact_person: s.primary_contact || null,
      email: s.email || null,
      phone: s.phone || s.mobile || row.phone,
      address: s.billing_address || s.billing_city || null,
      npwp: s.npwp || null,
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', id);
    if (error) throw error;
    await loadVendorMaster();
    const r2 = allVMRows.find(r => r.id === id);
    if (r2) _vmRenderIdentityTab(r2);
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function vmRelinkExisting(vmId, jubContactId) {
  const existing = allVMRows.find(r => r.jubelioContactId === jubContactId && r.id !== vmId);
  if (existing) {
    alert(`Pemasok ini sudah terhubung ke vendor "${vmSyncedField(existing,'name')}". Lepas dulu di sana.`);
    return;
  }
  try {
    const {error} = await sb.from('vendor_master').update({
      jubelio_contact_id: jubContactId,
      last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', vmId);
    if (error) throw error;
    await loadVendorMaster();
    const row = allVMRows.find(r => r.id === vmId);
    if (row) _vmRenderIdentityTab(row);
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function _vmRenderCatalogTab(r) {
  const cont = document.getElementById('vm-detail-tab-catalog');
  cont.innerHTML = `<div style="padding:20px;text-align:center;color:var(--g400);font-size:12px">Memuat catalog...</div>`;
  const name = vmSyncedField(r, 'name');
  try {
    // Pull all variants where vendor matches this vendor name (case-insensitive)
    const {data, error} = await sb.from('product_dev').select('*').eq('sku_type','variant').limit(20000);
    if (error) throw error;
    const variants = (data||[]).filter(v => (v.vendor||'').toLowerCase().trim() === (name||'').toLowerCase().trim());
    if (!variants.length) {
      cont.innerHTML = `
        <div style="background:var(--off);border-radius:6px;padding:20px;text-align:center;color:var(--g600);font-size:13px">
          Belum ada SKU di Product Dev yang diassign ke vendor ini.<br>
          <span style="font-size:11px;color:var(--g400)">Vendor di-match berdasarkan nama yang sama persis (case-insensitive).</span>
        </div>`;
      return;
    }
    // Group by parent_id (collection variant parent)
    const parentIds = [...new Set(variants.map(v => v.parent_id).filter(Boolean))];
    const {data: parents} = await sb.from('product_dev').select('id,sku_name,collection_id').in('id', parentIds);
    const parentById = new Map((parents||[]).map(p => [p.id, p]));
    const collectionIds = [...new Set((parents||[]).map(p => p.collection_id).filter(Boolean))];
    const {data: collections} = await sb.from('collections').select('id,collection_name,ip_related,status').in('id', collectionIds);
    const colById = new Map((collections||[]).map(c => [c.id, c]));

    // Aggregate by collection
    const byCol = new Map();
    let totalQty = 0, totalHpp = 0;
    variants.forEach(v => {
      const parent = parentById.get(v.parent_id);
      const col = parent ? colById.get(parent.collection_id) : null;
      const colKey = col?.id || '__no_collection__';
      if (!byCol.has(colKey)) byCol.set(colKey, { col, parents: new Map() });
      const colEntry = byCol.get(colKey);
      const pKey = v.parent_id || '__no_parent__';
      if (!colEntry.parents.has(pKey)) colEntry.parents.set(pKey, { parent: parentById.get(v.parent_id), variants: [] });
      colEntry.parents.get(pKey).variants.push(v);
      totalQty += v.qty || 0;
      totalHpp += (v.qty || 0) * (v.hpp || 0);
    });

    const colsArr = [...byCol.values()].sort((a,b) => (b.col?.name||'').localeCompare(a.col?.name||''));
    const totalSku = variants.length;

    cont.innerHTML = `
      <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:16px">
        <div class="stat-card"><div class="stat-num">${totalSku}</div><div class="stat-lbl">Total SKU</div></div>
        <div class="stat-card"><div class="stat-num">${totalQty.toLocaleString('id-ID')}</div><div class="stat-lbl">Total Qty</div></div>
        <div class="stat-card"><div class="stat-num">${(totalHpp/1000000).toFixed(1)}M</div><div class="stat-lbl">Total HPP</div></div>
        <div class="stat-card"><div class="stat-num">${totalQty?Math.round(totalHpp/totalQty).toLocaleString('id-ID'):'—'}</div><div class="stat-lbl">Avg HPP/pc</div></div>
      </div>
      ${colsArr.map(({col,parents:pMap}) => {
        const colName = col?.collection_name || '(no collection)';
        const ip = col?.ip_related || '';
        const status = col?.status || '';
        let cQty = 0, cHpp = 0, cSku = 0;
        pMap.forEach(({variants:vs}) => { vs.forEach(v => { cQty += v.qty||0; cHpp += (v.qty||0)*(v.hpp||0); cSku++; }); });
        return `
          <details style="background:var(--off);border-radius:6px;margin-bottom:8px" open>
            <summary style="padding:12px 14px;cursor:pointer;font-size:13px;display:flex;justify-content:space-between;align-items:center;gap:12px">
              <div>
                <strong>${colName.replace(/</g,'&lt;')}</strong>
                ${ip?`<span style="font-size:11px;color:var(--g600);margin-left:8px">${ip.replace(/</g,'&lt;')}</span>`:''}
                ${status?`<span class="pill p-${status==='Active'?'active':'draft'}" style="font-size:10px;margin-left:6px">${status}</span>`:''}
              </div>
              <div style="font-size:11px;color:var(--g600);font-family:'DM Mono',monospace">
                ${cSku} SKU · ${cQty} pcs · Rp ${cHpp.toLocaleString('id-ID')}
              </div>
            </summary>
            <div style="padding:0 14px 12px">
              <table style="width:100%;font-size:11px">
                <thead>
                  <tr style="background:var(--white)"><th style="text-align:left">SKU Code</th><th style="text-align:left">Parent</th><th style="text-align:left">Size</th><th style="text-align:right">Qty</th><th style="text-align:right">HPP/pc</th><th style="text-align:right">Subtotal</th></tr>
                </thead>
                <tbody>
                  ${[...pMap.values()].flatMap(({parent,variants:vs}) =>
                    vs.map(v => `<tr>
                      <td class="mono">${(v.display_code||v.id||'').replace(/</g,'&lt;')}</td>
                      <td>${(parent?.sku_name||'—').replace(/</g,'&lt;')}</td>
                      <td>${(v.size||'—').replace(/</g,'&lt;')}</td>
                      <td style="text-align:right">${v.qty||0}</td>
                      <td style="text-align:right">Rp ${(v.hpp||0).toLocaleString('id-ID')}</td>
                      <td style="text-align:right">Rp ${((v.qty||0)*(v.hpp||0)).toLocaleString('id-ID')}</td>
                    </tr>`)
                  ).join('')}
                </tbody>
              </table>
            </div>
          </details>`;
      }).join('')}`;
  } catch (e) {
    cont.innerHTML = `<div style="padding:20px;color:#c0392b;font-size:12px">Gagal: ${e.message||e}</div>`;
  }
}

async function _vmRenderPoTab(r) {
  const cont = document.getElementById('vm-detail-tab-po');
  cont.innerHTML = `<div style="padding:20px;text-align:center;color:var(--g400);font-size:12px">Memuat PO history...</div>`;
  try {
    let q = sb.from('jubelio_purchase_orders').select('*').order('transaction_date', {ascending:false}).limit(500);
    // If linked to Jubelio, match by contact_id (reliable); else fuzzy on supplier_name
    if (r.jubelioContactId) {
      q = q.eq('contact_id', r.jubelioContactId);
    } else {
      const name = vmSyncedField(r, 'name');
      q = q.ilike('supplier_name', name || '__none__');
    }
    const {data, error} = await q;
    if (error) throw error;
    if (!data || !data.length) {
      cont.innerHTML = `<div style="background:var(--off);border-radius:6px;padding:20px;text-align:center;color:var(--g600);font-size:13px">Belum ada PO di Jubelio untuk vendor ini.</div>`;
      return;
    }
    let totalAmt = 0, openCount = 0;
    data.forEach(po => { totalAmt += parseFloat(po.grand_total||0); if (!po.is_closed) openCount++; });
    cont.innerHTML = `
      <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:16px">
        <div class="stat-card"><div class="stat-num">${data.length}</div><div class="stat-lbl">Total PO</div></div>
        <div class="stat-card"><div class="stat-num">${openCount}</div><div class="stat-lbl">Open</div></div>
        <div class="stat-card"><div class="stat-num">${(totalAmt/1000000).toFixed(1)}M</div><div class="stat-lbl">Total Nilai</div></div>
      </div>
      <table style="width:100%;font-size:11px">
        <thead><tr><th>No.</th><th>Tanggal</th><th>Lokasi</th><th>Status</th><th style="text-align:right">Nilai</th></tr></thead>
        <tbody>
          ${data.map(po => `<tr>
            <td class="mono">${(po.purchaseorder_no||po.purchaseorder_id||'').toString().replace(/</g,'&lt;')}</td>
            <td>${(po.transaction_date||'').toString().slice(0,10)}</td>
            <td style="font-size:11px">${(po.location_name||'—').toString().replace(/</g,'&lt;')}</td>
            <td><span class="pill p-${po.is_closed?'active':'draft'}" style="font-size:10px">${po.is_closed?'Closed':(po.status||'Open')}</span></td>
            <td style="text-align:right">Rp ${parseFloat(po.grand_total||0).toLocaleString('id-ID')}</td>
          </tr>`).join('')}
        </tbody>
      </table>`;
  } catch (e) {
    cont.innerHTML = `<div style="padding:20px;color:#c0392b;font-size:12px">Gagal: ${e.message||e}</div>`;
  }
}

