function _rpResetBuilderState() {
  _rstAddedProducts = new Set();
  _rstSelectedItems = new Set();
  _rstQtyMap = {};
  _rstParentVendorMap = {};
  _rstParentPriceMap = {};
  _rpCurrentId = null;
  _rpCurrentStatus = 'Draft';
  _rpDirty = false;
  const nameEl = document.getElementById('rp-name'); if (nameEl) nameEl.value = '';
  const panel = document.getElementById('rp-progress-panel'); if (panel) panel.style.display = 'none';
}

// Mark dirty on any builder change — wired to onchange/oninput of inputs and toggles.
function _rpMarkDirty() { _rpDirty = true; }

// ── Project list ──
async function loadRestockProjects() {
  const listEl = document.getElementById('rp-list');
  const sumEl  = document.getElementById('rp-list-summary');
  if (!listEl) return;
  listEl.innerHTML = `<div style="padding:24px;text-align:center;color:var(--g400);font-size:12px">Memuat...</div>`;
  try {
    // Load projects + Jubelio POs/bills in parallel (for progress calc)
    const [pRes, poRes, billsRes, billItemsRes] = await Promise.all([
      sb.from('restock_projects').select('*').order('date_created', {ascending:false}),
      sb.from('jubelio_purchase_orders').select('purchaseorder_id,purchaseorder_no,supplier_name,transaction_date,contact_id,is_closed,status'),
      sb.from('jubelio_purchase_bills').select('bill_id,bill_no,purchaseorder_id,is_putaway,transaction_date'),
      sb.from('jubelio_purchase_order_items').select('purchaseorder_id,item_id,qty'),
    ]);
    if (pRes.error) throw pRes.error;
    _rpRows = pRes.data || [];
    const poById = new Map((poRes.data||[]).map(po => [po.purchaseorder_id, po]));
    const billsByPo = new Map();
    (billsRes.data||[]).forEach(b => {
      if (!billsByPo.has(b.purchaseorder_id)) billsByPo.set(b.purchaseorder_id, []);
      billsByPo.get(b.purchaseorder_id).push(b);
    });
    // PO line items grouped by purchaseorder_id — used to count qty already ordered (in PO),
    // which is the progress metric (NOT bill receipts / putaway).
    const poItemsByPo = new Map();
    (billItemsRes.data||[]).forEach(it => {
      if (!poItemsByPo.has(it.purchaseorder_id)) poItemsByPo.set(it.purchaseorder_id, []);
      poItemsByPo.get(it.purchaseorder_id).push(it);
    });

    // Compute progress + render
    if (!_rpRows.length) {
      listEl.innerHTML = `<div style="padding:48px 24px;text-align:center;background:var(--off);border:2px dashed var(--g100);border-radius:12px">
        <div style="font-size:14px;color:var(--g600);margin-bottom:6px">Belum ada project restock</div>
        <div style="font-size:12px;color:var(--g400);margin-bottom:14px">Klik <strong>+ Project Baru</strong> untuk mulai.</div>
        <button onclick="_rpStartNewProject()" style="padding:8px 16px;background:#3C3489;color:white;border:none;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600">+ Project Baru</button>
      </div>`;
      if (sumEl) sumEl.textContent = '0 project';
      return;
    }

    if (sumEl) {
      const draft = _rpRows.filter(r => r.status==='Draft').length;
      const active = _rpRows.filter(r => r.status==='Active').length;
      const done = _rpRows.filter(r => r.status==='Completed').length;
      sumEl.textContent = `${_rpRows.length} project · ${draft} draft · ${active} active · ${done} completed`;
    }

    listEl.innerHTML = _rpRows.map(p => {
      const progress = _rpComputeProgress(p, poById, poItemsByPo);
      return _rpRenderProjectCard(p, progress);
    }).join('');
  } catch (e) {
    listEl.innerHTML = `<div style="padding:24px;color:#c0392b;font-size:13px">Gagal: ${e.message||e}</div>`;
  }
}

// Progress tracks qty yang sudah masuk PO (sum dari jubelio_purchase_order_items)
// untuk PO yang ter-link ke project ini, dibatasi hanya item_id yang ada di project.items.
// (BUKAN qty yang sudah putaway/diterima via bill — itu metric berbeda.)
function _rpComputeProgress(project, poById, poItemsByPo) {
  const items = Array.isArray(project.items) ? project.items : [];
  const planned = items.reduce((s, it) => s + (Number(it.qty_planned)||0), 0);
  const plannedByItemId = new Map();
  for (const it of items) {
    const k = String(it.item_id);
    plannedByItemId.set(k, (plannedByItemId.get(k) || 0) + (Number(it.qty_planned)||0));
  }
  let inPo = 0;
  for (const poId of (project.linked_po_ids || [])) {
    const poItems = poItemsByPo.get(poId) || [];
    for (const pi of poItems) {
      if (plannedByItemId.has(String(pi.item_id))) {
        inPo += Number(pi.qty) || 0;
      }
    }
  }
  const pct = planned > 0 ? Math.min(100, Math.round(inPo / planned * 100)) : 0;
  return { planned, inPo, pct, linkedCount: (project.linked_po_ids||[]).length };
}

function _rpStatusPill(status, pct) {
  let cls = 'p-draft', lbl = status;
  if (status === 'Active') cls = pct >= 100 ? 'p-active' : 'p-signings';
  if (status === 'Completed') cls = 'p-active';
  if (status === 'Cancelled') cls = 'p-expired';
  return `<span class="pill ${cls}" style="font-size:11px">${lbl}</span>`;
}

function _rpRenderProjectCard(p, progress) {
  const items = Array.isArray(p.items) ? p.items : [];
  const vendors = new Set(items.map(it => it.vendor_master_id).filter(Boolean));
  const dateStr = p.date_created
    ? new Date(p.date_created).toLocaleDateString('id-ID',{day:'numeric',month:'short',year:'numeric'})
    : '—';
  const totalNilai = items.reduce((s, it) => s + (Number(it.qty_planned)||0) * (Number(it.price_planned)||0), 0);
  const fmtRp = v => 'Rp ' + Math.round(v).toLocaleString('id-ID');
  const pctClr = progress.pct >= 100 ? '#1e8f4e' : progress.pct > 0 ? '#3C3489' : '#aaa';
  const id = (p.id||'').replace(/'/g,"\\'");

  return `<div style="background:white;border:1px solid var(--g100);border-radius:8px;padding:14px 16px;box-shadow:0 1px 2px rgba(0,0,0,0.03)">
    <div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-bottom:8px">
      <div style="flex:1;min-width:0">
        <div style="font-size:14px;font-weight:700;line-height:1.3">
          <a href="#" onclick="_rpOpenProject('${id}');return false" style="color:var(--text);text-decoration:none">${(p.name||p.id).replace(/</g,'&lt;')}</a>
          <span style="margin-left:8px">${_rpStatusPill(p.status, progress.pct)}</span>
        </div>
        <div style="font-size:11px;color:var(--g400);margin-top:2px">${p.id} · ${dateStr} · ${items.length} SKU · ${vendors.size} vendor${totalNilai>0?` · est. ${fmtRp(totalNilai)}`:''}</div>
      </div>
      <div style="display:flex;gap:6px">
        <button onclick="_rpOpenProject('${id}')" style="padding:6px 12px;background:white;border:1px solid var(--g200);border-radius:4px;cursor:pointer;font-size:12px">Lihat</button>
        <button onclick="_rpDeleteProject('${id}')" style="padding:6px 12px;background:white;border:1px solid var(--g200);color:#c0392b;border-radius:4px;cursor:pointer;font-size:12px">Hapus</button>
      </div>
    </div>
    <div style="display:flex;gap:12px;align-items:center">
      <div style="flex:1;background:var(--g100);height:8px;border-radius:4px;overflow:hidden">
        <div style="height:100%;width:${progress.pct}%;background:${pctClr};transition:width 0.3s"></div>
      </div>
      <div style="font-size:11px;color:var(--g600);font-family:'DM Mono',monospace;white-space:nowrap" title="Qty sudah masuk PO / qty plan">${progress.inPo}/${progress.planned} pcs · ${progress.pct}%${progress.linkedCount>0?` · 🔗 ${progress.linkedCount} PO`:''}</div>
    </div>
  </div>`;
}

// ── Start new project (clear state, open builder) ──
async function _rpStartNewProject() {
  _rpResetBuilderState();
  _rpCurrentId = null;
  _rpCurrentStatus = 'Draft';
  // Auto-name
  const n = (_rpRows.filter(r => /^Restock #\d+$/.test(r.name||'')).length) + 1;
  document.getElementById('rp-name').value = `Restock #${n}`;
  // Default dates (last 30 days)
  const _now = new Date();
  const _to = _now.toISOString().slice(0,10);
  const _fr = new Date(_now - 30*864e5).toISOString().slice(0,10);
  const fe = document.getElementById('rst-from'); if (fe && !fe.value) fe.value = _fr;
  const te = document.getElementById('rst-to');   if (te && !te.value) te.value = _to;
  _rpRefreshStatusPill();
  _rpShowBuilderView();
  await loadRestock();
}

// ── Open existing project ──
async function _rpOpenProject(id) {
  const p = _rpRows.find(r => r.id === id);
  if (!p) { alert('Project tidak ditemukan'); return; }
  _rpCurrentId = id;
  _rpCurrentStatus = p.status || 'Draft';
  document.getElementById('rp-name').value = p.name || '';
  if (p.period_from) document.getElementById('rst-from').value = p.period_from;
  if (p.period_to)   document.getElementById('rst-to').value   = p.period_to;
  // Hydrate builder state from saved items
  _rstAddedProducts = new Set();
  _rstSelectedItems = new Set();
  _rstQtyMap = {};
  _rstParentVendorMap = {};
  _rstParentPriceMap = {};
  const items = Array.isArray(p.items) ? p.items : [];
  for (const it of items) {
    if (it.parent_name) _rstAddedProducts.add(it.parent_name);
    if (it.item_id != null) {
      _rstSelectedItems.add(Number(it.item_id));
      if (it.qty_planned != null) _rstQtyMap[Number(it.item_id)] = Number(it.qty_planned);
    }
    if (it.parent_name && it.vendor_master_id) _rstParentVendorMap[it.parent_name] = it.vendor_master_id;
    if (it.parent_name && it.price_planned != null) _rstParentPriceMap[it.parent_name] = Number(it.price_planned);
  }
  _rpRefreshStatusPill();
  _rpShowBuilderView();
  await loadRestock(); // loads data + auto-renders added products
  _rpDirty = false;    // Just loaded saved state, mark clean
}

// ── Save project (insert or update) ──
async function _rpSaveProject(activate) {
  const name = document.getElementById('rp-name').value.trim();
  if (!name) { alert('⚠️ Nama project wajib diisi dulu.'); return; }
  const lines = _rstCollectSelectedLines();
  if (!lines.length) {
    if (activate) { alert('⚠️ Belum ada SKU yang dipilih + qty > 0. Tambah produk dulu, centang variant, atur qty sebelum Activate.'); return; }
    // For Draft save, warn but allow
    if (!confirm('Belum ada SKU dipilih (semua qty 0). Tetap save sebagai Draft kosong?')) return;
  }
  const periodFrom = document.getElementById('rst-from').value || null;
  const periodTo   = document.getElementById('rst-to').value   || null;
  const itemsPayload = lines.map(l => ({
    item_id: l.itemId, item_code: l.sku, parent_name: l.parentName,
    brand: l.brand, ip: l.ip, collection: l.collection,
    size: l.size, thumbnail: l.thumbnail,
    vendor_master_id: l.vmId, qty_planned: l.qty, price_planned: l.price,
  }));
  const targetStatus = activate ? 'Active' : (_rpCurrentStatus === 'Draft' ? 'Draft' : _rpCurrentStatus);
  // Disable buttons while saving + show inline status
  const saveBtn = document.getElementById('rp-save-btn');
  const actBtn = document.getElementById('rp-activate-btn');
  const origSaveLabel = saveBtn?.textContent;
  const origActLabel = actBtn?.textContent;
  if (saveBtn) { saveBtn.disabled = true; saveBtn.textContent = '⟳ Menyimpan...'; }
  if (actBtn)  { actBtn.disabled = true; }
  try {
    if (_rpCurrentId) {
      const {error} = await sb.from('restock_projects').update({
        name, status: targetStatus, items: itemsPayload,
        period_from: periodFrom, period_to: periodTo,
        last_updated: new Date().toISOString(), last_updated_by: currentUser,
      }).eq('id', _rpCurrentId);
      if (error) throw error;
    } else {
      const newId = genId('RP');
      const {error, data} = await sb.from('restock_projects').insert({
        id: newId, name, status: targetStatus, items: itemsPayload,
        period_from: periodFrom, period_to: periodTo,
        created_by: currentUser, date_created: new Date().toISOString(),
      }).select().single();
      if (error) throw error;
      _rpCurrentId = newId;
      console.log('Restock project saved:', newId, data);
    }
    _rpCurrentStatus = targetStatus;
    _rpDirty = false;  // Reset dirty flag — current state is now persisted
    _rpRefreshStatusPill();
    // Inline feedback (not alert — feels faster + less disruptive)
    _rpFlashMessage(`✓ Tersimpan sebagai ${targetStatus} · ${itemsPayload.length} SKU`, 'ok');
    // Refresh list cache for progress panel
    await loadRestockProjects();
    if (targetStatus !== 'Draft') _rpUpdateProgressPanel();
  } catch (e) {
    console.error('Save project failed:', e);
    alert('❌ Gagal save: ' + (e.message || e) + '\n\nCek browser console untuk detail.');
  } finally {
    if (saveBtn) { saveBtn.disabled = false; saveBtn.textContent = origSaveLabel; }
    if (actBtn)  { actBtn.disabled = false;  actBtn.textContent = origActLabel; }
  }
}

// Inline flash message — non-blocking feedback, auto-hides + auto-removes
// so the fixed-position banner can't block clicks once it's gone.
function _rpFlashMessage(text, kind) {
  let bar = document.getElementById('rp-flash');
  if (!bar) {
    bar = document.createElement('div');
    bar.id = 'rp-flash';
    // pointer-events:none so even while visible it doesn't catch clicks
    bar.style.cssText = 'position:fixed;top:16px;right:16px;z-index:9000;padding:10px 16px;border-radius:6px;font-size:13px;font-weight:600;box-shadow:0 8px 24px rgba(0,0,0,0.15);transition:opacity 0.3s;pointer-events:none';
    document.body.appendChild(bar);
  }
  bar.style.background = kind === 'ok' ? '#daf3e0' : '#fde0e0';
  bar.style.color = kind === 'ok' ? '#0a7d3a' : '#b81d1d';
  bar.style.border = kind === 'ok' ? '1px solid #a7dab4' : '1px solid #f3a8a8';
  bar.textContent = text;
  bar.style.opacity = '1';
  bar.style.display = 'block';
  clearTimeout(_rpFlashMessage._t);
  clearTimeout(_rpFlashMessage._t2);
  _rpFlashMessage._t = setTimeout(() => { bar.style.opacity = '0'; }, 3000);
  // After fade completes, set display:none so it's fully removed from layout
  _rpFlashMessage._t2 = setTimeout(() => { bar.style.display = 'none'; }, 3400);
}

async function _rpDeleteProject(id) {
  const p = _rpRows.find(r => r.id === id);
  if (!p) return;
  let msg = `Hapus project "${p.name||id}"?\n\nTidak bisa di-undo.`;
  if (p.status === 'Active') {
    msg = `⚠️ Project ini status Active${(p.linked_po_ids||[]).length?` dan sudah ter-link ke ${(p.linked_po_ids||[]).length} PO Jubelio`:''}.\n\nHapus tetap akan menghapus snapshot project + link-nya (PO di Jubelio tidak terpengaruh).\n\nLanjut hapus "${p.name||id}"?`;
  } else if (p.status === 'Completed') {
    msg = `Project "${p.name||id}" sudah Completed (arsip). Yakin hapus permanen?`;
  }
  if (!confirm(msg)) return;
  try {
    const {error} = await sb.from('restock_projects').delete().eq('id', id);
    if (error) throw error;
    await loadRestockProjects();
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function _rpMarkComplete() {
  if (!_rpCurrentId) return;
  if (!confirm('Mark project ini sebagai Completed?')) return;
  try {
    const {error} = await sb.from('restock_projects').update({
      status: 'Completed', last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', _rpCurrentId);
    if (error) throw error;
    _rpCurrentStatus = 'Completed';
    _rpRefreshStatusPill();
    await loadRestockProjects();
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

function _rpRefreshStatusPill() {
  const el = document.getElementById('rp-status-pill');
  if (el) el.innerHTML = _rpStatusPill(_rpCurrentStatus, 0);
  // Show/hide progress panel
  const panel = document.getElementById('rp-progress-panel');
  if (panel) panel.style.display = (_rpCurrentId && _rpCurrentStatus !== 'Draft') ? 'block' : 'none';
  if (_rpCurrentId && _rpCurrentStatus !== 'Draft') _rpUpdateProgressPanel();
}

async function _rpUpdateProgressPanel() {
  if (!_rpCurrentId) return;
  // Re-fetch progress data (it's already cached if loadRestockProjects ran)
  const p = _rpRows.find(r => r.id === _rpCurrentId);
  if (!p) return;
  const [poRes, poItemsRes] = await Promise.all([
    sb.from('jubelio_purchase_orders').select('purchaseorder_id,purchaseorder_no,supplier_name,transaction_date,is_closed,status'),
    sb.from('jubelio_purchase_order_items').select('purchaseorder_id,item_id,qty'),
  ]);
  const poById = new Map((poRes.data||[]).map(po => [po.purchaseorder_id, po]));
  const poItemsByPo = new Map();
  (poItemsRes.data||[]).forEach(it => {
    if (!poItemsByPo.has(it.purchaseorder_id)) poItemsByPo.set(it.purchaseorder_id, []);
    poItemsByPo.get(it.purchaseorder_id).push(it);
  });
  const progress = _rpComputeProgress(p, poById, poItemsByPo);
  document.getElementById('rp-progress-text').textContent = `${progress.inPo} / ${progress.planned} pcs sudah masuk PO · ${progress.pct}%`;
  document.getElementById('rp-progress-bar').style.width = progress.pct + '%';
  document.getElementById('rp-progress-bar').style.background = progress.pct >= 100 ? '#1e8f4e' : '#3C3489';
  // Render linked POs
  const linkedDiv = document.getElementById('rp-linked-pos');
  const linkedIds = p.linked_po_ids || [];
  if (!linkedIds.length) {
    linkedDiv.innerHTML = `<span style="font-size:11px;color:var(--g400)">Belum ada PO terkait. Klik <strong>+ Link PO Jubelio</strong> untuk hubungkan.</span>`;
  } else {
    linkedDiv.innerHTML = linkedIds.map(poId => {
      const po = poById.get(poId);
      const label = po ? `${po.purchaseorder_no||poId} — ${po.supplier_name||'?'}` : `PO #${poId}`;
      return `<span style="display:inline-flex;align-items:center;gap:4px;background:white;border:1px solid var(--g200);border-radius:4px;padding:3px 8px;font-size:11px">
        🔗 ${label.replace(/</g,'&lt;')}
        <button onclick="_rpUnlinkPo(${poId})" style="background:none;border:none;cursor:pointer;color:#c0392b;font-size:13px;line-height:1;padding:0 0 0 4px" title="Lepas link">×</button>
      </span>`;
    }).join('');
  }
  // Show/hide Mark Complete button
  document.getElementById('rp-complete-btn').style.display =
    (_rpCurrentStatus === 'Active' && progress.pct >= 100) ? 'inline-block' : 'none';
}

// ── PO Link Picker modal ──
async function _rpOpenPoLinkPicker() {
  if (!_rpCurrentId) { alert('Save project dulu sebelum link PO.'); return; }
  document.getElementById('rp-po-picker-modal').style.display = 'flex';
  document.getElementById('rp-po-search').value = '';
  await _rpLoadPosForPicker();
}

function _rpClosePoLinkPicker() {
  document.getElementById('rp-po-picker-modal').style.display = 'none';
}

let _rpAllPos = [];
async function _rpLoadPosForPicker() {
  const listEl = document.getElementById('rp-po-list');
  listEl.innerHTML = `<div style="padding:24px;text-align:center;color:var(--g400);font-size:12px">Memuat PO...</div>`;
  try {
    const {data, error} = await sb.from('jubelio_purchase_orders')
      .select('purchaseorder_id,purchaseorder_no,supplier_name,transaction_date,grand_total,is_closed,status,location_name')
      .order('transaction_date', {ascending:false})
      .limit(200);
    if (error) throw error;
    _rpAllPos = data || [];
    // Populate vendor dropdown
    const sel = document.getElementById('rp-po-vendor-fil');
    const vendors = [...new Set(_rpAllPos.map(po => po.supplier_name).filter(Boolean))].sort();
    sel.innerHTML = '<option value="">Semua Vendor</option>' + vendors.map(v => `<option>${v.replace(/</g,'&lt;')}</option>`).join('');
    _rpRenderPoPicker();
  } catch (e) {
    listEl.innerHTML = `<div style="padding:24px;color:#c0392b;font-size:12px">Gagal: ${e.message||e}</div>`;
  }
}

function _rpRenderPoPicker() {
  const p = _rpRows.find(r => r.id === _rpCurrentId);
  const linkedIds = new Set((p?.linked_po_ids)||[]);
  const q = (document.getElementById('rp-po-search').value||'').toLowerCase().trim();
  const vfil = document.getElementById('rp-po-vendor-fil').value;
  let rows = _rpAllPos.slice();
  if (vfil) rows = rows.filter(po => po.supplier_name === vfil);
  if (q) rows = rows.filter(po =>
    (po.purchaseorder_no||'').toLowerCase().includes(q) ||
    (po.supplier_name||'').toLowerCase().includes(q));
  const listEl = document.getElementById('rp-po-list');
  if (!rows.length) {
    listEl.innerHTML = `<div style="padding:24px;text-align:center;color:var(--g400);font-size:12px">Tidak ada match.</div>`;
    return;
  }
  listEl.innerHTML = rows.slice(0, 100).map(po => {
    const linked = linkedIds.has(po.purchaseorder_id);
    const date = po.transaction_date ? new Date(po.transaction_date).toLocaleDateString('id-ID',{day:'2-digit',month:'short',year:'numeric'}) : '—';
    const amt = po.grand_total ? `Rp ${Math.round(po.grand_total).toLocaleString('id-ID')}` : '—';
    return `<div style="display:flex;align-items:center;gap:10px;padding:10px;border-bottom:1px solid var(--g100)">
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600" class="mono">${(po.purchaseorder_no||po.purchaseorder_id).replace(/</g,'&lt;')}</div>
        <div style="font-size:11px;color:var(--g600);margin-top:2px">${(po.supplier_name||'—').replace(/</g,'&lt;')} · ${date} · ${amt}</div>
      </div>
      ${linked
        ? `<button onclick="_rpUnlinkPo(${po.purchaseorder_id});setTimeout(_rpRenderPoPicker,400)" style="padding:5px 10px;background:white;color:#c0392b;border:1px solid #c0392b;border-radius:4px;cursor:pointer;font-size:11px">Lepas</button>`
        : `<button onclick="_rpLinkPo(${po.purchaseorder_id});setTimeout(_rpRenderPoPicker,400)" style="padding:5px 10px;background:#3C3489;color:white;border:none;border-radius:4px;cursor:pointer;font-size:11px">+ Link</button>`}
    </div>`;
  }).join('');
}

async function _rpLinkPo(poId) {
  const p = _rpRows.find(r => r.id === _rpCurrentId);
  if (!p) return;
  const cur = new Set(p.linked_po_ids || []);
  cur.add(poId);
  try {
    const {error} = await sb.from('restock_projects').update({
      linked_po_ids: [...cur], last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', _rpCurrentId);
    if (error) throw error;
    p.linked_po_ids = [...cur];
    await _rpUpdateProgressPanel();
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function _rpUnlinkPo(poId) {
  const p = _rpRows.find(r => r.id === _rpCurrentId);
  if (!p) return;
  const cur = new Set(p.linked_po_ids || []);
  cur.delete(poId);
  try {
    const {error} = await sb.from('restock_projects').update({
      linked_po_ids: [...cur], last_updated: new Date().toISOString(), last_updated_by: currentUser,
    }).eq('id', _rpCurrentId);
    if (error) throw error;
    p.linked_po_ids = [...cur];
    await _rpUpdateProgressPanel();
  } catch (e) { alert('Gagal: ' + (e.message || e)); }
}

async function loadRestockSupplierOptions() {
  const sel = document.getElementById('rst-supplier');
  if (!sel) return;
  try {
    const suppliers = await loadJubSuppliers();
    const cur = sel.value;
    if (!suppliers.length) {
      sel.innerHTML = '<option value="">Tidak ada supplier — sync dulu di Vendor Master</option>';
      return;
    }
    sel.innerHTML = '<option value="">Pilih supplier...</option>' +
      suppliers.map(s => {
        const id = String(s.contact_id);
        const name = (s.contact_name||'').replace(/</g,'&lt;').replace(/"/g,'&quot;');
        return `<option value="${id}"${cur===id?' selected':''}>${name}</option>`;
      }).join('');
  } catch (e) {
    sel.innerHTML = `<option value="">Gagal muat supplier: ${(e.message||e).toString().slice(0,60)}</option>`;
  }
}

async function loadRestock() {
  if (_rstLoading) return;
  _rstLoading = true;
  // Show loading state in the products container (only if user hasn't added anything yet)
  const container = document.getElementById('rst-products');
  if (container && _rstAddedProducts.size === 0) {
    container.innerHTML = `<div style="padding:48px 24px;text-align:center;background:var(--off);border:1px solid var(--g100);border-radius:8px">
      <div style="font-size:14px;color:var(--g600);margin-bottom:4px">⟳ Memuat data jualan, stock, &amp; supplier...</div>
      <div style="font-size:11px;color:var(--g400)">Pertama kali load butuh ~15–30 detik (ngumpulin riwayat PO tiap SKU)</div>
    </div>`;
  }
  const summaryBar = document.getElementById('rst-summary-bar');
  if (summaryBar) summaryBar.textContent = '⟳ memuat data...';

  try {
    const fromDate = document.getElementById('rst-from')?.value;
    const toDate   = document.getElementById('rst-to')?.value;
    if (!fromDate || !toDate) {
      if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Pilih periode terlebih dahulu.</td></tr>`;
      return;
    }
    const dayCount  = Math.max(1, Math.round((new Date(toDate)-new Date(fromDate))/864e5)+1);
    const brandFil  = document.getElementById('rst-brand')?.value || '';
    const brands    = brandFil ? [brandFil] : RESTOCK_BRANDS;

    // 1. Product mappings for target brands
    const mappings = await _fetchAllPages('product_mappings','jubelio_item_id,item_name,brand,ip,collection',
      q => q.in('brand', brands).not('jubelio_item_id','is',null));
    if (!mappings.length) {
      if (tbody) tbody.innerHTML = `<tr><td class="empty-td" colspan="9">Tidak ada produk untuk brand yang dipilih.</td></tr>`;
      return;
    }
    const allItemIds  = [...new Set(mappings.map(m => m.jubelio_item_id))];
    const mappingById = {};
    for (const m of mappings) mappingById[m.jubelio_item_id] = m;

    // 2. COMPLETED orders in date range (IDs only)
    const orders = await _fetchAllPages('jubelio_sales_orders','salesorder_id',
      q => q.eq('wms_status','COMPLETED')
            .gte('transaction_date', fromDate+'T00:00:00')
            .lte('transaction_date', toDate+'T23:59:59'));
    const orderIds = orders.map(o => o.salesorder_id);

    // 3-5. Parallel: sold items (filter by item only — orderIdSet applied client-side),
    //      stock, item info, last-PO history per item (for vendor auto-suggest),
    //      and vendor_master list. Chunk .in() to avoid URL-length limits when
    //      allItemIds is large (currently 2000+ for SDY/Lagaa/Marte).
    const orderIdSet = new Set(orderIds);
    const [soldItemsRaw, stockRows, itemInfoRows, poItemsForVendor, poOrders] = await Promise.all([
      _fetchAllPagesIn('jubelio_sales_order_items','salesorder_id,item_id,qty','item_id', allItemIds),
      _fetchAllPagesIn('jubelio_inventory_stocks','item_id,on_hand','item_id', allItemIds),
      _fetchAllPagesIn('jubelio_items','item_id,item_code,item_name,thumbnail,image_urls','item_id', allItemIds),
      _fetchAllPagesIn('jubelio_purchase_order_items','purchaseorder_id,item_id','item_id', allItemIds),
      _fetchAllPages('jubelio_purchase_orders','purchaseorder_id,supplier_name,contact_id,transaction_date'),
    ]);

    // Build last-PO map per item_id
    const poById = new Map(poOrders.map(po => [po.purchaseorder_id, po]));
    _rstLastPOByItem = {};
    for (const pi of poItemsForVendor) {
      const po = poById.get(pi.purchaseorder_id); if (!po) continue;
      const cur = _rstLastPOByItem[pi.item_id];
      if (!cur || (po.transaction_date || '') > (cur.date || '')) {
        _rstLastPOByItem[pi.item_id] = {
          supplier_name: po.supplier_name, contact_id: po.contact_id, date: po.transaction_date,
        };
      }
    }

    // Load vendor_master + Jubelio suppliers (uses existing module caches if available)
    if (!allVMRows.length) await loadVendorMaster();
    if (!allJubSuppliers.length) await loadJubSuppliers();
    _rstAllVendors = _rstBuildAllVendors();
    // Client-side: only count qty from orders in the selected period
    const soldItems = soldItemsRaw.filter(it => orderIdSet.has(it.salesorder_id));

    // Build lookups
    const qtyMap   = {};
    for (const it of soldItems) qtyMap[it.item_id] = (qtyMap[it.item_id]||0) + parseFloat(it.qty||0);
    const stockMap = {};
    for (const r of stockRows) stockMap[r.item_id] = (stockMap[r.item_id]||0) + parseFloat(r.on_hand||0);
    const infoMap  = {};
    for (const r of itemInfoRows) infoMap[r.item_id] = r;

    // Group by parent name
    const productMap = {};
    for (const m of mappings) {
      const { item_name: parentName, brand, ip, collection, jubelio_item_id: itemId } = m;
      if (!productMap[parentName]) productMap[parentName] = { name:parentName, brand, ip, collection:collection||'', thumbnail:null, imageUrls:[], variants:[] };
      const info        = infoMap[itemId]  || {};
      const stock       = stockMap[itemId] || 0;
      const qtySold     = qtyMap[itemId]   || 0;
      const avgDaily    = qtySold / dayCount;
      const daysOfStock = avgDaily > 0 ? stock / avgDaily : null;
      const suggestedQty= avgDaily > 0 ? Math.max(0, Math.ceil(RESTOCK_TARGET * avgDaily) - stock) : 0;
      const needsRestock= daysOfStock !== null && daysOfStock < RESTOCK_LEAD_DAYS;
      if (!productMap[parentName].thumbnail && info.thumbnail) productMap[parentName].thumbnail = info.thumbnail;
      // Capture the full image list once per parent (first variant that has it wins)
      if (!productMap[parentName].imageUrls.length && Array.isArray(info.image_urls) && info.image_urls.length) {
        productMap[parentName].imageUrls = info.image_urls;
      }
      productMap[parentName].variants.push({
        itemId, itemCode: info.item_code||'', itemNameFull: info.item_name||parentName,
        size: _rstParseSize(info.item_code),
        stock, qtySold, avgDaily, daysOfStock, suggestedQty, needsRestock,
      });
    }

    // Sort variants by size order
    const _SO = ['XS','S','M','L','XL','XXL','XXXL','4XL','5XL'];
    for (const p of Object.values(productMap)) {
      p.variants.sort((a,b) => { const ai=_SO.indexOf(a.size), bi=_SO.indexOf(b.size); if(ai>=0&&bi>=0)return ai-bi; if(ai>=0)return -1; if(bi>=0)return 1; return a.size.localeCompare(b.size); });
      p.restockCount = p.variants.filter(v => v.needsRestock).length;
      p.minDays      = p.variants.filter(v => v.daysOfStock!==null).reduce((m,v) => Math.min(m,v.daysOfStock), Infinity);
      if (p.minDays===Infinity) p.minDays=null;
    }

    // Sort products: urgent first, then by minDays, then name
    const products = Object.values(productMap).sort((a,b) => {
      if (a.restockCount>0 && b.restockCount===0) return -1;
      if (a.restockCount===0 && b.restockCount>0) return  1;
      if (a.minDays!==null && b.minDays!==null) return a.minDays-b.minDays;
      return a.name.localeCompare(b.name);
    });

    _rstData = { products, dayCount };

    // Populate IP filter in the picker modal (brand is hardcoded SDY/Lagaa/Marte)
    const ipSel = document.getElementById('rst-add-ip');
    if (ipSel) {
      const cur = ipSel.value;
      const ips = [...new Set(products.map(p => p.ip).filter(Boolean))].sort();
      ipSel.innerHTML = '<option value="">Semua IP</option>' + ips.map(v => `<option value="${v}"${v===cur?' selected':''}>${v}</option>`).join('');
    }

    // Render added products (cards) — does nothing if user hasn't added any yet
    _rstRenderAddedProducts();

  } catch(e) {
    console.error('loadRestock:',e);
    const container = document.getElementById('rst-products');
    if (container && _rstAddedProducts.size === 0) {
      container.innerHTML = `<div style="padding:24px;color:#c0392b;font-size:13px;background:#fdf0f0;border:1px solid #f3a8a8;border-radius:8px">
        <div style="font-weight:600;margin-bottom:4px">Gagal memuat data</div>
        <div style="font-size:11px;color:#7a0000">${(e.message||e).toString().replace(/</g,'&lt;')}</div>
      </div>`;
    }
    const sb2 = document.getElementById('rst-summary-bar');
    if (sb2) sb2.textContent = `❌ gagal load — ${e.message||'unknown'}`;
  } finally {
    _rstLoading = false;
  }
}

// ── New card-per-product render (only shows products user has added) ──
function _rstRenderAddedProducts() {
  const container = document.getElementById('rst-products');
  if (!container || !_rstData) return;

  const added = _rstData.products.filter(p => _rstAddedProducts.has(p.name));

  if (!added.length) {
    container.innerHTML = `<div style="padding:48px 24px;text-align:center;background:var(--off);border:2px dashed var(--g100);border-radius:12px">
      <div style="font-size:14px;color:var(--g600);margin-bottom:6px">Belum ada produk dalam order</div>
      <div style="font-size:12px;color:var(--g400);margin-bottom:14px">Klik <strong>+ Tambah Produk</strong> di atas untuk mulai membangun PO restock.</div>
      <button onclick="_rstOpenAddPicker()" style="padding:8px 16px;background:#3C3489;color:white;border:none;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600">+ Tambah Produk</button>
    </div>`;
    _rstUpdateSummaryBar();
    return;
  }

  // Sort added products: urgent (most restock-needed) first
  added.sort((a,b) => {
    if (a.restockCount > 0 && b.restockCount === 0) return -1;
    if (a.restockCount === 0 && b.restockCount > 0) return  1;
    if (a.minDays !== null && b.minDays !== null) return a.minDays - b.minDays;
    return a.name.localeCompare(b.name);
  });

  container.innerHTML = added.map(p => _rstRenderProductCard(p)).join('');
  _rstUpdateSummaryBar();
}

function _rstUpdateSummaryBar() {
  const bar = document.getElementById('rst-summary-bar');
  if (!bar) return;
  const prodCount = _rstAddedProducts.size;
  if (prodCount === 0) {
    bar.textContent = '— belum ada produk dalam order';
    return;
  }
  const skuCount = _rstSelectedItems.size;
  bar.textContent = `${prodCount} produk · ${skuCount} SKU dipilih`;
}

function _rstRenderProductCard(p) {
  const pKey = btoa(unescape(encodeURIComponent(p.name))).replace(/[^a-zA-Z0-9]/g,'');
  const safeParentName = p.name.replace(/'/g,"\\'").replace(/"/g,'&quot;');

  // ── Header ──
  let urgBadge = '';
  if (p.minDays !== null && p.minDays < RESTOCK_LEAD_DAYS) {
    const clr = p.minDays<7 ? '#c0392b' : p.minDays<14 ? '#e65100' : '#b8860b';
    const bg  = p.minDays<7 ? '#fdf0f0' : p.minDays<14 ? '#fff3e0' : '#fffde7';
    const bdr = p.minDays<7 ? '#e8b8b8' : p.minDays<14 ? '#ffb74d' : '#ffe082';
    urgBadge  = `<span style="font-size:10px;background:${bg};color:${clr};border:1px solid ${bdr};border-radius:3px;padding:2px 6px;font-family:var(--mono)">⚠ ${Math.floor(p.minDays)}d</span>`;
  }
  // Show as many photos as Jubelio gave us (max 2), but skip size-chart
  // templates so the builder shows real product photography only.
  const cardImgsRaw = (Array.isArray(p.imageUrls) && p.imageUrls.length)
    ? p.imageUrls
    : (p.thumbnail ? [p.thumbnail] : []);
  const cardImgs = cardImgsRaw.filter(u => u && !_rstIsSizeChartUrl(u)).slice(0, 2);
  const thumb = cardImgs.length
    ? `<div style="display:flex;flex-direction:column;gap:4px;flex-shrink:0">${cardImgs.map(u => `<img src="${u.replace(/"/g,'&quot;')}" style="width:56px;height:56px;object-fit:cover;border-radius:4px;border:1px solid var(--g100);display:block" onerror="this.style.display='none'">`).join('')}</div>`
    : `<div style="width:56px;height:56px;background:var(--g100);border-radius:4px;flex-shrink:0"></div>`;

  // ── Parent-level Vendor + Harga Beli ──
  const defaultVm = _rstParentDefaultVendor(p);
  const currentVm = (p.name in _rstParentVendorMap) ? _rstParentVendorMap[p.name] : (defaultVm || '');
  // Persist the inferred default to map so collect() can read it without recomputing
  if (!(p.name in _rstParentVendorMap) && defaultVm) _rstParentVendorMap[p.name] = defaultVm;
  const vendorOpts = _rstAllVendors.map(x =>
    `<option value="${x.id}"${currentVm===x.id?' selected':''}>${x.name.replace(/</g,'&lt;')}</option>`).join('');
  // Find the most recent last-PO date across variants — used in the hint
  const lastPOs = p.variants.map(v => _rstLastPOByItem[v.itemId]).filter(Boolean);
  const lastPOHint = lastPOs.length
    ? (() => {
        const newest = lastPOs.sort((a,b) => (b.date||'').localeCompare(a.date||''))[0];
        return `<span style="font-size:10px;color:var(--g400)" title="${(newest.supplier_name||'').replace(/"/g,'&quot;')} (${(newest.date||'').slice(0,10)})">📋 PO terakhir: ${(newest.supplier_name||'').replace(/</g,'&lt;')}</span>`;
      })()
    : '';
  const currentPrice = _rstParentPriceMap[p.name] != null ? _rstParentPriceMap[p.name] : '';

  // ── Transposed variant table: sizes as columns, metrics as rows ──
  const variants = p.variants;
  const totalStock = variants.reduce((s,v)=>s+(v.stock||0), 0);
  const totalSold  = variants.reduce((s,v)=>s+(v.qtySold||0), 0);

  // Initial total Order Qty across checked variants (manual override or suggest)
  let totalOrderQty = 0;
  for (const v of variants) {
    if (!_rstSelectedItems.has(v.itemId)) continue;
    const q = _rstQtyMap[v.itemId] != null ? _rstQtyMap[v.itemId] : (v.suggestedQty || 0);
    totalOrderQty += Number(q) || 0;
  }

  // Highlight color for the Sisa Hari indicator embedded in size header
  const _dClrFor = days => days===null ? null : days<7 ? '#c0392b' : days<14 ? '#e65100' : days<30 ? '#b8860b' : null;

  const sizeHead = variants.map(v => {
    const isSel = _rstSelectedItems.has(v.itemId);
    const dClr  = _dClrFor(v.daysOfStock);
    const daysHint = (v.daysOfStock !== null && dClr)
      ? `<div style="font-size:9px;font-family:var(--mono);color:${dClr};font-weight:600;margin-top:1px">${Math.floor(v.daysOfStock)}d</div>` : '';
    return `<th style="padding:5px 4px;text-align:center;background:${isSel?'#eaf3ff':'#fafafa'};border-bottom:1px solid var(--g100);font-size:11px;font-weight:700;color:var(--text)">${v.size.replace(/</g,'&lt;')}${daysHint}</th>`;
  }).join('');

  const checkRow = variants.map(v => {
    const chk = _rstSelectedItems.has(v.itemId);
    const safeItemName = (v.itemNameFull||'').replace(/"/g,'&quot;').replace(/'/g,'&#39;');
    return `<td style="padding:3px 4px;text-align:center;background:${chk?'#eaf3ff':''}">
      <input type="checkbox" class="rst-var-chk" data-item-id="${v.itemId}" data-item-code="${v.itemCode}" data-item-name="${safeItemName}" data-pkey="${pKey}" data-parent-name="${safeParentName}" ${chk?'checked':''} onchange="_rstToggleVariant(${v.itemId},this.checked)" style="cursor:pointer">
    </td>`;
  }).join('');

  const stockRow = variants.map(v => `<td style="padding:3px 4px;text-align:center;font-family:var(--mono);font-size:11px">${v.stock||0}</td>`).join('');
  const soldRow  = variants.map(v => `<td style="padding:3px 4px;text-align:center;font-family:var(--mono);font-size:11px;color:var(--g400)">${v.qtySold>0?v.qtySold:'—'}</td>`).join('');
  const qtyRow = variants.map(v => {
    const chk = _rstSelectedItems.has(v.itemId);
    const defaultQty = (_rstQtyMap[v.itemId] != null)
      ? _rstQtyMap[v.itemId]
      : (chk ? (v.suggestedQty || '') : '');
    return `<td style="padding:3px 4px;text-align:center;background:${chk?'#eaf3ff':''}">
      <input type="number" class="rst-qty-input" data-item-id="${v.itemId}" data-pkey="${pKey}" min="0" step="1" value="${defaultQty}" placeholder="0" oninput="_rstSetQty(${v.itemId},this.value);_rstRecalcCardTotal('${pKey}')" style="width:54px;text-align:center;font-size:11px;font-family:var(--mono);padding:3px 4px;border:1px solid var(--g200);border-radius:4px;background:white">
    </td>`;
  }).join('');

  const labelTd = 'padding:3px 8px;font-size:10px;color:var(--g600);text-transform:uppercase;letter-spacing:0.3px;font-weight:600;background:#fafafa;border-right:1px solid var(--g100);white-space:nowrap';
  const totLabelTd = 'padding:3px 8px;font-size:11px;color:var(--g400);text-align:right;border-left:1px solid var(--g100);background:#fafafa;font-weight:600;white-space:nowrap';

  return `<div class="rst-card" data-pkey="${pKey}" style="background:white;border:1px solid var(--g100);border-radius:8px;overflow:hidden;box-shadow:0 1px 2px rgba(0,0,0,0.03)">
    <div style="padding:10px 12px;display:flex;align-items:flex-start;gap:12px;background:var(--off);border-bottom:1px solid var(--g100)">
      ${thumb}
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:700;line-height:1.3">${p.name.replace(/</g,'&lt;')}</div>
        <div style="display:flex;gap:6px;align-items:center;margin-top:3px;flex-wrap:wrap">
          <span style="font-size:11px;color:var(--g600)">${p.brand}</span>
          ${p.ip ? `<span style="font-size:11px;color:var(--g300)">·</span><span style="font-size:11px;color:var(--g600)">${p.ip.replace(/</g,'&lt;')}</span>` : ''}
          ${urgBadge}
          ${p.restockCount>0
            ? `<span style="font-size:10px;color:var(--g400)">${p.restockCount} SKU perlu restock</span>`
            : `<span style="font-size:10px;color:#2d7a2d">✓ stok aman</span>`}
        </div>
        <!-- Parent-level Vendor + Harga Beli (more compact, inline) -->
        <div style="display:flex;gap:10px;align-items:center;margin-top:6px;flex-wrap:wrap">
          <select onchange="_rstSetParentVendor('${safeParentName}',this.value)" style="font-size:11px;padding:3px 6px;border:1px solid var(--g200);border-radius:4px;background:white;min-width:160px">
            <option value="">— Pilih vendor —</option>${vendorOpts}
          </select>
          <input type="number" min="0" step="1000" value="${currentPrice}" placeholder="Harga beli (Rp)" onchange="_rstSetParentPrice('${safeParentName}',this.value)" style="width:120px;text-align:right;font-size:11px;font-family:var(--mono);padding:3px 6px;border:1px solid var(--g200);border-radius:4px;background:white">
          ${lastPOHint}
        </div>
      </div>
      <div style="display:flex;flex-direction:column;gap:4px">
        <button onclick="_rstOpenMoveSku('${safeParentName}')" title="Pindahkan / salin SKU ini ke project restock lain" style="background:none;border:1px solid var(--g200);border-radius:4px;color:#3C3489;cursor:pointer;font-size:11px;padding:4px 8px;white-space:nowrap">↗ Pindah</button>
        <button onclick="_rstRemoveProduct('${safeParentName}')" style="background:none;border:1px solid var(--g200);border-radius:4px;color:#c0392b;cursor:pointer;font-size:11px;padding:4px 8px;white-space:nowrap">✕ Hapus</button>
      </div>
    </div>
    <div style="overflow-x:auto">
      <table style="width:100%;border-collapse:collapse;font-size:11px">
        <thead>
          <tr>
            <th style="padding:5px 8px;text-align:right;font-size:9px;color:var(--g400);text-transform:uppercase;letter-spacing:0.3px;font-weight:600;background:#fafafa;border-right:1px solid var(--g100)">Size →</th>
            ${sizeHead}
            <th style="${totLabelTd}">Total</th>
          </tr>
        </thead>
        <tbody>
          <tr><td style="${labelTd}">Pilih</td>${checkRow}<td style="${totLabelTd}" id="rst-total-chk-${pKey}">${variants.filter(v=>_rstSelectedItems.has(v.itemId)).length}/${variants.length}</td></tr>
          <tr><td style="${labelTd}">Stock</td>${stockRow}<td style="${totLabelTd}">${totalStock.toLocaleString('id-ID')}</td></tr>
          <tr><td style="${labelTd}">Sold</td>${soldRow}<td style="${totLabelTd}">${totalSold>0?totalSold.toLocaleString('id-ID'):'—'}</td></tr>
          <tr style="border-top:2px solid var(--g100)">
            <td style="${labelTd};background:#f0f7ff;color:var(--text)">Order</td>${qtyRow}
            <td style="${totLabelTd};background:#f0f7ff;color:var(--text);font-weight:700;font-size:12px" id="rst-total-qty-${pKey}">${totalOrderQty > 0 ? totalOrderQty.toLocaleString('id-ID') : '—'}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>`;
}

// Live-update the Total Order Qty + Total Selected count for a product card
function _rstRecalcCardTotal(pKey) {
  let totalQty = 0;
  let selectedCount = 0;
  let totalChks = 0;
  document.querySelectorAll(`.rst-var-chk[data-pkey="${pKey}"]`).forEach(chk => {
    totalChks++;
    if (chk.checked) selectedCount++;
  });
  document.querySelectorAll(`.rst-qty-input[data-pkey="${pKey}"]`).forEach(input => {
    const chk = document.querySelector(`.rst-var-chk[data-item-id="${input.dataset.itemId}"]`);
    if (chk?.checked) totalQty += parseFloat(input.value) || 0;
  });
  const qtyCell = document.getElementById(`rst-total-qty-${pKey}`);
  if (qtyCell) qtyCell.textContent = totalQty > 0 ? totalQty.toLocaleString('id-ID') : '—';
  const chkCell = document.getElementById(`rst-total-chk-${pKey}`);
  if (chkCell) chkCell.textContent = `${selectedCount}/${totalChks}`;
}

// ── Add/remove a product from the order ──
function _rstAddProduct(parentName) {
  if (!_rstData) return;
  const p = _rstData.products.find(pp => pp.name === parentName);
  if (!p) return;
  _rstAddedProducts.add(parentName);
  // Auto-check restock-needed variants with raw per-variant suggestion qty
  // (just enough to cover RESTOCK_TARGET days minus current stock — no roll
  // rounding, no proportional redistribution; user can adjust freely).
  for (const v of p.variants) {
    if (!(v.suggestedQty > 0)) continue;
    _rstSelectedItems.add(v.itemId);
    if (_rstQtyMap[v.itemId] == null) _rstQtyMap[v.itemId] = v.suggestedQty;
  }
  if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
  _rstRenderAddedProducts();
}

function _rstRemoveProduct(parentName) {
  if (!confirm(`Hapus produk "${parentName}" dari order? Qty/price/vendor yang sudah diisi akan hilang.`)) return;
  _rstAddedProducts.delete(parentName);
  delete _rstParentVendorMap[parentName];
  delete _rstParentPriceMap[parentName];
  if (_rstData) {
    const p = _rstData.products.find(pp => pp.name === parentName);
    if (p) {
      for (const v of p.variants) {
        _rstSelectedItems.delete(v.itemId);
        delete _rstQtyMap[v.itemId];
      }
    }
  }
  if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
  _rstRenderAddedProducts();
}

// ── Move/Copy a SKU (parent product) to another restock project ──
// Reads the LIVE builder state for this parent (selected variants + qty + vendor + price)
// then merges it into the target project's items[] and persists via Supabase.
// Mode 'move'  → removes the SKU from current builder + clears its qty/vendor/price.
// Mode 'copy'  → leaves the current builder untouched.
//
// Note: works even when the current project is unsaved (we don't touch current row in DB —
// the save handler will pick up the cleaned state on next Save).
async function _rstOpenMoveSku(parentName) {
  if (!_rstData) return;
  const p = _rstData.products.find(pp => pp.name === parentName);
  if (!p) { alert('Produk tidak ditemukan di data.'); return; }
  // Build candidate target list (other Draft/Active projects, exclude current)
  let projects = (_rpRows || []).filter(r => r.id !== _rpCurrentId && (r.status === 'Draft' || r.status === 'Active'));
  // Fallback: refresh _rpRows if empty
  if (!projects.length && (!_rpRows || !_rpRows.length)) {
    try {
      const {data} = await sb.from('restock_projects').select('*').order('date_created', {ascending:false});
      _rpRows = data || [];
      projects = _rpRows.filter(r => r.id !== _rpCurrentId && (r.status === 'Draft' || r.status === 'Active'));
    } catch(_) {}
  }
  // Count selected variants in current state for this parent
  const selVariants = p.variants.filter(v => _rstSelectedItems.has(v.itemId));
  const totalQty = selVariants.reduce((s,v) => s + (Number(_rstQtyMap[v.itemId])||0), 0);
  if (!selVariants.length || totalQty <= 0) {
    alert('⚠️ SKU ini belum ada variant yang dipilih + qty > 0. Centang + isi qty dulu sebelum pindah.');
    return;
  }
  // Build modal
  let modal = document.getElementById('rst-move-modal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'rst-move-modal';
    modal.style.cssText = 'display:flex;position:fixed;inset:0;background:rgba(0,0,0,0.4);z-index:8500;align-items:center;justify-content:center;padding:20px';
    document.body.appendChild(modal);
  }
  const projOpts = projects.length
    ? projects.map(r => `<option value="${r.id}">${(r.name||r.id).replace(/</g,'&lt;')} · ${r.status} · ${(r.items||[]).length} SKU</option>`).join('')
    : '<option value="">(Tidak ada project lain yang Draft/Active)</option>';
  modal.innerHTML = `<div style="background:white;border-radius:10px;max-width:480px;width:100%;box-shadow:0 12px 40px rgba(0,0,0,0.25)">
    <div style="padding:14px 18px;border-bottom:1px solid var(--g100);display:flex;justify-content:space-between;align-items:center">
      <div style="font-weight:700;font-size:14px">Pindahkan / Salin SKU</div>
      <button onclick="_rstCloseMoveSku()" style="background:none;border:none;font-size:18px;cursor:pointer;color:var(--g600);line-height:1">×</button>
    </div>
    <div style="padding:16px 18px;font-size:13px">
      <div style="margin-bottom:12px;padding:10px 12px;background:var(--off);border:1px solid var(--g100);border-radius:6px">
        <div style="font-weight:700;font-size:13px">${p.name.replace(/</g,'&lt;')}</div>
        <div style="font-size:11px;color:var(--g600);margin-top:3px">${selVariants.length} variant · ${totalQty.toLocaleString('id-ID')} pcs total</div>
      </div>
      <label style="display:block;font-size:11px;color:var(--g600);text-transform:uppercase;letter-spacing:0.3px;font-weight:600;margin-bottom:4px">Target Project</label>
      <select id="rst-move-target" style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:6px;font-size:13px;margin-bottom:12px" ${projects.length?'':'disabled'}>${projOpts}</select>
      <label style="display:block;font-size:11px;color:var(--g600);text-transform:uppercase;letter-spacing:0.3px;font-weight:600;margin-bottom:4px">Aksi</label>
      <div style="display:flex;gap:14px;font-size:13px;margin-bottom:8px">
        <label style="display:flex;gap:6px;align-items:center;cursor:pointer">
          <input type="radio" name="rst-move-mode" value="move" checked> Pindahkan (hapus dari sini)
        </label>
        <label style="display:flex;gap:6px;align-items:center;cursor:pointer">
          <input type="radio" name="rst-move-mode" value="copy"> Salin (tetap di sini)
        </label>
      </div>
      <div style="font-size:11px;color:var(--g400);margin-bottom:14px">Variant + qty + vendor + harga ikut terbawa ke project target.${_rpCurrentId?'':' Project ini belum disimpan — perubahan di-builder saja, target tetap akan ter-update di DB.'}</div>
      <div style="display:flex;gap:8px;justify-content:flex-end">
        <button onclick="_rstCloseMoveSku()" style="padding:8px 14px;background:white;border:1px solid var(--g200);border-radius:6px;cursor:pointer;font-size:13px">Batal</button>
        <button onclick="_rstConfirmMoveSku('${(parentName||'').replace(/'/g,"\\'")}')" ${projects.length?'':'disabled'} style="padding:8px 14px;background:#3C3489;color:white;border:none;border-radius:6px;cursor:pointer;font-size:13px;font-weight:600;${projects.length?'':'opacity:0.4;cursor:not-allowed'}">Konfirmasi</button>
      </div>
    </div>
  </div>`;
  modal.style.display = 'flex';
}

function _rstCloseMoveSku() {
  const m = document.getElementById('rst-move-modal');
  if (m) m.style.display = 'none';
}

async function _rstConfirmMoveSku(parentName) {
  if (!_rstData) return;
  const p = _rstData.products.find(pp => pp.name === parentName);
  if (!p) { alert('Produk tidak ditemukan.'); return; }
  const targetId = document.getElementById('rst-move-target')?.value;
  if (!targetId) { alert('Pilih project target dulu.'); return; }
  const mode = (document.querySelector('input[name="rst-move-mode"]:checked')||{}).value || 'move';
  const target = _rpRows.find(r => r.id === targetId);
  if (!target) { alert('Project target tidak ditemukan.'); return; }
  // Build lines for selected variants of this parent from live builder state
  const vmId = _rstParentVendorMap[parentName] || null;
  const price = _rstParentPriceMap[parentName] != null ? Number(_rstParentPriceMap[parentName]) : null;
  const lines = [];
  for (const v of p.variants) {
    if (!_rstSelectedItems.has(v.itemId)) continue;
    const qty = Number(_rstQtyMap[v.itemId]) || 0;
    if (qty <= 0) continue;
    lines.push({
      item_id: v.itemId, item_code: v.sku, parent_name: p.name,
      brand: p.brand, ip: p.ip, collection: p.collection,
      size: v.size, thumbnail: v.thumbnail,
      vendor_master_id: vmId, qty_planned: qty, price_planned: price,
    });
  }
  if (!lines.length) { alert('⚠️ Tidak ada variant valid (semua qty 0).'); return; }
  // Merge into target.items — if same item_id already exists in target, replace with new line
  // (avoids double-counting + lets user override vendor/price by re-moving).
  const existing = Array.isArray(target.items) ? target.items.slice() : [];
  const newItemIds = new Set(lines.map(l => String(l.item_id)));
  const filtered = existing.filter(it => !newItemIds.has(String(it.item_id)));
  const mergedItems = filtered.concat(lines);
  try {
    const {error} = await sb.from('restock_projects').update({
      items: mergedItems,
      last_updated: new Date().toISOString(),
      last_updated_by: currentUser,
    }).eq('id', targetId);
    if (error) throw error;
    target.items = mergedItems; // update local cache
  } catch (e) {
    alert('❌ Gagal update project target: ' + (e.message||e));
    return;
  }
  // If mode = move, clear from current builder state
  if (mode === 'move') {
    _rstAddedProducts.delete(parentName);
    delete _rstParentVendorMap[parentName];
    delete _rstParentPriceMap[parentName];
    for (const v of p.variants) {
      _rstSelectedItems.delete(v.itemId);
      delete _rstQtyMap[v.itemId];
    }
    if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
    _rstRenderAddedProducts();
  }
  _rstCloseMoveSku();
  const verb = mode === 'move' ? 'Dipindahkan' : 'Disalin';
  _rpFlashMessage(`✓ ${verb} ke "${target.name||target.id}" · ${lines.length} variant`, 'ok');
  // If we moved, current builder must be persisted so the SKU removal sticks.
  // Auto-save current project if it exists (silently, no activate change).
  if (mode === 'move' && _rpCurrentId) {
    try {
      const itemsPayload = _rstCollectSelectedLines().map(l => ({
        item_id: l.itemId, item_code: l.sku, parent_name: l.parentName,
        brand: l.brand, ip: l.ip, collection: l.collection,
        size: l.size, thumbnail: l.thumbnail,
        vendor_master_id: l.vmId, qty_planned: l.qty, price_planned: l.price,
      }));
      await sb.from('restock_projects').update({
        items: itemsPayload,
        last_updated: new Date().toISOString(),
        last_updated_by: currentUser,
      }).eq('id', _rpCurrentId);
      _rpDirty = false;
    } catch (e) {
      console.warn('Auto-save current project after move failed:', e);
      // Non-fatal — user can save manually.
    }
  }
}

function _rstToggleVariant(itemId, checked) {
  if (checked) _rstSelectedItems.add(itemId);
  else         _rstSelectedItems.delete(itemId);
  if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
  // Visually highlight selected cells + recalc card totals + summary bar
  const chk = document.querySelector(`.rst-var-chk[data-item-id="${itemId}"]`);
  if (chk) {
    const pKey = chk.dataset.pkey;
    chk.parentElement.style.background = checked ? '#eaf3ff' : '';
    const qtyInput = document.querySelector(`.rst-qty-input[data-item-id="${itemId}"]`);
    if (qtyInput) {
      qtyInput.parentElement.style.background = checked ? '#eaf3ff' : '';
      // If checked and qty is empty, prefill with suggested qty (if any)
      if (checked && (!qtyInput.value || qtyInput.value === '0')) {
        if (_rstQtyMap[itemId] != null) qtyInput.value = _rstQtyMap[itemId];
      }
    }
    if (pKey) _rstRecalcCardTotal(pKey);
  }
  _rstUpdateSummaryBar();
}

function _rstSetQty(itemId, val) {
  const n = parseFloat(val);
  if (isNaN(n) || n <= 0) delete _rstQtyMap[itemId];
  else _rstQtyMap[itemId] = n;
  if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
}

// ── Add Product picker modal ──
function _rstOpenAddPicker() {
  if (!_rstData) {
    if (_rstLoading) {
      alert('Data masih dimuat — tunggu loading bar di tengah selesai (~15-30 detik), terus klik Tambah lagi.');
    } else {
      alert('Data belum dimuat. Cek tanggal periode di atas lalu refresh halaman.');
    }
    return;
  }
  document.getElementById('rst-add-modal').style.display = 'flex';
  document.getElementById('rst-add-search').value = '';
  _rstRenderAddPicker();
}
function _rstCloseAddPicker() {
  document.getElementById('rst-add-modal').style.display = 'none';
}

function _rstRenderAddPicker() {
  if (!_rstData) return;
  const listEl = document.getElementById('rst-add-list');
  const countEl = document.getElementById('rst-add-count');
  const q = (document.getElementById('rst-add-search')?.value || '').toLowerCase().trim();
  const brandFil = document.getElementById('rst-add-brand')?.value || '';
  const ipFil = document.getElementById('rst-add-ip')?.value || '';
  const urgentOnly = !!document.getElementById('rst-add-urgent-only')?.checked;

  let candidates = _rstData.products.slice();
  if (urgentOnly) candidates = candidates.filter(p => p.restockCount > 0);
  if (brandFil) candidates = candidates.filter(p => p.brand === brandFil);
  if (ipFil) candidates = candidates.filter(p => p.ip === ipFil);
  if (q) candidates = candidates.filter(p => p.name.toLowerCase().includes(q));

  // Already-added float to bottom (greyed); urgent floats to top
  candidates.sort((a,b) => {
    const aAdded = _rstAddedProducts.has(a.name) ? 1 : 0;
    const bAdded = _rstAddedProducts.has(b.name) ? 1 : 0;
    if (aAdded !== bAdded) return aAdded - bAdded;
    if (a.restockCount > 0 && b.restockCount === 0) return -1;
    if (a.restockCount === 0 && b.restockCount > 0) return  1;
    if (a.minDays !== null && b.minDays !== null) return a.minDays - b.minDays;
    return a.name.localeCompare(b.name);
  });

  countEl.textContent = candidates.length;

  if (!candidates.length) {
    listEl.innerHTML = `<div style="padding:32px;text-align:center;color:var(--g400);font-size:12px">Tidak ada match.</div>`;
    return;
  }

  listEl.innerHTML = candidates.slice(0, 200).map(p => {
    const added = _rstAddedProducts.has(p.name);
    const thumb = p.thumbnail
      ? `<img src="${p.thumbnail}" style="width:40px;height:40px;object-fit:cover;border-radius:3px;border:1px solid var(--g100);flex-shrink:0">`
      : `<div style="width:40px;height:40px;background:var(--g100);border-radius:3px;flex-shrink:0"></div>`;
    let urgBadge = '';
    if (p.minDays !== null && p.minDays < RESTOCK_LEAD_DAYS) {
      const clr = p.minDays<7 ? '#c0392b' : p.minDays<14 ? '#e65100' : '#b8860b';
      const bg  = p.minDays<7 ? '#fdf0f0' : p.minDays<14 ? '#fff3e0' : '#fffde7';
      urgBadge  = `<span style="font-size:9px;background:${bg};color:${clr};border-radius:3px;padding:1px 5px;font-family:var(--mono)">⚠ ${Math.floor(p.minDays)}d</span>`;
    }
    return `<div onclick="${added?'':`_rstAddFromPicker('${p.name.replace(/'/g,"\\'").replace(/"/g,'&quot;')}')`}" style="display:flex;align-items:center;gap:10px;padding:8px;border-radius:6px;cursor:${added?'default':'pointer'};margin-bottom:4px;opacity:${added?'0.5':'1'};background:${added?'#f6f6f6':'transparent'}" ${added?'':'onmouseover="this.style.background=\'var(--off)\'" onmouseout="this.style.background=\'transparent\'"'}>
      ${thumb}
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:600">${p.name.replace(/</g,'&lt;')}</div>
        <div style="display:flex;gap:6px;align-items:center;margin-top:2px;flex-wrap:wrap">
          <span style="font-size:10px;color:var(--g400)">${p.brand}</span>
          ${p.ip ? `<span style="font-size:10px;color:var(--g300)">·</span><span style="font-size:10px;color:var(--g400)">${p.ip.replace(/</g,'&lt;')}</span>` : ''}
          ${urgBadge}
          ${p.restockCount>0 ? `<span style="font-size:10px;color:var(--g400)">${p.restockCount} SKU urgent</span>` : ''}
        </div>
      </div>
      <div style="font-size:11px;color:${added?'#888':'#3C3489'};font-weight:600;white-space:nowrap">${added ? '✓ sudah ditambah' : '+ Tambah'}</div>
    </div>`;
  }).join('') + (candidates.length > 200 ? `<div style="padding:10px;text-align:center;color:var(--g400);font-size:11px">Menampilkan 200 dari ${candidates.length}. Pakai search/filter untuk persempit.</div>` : '');
}

function _rstAddFromPicker(name) {
  _rstAddProduct(name);
  _rstRenderAddPicker(); // update added state in modal
}

function generateRestockPO() {
  // legacy alias — old global Supplier+Generate button removed; route to Review
  _rstShowReview();
}

function _rstSetParentVendor(parentName, vmId) {
  if (vmId) _rstParentVendorMap[parentName] = vmId;
  else delete _rstParentVendorMap[parentName];
  if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
}

// Merge Vendor Master + Jubelio supplier list into one dropdown source.
// Each entry has a stable `id` — uses VM-id when linked to vendor_master,
// otherwise 'jub:<contact_id>' for Jubelio-only suppliers.
function _rstBuildAllVendors() {
  const out = [];
  const seenJubIds = new Set();
  const seenNames = new Set();
  // 1) Vendor Master entries (manual + Jubelio-linked)
  for (const v of allVMRows) {
    const name = vmSyncedField(v, 'name'); if (!name) continue;
    out.push({
      id: v.id, name, source: v.jubelioContactId ? 'both' : 'vm',
      vendorMasterId: v.id, jubelioContactId: v.jubelioContactId || null,
    });
    if (v.jubelioContactId) seenJubIds.add(v.jubelioContactId);
    seenNames.add(name.toLowerCase());
  }
  // 2) Jubelio suppliers not yet in Vendor Master
  for (const s of allJubSuppliers) {
    if (seenJubIds.has(s.contact_id)) continue;
    if (seenNames.has((s.contact_name||'').toLowerCase())) continue;
    out.push({
      id: `jub:${s.contact_id}`, name: s.contact_name || '(unnamed)', source: 'jub',
      vendorMasterId: null, jubelioContactId: s.contact_id,
    });
  }
  return out.sort((a,b) => a.name.localeCompare(b.name, 'id'));
}

// Resolve a vendor id (VM id OR 'jub:N') into a usable contact + defaults
// for CSV/PDF export. Falls back gracefully when only Jubelio data exists.
function _rstResolveVendor(vendorId) {
  if (!vendorId) return null;
  const v = _rstAllVendors.find(x => x.id === vendorId);
  if (!v) return null;
  const vm = v.vendorMasterId ? allVMRows.find(r => r.id === v.vendorMasterId) : null;
  const jub = v.jubelioContactId ? allJubSuppliers.find(s => s.contact_id === v.jubelioContactId) : null;
  // Prefer manual VM values, fall back to Jubelio mirror
  const pick = (vmField, jubField) => {
    const a = vm ? vmSyncedField(vm, vmField) : '';
    if (a) return a;
    return (jub && jubField) ? (jub[jubField] || '') : '';
  };
  return {
    name: (vm ? vmSyncedField(vm, 'name') : null) || (jub?.contact_name) || v.name,
    email: pick('email', 'email'),
    phone: pick('phone', 'phone') || (jub?.mobile || ''),
    defaultLocation: vm?.defaultLocation || 'Gudang Penerimaan Barang',
    defaultTax: vm?.defaultTax || 'No Tax',
    defaultTaxIncluded: vm?.defaultTaxIncluded === true,
    jubelioContactId: v.jubelioContactId,
    source: v.source,
  };
}

function _rstSetParentPrice(parentName, val) {
  const n = parseFloat(val);
  if (isNaN(n) || n <= 0) delete _rstParentPriceMap[parentName];
  else _rstParentPriceMap[parentName] = n;
  if (typeof _rpMarkDirty === 'function') _rpMarkDirty();
}

// Compute parent-level vendor default from variants' last PO history.
// Returns the most-frequently-seen supplier id (VM id or 'jub:N'), or null.
function _rstParentDefaultVendor(parentProduct) {
  if (!_rstAllVendors.length) return null;
  const byJubId = new Map(_rstAllVendors.filter(x=>x.jubelioContactId).map(x => [x.jubelioContactId, x.id]));
  const byName  = new Map(_rstAllVendors.map(x => [x.name.toLowerCase(), x.id]));
  const votes = {};
  for (const v of parentProduct.variants) {
    const lp = _rstLastPOByItem[v.itemId]; if (!lp) continue;
    const id = byJubId.get(lp.contact_id) || byName.get((lp.supplier_name||'').toLowerCase());
    if (id) votes[id] = (votes[id] || 0) + 1;
  }
  const sorted = Object.entries(votes).sort((a,b) => b[1] - a[1]);
  return sorted.length ? sorted[0][0] : null;
}

// ── Collect selected line items. Vendor + price live at parent level; qty per variant. ──
function _rstCollectSelectedLines() {
  const lines = [];
  document.querySelectorAll('.rst-var-chk:checked').forEach(chk => {
    // qty input now lives in a different cell — find by data-item-id rather than DOM walking
    const itemId = Number(chk.dataset.itemId);
    const qtyInput = document.querySelector(`.rst-qty-input[data-item-id="${itemId}"]`);
    const qty = parseFloat(qtyInput?.value) || 0;
    if (qty <= 0) return;
    const sku = chk.dataset.itemCode || '';
    const itemName = chk.dataset.itemName || '';
    const parentName = chk.dataset.parentName || '';
    const vmId = _rstParentVendorMap[parentName] || null;
    const price = _rstParentPriceMap[parentName] || 0;
    let brand = '', ip = '', collection = '', size = '?', thumbnail = null;
    if (_rstData) {
      const p = _rstData.products.find(pp => pp.name === parentName);
      if (p) {
        brand = p.brand; ip = p.ip||''; collection = p.collection||'';
        thumbnail = p.thumbnail || null;
        const v = p.variants.find(vv => vv.itemId === itemId);
        if (v) size = v.size;
      }
    }
    lines.push({ itemId, sku, itemName, qty, price, vmId, parentName, brand, ip, collection, size, thumbnail });
  });
  return lines;
}

// ── Group lines by vendor ──
function _rstGroupByVendor(lines) {
  const byVendor = new Map();
  const unassigned = [];
  for (const l of lines) {
    if (!l.vmId) { unassigned.push(l); continue; }
    if (!byVendor.has(l.vmId)) byVendor.set(l.vmId, []);
    byVendor.get(l.vmId).push(l);
  }
  return { byVendor, unassigned };
}

function _rstShowReview() {
  const lines = _rstCollectSelectedLines();
  if (!lines.length) { alert('Tidak ada item dipilih, atau semua qty = 0.'); return; }
  const {byVendor, unassigned} = _rstGroupByVendor(lines);
  const vmById = new Map(_rstAllVendors.map(v => [v.id, v]));

  const cont = document.getElementById('rst-summary-content');
  const totalQty = lines.reduce((s,l) => s+l.qty, 0);
  const totalNilai = lines.reduce((s,l) => s + l.qty*l.price, 0);
  const fmtRp = v => 'Rp ' + Math.round(v).toLocaleString('id-ID');

  let html = '';
  if (unassigned.length) {
    html += `<div style="background:#fff3e0;border:1px solid #ffb74d;border-radius:6px;padding:10px 14px;margin-bottom:12px;font-size:12px;color:#7a3d00">
      ⚠️ <strong>${unassigned.length} item belum punya vendor.</strong> Pilih vendor per row dulu sebelum export.
      <div style="font-size:11px;color:#7a3d00;margin-top:4px">${unassigned.slice(0,5).map(l => l.sku||l.parentName).join(', ')}${unassigned.length>5?` (+${unassigned.length-5} lagi)`:''}</div>
    </div>`;
  }

  // Per-vendor sections
  const vendorEntries = [...byVendor.entries()].map(([vmId, items]) => {
    const vm = vmById.get(vmId);
    return { vmId, vm, name: vm?.name || vmId, items };
  }).sort((a,b) => a.name.localeCompare(b.name, 'id'));

  for (const {vmId, vm, name, items} of vendorEntries) {
    const vQty = items.reduce((s,l) => s+l.qty, 0);
    const vNilai = items.reduce((s,l) => s+l.qty*l.price, 0);
    const safeName = name.replace(/'/g,"\\'").replace(/"/g,'&quot;');
    html += `<div style="background:var(--off);border:1px solid var(--g100);border-radius:8px;margin-bottom:12px;overflow:hidden">
      <div style="padding:10px 14px;background:white;display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;border-bottom:1px solid var(--g100)">
        <div style="flex:1;min-width:160px">
          <div style="font-weight:700;font-size:13px">${name.replace(/</g,'&lt;')}${vm?.jubelioContactId?' <span class="pill p-active" style="font-size:9px;margin-left:6px">🔗 Jubelio</span>':''}</div>
          <div style="font-size:11px;color:var(--g400);margin-top:2px">${items.length} SKU · ${vQty} unit${vNilai>0?` · ${fmtRp(vNilai)}`:''}</div>
        </div>
        <div style="display:flex;gap:6px">
          <button onclick="_rstExportCSVForVendor('${vmId}')" style="padding:6px 12px;background:#3C3489;color:white;border:none;border-radius:4px;cursor:pointer;font-size:11px;font-weight:600">⬇️ CSV (Jubelio)</button>
          <button onclick="_rstExportPDFForVendor('${vmId}')" style="padding:6px 12px;background:white;color:#3C3489;border:1px solid #3C3489;border-radius:4px;cursor:pointer;font-size:11px;font-weight:600">📄 PDF</button>
        </div>
      </div>
      <div style="padding:0 14px 10px">
        <table style="width:100%;font-size:11px;margin-top:6px">
          <thead><tr style="color:var(--g400);text-transform:uppercase;font-size:9px">
            <th style="text-align:left;padding:4px 4px">SKU</th>
            <th style="text-align:left;padding:4px 4px">Produk</th>
            <th style="padding:4px 4px">Size</th>
            <th style="text-align:right;padding:4px 4px">Qty</th>
            <th style="text-align:right;padding:4px 4px">Harga</th>
            <th style="text-align:right;padding:4px 4px">Subtotal</th>
          </tr></thead>
          <tbody>${items.map(l => `<tr style="border-top:1px solid var(--g100)">
            <td class="mono" style="padding:4px 4px;font-size:10px;color:var(--g600)">${(l.sku||'—').replace(/</g,'&lt;')}</td>
            <td style="padding:4px 4px;font-size:11px">${(l.parentName||l.itemName||'—').replace(/</g,'&lt;')}</td>
            <td style="padding:4px 4px;font-size:11px;text-align:center">${(l.size||'').replace(/</g,'&lt;')}</td>
            <td style="padding:4px 4px;text-align:right;font-family:var(--mono)">${l.qty}</td>
            <td style="padding:4px 4px;text-align:right;font-family:var(--mono);color:${l.price?'var(--text)':'#c0392b'}">${l.price?fmtRp(l.price):'—'}</td>
            <td style="padding:4px 4px;text-align:right;font-family:var(--mono);font-weight:600">${fmtRp(l.qty*l.price)}</td>
          </tr>`).join('')}</tbody>
        </table>
      </div>
    </div>`;
  }

  if (vendorEntries.length === 0 && unassigned.length === 0) {
    html += `<div style="padding:24px;text-align:center;color:var(--g400);font-size:13px">Belum ada item yang siap di-review.</div>`;
  }

  cont.innerHTML = html;
  document.getElementById('rst-summary-modal').style.display = 'flex';
  document.getElementById('rst-review-summary').textContent = `${lines.length} SKU · ${totalQty} unit${totalNilai>0?` · ${fmtRp(totalNilai)}`:''} · ${vendorEntries.length} vendor${unassigned.length?` · ${unassigned.length} unassigned`:''}`;
}

function _rstCloseSummary() {
  const modal = document.getElementById('rst-summary-modal');
  if (modal) modal.style.display = 'none';
}

// ── Per-vendor CSV export (Jubelio Purchase import format) ──
function _rstExportCSVForVendor(vmId) {
  _rstCloseSummary(); // close Review modal so user is back on builder after export
  const lines = _rstCollectSelectedLines().filter(l => l.vmId === vmId);
  if (!lines.length) { alert('Tidak ada item untuk vendor ini.'); return; }
  const res = _rstResolveVendor(vmId);
  if (!res) { alert('Vendor tidak ditemukan.'); return; }

  // ── Jubelio-import requires these exact constraints on the header row ──
  // Match Jubelio template: True/False mixed-case, phone digits-only, every
  // header field populated. We validate here so the user gets actionable
  // feedback instead of Jubelio bouncing the CSV on upload.
  const supplierName = (res.name || '').trim();
  // "angka tanpa spasi atau tanda hubung" — strip anything non-numeric
  const phone = String(res.phone || '').replace(/[^0-9]/g, '');
  const email = (res.email || '').trim();
  const defaultLoc = (res.defaultLocation || '').trim();
  // Match Jubelio reference exactly: "PPN" alone gets rejected; the registered
  // code in Jubelio is "PPN 11%" (sample row in template uses this). Map our
  // vendor master enum to what Jubelio's importer recognizes.
  let defaultTax = (res.defaultTax || 'No Tax').trim();
  if (defaultTax === 'PPN') defaultTax = 'PPN 11%';
  // Jubelio reference uses "True"/"False" (capitalised), not all-caps
  const taxIncl = res.defaultTaxIncluded ? 'True' : 'False';

  const missing = [];
  if (!supplierName) missing.push('Nama Pemasok');
  if (!phone)        missing.push('No Telp Pemasok (header wajib, format: angka tanpa spasi/dash)');
  if (!defaultLoc)   missing.push('Lokasi (set Default Lokasi di Vendor Master)');
  if (!defaultTax)   missing.push('Pajak (set Default Pajak di Vendor Master)');
  if (missing.length) {
    alert(`Vendor "${supplierName||vmId}" belum lengkap untuk Jubelio CSV:\n\n• ${missing.join('\n• ')}\n\nLengkapi di Database → Vendor Master, lalu coba lagi.`);
    return;
  }

  // Line-level validation
  const badLines = lines.filter(l => !l.sku || !(Number(l.price) > 0) || !(Number(l.qty) > 0));
  if (badLines.length) {
    const sample = badLines.slice(0,5).map(l => `• ${l.sku||'(no sku)'} — price ${l.price||0}, qty ${l.qty||0}`).join('\n');
    if (!confirm(`${badLines.length} baris belum lengkap (price atau qty = 0):\n\n${sample}${badLines.length>5?`\n...dan ${badLines.length-5} lainnya`:''}\n\nLanjutkan export? (baris kosong bakal di-reject Jubelio)`)) return;
  }

  // Match Jubelio importer rules (confirmed via reject messages):
  //   - Tanggal: bare 'YYYY-MM-DD'. Adding ' 00:00:00' is REJECTED with
  //     "Format tanggal tidak sesuai". Spec text is the source of truth
  //     here, not the time-bearing example row in the template sheet.
  //   - Pajak:   'PPN 11%' or 'No Tax' (registered tax codes)
  //   - No. Pesanan: explicit reference. Deterministic per (project,
  //     vendor) so re-exports collide on Jubelio's side — protects
  //     against accidental double-records when the user re-uploads.
  const todayDate = new Date().toISOString().slice(0, 10);
  const today     = todayDate;
  // Short, stable vendor code from supplier name (first 4 alphanumerics).
  const vendorCode = (supplierName.match(/[A-Za-z0-9]/g) || []).slice(0, 4).join('').toUpperCase() || 'VND';
  // Project tail: prefer the saved project's id ("RP-YYYYMMDD-NNNN" → keep
  // the date+seq part). When the project hasn't been saved yet, fall back to
  // today's date — at least same-day re-exports stay idempotent.
  const projectTail = (typeof _rpCurrentId === 'string' && _rpCurrentId)
    ? _rpCurrentId.replace(/^RP-/, '')
    : todayDate.replace(/-/g,'');
  const poRef = `RST-${projectTail}-${vendorCode}`;
  const esc = v => {
    const s = String(v ?? '');
    return (s.includes(',') || s.includes('"') || s.includes('\n'))
      ? '"' + s.replace(/"/g, '""') + '"' : s;
  };
  const COLS = ['No. Pesanan','No. Ref Pemasok','Tanggal','Zona Waktu','Nama Pemasok',
                'Email Pemasok','No Telp. Pemasok','Harga Termasuk Pajak','Lokasi',
                'Keterangan','SKU','Harga','Qty','Nilai Diskon','Pajak'];
  const note = `Restock ${todayDate}`;
  const csvRows = [COLS.join(',')];
  lines.forEach((it, i) => {
    const sku   = String(it.sku || '').trim();
    const price = Math.max(0, Math.round(Number(it.price) || 0));
    const qty   = Math.max(0, Math.round(Number(it.qty) || 0));
    if (i === 0) {
      csvRows.push([esc(poRef), '', esc(today), 'WIB', esc(supplierName),
        esc(email), esc(phone), taxIncl, esc(defaultLoc),
        esc(note), esc(sku), price, qty, 0, esc(defaultTax)].join(','));
    } else {
      // Continuation rows: header cells empty, only line cells filled
      csvRows.push(['', '', '', '', '', '', '', '', '', '',
        esc(sku), price, qty, 0, esc(defaultTax)].join(','));
    }
  });
  // Jubelio's importer reads plain UTF-8; the BOM occasionally confuses it
  // when the header row gets parsed literally. Skip the BOM and use \n line
  // endings (matches Excel's CSV export from the template sheet).
  const csv = csvRows.join('\n');
  const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const safeName = supplierName.replace(/[^a-zA-Z0-9._-]+/g,'_').slice(0,40);
  const filename = `PO-Restock-${safeName}-${todayDate}.csv`;
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  setTimeout(() => URL.revokeObjectURL(url), 200);
}

// Make sure product_dev rows are cached so _rstResolveParentPictures() can
// match parent names to PD photo arrays. Cheap no-op once loaded.
async function _rstEnsurePDLoaded() {
  if (Array.isArray(allPDRows) && allPDRows.length) return;
  if (typeof fetchPDRows === 'function') {
    try { await fetchPDRows(); } catch(_) {}
  }
}

// ── Per-vendor PDF export (window.print pattern, consistent with PD module) ──
async function _rstExportPDFForVendor(vmId) {
  _rstCloseSummary();
  const lines = _rstCollectSelectedLines().filter(l => l.vmId === vmId);
  if (!lines.length) { alert('Tidak ada item untuk vendor ini.'); return; }
  const res = _rstResolveVendor(vmId);
  if (!res) { alert('Vendor tidak ditemukan.'); return; }
  await _rstEnsurePDLoaded();
  const supplierName = res.name;
  const today = new Date().toLocaleDateString('id-ID',{day:'numeric',month:'long',year:'numeric'});
  _rstOpenPrintWindow(`PO Restock — ${supplierName}`, _rstBuildPDFBody(supplierName, {phone: res.phone, email: res.email}, lines, today));
}

// ── Combined "PDF All" — flat table with Vendor column ──
async function _rstExportPDFAll() {
  _rstCloseSummary();
  const lines = _rstCollectSelectedLines();
  if (!lines.length) { alert('Tidak ada item dipilih.'); return; }
  await _rstEnsurePDLoaded();
  const vmById = new Map(_rstAllVendors.map(v => [v.id, v]));
  const enriched = lines.map(l => ({
    ...l,
    vendorName: l.vmId ? (vmById.get(l.vmId)?.name || l.vmId) : '— belum di-assign —',
  }));
  const today = new Date().toLocaleDateString('id-ID',{day:'numeric',month:'long',year:'numeric'});
  _rstOpenPrintWindow(`PO Restock — All Vendors`, _rstBuildPDFAllBody(enriched, today));
}

function _rstOpenPrintWindow(title, bodyHtml) {
  const w = window.open('', '_blank');
  if (!w) { alert('Pop-up diblokir. Izinkan pop-up untuk export PDF.'); return; }
  w.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>${title.replace(/</g,'&lt;')}</title>
    <style>
      body{font-family:Arial,Helvetica,sans-serif;color:#222;padding:24px;max-width:1100px;margin:0 auto}
      h1{font-size:20px;margin:0 0 4px;font-weight:700}
      .sub{font-size:11px;color:#888;margin-bottom:18px}
      .meta{font-size:12px;margin-bottom:16px;display:grid;grid-template-columns:auto 1fr;gap:4px 16px}
      .meta dt{font-weight:600;color:#666}
      table{width:100%;border-collapse:collapse;font-size:11px;margin-top:10px}
      thead th{background:#f2f2f2;padding:6px 8px;text-align:left;border-bottom:1px solid #999;font-size:10px;text-transform:uppercase;letter-spacing:0.3px}
      tbody td{padding:6px 8px;border-bottom:1px solid #eee;vertical-align:middle}
      .mono{font-family:'Courier New',monospace}
      .num{text-align:right;font-family:'Courier New',monospace;white-space:nowrap}
      .total{font-weight:700;background:#f9f9f9}
      .thumb{width:54px;height:54px;object-fit:cover;border:1px solid #ddd;border-radius:4px}
      .thumb-empty{width:54px;height:54px;background:#eee;border-radius:4px;display:inline-block}
      .footer{margin-top:24px;font-size:10px;color:#888;text-align:right}
      @media print{ body{padding:12px} .thumb{print-color-adjust:exact;-webkit-print-color-adjust:exact} }
    </style></head><body>${bodyHtml}
    <div class="footer">Generated ${new Date().toLocaleString('id-ID')} · Sentra Portal</div>
    </body></html>`);
  w.document.close();
  // Wait for images to load before printing, with a 4s cap
  w.addEventListener('load', () => {
    const imgs = Array.from(w.document.images || []);
    let pending = imgs.length;
    const done = () => setTimeout(()=>w.print(), 200);
    if (!pending) return done();
    const tick = () => { pending--; if (pending<=0) done(); };
    imgs.forEach(img => {
      if (img.complete) tick();
      else { img.addEventListener('load', tick); img.addEventListener('error', tick); }
    });
    setTimeout(() => done(), 4000); // hard cap
  });
}

// Group lines by parent product for image-friendly PDFs. Uses rowspan to show
// each product thumbnail once across its variant rows.
// Apparel sizing convention — smallest first, OS at the end. Used to sort
// variant rows inside each parent group in the vendor PDFs.
const _RST_SIZE_ORDER = ['XS','S','M','L','XL','XXL','XXXL','4XL','5XL','OS'];

function _rstGroupByParentForPDF(lines) {
  const map = new Map();
  for (const l of lines) {
    if (!map.has(l.parentName)) map.set(l.parentName, { thumbnail: l.thumbnail, parentName: l.parentName, brand: l.brand, ip: l.ip, vendorName: l.vendorName, items: [] });
    map.get(l.parentName).items.push(l);
  }
  // Sort items inside each parent by apparel-size order (S→M→L→XL…), SKU tiebreak.
  for (const g of map.values()) g.items.sort((a, b) => {
    const ai = _RST_SIZE_ORDER.indexOf((a.size||'').trim().toUpperCase());
    const bi = _RST_SIZE_ORDER.indexOf((b.size||'').trim().toUpperCase());
    const ax = ai < 0 ? _RST_SIZE_ORDER.length : ai;
    const bx = bi < 0 ? _RST_SIZE_ORDER.length : bi;
    if (ax !== bx) return ax - bx;
    return (a.sku||'').localeCompare(b.sku||'');
  });
  // Enrich with up to 2 photos
  const groups = [...map.values()];
  for (const g of groups) {
    g.pictures = _rstResolveParentPictures(g.parentName);
  }
  return groups;
}

// Heuristic: skip Jubelio image URLs that look like size-chart / size-guide
// templates. SDY's template images use the "*_final_fix*" / "*fix_2025*"
// pattern; other brands sometimes name files with "size-chart" or "chart"
// directly. False positives are rare; if a real photo gets dropped, add a
// stricter pattern here.
function _rstIsSizeChartUrl(url) {
  if (!url) return false;
  const u = String(url).toLowerCase();
  return /size[-_]?chart/.test(u)
      || /sizechart/.test(u)
      || /size[-_]?guide/.test(u)
      || /measurement/.test(u)
      || /final[-_]fix/.test(u)   // SDY template overlay
      || /fix[-_]?2025/.test(u);  // SDY 2025 template
}

// Map a restock parent name to up to 2 photos (front + back). Priority:
//   1. product_dev.picture_urls (manually uploaded)
//   2. jubelio_items.image_urls (auto-pulled by sync-jubelio-item-thumbnails)
// Falls back silently to [] when neither has them — caller will render the
// 'Belum ada foto...' placeholder.
function _rstResolveParentPictures(parentName) {
  const pics = [];
  if (!parentName) return pics;
  const want = parentName.trim().toLowerCase();
  const push = (u) => {
    if (!u) return;
    if (_rstIsSizeChartUrl(u)) return;   // never let template/size-chart slip into vendor PDFs
    if (pics.includes(u)) return;
    if (pics.length < 2) pics.push(u);
  };
  // 1. Product Dev manual uploads (preferred — usually better staged photography)
  if (Array.isArray(allPDRows)) {
    const parent = allPDRows.find(r => !r.parentId && (r.skuName||'').trim().toLowerCase() === want);
    if (parent && Array.isArray(parent.pictures)) parent.pictures.forEach(push);
  }
  if (pics.length >= 2) return pics;
  // 2. Jubelio group-level images
  if (_rstData?.products) {
    const p = _rstData.products.find(x => (x.name||'').trim().toLowerCase() === want);
    if (p && Array.isArray(p.imageUrls)) p.imageUrls.forEach(push);
  }
  return pics;
}

function _rstBuildPDFBody(supplierName, contact, lines, today) {
  const totalQty = lines.reduce((s,l) => s+l.qty, 0);
  const totalNilai = lines.reduce((s,l) => s+l.qty*l.price, 0);
  const fmt = v => 'Rp ' + Math.round(v).toLocaleString('id-ID');
  const groups = _rstGroupByParentForPDF(lines);

  // Render whatever photos Jubelio gave us (max 2). No 'Depan/Belakang'
  // labels — slot 2 is sometimes a size chart or detail shot, not the
  // actual back design. No placeholder for missing slot 2 either.
  const photoCell = (pics, thumb, span) => {
    const imgs = (pics && pics.length) ? pics : (thumb ? [thumb] : []);
    if (!imgs.length) return `<td rowspan="${span}" style="text-align:center;width:300px;padding:8px">
      <span class="slot-label">No photo</span>
    </td>`;
    return `<td rowspan="${span}" style="text-align:center;width:300px;padding:8px">
      <div class="photo-grid">
        ${imgs.map(u => `<img class="photo" src="${u.replace(/"/g,'&quot;')}" onerror="this.style.display='none'">`).join('')}
      </div>
    </td>`;
  };
  const rowsHtml = groups.flatMap(g => {
    const span = g.items.length;
    return g.items.map((l, idx) => `<tr>
      ${idx === 0 ? photoCell(g.pictures, g.thumbnail, span) : ''}
      <td>${(l.parentName||l.itemName||'—').replace(/</g,'&lt;')}${idx===0 && l.brand ? `<div style="font-size:9px;color:#888;margin-top:2px">${l.brand}${l.ip?' · '+l.ip:''}</div>` : ''}</td>
      <td>${(l.size||'').replace(/</g,'&lt;')}</td>
      <td class="num">${l.qty}</td>
      <td class="num">${l.price?fmt(l.price):'—'}</td>
      <td class="num">${fmt(l.qty*l.price)}</td>
    </tr>`);
  }).join('');

  return `
    <style>
      .photo-grid{display:flex;gap:6px;justify-content:center;align-items:center;flex-wrap:wrap}
      .photo{width:140px;height:140px;object-fit:cover;border:1px solid #ddd;border-radius:6px;display:block}
      .slot-label{display:inline-flex;align-items:center;justify-content:center;width:140px;height:140px;background:#f5f5f5;border:1px dashed #ccc;border-radius:6px;color:#aaa;font-size:10px}
      tbody tr{page-break-inside:avoid}
    </style>
    <h1>Purchase Order — Restock</h1>
    <div class="sub">${today}</div>
    <dl class="meta">
      <dt>Pemasok</dt><dd>${supplierName.replace(/</g,'&lt;')}</dd>
      ${contact.phone?`<dt>Telp</dt><dd>${contact.phone.replace(/</g,'&lt;')}</dd>`:''}
      ${contact.email?`<dt>Email</dt><dd>${contact.email.replace(/</g,'&lt;')}</dd>`:''}
      <dt>Tanggal</dt><dd>${today}</dd>
      <dt>Total Item</dt><dd>${lines.length} SKU · ${totalQty} unit</dd>
    </dl>
    <table>
      <thead><tr><th style="width:300px">Foto</th><th>Produk</th><th>Size</th><th class="num">Qty</th><th class="num">Harga</th><th class="num">Subtotal</th></tr></thead>
      <tbody>
        ${rowsHtml}
        <tr class="total"><td colspan="3">TOTAL</td><td class="num">${totalQty}</td><td></td><td class="num">${fmt(totalNilai)}</td></tr>
      </tbody>
    </table>`;
}

function _rstBuildPDFAllBody(lines, today) {
  const totalQty = lines.reduce((s,l) => s+l.qty, 0);
  const totalNilai = lines.reduce((s,l) => s+l.qty*l.price, 0);
  const fmt = v => 'Rp ' + Math.round(v).toLocaleString('id-ID');
  // Sort by vendor then parent (preserve grouping for nicer rowspan)
  // Sort by vendor → parent → size (apparel order), SKU as last tiebreak.
  const sorted = lines.slice().sort((a, b) => {
    const v = (a.vendorName||'').localeCompare(b.vendorName||'', 'id'); if (v) return v;
    const p = (a.parentName||'').localeCompare(b.parentName||'', 'id'); if (p) return p;
    const ai = _RST_SIZE_ORDER.indexOf((a.size||'').trim().toUpperCase());
    const bi = _RST_SIZE_ORDER.indexOf((b.size||'').trim().toUpperCase());
    const ax = ai < 0 ? _RST_SIZE_ORDER.length : ai;
    const bx = bi < 0 ? _RST_SIZE_ORDER.length : bi;
    if (ax !== bx) return ax - bx;
    return (a.sku||'').localeCompare(b.sku||'');
  });
  // Group by parentName preserving sort
  const groups = [];
  let cur = null;
  for (const l of sorted) {
    if (!cur || cur.parentName !== l.parentName || cur.vendorName !== l.vendorName) {
      cur = { thumbnail: l.thumbnail, parentName: l.parentName, brand: l.brand, ip: l.ip, vendorName: l.vendorName, items: [] };
      groups.push(cur);
    }
    cur.items.push(l);
  }
  // Attach photos per group + render whatever's available (no labels,
  // no placeholder for missing slot 2 — slot 2 isn't reliably back).
  for (const g of groups) g.pictures = _rstResolveParentPictures(g.parentName);
  const photoCell = (pics, thumb, span) => {
    const imgs = (pics && pics.length) ? pics : (thumb ? [thumb] : []);
    if (!imgs.length) return `<td rowspan="${span}" style="text-align:center;width:300px;padding:8px">
      <span class="slot-label">No photo</span>
    </td>`;
    return `<td rowspan="${span}" style="text-align:center;width:300px;padding:8px">
      <div class="photo-grid">
        ${imgs.map(u => `<img class="photo" src="${u.replace(/"/g,'&quot;')}" onerror="this.style.display='none'">`).join('')}
      </div>
    </td>`;
  };
  const rowsHtml = groups.flatMap(g => {
    const span = g.items.length;
    return g.items.map((l, idx) => `<tr>
      ${idx === 0 ? photoCell(g.pictures, g.thumbnail, span) : ''}
      ${idx === 0 ? `<td rowspan="${span}">${(l.vendorName||'—').replace(/</g,'&lt;')}</td>` : ''}
      <td>${(l.parentName||l.itemName||'—').replace(/</g,'&lt;')}${idx===0 && l.brand ? `<div style="font-size:9px;color:#888;margin-top:2px">${l.brand}${l.ip?' · '+l.ip:''}</div>` : ''}</td>
      <td>${(l.size||'').replace(/</g,'&lt;')}</td>
      <td class="num">${l.qty}</td>
      <td class="num">${l.price?fmt(l.price):'—'}</td>
      <td class="num">${fmt(l.qty*l.price)}</td>
    </tr>`);
  }).join('');
  return `
    <style>
      .photo-grid{display:flex;gap:6px;justify-content:center;align-items:center;flex-wrap:wrap}
      .photo{width:140px;height:140px;object-fit:cover;border:1px solid #ddd;border-radius:6px;display:block}
      .slot-label{display:inline-flex;align-items:center;justify-content:center;width:140px;height:140px;background:#f5f5f5;border:1px dashed #ccc;border-radius:6px;color:#aaa;font-size:10px}
      tbody tr{page-break-inside:avoid}
    </style>
    <h1>Purchase Order — Restock (All Vendors)</h1>
    <div class="sub">${today} · ${lines.length} SKU · ${totalQty} unit · ${fmt(totalNilai)}</div>
    <table>
      <thead><tr><th style="width:300px">Foto</th><th>Vendor</th><th>Produk</th><th>Size</th><th class="num">Qty</th><th class="num">Harga</th><th class="num">Subtotal</th></tr></thead>
      <tbody>
        ${rowsHtml}
        <tr class="total"><td colspan="4">TOTAL</td><td class="num">${totalQty}</td><td></td><td class="num">${fmt(totalNilai)}</td></tr>
      </tbody>
    </table>`;
}

// ── MARTE SKU CATEGORIES ──
const MSC_CATS = ['Apparel','Accessories','Collectible','Wellness','Preloved','Others'];
let _mscAllRows  = [];    // raw rows from RPC
let _mscFiltered = [];    // rows after filter
let _mscPending  = {};    // {item_code: new_category} — unsaved changes

async function loadMarteSKUCat() {
  const wrap = document.getElementById('msc-brand-groups');
  const empty = document.getElementById('msc-empty');
  if (!wrap) return;
  wrap.innerHTML = '<div style="padding:40px;text-align:center;color:var(--g400)">Memuat data…</div>';
  empty.style.display = 'none';
  _mscPending = {};
  _mscUpdatePendingBadge();

  // Page the RPC response — PostgREST caps each response at 1000 rows.
  _mscAllRows = [];
  { const PAGE = 1000; let _from = 0;
    while (true) {
      const { data, error } = await sb.rpc('get_marte_sku_mapping').range(_from, _from + PAGE - 1);
      if (error) {
        wrap.innerHTML = `<div style="padding:40px;text-align:center;color:var(--red)">Error: ${error.message}</div>`;
        return;
      }
      _mscAllRows = _mscAllRows.concat(data || []);
      if (!data || data.length < PAGE) break;
      _from += PAGE;
    }
  }

  // Populate brand dropdown
  const brands = [...new Set(_mscAllRows.map(r => r.brand))].sort((a,b)=>a.localeCompare(b,'id'));
  const sel = document.getElementById('msc-filter-brand');
  const curVal = sel.value;
  sel.innerHTML = '<option value="">Semua Brand</option>';
  brands.forEach(b => {
    const o = document.createElement('option');
    o.value = b; o.textContent = b;
    if (b === curVal) o.selected = true;
    sel.appendChild(o);
  });

  _mscRenderStats();
  _mscApplyFilter();
}

function _mscRenderStats() {
  const el = document.getElementById('msc-stats');
  if (!el) return;
  const total = _mscAllRows.length;
  const uncat = _mscAllRows.filter(r => !r.fee_category).length;
  const catCount = total - uncat;
  const byBrand = {};
  _mscAllRows.forEach(r => {
    if (!byBrand[r.brand]) byBrand[r.brand] = {total:0,uncat:0};
    byBrand[r.brand].total++;
    if (!r.fee_category) byBrand[r.brand].uncat++;
  });
  const uncatBrands = Object.entries(byBrand).filter(([,v])=>v.uncat>0).length;

  el.innerHTML = `
    <div class="stat-card"><div class="sc-val">${total}</div><div class="sc-lbl">Total SKU</div></div>
    <div class="stat-card"><div class="sc-val" style="color:var(--green)">${catCount}</div><div class="sc-lbl">Terkategorikan</div></div>
    <div class="stat-card"><div class="sc-val" style="color:var(--amber,#f59e0b)">${uncat}</div><div class="sc-lbl">Belum Kategori</div></div>
    <div class="stat-card"><div class="sc-val" style="color:var(--amber,#f59e0b)">${uncatBrands}</div><div class="sc-lbl">Brand dgn gap</div></div>
  `;
}

function _mscApplyFilter() {
  const brand = document.getElementById('msc-filter-brand').value;
  const uncatOnly = document.getElementById('msc-filter-uncat').checked;
  _mscFiltered = _mscAllRows.filter(r => {
    if (brand && r.brand !== brand) return false;
    if (uncatOnly && r.fee_category) return false;
    return true;
  });
  _mscRenderGroups();
}

function _mscRenderGroups() {
  const wrap = document.getElementById('msc-brand-groups');
  const empty = document.getElementById('msc-empty');
  if (!wrap) return;

  if (_mscFiltered.length === 0) {
    wrap.innerHTML = '';
    empty.style.display = 'block';
    return;
  }
  empty.style.display = 'none';

  // Group by brand
  const groups = {};
  _mscFiltered.forEach(r => {
    if (!groups[r.brand]) groups[r.brand] = [];
    groups[r.brand].push(r);
  });

  let html = '';
  Object.keys(groups).sort((a,b)=>a.localeCompare(b,'id')).forEach(brand => {
    const rows = groups[brand];
    const uncatCount = rows.filter(r => !r.fee_category && !_mscPending[r.item_code]).length;
    const catOptions = MSC_CATS.map(c=>`<option value="${c}">${c}</option>`).join('');
    const safeB = brand.replace(/'/g,"\\'");

    html += `
      <div class="msc-brand-block" id="msc-block-${_mscSafeId(brand)}" style="margin-bottom:24px">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px;padding:8px 10px;background:var(--g50,#f8f9fa);border-radius:8px;flex-wrap:wrap">
          <div style="font-family:var(--syne);font-weight:600;font-size:14px;flex:1;min-width:120px">${brand}</div>
          <div style="font-size:12px;color:var(--g400)">${rows.length} SKU${uncatCount>0?` · <span style="color:var(--amber,#f59e0b)">${uncatCount} belum</span>`:' · ✅ semua terkategori'}</div>
          <div style="display:flex;align-items:center;gap:6px">
            <span style="font-size:12px;color:var(--g500)">Set semua ke:</span>
            <select id="msc-bulk-${_mscSafeId(brand)}" style="padding:4px 8px;font-size:12px;border:1px solid var(--g200);border-radius:6px">
              <option value="">— Pilih —</option>
              ${catOptions}
            </select>
            <button onclick="_mscBulkApply('${safeB}', false)" title="Hanya terapkan ke item yang belum punya kategori" style="padding:4px 10px;font-size:12px;background:var(--g100);border:1px solid var(--g200);border-radius:6px;cursor:pointer">Yg Belum</button>
            <button onclick="_mscBulkApply('${safeB}', true)" title="Terapkan ke semua item brand ini" style="padding:4px 10px;font-size:12px;background:var(--primary);color:#fff;border:none;border-radius:6px;cursor:pointer">Semua</button>
          </div>
        </div>
        <table style="width:100%;border-collapse:collapse;font-size:13px">
          <thead>
            <tr style="border-bottom:2px solid var(--g100)">
              <th style="text-align:left;padding:6px 8px;color:var(--g400);font-weight:500;width:180px">Item Code</th>
              <th style="text-align:left;padding:6px 8px;color:var(--g400);font-weight:500">Nama Item</th>
              <th style="text-align:center;padding:6px 8px;color:var(--g400);font-weight:500;width:140px">Kategori Saat Ini</th>
              <th style="text-align:center;padding:6px 8px;color:var(--g400);font-weight:500;width:160px">Set Kategori</th>
            </tr>
          </thead>
          <tbody id="msc-tbody-${_mscSafeId(brand)}">
            ${rows.map(r => _mscItemRow(r)).join('')}
          </tbody>
        </table>
      </div>
    `;
  });
  wrap.innerHTML = html;
}

function _mscSafeId(brand) {
  return brand.replace(/[^a-zA-Z0-9]/g,'_');
}

function _mscItemRow(r) {
  const curCat = r.fee_category || '';
  const pending = _mscPending[r.item_code];
  const displayCat = pending !== undefined ? pending : curCat;
  const isChanged = pending !== undefined && pending !== curCat;

  const catPill = curCat
    ? `<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;background:var(--g100);color:var(--g600)">${curCat}</span>`
    : `<span style="display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;background:#fef3c7;color:#92400e">Belum</span>`;

  const catOpts = `<option value="">— Pilih —</option>`
    + MSC_CATS.map(c=>`<option value="${c}"${displayCat===c?' selected':''}>${c}</option>`).join('');

  const rowStyle = isChanged ? 'background:#fffbeb' : '';

  return `<tr style="border-bottom:1px solid var(--g50,#f8f9fa);${rowStyle}" id="msc-row-${r.item_code.replace(/[^a-zA-Z0-9]/g,'_')}">
    <td style="padding:6px 8px;font-family:var(--mono,monospace);font-size:11px;color:var(--g500)">${r.item_code}</td>
    <td style="padding:6px 8px">${r.item_name || '—'}</td>
    <td style="padding:6px 8px;text-align:center">${catPill}</td>
    <td style="padding:6px 8px;text-align:center">
      <select style="padding:4px 8px;font-size:12px;border:1px solid ${isChanged?'var(--amber,#f59e0b)':'var(--g200)'};border-radius:6px;width:140px"
              onchange="_mscSetPending('${r.item_code.replace(/'/g,"\\'")}', this.value)">${catOpts}</select>
    </td>
  </tr>`;
}

function _mscSetPending(itemCode, val) {
  const original = (_mscAllRows.find(r=>r.item_code===itemCode)||{}).fee_category || '';
  if (val === original) {
    delete _mscPending[itemCode];
  } else {
    _mscPending[itemCode] = val;
  }
  _mscUpdatePendingBadge();
  // highlight row
  const rowId = 'msc-row-'+itemCode.replace(/[^a-zA-Z0-9]/g,'_');
  const row = document.getElementById(rowId);
  if (row) {
    const isChanged = _mscPending[itemCode] !== undefined;
    row.style.background = isChanged ? '#fffbeb' : '';
    const sel = row.querySelector('select');
    if (sel) sel.style.borderColor = isChanged ? 'var(--amber,#f59e0b)' : 'var(--g200)';
  }
}

function _mscBulkApply(brand, applyAll) {
  const selEl = document.getElementById('msc-bulk-'+_mscSafeId(brand));
  if (!selEl || !selEl.value) { alert('Pilih kategori dulu.'); return; }
  const cat = selEl.value;
  const rows = _mscAllRows.filter(r => r.brand === brand);
  rows.forEach(r => {
    // "Unset" button (applyAll=false) → only apply to currently uncategorized
    // "Semua" button (applyAll=true) → apply to all items in brand
    if (applyAll || !r.fee_category) {
      const original = r.fee_category || '';
      if (cat === original) {
        delete _mscPending[r.item_code];
      } else {
        _mscPending[r.item_code] = cat;
      }
    }
  });
  _mscUpdatePendingBadge();
  _mscApplyFilter(); // re-render to show highlights
}

function _mscUpdatePendingBadge() {
  const count = Object.keys(_mscPending).length;
  const badge = document.getElementById('msc-pending-badge');
  const btn = document.getElementById('msc-save-btn');
  if (!badge || !btn) return;
  if (count > 0) {
    badge.style.display = 'inline-block';
    badge.textContent = `${count} perubahan pending`;
    btn.style.display = 'inline-block';
  } else {
    badge.style.display = 'none';
    btn.style.display = 'none';
  }
}

async function saveMarteSKUCat() {
  const pending = Object.entries(_mscPending);
  if (pending.length === 0) return;

  const btn = document.getElementById('msc-save-btn');
  if (btn) { btn.disabled = true; btn.textContent = 'Menyimpan…'; }

  // Only save rows that have a category (skip empty/cleared)
  const toUpsert = pending
    .filter(([,cat]) => cat !== '')
    .map(([item_code, fee_category]) => ({ item_code, fee_category }));

  // For cleared rows (set to ""), delete from marte_sku_categories
  const toDelete = pending.filter(([,cat]) => cat === '').map(([code]) => code);

  let errors = [];

  if (toUpsert.length > 0) {
    const { error } = await sb.from('marte_sku_categories')
      .upsert(toUpsert, { onConflict: 'item_code' });
    if (error) errors.push(error.message);
  }

  if (toDelete.length > 0) {
    const { error } = await sb.from('marte_sku_categories')
      .delete().in('item_code', toDelete);
    if (error) errors.push(error.message);
  }

  if (errors.length > 0) {
    alert('Ada error saat menyimpan:\n' + errors.join('\n'));
    if (btn) { btn.disabled = false; btn.textContent = '💾 Simpan Perubahan'; }
    return;
  }

  // Update local cache
  pending.forEach(([item_code, fee_category]) => {
    const row = _mscAllRows.find(r => r.item_code === item_code);
    if (row) row.fee_category = fee_category || null;
  });

  _mscPending = {};
  _mscUpdatePendingBadge();
  _mscRenderStats();
  _mscApplyFilter();

  if (btn) { btn.disabled = false; btn.textContent = '💾 Simpan Perubahan'; }

  // Brief success flash
  const badge = document.getElementById('msc-pending-badge');
  if (badge) {
    badge.style.display = 'inline-block';
    badge.style.background = 'var(--green)';
    badge.textContent = `✓ ${toUpsert.length + toDelete.length} SKU tersimpan`;
    setTimeout(() => { badge.style.display = 'none'; badge.style.background = ''; }, 3000);
  }

  await logActivity('marteskucat','bulk_update',null,`${toUpsert.length} categorized, ${toDelete.length} cleared`);
}

// Keep session in sync (handles token refresh, tab-switching, etc.)
sb.auth.onAuthStateChange((event, session) => {
  if (event === "SIGNED_OUT") {
    currentUser = ""; allRows = [];
    document.getElementById("app").style.display = "none";
    document.getElementById("loginScreen").style.display = "grid";
    const _cf = document.getElementById('chat-fab'); if (_cf) _cf.style.display='none';
    const _cp = document.getElementById('chat-popup'); if (_cp) _cp.style.display = 'none';
    _chatLoaded = false; _chatRealtime = null; _chatMsgs = [];
    document.getElementById("loginBox").style.display = "block";
    document.getElementById("resetBox").style.display = "none";
  }
});

// ── TEAM MEMBERS ──
let _teamRows = [];

async function loadTeamMembers(){
  const el = document.getElementById('team-list');
  if(!el) return;
  el.innerHTML = `<div style="color:var(--g400);font-size:13px;padding:20px">Memuat...</div>`;
  try{
    const { data, error } = await sb.from('team_members').select('*').order('name');
    if(error) throw error;
    _teamRows = data || [];
    renderTeamList();
  } catch(e){
    el.innerHTML = `<div style="color:#ef4444;font-size:13px;padding:20px">Gagal memuat: ${_esc(e.message)}</div>`;
  }
}

function renderTeamList(){
  const el = document.getElementById('team-list');
  if(!el) return;
  if(!_teamRows.length){
    el.innerHTML = `<div style="color:var(--g400);font-size:13px;padding:20px;font-style:italic">Belum ada anggota tim. Klik "+ Tambah Anggota" untuk mulai.</div>`;
    return;
  }
  el.innerHTML = _teamRows.map(m => {
    const initials = (m.name||'?').split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);
    return `
    <div style="background:var(--white);border:1px solid var(--g100);border-radius:12px;padding:16px 18px;display:flex;flex-direction:column;gap:10px;transition:box-shadow .15s;${m.is_active?'':'opacity:.55'}"
      onmouseover="this.style.boxShadow='0 2px 10px rgba(0,0,0,.07)'" onmouseout="this.style.boxShadow=''">
      <div style="display:flex;align-items:center;gap:12px">
        <div style="width:42px;height:42px;border-radius:50%;background:${_teamAvatarColor(m.name)};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;color:#fff;flex-shrink:0;letter-spacing:.5px">
          ${initials}
        </div>
        <div style="flex:1;min-width:0">
          <div style="font-size:14px;font-weight:600;color:var(--black);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${_esc(m.name)}${m.is_admin?' <span class="pill p-signings" style="font-size:9px;vertical-align:middle">ADMIN</span>':''}</div>
          <div style="font-size:11px;color:var(--g400);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${m.role ? _esc(m.role) : '<span style="font-style:italic;color:var(--g300)">No role</span>'}</div>
        </div>
      </div>
      ${m.email ? `<div style="font-size:11px;color:var(--g400);font-family:var(--mono);background:var(--off);border-radius:6px;padding:5px 8px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${_esc(m.email)}</div>` : ''}
      <div style="font-size:11px;color:var(--g400)">Akses: <strong style="color:var(--g600)">${m.is_admin?'Semua (admin)':(Array.isArray(m.module_access)?m.module_access.length+' modul':'Semua')}</strong></div>
      ${_isAdmin?`<button onclick="openTeamAccess('${_esc(m.id)}')" style="padding:5px 10px;border-radius:6px;border:1px solid #c7d2fe;background:#eef2ff;color:#4f46e5;font-size:12px;cursor:pointer;text-align:center">🔑 Atur Akses</button>`:''}
      <div style="display:flex;align-items:center;gap:6px;padding-top:2px;border-top:1px solid var(--g100)">
        <button onclick="openEditTeamMember('${_esc(m.id)}')"
          style="flex:1;padding:5px 10px;border-radius:6px;border:1px solid var(--g200);background:none;color:var(--g600);font-size:12px;cursor:pointer;text-align:center"
          onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background='none'">✏ Edit</button>
        <button onclick="toggleTeamActive('${_esc(m.id)}',${!m.is_active})"
          style="flex:1;padding:5px 10px;border-radius:6px;border:1px solid ${m.is_active?'var(--g200)':'#fca5a5'};background:${m.is_active?'none':'#fff1f2'};color:${m.is_active?'var(--g600)':'#ef4444'};font-size:12px;cursor:pointer;text-align:center"
          onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background='${m.is_active?'none':'#fff1f2'}'">
          ${m.is_active?'✓ Aktif':'✕ Nonaktif'}</button>
        <button onclick="deleteTeamMember('${_esc(m.id)}')"
          style="padding:5px 9px;border-radius:6px;border:1px solid var(--g100);background:none;color:var(--g400);font-size:13px;cursor:pointer"
          onmouseover="this.style.color='#ef4444';this.style.borderColor='#fca5a5'" onmouseout="this.style.color='var(--g400)';this.style.borderColor='var(--g100)'">🗑</button>
      </div>
    </div>`;
  }).join('');
}

function _teamAvatarColor(name){
  const colors = ['#6366f1','#3b82f6','#10b981','#f59e0b','#ef4444','#8b5cf6','#ec4899','#14b8a6'];
  let h = 0; for(let i=0;i<(name||'').length;i++) h = name.charCodeAt(i) + ((h<<5)-h);
  return colors[Math.abs(h) % colors.length];
}

function openAddTeamMember(){
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center';
  modal.onclick = e => { if(e.target===modal) modal.remove(); };
  modal.innerHTML = `
    <div style="background:var(--white);border-radius:14px;padding:28px;width:360px;box-shadow:0 8px 32px rgba(0,0,0,.15)">
      <div style="font-family:var(--head);font-size:16px;font-weight:700;margin-bottom:18px">Tambah Anggota Tim</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        <div>
          <div class="fg-label">Nama <span style="color:#ef4444">*</span></div>
          <input id="tm-name" type="text" placeholder="Nama lengkap…"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Role / Jabatan</div>
          <input id="tm-role" type="text" placeholder="mis. Designer, PM, Sales…"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Email</div>
          <input id="tm-email" type="email" placeholder="nama@sentra.com"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:20px;justify-content:flex-end">
        <button onclick="this.closest('[style*=fixed]').remove()"
          style="padding:8px 16px;background:none;border:1px solid var(--g200);border-radius:8px;font-size:13px;cursor:pointer">Batal</button>
        <button onclick="saveNewTeamMember(this)"
          style="padding:8px 18px;background:var(--black);color:var(--white);border:none;border-radius:8px;font-size:13px;cursor:pointer">Simpan</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.querySelector('#tm-name').focus();
  modal.querySelector('#tm-name').onkeydown = e => { if(e.key==='Enter') modal.querySelector('[onclick*=saveNewTeamMember]').click(); };
}

async function saveNewTeamMember(btn){
  const modal = btn.closest('[style*=fixed]');
  const name = modal.querySelector('#tm-name').value.trim();
  if(!name){ modal.querySelector('#tm-name').style.borderColor='#ef4444'; return; }
  const role  = modal.querySelector('#tm-role').value.trim() || null;
  const email = modal.querySelector('#tm-email').value.trim() || null;
  btn.disabled = true; btn.textContent = 'Menyimpan…';
  try{
    const { data, error } = await sb.from('team_members').insert({ name, role, email }).select().single();
    if(error) throw error;
    _teamRows.push(data);
    // Update _teamPics + acPics live so autocomplete works immediately
    if(!_teamPics.includes(data.name)) _teamPics.push(data.name);
    if(!acPics.includes(data.name)) acPics.push(data.name);
    renderTeamList();
    modal.remove();
  } catch(e){
    btn.disabled=false; btn.textContent='Simpan';
    alert('Gagal menyimpan: '+e.message);
  }
}

function openEditTeamMember(id){
  const m = _teamRows.find(x=>x.id===id);
  if(!m) return;
  const modal = document.createElement('div');
  modal.style.cssText = 'position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center';
  modal.onclick = e => { if(e.target===modal) modal.remove(); };
  modal.innerHTML = `
    <div style="background:var(--white);border-radius:14px;padding:28px;width:360px;box-shadow:0 8px 32px rgba(0,0,0,.15)">
      <div style="font-family:var(--head);font-size:16px;font-weight:700;margin-bottom:18px">Edit Anggota Tim</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        <div>
          <div class="fg-label">Nama <span style="color:#ef4444">*</span></div>
          <input id="tm-edit-name" type="text" value="${_esc(m.name)}"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Role / Jabatan</div>
          <input id="tm-edit-role" type="text" value="${_esc(m.role||'')}" placeholder="mis. Designer, PM, Sales…"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
        <div>
          <div class="fg-label">Email</div>
          <input id="tm-edit-email" type="email" value="${_esc(m.email||'')}" placeholder="nama@sentra.com"
            style="width:100%;padding:8px 10px;border:1px solid var(--g200);border-radius:8px;font-size:13px;outline:none;box-sizing:border-box">
        </div>
      </div>
      <div style="display:flex;gap:8px;margin-top:20px;justify-content:flex-end">
        <button onclick="this.closest('[style*=fixed]').remove()"
          style="padding:8px 16px;background:none;border:1px solid var(--g200);border-radius:8px;font-size:13px;cursor:pointer">Batal</button>
        <button onclick="saveEditTeamMember('${_esc(id)}',this)"
          style="padding:8px 18px;background:var(--black);color:var(--white);border:none;border-radius:8px;font-size:13px;cursor:pointer">Simpan</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
  modal.querySelector('#tm-edit-name').focus();
}

async function saveEditTeamMember(id, btn){
  const modal = btn.closest('[style*=fixed]');
  const name  = modal.querySelector('#tm-edit-name').value.trim();
  if(!name){ modal.querySelector('#tm-edit-name').style.borderColor='#ef4444'; return; }
  const role  = modal.querySelector('#tm-edit-role').value.trim() || null;
  const email = modal.querySelector('#tm-edit-email').value.trim() || null;
  btn.disabled = true; btn.textContent = 'Menyimpan…';
  try{
    const { error } = await sb.from('team_members').update({ name, role, email }).eq('id', id);
    if(error) throw error;
    const m = _teamRows.find(x=>x.id===id);
    if(m){
      // Update _teamPics/acPics if name changed
      if(m.name !== name){
        const oldName = m.name;
        _teamPics = _teamPics.map(n => n===oldName ? name : n);
        acPics    = acPics.map(n => n===oldName ? name : n);
      }
      m.name = name; m.role = role; m.email = email;
    }
    renderTeamList();
    modal.remove();
  } catch(e){
    btn.disabled=false; btn.textContent='Simpan';
    alert('Gagal menyimpan: '+e.message);
  }
}

// ── Access management (admin only) ──
function openTeamAccess(id){
  if(!_isAdmin) return;
  const m=_teamRows.find(x=>x.id===id); if(!m) return;
  const cur = Array.isArray(m.module_access) ? new Set(m.module_access) : null; // null = all
  const allChecked = cur===null;
  const modal=document.createElement('div');
  modal.style.cssText='position:fixed;inset:0;z-index:600;background:rgba(0,0,0,0.45);display:flex;align-items:center;justify-content:center;padding:20px';
  modal.onclick=e=>{ if(e.target===modal) modal.remove(); };
  const checks=ACCESS_MODULES.map(mod=>`
    <label style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:6px;font-size:12px;cursor:pointer"
      onmouseover="this.style.background='var(--off)'" onmouseout="this.style.background=''">
      <input type="checkbox" class="tac-mod" value="${mod.key}" ${allChecked||cur.has(mod.key)?'checked':''}> ${_esc(mod.label)}
    </label>`).join('');
  modal.innerHTML=`
    <div style="background:var(--white);border-radius:14px;padding:24px;width:520px;max-height:88vh;display:flex;flex-direction:column;box-shadow:0 8px 32px rgba(0,0,0,.15)">
      <div style="font-family:var(--head);font-size:16px;font-weight:700;margin-bottom:4px">Atur Akses — ${_esc(m.name)}</div>
      <div style="font-size:12px;color:var(--g400);margin-bottom:14px">Centang modul yang boleh diakses. Centang semua = akses penuh.</div>
      <label style="display:flex;align-items:center;gap:8px;font-size:13px;font-weight:600;margin-bottom:10px;padding:8px;background:#eef2ff;border-radius:8px;cursor:pointer">
        <input type="checkbox" id="tac-admin" ${m.is_admin?'checked':''}> 👑 Admin (akses semua + bisa atur akses orang lain)
      </label>
      <div style="display:flex;gap:8px;margin-bottom:8px">
        <button onclick="document.querySelectorAll('.tac-mod').forEach(c=>c.checked=true)" style="font-size:11px;padding:4px 10px;border:1px solid var(--g200);border-radius:6px;background:none;cursor:pointer">Centang semua</button>
        <button onclick="document.querySelectorAll('.tac-mod').forEach(c=>c.checked=false)" style="font-size:11px;padding:4px 10px;border:1px solid var(--g200);border-radius:6px;background:none;cursor:pointer">Kosongkan</button>
      </div>
      <div style="flex:1;overflow-y:auto;border:1px solid var(--g100);border-radius:8px;padding:6px;display:grid;grid-template-columns:1fr 1fr;gap:2px">${checks}</div>
      <div style="display:flex;gap:8px;margin-top:16px;justify-content:flex-end">
        <button onclick="this.closest('[style*=fixed]').remove()" style="padding:8px 16px;background:none;border:1px solid var(--g200);border-radius:8px;font-size:13px;cursor:pointer">Batal</button>
        <button onclick="saveTeamAccess('${_esc(id)}',this)" style="padding:8px 18px;background:var(--black);color:var(--white);border:none;border-radius:8px;font-size:13px;cursor:pointer">Simpan</button>
      </div>
    </div>`;
  document.body.appendChild(modal);
}

async function saveTeamAccess(id, btn){
  const modal=btn.closest('[style*=fixed]');
  const isAdmin=modal.querySelector('#tac-admin').checked;
  const checked=[...modal.querySelectorAll('.tac-mod:checked')].map(c=>c.value);
  // all checked → null (full access); else the array
  const moduleAccess = (checked.length===ACCESS_MODULES.length) ? null : checked;
  btn.disabled=true; btn.textContent='Menyimpan…';
  try{
    const {error}=await sb.from('team_members').update({is_admin:isAdmin, module_access:moduleAccess}).eq('id',id);
    if(error) throw error;
    const m=_teamRows.find(x=>x.id===id);
    if(m){ m.is_admin=isAdmin; m.module_access=moduleAccess; }
    renderTeamList();
    modal.remove();
  }catch(e){ btn.disabled=false; btn.textContent='Simpan'; alert('Gagal: '+e.message); }
}

async function toggleTeamActive(id, newState){
  try{
    await sb.from('team_members').update({is_active:newState}).eq('id',id);
    const m = _teamRows.find(x=>x.id===id);
    if(m) m.is_active = newState;
    // Sync _teamPics and acPics
    _teamPics = _teamRows.filter(x=>x.is_active).map(x=>x.name);
    acPics = [...new Set([..._teamPics, ...acPics.filter(n=>!_teamRows.map(x=>x.name).includes(n))])];
    renderTeamList();
  } catch(e){ alert('Gagal: '+e.message); }
}

async function deleteTeamMember(id){
  if(!confirm('Hapus anggota ini dari daftar tim?')) return;
  try{
    await sb.from('team_members').delete().eq('id',id);
    _teamRows = _teamRows.filter(x=>x.id!==id);
    _teamPics = _teamRows.filter(x=>x.is_active).map(x=>x.name);
    acPics = [...new Set([..._teamPics, ...acPics.filter(n=>!_teamRows.map(x=>x.name).includes(n))])];
    renderTeamList();
  } catch(e){ alert('Gagal hapus: '+e.message); }
}

